// Run all structural rules against parsed data + context.
function runStructuralRules(data, ctx) {
  const presence = {
    always: true, any: true,
    accounts: (data.accounts || []).length > 0,
    customers: (data.customers || []).length > 0,
    suppliers: (data.suppliers || []).length > 0,
    taxCodes: (data.taxCodes || []).length > 0,
    products: (data.products || []).length > 0,
    assets: (data.assets || []).length > 0,
    owners: (data.owners || []).length > 0,
    transactions: (data.transactions || []).length > 0,
    sales: (data.sales?.items || []).length > 0,
    purchases: (data.purchases?.items || []).length > 0,
    payments: (data.payments || []).length > 0,
    stockMovements: (data.stockMovements || []).length > 0,
    assetTransactions: (data.assetTransactions || []).length > 0,
  };
  return STRUCTURAL_RULES.map((rule) => {
    const applicable = presence[rule.requires] !== false;
    let hits = [], error = null;
    if (applicable) { try { hits = rule.evaluate(data, ctx) || []; } catch (e) { error = e.message; } }
    const status = error ? "error" : !applicable ? "na" : hits.length ? "flagged" : "clear";
    return { ...rule, status, count: hits.length, error, hits: hits.slice(0, 200) };
  });
}

// Public API: runAllRules + supporting orchestration
// ════════════════════════════════════════════════════════════════════

/**
 * Execute all SAF-T rules (117 VAT audit + 180 structural + 161 XSD-conformance + 20 duplicate + 4 classifier rules, plus full XSD v2.01 schema validation) against parsed data.
 * @param data       Output of parseSAFTFull()
 * @param opts       {thresholds: partial override of DEFAULT_THRESHOLDS}
 * @returns          {findings, summary, byRule, byCategory, bySeverity}
 */
function runAllRules(data, opts = {}) {
  if (!data || data._parseError) {
    return {
      findings: [{ rule_id: "PARSE", category: "Schema", severity: "Block", severityUi: "Critical", type: "S", typeName: "Schema", title: "XML parse failed", detail: data?._parseError || "Empty input", evidence: [] }],
      summary: { total: 1, rulesExecuted: AUDIT_RULES.length, Block: 1, Reject: 0, Warn: 0 },
      byRule: {}, byCategory: {}, bySeverity: { Block: 1, Reject: 0, Warn: 0 },
      audit: null,
    };
  }
  // Severity mapping from the source workbook: High -> Reject, Low -> Warn.
  const sevMap = { High: "Reject", Low: "Warn" };
  const uiMap = { Reject: "High", Warn: "Medium", Block: "Critical" };
  const audit = runAuditRules(data);
  const findings = [];
  const ruleById = {}; AUDIT_RULES.forEach((a) => { ruleById[a.id] = a; });
  audit.results.forEach((r) => {
    if (r.status !== "flagged") return;
    const severity = sevMap[r.severity] || "Warn";
    const meta = ruleById[r.id] || {};
    const h = r.hits[0]; const n = r.count || r.hits.length;
    findings.push({
      rule_id: r.id,
      category: r.scope === "sales" ? "Sales VAT" : r.scope === "both" ? "VAT (Sales + Purchases)" : "Purchase VAT",
      severity, severityUi: uiMap[severity] || "Medium",
      type: "B", typeName: "Audit",
      title: r.title,
      count: n,
      detail: h.msg + (n > 1 ? " | Total = " + n : "") + "  —  " + (r.legal || ""),
      evidence: r.hits.slice(0, 10).map((x) => x.msg),
      // rich metadata for the finding-detail page:
      ruleMeta: {
        titleLt: meta.title || r.title, titleEn: meta.titleEn || r.title,
        descriptionLt: meta.description || "", descriptionEn: meta.descriptionEn || "", legal: meta.legal || r.legal || "",
        fixEn: meta.fixEn || "", fixLt: meta.fixLt || "",
        dataTypes: meta.dataTypes || "", refType: meta.refType || "", scope: r.scope,
      },
      evidenceRow: h.row || null,   // structured @field values
      evidenceRows: r.hits.slice(0, 10).map((x) => x.row || null),
    });
  });
  // ── Structural / schema rules (SCHEMA family) — whole-file integrity ──
  const ctx = buildContext(data);
  const structural = runStructuralRules(data, ctx);
  structural.forEach((r) => {
    if (r.status !== "flagged") return;
    const severity = sevMap[r.severity] || "Warn";
    const row = r.hits[0]; const n = r.hits.length;
    {
      const msg = renderFailMsg(r.failTpl, row);
      findings.push({
        rule_id: r.id,
        category: r.category,
        severity, severityUi: uiMap[severity] || "Medium",
        type: "S", typeName: "Schema",
        title: r.titleEn || r.title,
        count: n,
        detail: msg + (n > 1 ? " | Total = " + n : "") + "  —  " + (r.legalReq || ""),
        evidence: r.hits.slice(0, 10).map((rw) => renderFailMsg(r.failTpl, rw)),
        ruleMeta: {
          titleLt: r.title, titleEn: r.titleEn || r.title,
          descriptionLt: r.description || "", legal: r.legalReq || "",
          fixEn: r.fixEn || "", fixLt: r.fixLt || "",
          dataTypes: r.dataTypes || "", refType: r.refType || "", scope: "schema",
        },
        evidenceRow: row || null,
        evidenceRows: r.hits.slice(0, 10),
      });
    }
  });
  // ── XSD-conformance rules (SCHEMA-level, from VMI's official XSD v2.01) ──
  const xsd = data.xsdResults || [];
  xsd.forEach((r) => {
    if (r.status !== "flagged") return;
    const severity = sevMap[r.severity] || "Reject";
    const fmtX = (rw) => Object.entries(rw).map(([k, v]) => `${k} = ${v}`).join(" | ");
    const row = r.hits[0]; const n = r.hits.length; const msg = fmtX(row);
    {
      findings.push({
        rule_id: r.id,
        category: r.category,
        severity, severityUi: uiMap[severity] || "High",
        type: "X", typeName: "XSD",
        title: r.titleEn,
        count: n,
        detail: msg + (n > 1 ? " | Total = " + n : "") + "  —  SAF-T XSD v2.01",
        evidence: r.hits.slice(0, 10).map(fmtX),
        ruleMeta: {
          titleLt: r.titleLt, titleEn: r.titleEn,
          descriptionLt: r.descLt, descriptionEn: r.descEn || "", legal: "SAF-T XSD v2.01 (VMI, įsakymas VA-49)",
          fixEn: r.fixEn || "", fixLt: r.fixLt || "",
          dataTypes: "F-Full", refType: r.el, scope: "xsd",
        },
        evidenceRow: row || null,
        evidenceRows: r.hits.slice(0, 10),
      });
    }
  });
  // ── Duplicate-record rules (Table 6 / DUBL — informational) ──
  const dub = data.dubResults || [];
  dub.forEach((r) => {
    if (r.status !== "flagged") return;
    const severity = sevMap[r.severity] || "Warn";
    const fmtD = (rw) => Object.entries(rw).map(([k, v]) => `${k} = ${v}`).join(" | ");
    const row = r.hits[0]; const n = r.hits.length; const msg = fmtD(row);
    {
      findings.push({
        rule_id: r.id,
        category: r.category,
        severity, severityUi: uiMap[severity] || "Medium",
        type: "D", typeName: "Duplicate",
        title: r.titleEn,
        count: n,
        detail: msg + (n > 1 ? " | Total = " + n : "") + "  —  SAF-T spec Table 6",
        evidence: r.hits.slice(0, 10).map(fmtD),
        ruleMeta: {
          titleLt: r.titleLt, titleEn: r.titleEn,
          descriptionLt: r.descLt, descriptionEn: r.descEn || "", legal: "SAF-T techninė specifikacija, 6 lentelė (DUBL)",
          fixEn: r.fixEn || "", fixLt: r.fixLt || "",
          dataTypes: "F-Full", refType: r.record, scope: "duplicate",
        },
        evidenceRow: row || null,
        evidenceRows: r.hits.slice(0, 10),
      });
    }
  });
  // ── Classifier-validation rules (VMI VA-49 Annex 2 code lists) ──
  const cls = data.clsResults || [];
  cls.forEach((r) => {
    if (r.status !== "flagged") return;
    const severity = sevMap[r.severity] || "Warn";
    const fmtK = (rw) => Object.entries(rw).map(([k, v]) => `${k} = ${v}`).join(" | ");
    const row = r.hits[0]; const n = r.hits.length; const msg = fmtK(row);
    {
      findings.push({
        rule_id: r.id,
        category: r.category,
        severity, severityUi: uiMap[severity] || "Medium",
        type: "K", typeName: "Classifier",
        title: r.titleEn,
        count: n,
        detail: msg + (n > 1 ? " | Total = " + n : "") + "  —  VMI klasifikatorius (VA-49 2 priedas)",
        evidence: r.hits.slice(0, 10).map(fmtK),
        ruleMeta: {
          titleLt: r.titleLt, titleEn: r.titleEn,
          descriptionLt: r.descLt, descriptionEn: r.descEn || "", legal: "VMI klasifikatoriai Nr.1–3 (VA-49 2 priedas)",
          fixEn: r.fixEn || "", fixLt: r.fixLt || "",
          dataTypes: "F-Full", refType: r.el, scope: "classifier",
        },
        evidenceRow: row || null,
        evidenceRows: r.hits.slice(0, 10),
      });
    }
  });
  // ── Full XSD schema validation (entire document vs. official XSD) ──
  // Complementary to the itemized XSD rules: catches undeclared elements,
  // cardinality (maxOccurs), and type/facet violations on ANY element.
  const sv = data.schemaValidation || { findings: [] };
  if (sv.findings && sv.findings.length) {
    const coveredEls = new Set(findings.filter((f) => f.type === "X").map((f) => f.ruleMeta && f.ruleMeta.refType).filter(Boolean));
    const facetKinds = new Set(["enum", "maxLength", "minLength", "minInclusive", "fractionDigits", "totalDigits", "numeric", "date"]);
    const kindTitle = {
      undeclared: "Undeclared element (not in XSD)", maxOccurs: "Element occurs more times than the XSD allows",
      enum: "Value not allowed by the XSD type", maxLength: "Value exceeds XSD maxLength", minLength: "Value below XSD minLength",
      minInclusive: "Value below XSD minimum", fractionDigits: "Too many decimal places for the XSD type",
      totalDigits: "Too many digits for the XSD type", numeric: "Non-numeric value in a numeric XSD type", date: "Invalid date for the XSD type",
    };
    const secOf = (p) => {
      const parts = p.split("/");
      const m = { Header: "Header", GeneralLedgerAccounts: "GL Accounts", Customers: "Customers", Suppliers: "Suppliers",
        TaxTable: "Tax / Classifiers", UOMTable: "Products", AnalysisTypeTable: "Analysis", Products: "Products",
        Owners: "Owners", Assets: "Assets", GeneralLedgerEntries: "GL Transactions", SalesInvoices: "Invoices",
        PurchaseInvoices: "Invoices", Payments: "Payments", MovementOfGoods: "Stock Movements", AssetTransactions: "Asset Transactions" };
      for (const seg of parts) if (m[seg]) return m[seg];
      return "Schema";
    };
    const grouped = new Map();
    for (const v of sv.findings) {
      const leaf = v.path.split("/").pop();
      if (facetKinds.has(v.kind) && coveredEls.has(leaf)) continue; // itemized rule already flagged this element
      const g = grouped.get(v.kind) || { kind: v.kind, items: [] };
      g.items.push(v); grouped.set(v.kind, g);
    }
    for (const g of grouped.values()) {
      const v = g.items[0]; const n = g.items.length; const leaf = v.path.split("/").pop();
      findings.push({
        rule_id: "SAFT_XSDV_" + g.kind,
        category: secOf(v.path),
        severity: "Reject", severityUi: "High",
        type: "V", typeName: "XSD Schema",
        title: kindTitle[g.kind] || ("XSD schema violation (" + g.kind + ")"),
        count: n,
        detail: v.path + (v.detail ? "  —  " + v.detail : "") + (n > 1 ? " | Total = " + n : "") + "  ·  full XSD v2.01 validation",
        evidence: g.items.slice(0, 10).map((x) => x.path + (x.detail ? " (" + x.detail + ")" : "")),
        ruleMeta: {
          titleLt: "Pilna XSD validacija: " + (kindTitle[g.kind] || g.kind),
          titleEn: kindTitle[g.kind] || ("XSD schema violation (" + g.kind + ")"),
          descriptionLt: "Visa SAF-T rinkmena tikrinama pagal oficialų VMI XSD v2.01. Pažeidimas: " + v.path,
          descriptionEn: "The entire SAF-T file is validated against the official VMI XSD v2.01. Violation at: " + v.path,
          legal: "VMI SAF-T XSD v2.01 (VA-49)", fixEn: "Correct the element to conform to the SAF-T XSD.",
          fixLt: "Pataisykite elementą pagal SAF-T XSD reikalavimus.",
          dataTypes: "F-Full", refType: leaf, scope: "xsd-schema",
        },
        evidenceRow: { Path: v.path, Issue: g.kind, Detail: v.detail || "" },
        evidenceRows: g.items.slice(0, 10).map((x) => ({ Path: x.path, Issue: g.kind, Detail: x.detail || "" })),
      });
    }
  }
  const byRule = {}, byCategory = {}, bySeverity = { Block: 0, Reject: 0, Warn: 0 };
  for (const f of findings) {
    const w = f.count || 1;
    byRule[f.rule_id] = (byRule[f.rule_id] || 0) + w;
    byCategory[f.category] = (byCategory[f.category] || 0) + w;
    bySeverity[f.severity] = (bySeverity[f.severity] || 0) + w;
  }
  const TOTAL_RULES = AUDIT_RULES.length + STRUCTURAL_RULES.length + XSD_RULES.length + DUPLICATE_RULES.length + CLASSIFIER_RULES.length;
  return {
    findings,
    summary: { total: findings.length, occurrences: findings.reduce((s, f) => s + (f.count || 1), 0), rulesExecuted: TOTAL_RULES, ...bySeverity },
    byRule, byCategory, bySeverity,
    coverage: { rulesTotal: TOTAL_RULES, rulesRegistered: TOTAL_RULES, rulesTriggered: Object.keys(byRule).length, rulesVat: AUDIT_RULES.length, rulesSchema: STRUCTURAL_RULES.length, rulesXsd: XSD_RULES.length, rulesDup: DUPLICATE_RULES.length, rulesCls: CLASSIFIER_RULES.length, schemaValidation: { active: true, types: Object.keys((typeof XSD_SCHEMA_MODEL !== "undefined" && XSD_SCHEMA_MODEL.types) || {}).length, violations: (data.schemaValidation && data.schemaValidation.total) || 0 } },
    audit, structural, xsd, dub, cls, // structured results for all families
  };
}

function getRuleCatalog() {
  const sevMap = { High: "Reject", Low: "Warn" };
  const vat = AUDIT_RULES.map((r) => ({
    id: r.id,
    category: r.scope === "sales" ? "Sales VAT" : "Purchase VAT",
    severity: sevMap[r.severity] || "Warn",
    severityUi: r.severity === "High" ? "High" : "Medium",
    type: "B", typeName: "Audit",
    title: r.title, titleEn: r.titleEn,
    rationale: r.description || "",
    legal: r.legal, dataTypes: r.dataTypes, refType: r.refType,
  }));
  const schema = STRUCTURAL_RULES.map((r) => ({
    id: r.id,
    category: r.category,
    severity: sevMap[r.severity] || "Warn",
    severityUi: r.severity === "High" ? "High" : "Medium",
    type: "S", typeName: "Schema",
    title: r.title, titleEn: r.titleEn,
    rationale: r.description || "",
    legal: r.legalReq, dataTypes: r.dataTypes, refType: r.refType,
  }));
  const xsd = XSD_RULES.map((r) => ({
    id: r.id,
    category: r.category,
    severity: sevMap[r.severity] || "Reject",
    severityUi: "High",
    type: "X", typeName: "XSD",
    title: r.titleLt, titleEn: r.titleEn,
    rationale: r.descEn || "",
    legal: "SAF-T XSD v2.01", dataTypes: "F-Full", refType: r.el,
  }));
  const dup = DUPLICATE_RULES.map((r) => ({
    id: r.id,
    category: r.category,
    severity: sevMap[r.severity] || "Warn",
    severityUi: "Medium",
    type: "D", typeName: "Duplicate",
    title: r.titleLt, titleEn: r.titleEn,
    rationale: r.descEn || "",
    legal: "SAF-T spec Table 6", dataTypes: "F-Full", refType: r.record,
  }));
  const cls = CLASSIFIER_RULES.map((r) => ({
    id: r.id,
    category: r.category,
    severity: sevMap[r.severity] || "Warn",
    severityUi: r.severity === "High" ? "High" : "Medium",
    type: "K", typeName: "Classifier",
    title: r.titleLt, titleEn: r.titleEn,
    rationale: r.descEn || "",
    legal: "VMI klasifikatoriai (VA-49)", dataTypes: "F-Full", refType: r.el,
  }));
  return [...xsd, ...dup, ...cls, ...schema, ...vat];
}

/**
 * Build a compact structured packet for AI agent consumption.
 * Strips verbose evidence to keep tokens manageable while preserving
 * everything the AI needs to interpret findings.
 */
function buildAiInterpretationPayload(data, runResult) {
  const sample = (findings, n = 3) => findings.slice(0, n).map((f) => ({
    rule_id: f.rule_id,
    severity: f.severity,
    title: f.title,
    detail: f.detail.length > 200 ? f.detail.substring(0, 200) + "..." : f.detail,
    evidence_count: f.evidence?.length || 0,
    evidence_sample: (f.evidence || []).slice(0, 3),
  }));

  // Group findings by category, then within category surface up to 5 examples
  const byCat = {};
  for (const f of runResult.findings) {
    byCat[f.category] = byCat[f.category] || [];
    byCat[f.category].push(f);
  }
  const groupedSummary = Object.entries(byCat).map(([cat, arr]) => ({
    category: cat,
    finding_count: arr.length,
    severities: {
      Block: arr.filter((f) => f.severity === "Block").length,
      Reject: arr.filter((f) => f.severity === "Reject").length,
      Warn: arr.filter((f) => f.severity === "Warn").length,
    },
    top_findings: sample(arr, 5),
  }));

  // Company context for AI to ground its interpretation
  const company = {
    name: data.header?.company?.name || "(unknown)",
    registration: data.header?.company?.registrationNumber || "",
    vat: data.header?.company?.taxRegistration || "",
    period: `${data.header?.fiscalYearFrom || ""} → ${data.header?.fiscalYearTo || ""}`,
    dataType: data.header?.dataType || "",
    counts: data.counts || {},
  };

  return {
    company,
    summary: runResult.summary,
    coverage: runResult.coverage,
    bySeverity: runResult.bySeverity,
    byCategory: runResult.byCategory,
    groupedSummary,
    thresholds: runResult.thresholds,
  };
}

// ════════════════════════════════════════════════════════════════════
// SAF-T AI LAYER — Interpretation + Smart Analysis (inlined from saftAI.ts)
// Two distinct AI calls operate on the structured findings produced by
// the deterministic rule engine above. NEVER use these for validation —
// validation is done deterministically by runAllRules(). These functions
// only INTERPRET the findings the engine already produced.
// ════════════════════════════════════════════════════════════════════


// ─── INTERPRETATION SYSTEM PROMPT ────────────────────────────────────
const SYSTEM_PROMPT_INTERPRETATION = `You are the **TAXAI SAF-T Senior Auditor** — a forensic-grade Lithuanian tax analyst.

You are interpreting findings from a DETERMINISTIC 482-rule SAF-T engine (XSD v2.01, Order VA-127). The findings are objective facts: each one has a rule_id, severity (Block/Reject/Warn), type (S=Schema/B=Business/C=Consistency/F=Financial), category, title, detail, and evidence samples.

Your job is NOT to re-validate. Your job is to INTERPRET, PRIORITIZE, and EXPLAIN.

# Output structure (use this markdown exactly)

## 🎯 Executive summary
- 3-5 sentences. State overall file health, the most material risks, and whether the file is fit for VMI submission.
- Lead with the dominant pattern (e.g., "11 of 18 findings cluster in tax-arithmetic rules — suggests a single rounding configuration bug").

## 🚨 Material findings (Block + Reject)
For each finding ranked by financial/legal impact:
- **[rule_id] Title** — severity badge
- *What it means in plain Lithuanian/business terms:* one sentence
- *Legal basis:* exact article (e.g., "PMĮ 11 str. 1 d.", "PVMĮ 64 str.", "MAĮ 13 str. 5 d.", "Buhalterinės apskaitos įstatymas 16 str.", VA-49/VA-127)
- *Likely root cause:* configuration bug / data-entry / process gap / system limitation
- *Financial impact estimate:* if calculable from evidence, give €-range; otherwise "depends on N"
- *Immediate fix:* concrete action this week
- *Defensibility on inspection:* high/medium/low and why

## 🟡 Warn-level findings worth addressing
Group similar warnings (e.g., "5 weekend postings", "3 round-trip patterns") into a single paragraph each. No need to itemize every Warn.

## ✅ What looks correct
Mention rules that DIDN'T fire on areas where they easily could have (e.g., "Trial balance equality B-045/046 passed cleanly — opening and closing TB are balanced", "All TaxCodes referenced exist in MasterFiles").

## 📊 Pattern analysis
- Is there a temporal pattern? (e.g., all errors in Q4)
- Is there an account-cluster pattern? (e.g., all errors involve account 271)
- Is there a counterparty-cluster pattern? (e.g., 3 of 5 supplier issues involve the same supplier)
- Is this likely a SYSTEM problem (ERP config), a PROCESS problem (procedure), or a PEOPLE problem (training)?

# Style rules
- Lithuanian tax-law fluency is mandatory. Cite specific articles, not vague "tax law".
- Distinguish between SCHEMA errors (file will not load) vs CONSISTENCY errors (file loads, math fails) vs FINANCIAL flags (legal but suspicious).
- Never invent legal article numbers. If you are not sure, write "(verify article)".
- Never recommend tax evasion or aggressive minimization. Recommend defensible, compliant approaches.
- Lithuanian terminology where it matters: PVM (VAT), PM (CIT), GPM (PIT), MAĮ (Tax Administration Law), PMĮ (CIT Law), PVMĮ (VAT Law), SODRA, VMI, FNTT, FR0600, GPM313, PLN204, SAM/SAV.
- Be direct. The user is a professional. Skip pleasantries.
- If findings are zero or trivial, say so — do not invent problems to look thorough.`;

// ─── SMART ANALYSIS SYSTEM PROMPT ────────────────────────────────────
const SYSTEM_PROMPT_SMART_ANALYSIS = `You are the **TAXAI Smart Analysis Engine** — a meta-level critic that improves the rule engine itself and proposes legal/financial strategies.

You receive: (1) the file's deterministic findings, (2) the rule catalog (250 rules), (3) coverage stats. You DO NOT redo the engine's work. You operate one level above it.

# Output structure (use this markdown exactly)

## 🧠 Rule-engine self-critique

### Coverage assessment
Rate each of the 9 rule categories on a 1-5 scale for how well the existing rules caught what they should have:
- **A Header (35 rules)** — score, one-line justification
- **B Master Files (75 rules)** — score
- **C General Ledger (55 rules)** — score
- **D Sales Invoices (35 rules)** — score
- **E Purchase Invoices (30 rules)** — score
- **F Payments (20 rules)** — score
- **G Movements (15 rules)** — score
- **H Asset Transactions (10 rules)** — score
- **I Cross-section (25 rules)** — score

### What the engine likely missed
List 3-7 SPECIFIC additional rules that would catch issues the current 300 don't cover. Format each as:
- **PROPOSED rule [NEW-###]** — Severity / Type
  - *Trigger:* exact condition
  - *Why it matters:* concrete fraud/error scenario
  - *Detection logic:* what to compute
  - *Threshold to use:* numeric default

Bias your suggestions toward:
- Sector-specific patterns (retail vs construction vs IT vs transport)
- Patterns the LLM can see in the data that the deterministic engine cannot easily express (NLP on descriptions, anomaly detection across multiple dimensions)
- New 2026 LT tax-law changes (CIT 17%, instant depreciation per PM 18 str., new VAT structure 21/12/5/0)

### Rules that probably over-fire
If you see rules producing high false-positive rates given THIS company's profile, name them and explain why the default threshold is wrong for this entity.

## ⚖️ Legal remediation pathway

For each material finding (Block/Reject) or finding cluster:

### [rule_id or cluster name]
- **Risk if VMI catches it:** specific exposure (additional tax + bauda + delspinigiai with article)
  - VAT shortfall: PVMĮ 123 str. baudos 10-50% + delspinigiai 0.03%/day (MAĮ 99)
  - CIT shortfall: PMĮ 47 str. + delspinigiai + bauda
  - Late SAF-T submission / refusal: MAĮ 139-1 str. baudos 200-1820 EUR

- **Defensive option A — Voluntary disclosure (MAĮ 68 str.):**
  - When applicable: error discovered by taxpayer BEFORE VMI inspection notice
  - Effect: bauda may be reduced 50-70% (50% standard, 70% if disclosure within first 30 days of becoming aware)
  - Procedure: corrective declaration + written explanation + payment of tax + delspinigiai
  - Practical steps for THIS finding

- **Defensive option B — Tax ruling / position confirmation (MAĮ 37-1):**
  - When applicable: ambiguous treatment, want VMI to bless the position prospectively
  - Effect: binding on VMI if facts stay the same
  - When NOT to use: when the position is clearly wrong (forces VMI to formalize)

- **Defensive option C — Settlement / sutaikinimas (MAĮ 71 str.):**
  - When applicable: dispute already opened, want to avoid litigation
  - Effect: negotiated reduction of penalties, sometimes principal
  - Trade-offs

- **Defensive option D — Restatement / amended SAF-T:**
  - Procedure under VA-127 §3.1: re-submission under revised Entity identifier
  - Original Entity preserved in audit logs

Pick the BEST option for the specific finding and explain why.

## 💶 Financing & management strategies

If the findings imply additional tax due, suggest financing and operational strategies:

### Cash-flow management
- **Mokesčių paskirstymas (MAĮ 88 str.) — installment plan:** when payment hardship is documented, VMI may grant up to 5 years. Show indicative payment schedule for the estimated liability.
- **Deferment under MAĮ 88 str. 5 d.:** force majeure / sector crisis triggers
- **Working-capital financing:** short-term bank line vs invoice factoring vs VMI installment — compare effective cost

### Offsetting strategies (legal CIT optimization)
- **R&D credit (PMĮ 17-1 str.):** R&D expenses can be 3× deducted. If the entity does any product development, validate eligibility — typical multi-€10k-€100k reduction.
- **Investment-project relief (PMĮ 46-1 str.):** up to 100% CIT reduction for qualifying investments in technology/equipment/software 2026-2030. Tight conditions but high impact.
- **Instant depreciation (PMĮ 18 str. amend. from 2026):** new fixed assets bought 2026+ can be 100%-depreciated in year of acquisition. If the company is buying equipment, accelerate to before year-end.
- **Small-entity 7% CIT band (PMĮ 5 str.):** if revenue ≤ €300,000 and ≤10 employees, 7% rate instead of 17%. Check eligibility.
- **Loss carry-forward (PMĮ 30 str.):** ordinary losses 5 years, infrastructure losses indefinite.

### External funding
- **Invega (national promotional bank):** working-capital loans, guarantees, EU-funded programs (DUK, COSME, InvestEU instruments)
- **Innovation/digital-transformation grants (LVPA, EIM):** non-refundable if eligible
- **EU recovery and resilience funds (NextGenEU via national plan):** sectoral calls

### Process improvements (prevent recurrence)
- ERP-side: configuration patches to stop the error at source (tax-code lookup table, posting-date validation, weekend-block flag)
- Procedure-side: monthly mini-SAF-T export + internal validation before close
- Controls-side: 4-eyes review for journals > €10k, system blocks on backposting > 30 days
- Training-side: where the people factor is causing repeat errors

## 🎯 Prioritized 30-day action plan
Numbered list, each item:
- (a) what to do, (b) who does it, (c) by when, (d) expected outcome

# Style rules
- Be concrete. "Use MAĮ 68" is useless; "File corrective FR0600 for May 2025 within 30 days of discovery, request 70% bauda reduction citing MAĮ 68 str. 2 d." is useful.
- Money figures: estimate ranges when exact numbers aren't in the findings; never invent numbers that aren't derivable.
- Never recommend evasion or aggressive minimization that would not survive inspection.
- Lithuanian legal vocabulary where precise: bauda (penalty), delspinigiai (default interest), permokos (overpayment), mokestinė nepriemoka (tax arrears), patikrinimas (inspection), kontrolinis pirkimas (test purchase).
- Do not pad. If a section has nothing to say for this file, write "Not applicable to this file." and move on.`;

// ─── BUILD COMPACT AI PAYLOAD STRINGS ────────────────────────────────

/**
 * Build a token-efficient findings packet for the AI.
 * Compresses 300+ potential findings into a structured, readable block.
 */
function formatFindingsForAi(payload, maxFindingsPerCategory = 8) {
  const lines = [];
  lines.push(`COMPANY: ${payload.company.name}`);
  lines.push(`REG: ${payload.company.registration}  VAT: ${payload.company.vat}`);
  lines.push(`PERIOD: ${payload.company.period}  DATA TYPE: ${payload.company.dataType}`);
  lines.push("");
  lines.push("COUNTS:");
  for (const [k, v] of Object.entries(payload.company.counts || {})) {
    if (v > 0) lines.push(`  ${k}: ${v}`);
  }
  lines.push("");
  lines.push(`FINDINGS SUMMARY: total=${payload.summary.total}, rulesExecuted=${payload.summary.rulesExecuted}, Block=${payload.bySeverity.Block}, Reject=${payload.bySeverity.Reject}, Warn=${payload.bySeverity.Warn}`);
  lines.push(`COVERAGE: ${payload.coverage.rulesTriggered}/${payload.coverage.rulesRegistered} rules triggered`);
  lines.push("");
  lines.push("FINDINGS BY CATEGORY:");

  for (const grp of payload.groupedSummary || []) {
    lines.push(`\n### ${grp.category} — ${grp.finding_count} finding(s) [Block=${grp.severities.Block} Reject=${grp.severities.Reject} Warn=${grp.severities.Warn}]`);
    for (const f of grp.top_findings.slice(0, maxFindingsPerCategory)) {
      lines.push(`  - [${f.rule_id} ${f.severity}] ${f.title}`);
      lines.push(`    detail: ${f.detail}`);
      if (f.evidence_count > 0) {
        lines.push(`    evidence (${f.evidence_count} items, showing ${f.evidence_sample.length}):`);
        f.evidence_sample.forEach((ev) => lines.push(`      • ${String(ev).substring(0, 200)}`));
      }
    }
    if (grp.finding_count > maxFindingsPerCategory) {
      lines.push(`  ... +${grp.finding_count - maxFindingsPerCategory} more in this category`);
    }
  }

  lines.push("");
  lines.push(`THRESHOLDS USED: ${JSON.stringify(payload.thresholds)}`);
  return lines.join("\n");
}

/**
 * Build a compact rule-catalog summary for the smart-analysis prompt.
 * Keeps context window manageable while giving the AI enough to critique.
 */
function formatRuleCatalogForAi() {
  const catalog = getRuleCatalog();
  // Group by category and emit counts + a few exemplar titles
  const groups = {};
  for (const r of catalog) {
    groups[r.category] = groups[r.category] || [];
    groups[r.category].push(r);
  }
  const lines = ["RULE CATALOG (250 deterministic rules):"];
  for (const [cat, rules] of Object.entries(groups).sort()) {
    lines.push(`\n${cat} (${rules.length} rules):`);
    const sev = { Block: 0, Reject: 0, Warn: 0 };
    rules.forEach((r) => sev[r.severity]++);
    lines.push(`  severity mix: Block=${sev.Block}, Reject=${sev.Reject}, Warn=${sev.Warn}`);
    // First/middle/last as exemplars
    const samples = [rules[0], rules[Math.floor(rules.length / 2)], rules[rules.length - 1]];
    samples.forEach((r) => lines.push(`  ${r.id}: ${r.title.substring(0, 80)}`));
  }
  return lines.join("\n");
}

// ─── PUBLIC RUNNERS ──────────────────────────────────────────────────

/**
 * Run AI INTERPRETATION over the findings.
 * Drop-in replacement for the existing runAI in TaxAI.tsx.
 *
 * @param data       parsed SAF-T from parseSAFTFull()
 * @param result     output of runAllRules()
 * @param callAI     existing callAI(systemPrompt, userPrompt, history, attachments) function
 * @returns          markdown string for <Md/>
 */
// ═════════════════════════════════════════════════════════════════════════
// GROUNDED AGENT PIPELINE (verification contract for every AI tab).
// Principle: the model NEVER computes — the deterministic engine computes,
// the model explains. Every number must be copied verbatim from the FACTS
// brief; every legal statement must cite a [source-id]; the draft is
// verified claim-by-claim against the engine and repaired once if needed;
// the final report carries a confidence score and an official-source list.
// Offline (no AI endpoint) it degrades to the deterministic brief — 100%.
// ═════════════════════════════════════════════════════════════════════════
// ═════════════════════════════════════════════════════════════════════════
// E-AUDIT ENGINE — ISA (TAS) financial-audit layer on SAF-T data.
// Methodology references: "TSA taikymo MVĮ audito vadovas" (IFAC SMP guide,
// LT translation, 3rd ed.) Vol I core concepts (V1-7 materiality/TAS 320,
// V1-8 risk assessment/TAS 240+315, V1-14 going concern/TAS 570) and Vol II
// practical guidance (V2-10 further procedures/TAS 330+520, V2 sampling:
// "Imties dydis = visuma ÷ atrankos intervalas"). Percentages are
// configurable professional-judgment defaults under TAS 320 — the guide
// deliberately prescribes none.
// ═════════════════════════════════════════════════════════════════════════
const EA_DEFAULTS = { pbtPct: 5, revenuePct: 1, assetsPct: 1, equityPct: 2, perfPct: 75, trivialPct: 5, reliabilityFactor: 3.0 };
const ea2 = (v) => Math.round((v + Number.EPSILON) * 100) / 100;
function eaSig2(v) { if (!isFinite(v) || v === 0) return 0; const m = Math.pow(10, Math.floor(Math.log10(Math.abs(v))) - 1); return Math.round(v / m) * m; }

function eaTrialBalance(d) {
  const tb = {};
  ((d && d.transactions) || []).forEach((t) => (t.lines || []).forEach((l) => {
    const a = l.accountID || "?"; const r = tb[a] = tb[a] || { debit: 0, credit: 0 };
    r.debit += l.debitAmount || 0; r.credit += l.creditAmount || 0;
  }));
  const names = {};
  ((d && d.accounts) || []).forEach((a) => { names[a.accountID] = a.accountDescription || a.description || a.name || ""; });
  Object.keys(tb).forEach((a) => { tb[a].net = ea2(tb[a].debit - tb[a].credit); tb[a].name = names[a] || ""; });
  return tb;
}

// ── TAS 320 / Vadovas V1-7: materiality ──
function eaMateriality(d, opts) {
  const o = Object.assign({}, EA_DEFAULTS, opts || {});
  const k = (o.kpis) || (typeof computeKPIs === "function" && typeof buildContext === "function" ? (computeKPIs(d, buildContext(d)) || {}).kpis || {} : {});
  const alts = [];
  const add = (basis, basisLt, value, pct) => { if (value != null && isFinite(value) && Math.abs(value) > 0) alts.push({ basis, basisLt, value: ea2(value), pct, overall: eaSig2(Math.abs(value) * pct / 100) }); };
  add("Profit before tax (proxy: gross result)", "Pelnas prieš mokesčius (aproks.: bendrasis rezultatas)", k.grossResult, o.pbtPct);
  add("Revenue", "Pajamos", k.revenue, o.revenuePct);
  add("Total assets", "Visas turtas", k.totalAssets, o.assetsPct);
  add("Equity", "Nuosavas kapitalas", k.equity, o.equityPct);
  const pick = o.benchmark ? alts.find((a) => a.basis.toLowerCase().includes(o.benchmark)) || alts[0] : (alts[0] || null);
  const overall = pick ? pick.overall : 0;
  return { kpis: k, alternatives: alts, basis: pick ? pick.basis : "—", basisLt: pick ? pick.basisLt : "—", baseValue: pick ? pick.value : 0, pct: pick ? pick.pct : 0,
    overall, performance: eaSig2(overall * o.perfPct / 100), trivial: eaSig2(overall * o.trivialPct / 100),
    perfPct: o.perfPct, trivialPct: o.trivialPct, ref: "TAS 320 · Vadovas V1-7" };
}

// ── TAS 240 / Vadovas V1-8, V2-10: journal-entry CAAT battery ──
function eaJournalTests(d, mat) {
  const txs = (d && d.transactions) || [];
  const pe = (d && d.header && d.header.periodEnd) || "";
  const tests = [];
  const T = (id, tas, lt, en, hits, sev, stats) => tests.push({ id, tas, lt, en, hits: hits.slice(0, 50), count: hits.length, severity: sev, stats: stats || null });
  const wk = (ds) => { const t = new Date(String(ds) + "T12:00:00"); const g = t.getDay(); return !isNaN(t) && (g === 0 || g === 6); };
  const row = (t, l, extra) => Object.assign({ tx: t.transactionID || "—", data: t.transactionDate || "—", acct: l ? (l.accountID || "—") : "—", suma: l ? ea2(Math.max(l.debitAmount || 0, l.creditAmount || 0)) : "—" }, extra || {});

  const weekend = []; txs.forEach((t) => { if (wk(t.transactionDate)) (t.lines || []).slice(0, 1).forEach((l) => weekend.push(row(t, l))); });
  T("JE_WEEKEND", "TAS 240", "Įrašai savaitgaliais", "Entries posted on weekends", weekend, "Medium");

  let last3 = [], total = txs.length;
  if (pe) { const cut = new Date(pe + "T00:00:00"); cut.setDate(cut.getDate() - 2); const cs = cut.toISOString().slice(0, 10); txs.forEach((t) => { if (t.transactionDate && t.transactionDate >= cs && t.transactionDate <= pe) last3.push(row(t, (t.lines || [])[0])); }); }
  T("JE_PERIOD_END", "TAS 240", "Koncentracija paskutines 3 d.", "Period-end concentration (last 3 days)", last3, last3.length / Math.max(1, total) > 0.15 ? "High" : "Low", { sharePct: ea2(100 * last3.length / Math.max(1, total)) });

  const round = []; txs.forEach((t) => (t.lines || []).forEach((l) => { const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (v >= Math.max(1000, mat.trivial) && v % 1000 === 0) round.push(row(t, l)); }));
  T("JE_ROUND", "TAS 240", "Apvalios sumos (×1000)", "Round-sum entries (×1000)", round, "Medium");

  // Benford first-digit (lines ≥ 10): expected log10(1+1/d); MAD bands (Nigrini)
  const dist = Array(10).fill(0); let n = 0;
  txs.forEach((t) => (t.lines || []).forEach((l) => { const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (v >= 10) { const fd = Number(String(Math.floor(v))[0]); if (fd >= 1) { dist[fd]++; n++; } } }));
  let mad = 0; const rows9 = [];
  if (n >= 30) {
    for (let dg = 1; dg <= 9; dg++) { const act = dist[dg] / n, exp = Math.log10(1 + 1 / dg); mad += Math.abs(act - exp); rows9.push({ skaitmuo: dg, faktas: ea2(act * 100), tiketina: ea2(exp * 100) }); }
    mad = mad / 9;
  }
  const bVerdict = n < 30 ? "insufficient" : mad < 0.006 ? "close" : mad < 0.012 ? "acceptable" : mad < 0.015 ? "marginal" : "nonconformity";
  T("JE_BENFORD", "TAS 240", "Benfordo pirmo skaitmens analizė", "Benford first-digit analysis", bVerdict === "nonconformity" || bVerdict === "marginal" ? rows9 : [], bVerdict === "nonconformity" ? "High" : "Low", { n, mad: ea2(mad * 1000) / 1000, verdict: bVerdict, dist: rows9 });

  const abovePM = []; txs.forEach((t) => (t.lines || []).forEach((l) => { const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (mat.performance > 0 && v >= mat.performance) abovePM.push(row(t, l)); }));
  T("JE_ABOVE_PM", "TAS 330", "Įrašai ≥ veiklos reikšmingumo (testuojami 100%)", "Entries ≥ performance materiality (test 100%)", abovePM, abovePM.length ? "High" : "Low");

  const noDesc = []; txs.forEach((t) => (t.lines || []).forEach((l) => { const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (v >= mat.trivial && !String(l.description || t.description || "").trim()) noDesc.push(row(t, l)); }));
  T("JE_NO_DESC", "TAS 240", "Reikšmingi įrašai be aprašymo", "Material entries without description", noDesc, "Medium");

  const seen = new Map(); const dup = [];
  txs.forEach((t) => (t.lines || []).forEach((l) => { const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (v < Math.max(100, mat.trivial)) return; const key = `${t.transactionDate}|${l.accountID}|${v}`; if (seen.has(key)) dup.push(row(t, l, { pora: seen.get(key) })); else seen.set(key, t.transactionID || "—"); }));
  T("JE_DUP", "TAS 240", "Galimi dubliuoti įrašai (data+sąskaita+suma)", "Possible duplicate entries (date+account+amount)", dup, "Medium");

  const unb = []; txs.forEach((t) => { let dr = 0, cr = 0; (t.lines || []).forEach((l) => { dr += l.debitAmount || 0; cr += l.creditAmount || 0; }); if (Math.abs(dr - cr) > 0.011) unb.push({ tx: t.transactionID || "—", data: t.transactionDate || "—", debetas: ea2(dr), kreditas: ea2(cr), skirtumas: ea2(dr - cr) }); });
  T("JE_UNBALANCED", "TAS 240", "Nesubalansuoti įrašai (D≠K)", "Unbalanced entries (D≠C)", unb, unb.length ? "Critical" : "Low");

  const use = {}; txs.forEach((t) => (t.lines || []).forEach((l) => { use[l.accountID || "?"] = (use[l.accountID || "?"] || 0) + 1; }));
  const seldom = []; txs.forEach((t) => (t.lines || []).forEach((l) => { const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (use[l.accountID || "?"] <= 2 && v >= mat.trivial) seldom.push(row(t, l, { panaudota: use[l.accountID || "?"] })); }));
  T("JE_SELDOM", "TAS 240", "Retai naudojamos sąskaitos su reikšmingomis sumomis", "Seldom-used accounts with material amounts", seldom, "Medium");

  // ── SOTA battery extensions (all deterministic, file-derived) ──
  // After-hours posting: SystemEntryDate timestamp outside 06:00–22:00
  const night = []; txs.forEach((t) => { const ts = String(t.systemEntryDate || ""); const hh = ts.length >= 13 ? parseInt(ts.slice(11, 13), 10) : NaN; if (!isNaN(hh) && (hh >= 22 || hh < 6)) night.push(row(t, (t.lines || [])[0], { laikas: ts.slice(11, 16) })); });
  T("JE_NIGHT", "TAS 240", "Registracija ne darbo valandomis (22:00–06:00)", "Posted outside business hours (22:00–06:00)", night, night.length / Math.max(1, total) > 0.05 ? "High" : "Medium");

  // Backdating: GL posting / system entry ≥ 30 d. after the economic date
  const back = []; txs.forEach((t) => { const td = t.transactionDate, gd = (t.glPostingDate || String(t.systemEntryDate || "").slice(0, 10)); if (!td || !gd) return; const gap = (new Date(gd) - new Date(td)) / 86400000; if (isFinite(gap) && gap >= 30) { const l = (t.lines || [])[0]; const v = l ? Math.max(l.debitAmount || 0, l.creditAmount || 0) : 0; if (v >= mat.trivial) back.push(row(t, l, { registruota: gd, velavimas_d: Math.round(gap) })); } });
  T("JE_BACKDATED", "TAS 240/315", "Vėluojanti registracija (≥30 d. po op. datos)", "Late posting (≥30 days after transaction date)", back, back.length ? "High" : "Low");

  // Same-day equal-and-opposite reversal pairs on one account (above trivial)
  const revKey = new Map(); const samerev = [];
  txs.forEach((t) => (t.lines || []).forEach((l) => { const dv = l.debitAmount || 0, cv = l.creditAmount || 0; const v = Math.max(dv, cv); if (v < Math.max(100, mat.trivial)) return; const side = dv > cv ? "D" : "K"; const opp = `${t.transactionDate}|${l.accountID}|${side === "D" ? "K" : "D"}|${ea2(v)}`; if (revKey.has(opp)) { samerev.push(row(t, l, { pora: revKey.get(opp) })); revKey.delete(opp); } else revKey.set(`${t.transactionDate}|${l.accountID}|${side}|${ea2(v)}`, t.transactionID || "—"); }));
  T("JE_SAME_REV", "TAS 240", "Tos pačios dienos storno poros (D↔K)", "Same-day equal-and-opposite reversals", samerev, "Medium");

  // Manual postings into revenue (class 5) from non-sales journals
  const revman = []; txs.forEach((t) => { const j = String(t._journalType || t.journalType || t.journalID || "").toUpperCase(); const isSalesJournal = /SAL|PARD|SF|AR/.test(j); if (isSalesJournal) return; (t.lines || []).forEach((l) => { const a = String(l.accountID || ""); const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (a[0] === "5" && v >= mat.trivial) revman.push(row(t, l, { zurnalas: j || "—" })); }); });
  T("JE_REV_MANUAL", "TAS 240 (pajamų pripažinimas)", "Rankiniai įrašai į pajamų (5) sąskaitas ne pardavimo žurnale", "Manual postings to revenue (class 5) outside sales journals", revman, revman.length ? "High" : "Low");

  // Trailing-zeros test: share of amounts ending “…00.00” among lines ≥ €100
  let z00 = 0, zN = 0; txs.forEach((t) => (t.lines || []).forEach((l) => { const v = Math.max(l.debitAmount || 0, l.creditAmount || 0); if (v >= 100) { zN++; if (Math.round(v * 100) % 10000 === 0) z00++; } }));
  const zShare = zN ? ea2(100 * z00 / zN) : 0;
  T("JE_TRAIL00", "TAS 240 (Benford-2)", "„…00,00“ galūnių dažnis (lyginama su ~1 %)", "Trailing “…00.00” frequency (vs ~1% expected)", [], zN >= 50 && zShare > 8 ? "High" : zN >= 50 && zShare > 4 ? "Medium" : "Low", { n: zN, hits: z00, sharePct: zShare, expectedPct: 1 });

  return tests;
}

// ── TAS 315/240: inherent-risk map per FS area ──
function eaRiskMap(d, mat, je, vmi) {
  const areas = [];
  const A = (lt, en, factors) => { const fs = factors.filter(Boolean); areas.push({ lt, en, level: fs.length >= 2 ? "High" : fs.length === 1 ? "Medium" : "Low", factors: fs, tas: "TAS 315/240" }); };
  const k = mat.kpis || {};
  const sales = ((d.sales && d.sales.items) || []);
  const byCust = {}; let rev = 0;
  sales.forEach((i) => { const v = (i.documentTotals && (i.documentTotals.netTotal != null ? i.documentTotals.netTotal : i.documentTotals.grossTotal)) || 0; rev += v; byCust[i.customerID || "?"] = (byCust[i.customerID || "?"] || 0) + v; });
  const top = Object.values(byCust).sort((a, b) => b - a)[0] || 0;
  const concPct = rev > 0 ? ea2(100 * top / rev) : 0;
  const jeBy = (id) => (je.find((t) => t.id === id) || { count: 0, stats: {} });
  A("Pajamų pripažinimas", "Revenue recognition", [
    "TAS 240 prielaida: pajamų pripažinimo apgaulės rizika (visada)",
    concPct > 30 ? `Klientų koncentracija: didžiausias klientas ${concPct}% pajamų` : null,
    jeBy("JE_PERIOD_END").stats && jeBy("JE_PERIOD_END").stats.sharePct > 15 ? `Laikotarpio pabaigos koncentracija ${jeBy("JE_PERIOD_END").stats.sharePct}%` : null,
  ]);
  A("Gautinos sumos", "Receivables", [k.dso != null && k.dso > 90 ? `DSO ${ea2(k.dso)} d. (>90)` : null, concPct > 30 ? "Koncentracija (žr. pajamas)" : null]);
  A("Mokėtinos sumos", "Payables", [k.dpo != null && k.dpo > 120 ? `DPO ${ea2(k.dpo)} d. (>120)` : null]);
  A("Pinigai ir įrašai", "Cash & journal entries", [jeBy("JE_WEEKEND").count ? `${jeBy("JE_WEEKEND").count} įrašai savaitgaliais` : null, jeBy("JE_UNBALANCED").count ? `${jeBy("JE_UNBALANCED").count} nesubalansuoti` : null, (jeBy("JE_BENFORD").stats || {}).verdict === "nonconformity" ? "Benfordo nuokrypis" : null]);
  A("Veiklos tęstinumas", "Going concern", [k.equity != null && k.equity < 0 ? "Neigiamas nuosavas kapitalas" : null, k.currentRatio != null && k.currentRatio < 1 ? `Trumpalaikis likvidumas ${ea2(k.currentRatio)} (<1)` : null]);
  if (vmi) A("Mokesčių atitiktis (VMI · SAF-T)", "Tax compliance (VMI · SAF-T)", [
    vmi.gate && vmi.gate.verdict === "rejected" ? `i.SAF-T vartai: ATMESTA (${vmi.gate.blockingTotal} blokuojančios)` : null,
    vmi.risk && (vmi.risk.band === "high" || vmi.risk.band === "elevated") ? `VMI rizikos balas ${vmi.risk.score} (${vmi.risk.band})` : null,
    vmi.sev && vmi.sev.Critical > 0 ? `${vmi.sev.Critical} kritiniai radiniai (482 taisyklės)` : null,
  ]);
  return areas;
}

// ── TAS 520 / V2-10: monthly analytics with z-scores + full matrix ──
function eaAnalytics(d, mat) {
  const out = [];
  const matrix = {}; // ym → { revenue, purchases }
  const series = (items, label, key) => {
    const byM = {};
    (items || []).forEach((i) => { const m = String(i.invoiceDate || "").slice(0, 7); if (!m) return; const v = (i.documentTotals && (i.documentTotals.netTotal != null ? i.documentTotals.netTotal : i.documentTotals.grossTotal)) || 0; byM[m] = (byM[m] || 0) + v; });
    Object.keys(byM).forEach((m) => { matrix[m] = matrix[m] || { m, revenue: 0, purchases: 0 }; matrix[m][key] = ea2(byM[m]); });
    const months = Object.keys(byM).sort(); if (months.length < 3) return;
    const vals = months.map((m) => byM[m]);
    const mean = vals.reduce((a, b) => a + b, 0) / vals.length;
    const sd = Math.sqrt(vals.reduce((a, b) => a + (b - mean) * (b - mean), 0) / vals.length) || 1;
    months.forEach((m, i) => { const z = (vals[i] - mean) / sd; if (Math.abs(z) > 2 && Math.abs(vals[i] - mean) > mat.performance) out.push({ sritis: label, men: m, suma: ea2(vals[i]), vidurkis: ea2(mean), z: ea2(z) }); });
  };
  series(d.sales && d.sales.items, "Pajamos / Revenue", "revenue");
  series(d.purchases && d.purchases.items, "Pirkimai / Purchases", "purchases");
  // Gross-margin volatility (TAS 520 plausibility): flag months whose margin
  // deviates from the period mean by >15 p.p. while revenue is material.
  const monthly = Object.values(matrix).sort((a, b) => a.m < b.m ? -1 : 1).map((r) => ({ ...r, margin: r.revenue > 0 ? ea2(100 * (r.revenue - r.purchases) / r.revenue) : null }));
  const margins = monthly.filter((r) => r.margin != null && r.revenue >= mat.trivial).map((r) => r.margin);
  if (margins.length >= 3) {
    const mMean = margins.reduce((a, b) => a + b, 0) / margins.length;
    monthly.forEach((r) => { if (r.margin != null && r.revenue >= mat.performance && Math.abs(r.margin - mMean) > 15) out.push({ sritis: "Bendroji marža / Gross margin", men: r.m, suma: r.margin, vidurkis: ea2(mMean), z: ea2((r.margin - mMean) / 15) }); });
  }
  return { flags: out, monthly, ref: "TAS 520 · Vadovas V2-10" };
}

// ── TAS 530 / Vadovas V2: monetary-unit sampling ──
// Formula per the guide: "Imties dydis = visuma ÷ atrankos intervalas",
// where interval = tolerable misstatement (performance materiality) ÷
// reliability factor. Seeded systematic PPS selection; items ≥ interval
// form the top stratum and are examined 100%.
function eaMusSample(items, valueOf, mat, opts) {
  const o = Object.assign({}, EA_DEFAULTS, opts || {});
  const rows = (items || []).map((it, i) => ({ i, ref: it.invoiceNo || it.transactionID || it.paymentRefNo || String(i + 1), value: Math.abs(valueOf(it) || 0) })).filter((r) => r.value > 0);
  const population = ea2(rows.reduce((a, r) => a + r.value, 0));
  const interval = Math.max(1, ea2((mat.performance || 1) / o.reliabilityFactor));
  const size = Math.max(1, Math.ceil(population / interval));
  const topStratum = rows.filter((r) => r.value >= interval);
  let seed = (opts && opts.seed != null) ? opts.seed : (rows.length * 2654435761 % 4294967296);
  const seed0 = seed;
  const rnd = () => { seed = (seed * 1664525 + 1013904223) % 4294967296; return seed / 4294967296; };
  const start = rnd() * interval;
  const sample = []; let cum = 0; let nextPoint = start; const inTop = new Set(topStratum.map((r) => r.i));
  for (const r of rows) {
    const lo = cum; cum += r.value;
    while (nextPoint < cum && sample.length < size) {
      if (!inTop.has(r.i) && !sample.some((s) => s.i === r.i)) sample.push({ i: r.i, ref: r.ref, value: r.value, point: ea2(nextPoint) });
      nextPoint += interval;
    }
    if (nextPoint >= population) break;
  }
  return { population, interval, size, reliabilityFactor: o.reliabilityFactor, topStratum: topStratum.slice(0, 50), sample: sample.slice(0, 200), seed: seed0, ref: "TAS 530 · Vadovas V2 (Imties dydis = visuma ÷ atrankos intervalas)" };
}

// ── TAS 570 / V1-14 + LT law: going concern ──
function eaGoingConcern(mat, tb) {
  const k = mat.kpis || {}; const flags = [];
  let shareCapital = 0;
  Object.keys(tb || {}).forEach((a) => { if (String(a).slice(0, 2) === "30") shareCapital += -(tb[a].net || 0); });
  shareCapital = ea2(shareCapital);
  const F = (test, value, ref) => flags.push({ test, value, ref });
  if (k.equity != null && k.equity < 0) F("Neigiamas nuosavas kapitalas / Negative equity", ea2(k.equity), "TAS 570 · V1-14");
  if (shareCapital > 0 && k.equity != null && k.equity < shareCapital / 2) F("Nuosavas kapitalas < 1/2 įstatinio kapitalo / Equity below half of share capital", `${ea2(k.equity)} < ${ea2(shareCapital / 2)}`, "LR ABĮ (nuosavo kapitalo reikalavimai) · TAS 570");
  if (k.currentRatio != null && k.currentRatio < 1) F("Trumpalaikio likvidumo rodiklis < 1 / Current ratio below 1", ea2(k.currentRatio), "TAS 570 · V1-14");
  if (k.workingCapital != null && k.workingCapital < 0) F("Neigiamas apyvartinis kapitalas / Negative working capital", ea2(k.workingCapital), "TAS 570 · V1-14");
  if (k.netMarginPct != null && k.netMarginPct < 0) F("Nuostolinga veikla / Loss-making operations", ea2(k.netMarginPct) + "%", "TAS 570 · V1-14");
  return { flags, shareCapital };
}

// ── Vadovas V2-9/10: audit-program generator ──
function eaBuildPlan(riskMap, mat) {
  const proc = {
    High: ["Detalieji testai visiems vienetams ≥ veiklos reikšmingumo (" + mat.performance + ")", "Piniginių vienetų atranka likusiai visumai (TAS 530)", "Pjūvio (cut-off) testai ±5 d. nuo laikotarpio pabaigos", "Nepriklausomi patvirtinimai / išoriniai įrodymai (TAS 505)"],
    Medium: ["Piniginių vienetų atranka (TAS 530)", "Analitinės procedūros su lūkesčiu ir tyrimu (TAS 520)"],
    Low: ["Analitinės procedūros (TAS 520)", "Apžvalginis testavimas mažesne apimtimi"],
  };
  return riskMap.map((a) => ({ sritis: a.lt, lygis: a.level, procedūros: proc[a.level] || proc.Low, tas: a.tas }));
}

// ── Industry packs: deterministic, formula-disclosed checks per sector.
//    Signals come only from the file (account names, invoice statistics) —
//    no legal codes are guessed; each check states its formula.
const INDUSTRY_PACKS = [
  { id: "prekyba", lt: "Prekyba", en: "Trade / retail" },
  { id: "gamyba", lt: "Gamyba", en: "Manufacturing" },
  { id: "paslaugos", lt: "Paslaugos", en: "Services" },
  { id: "statyba", lt: "Statyba", en: "Construction" },
  { id: "transportas", lt: "Transportas ir logistika", en: "Transport & logistics" },
];
function eaAcctShare(d, tb, nameRe, idPrefixes) {
  let hit = 0, total = 0;
  Object.keys(tb || {}).forEach((a) => {
    const v = Math.abs(tb[a].debit || 0) + Math.abs(tb[a].credit || 0);
    total += v;
    const nm = cpNorm(tb[a].name || "");
    if ((nameRe && nameRe.test(nm)) || (idPrefixes || []).some((p) => String(a).indexOf(p) === 0)) hit += v;
  });
  return total > 0 ? ea2(100 * hit / total) : 0;
}
function eaInferIndustry(d, tb) {
  const names = cpNorm(Object.values(tb || {}).map((x) => x.name).join(" ") + " " + ((d.header && d.header.company && d.header.company.name) || ""));
  const sales = (d.sales && d.sales.items) || [];
  const vals = sales.map((i) => (i.documentTotals && (i.documentTotals.netTotal != null ? i.documentTotals.netTotal : i.documentTotals.grossTotal)) || 0).sort((a, b) => a - b);
  const median = vals.length ? vals[Math.floor(vals.length / 2)] : 0;
  const signals = [];
  let id = "paslaugos";
  if (/degal|kuras|kuro|transport|logist|vezim/.test(names)) { id = "transportas"; signals.push("sąskaitų pavadinimai: degalai/transportas"); }
  else if (/statyb|rangov/.test(names)) { id = "statyba"; signals.push("sąskaitų pavadinimai: statyba/rangovai"); }
  else if (/zaliav|gamyb|nebaigta gamyba/.test(names)) { id = "gamyba"; signals.push("sąskaitų pavadinimai: žaliavos/gamyba"); }
  else if (/atsarg|prekes|prekiu|kasa/.test(names) || (sales.length > 50 && median > 0 && median < 200)) { id = "prekyba"; signals.push(sales.length > 50 && median < 200 ? `daug smulkių sąskaitų (mediana ${ea2(median)})` : "sąskaitų pavadinimai: atsargos/prekės/kasa"); }
  else signals.push("numatytasis profilis (nėra ryškių signalų)");
  return { id, signals };
}
function eaIndustryChecks(d, mat, tb, industryId) {
  const checks = [];
  const C = (id, lt, en, value, flag, formula) => checks.push({ id, lt, en, value, flag: !!flag, formula });
  const sales = (d.sales && d.sales.items) || [];
  const noVatShare = (() => { let no = 0; sales.forEach((i) => { const codes = (i.lines || []).some((l) => l.taxInfo && l.taxInfo.taxCode); if (!codes) no++; }); return sales.length ? ea2(100 * no / sales.length) : 0; })();
  if (industryId === "prekyba") {
    const cash = eaAcctShare(d, tb, /kasa/, ["272"]);
    C("IND_CASH", "Grynųjų pinigų intensyvumas", "Cash intensity", cash + "%", cash > 30, "Σ|D|+|K| sąskaitose „kasa“/272* ÷ visos apyvartos");
    const inv = eaAcctShare(d, tb, /atsarg|prekes|prekiu/, ["20"]);
    C("IND_INV", "Atsargų apyvartos buvimas", "Inventory activity present", inv + "%", inv === 0, "Σ apyvarta 20* / „atsargos“ sąskaitose (0% — rizika prekybai)");
  } else if (industryId === "gamyba") {
    const inv = eaAcctShare(d, tb, /zaliav|atsarg|nebaigta/, ["20", "21"]);
    C("IND_WIP", "Žaliavų/nebaigtos gamybos apyvarta", "Raw-materials / WIP activity", inv + "%", inv === 0, "Σ apyvarta 20*/21* arba „žaliavos/nebaigta gamyba“");
  } else if (industryId === "transportas") {
    const fuel = eaAcctShare(d, tb, /degal|kuras|kuro/, []);
    C("IND_FUEL", "Degalų sąnaudų dalis", "Fuel-cost share", fuel + "%", fuel > 15, "Σ apyvarta sąskaitose „degalai/kuras“ ÷ visos apyvartos");
    C("IND_0VAT", "Pardavimai be PVM kodų (eksportas/0%)", "Sales without VAT codes (export/0%)", noVatShare + "%", false, "sąskaitos be PVM kodų eilutėse ÷ visos pardavimo sąskaitos (informacinis)");
  } else if (industryId === "statyba") {
    const byS = {}; let tot = 0;
    (((d.purchases && d.purchases.items) || [])).forEach((i) => { const v = (i.documentTotals && (i.documentTotals.netTotal != null ? i.documentTotals.netTotal : i.documentTotals.grossTotal)) || 0; tot += v; byS[i.supplierID || "?"] = (byS[i.supplierID || "?"] || 0) + v; });
    const top = Object.values(byS).sort((a, b) => b - a)[0] || 0;
    const conc = tot > 0 ? ea2(100 * top / tot) : 0;
    C("IND_SUBC", "Subrangovų koncentracija", "Subcontractor concentration", conc + "%", conc > 40, "didžiausio tiekėjo pirkimai ÷ visi pirkimai");
    C("IND_REV0", "Pardavimai be PVM kodų (atvirkštinis apmok.?)", "Sales without VAT codes (reverse charge?)", noVatShare + "%", false, "informacinis — patikrinkite atvirkštinio apmokestinimo žymėjimą");
  } else {
    const payroll = eaAcctShare(d, tb, /darbo uzmok|atlygin/, []);
    C("IND_PAYR", "Darbo užmokesčio sąnaudų dalis", "Payroll-cost share", payroll + "%", false, "Σ apyvarta „darbo užmokestis/atlyginimai“ ÷ visos apyvartos (informacinis)");
  }
  return checks;
}

function eaRunAll(d, opts) {
  const o = opts || {};
  const tb = eaTrialBalance(d);
  const mat = eaMateriality(d, o);
  const je = eaJournalTests(d, mat);
  const vmi = o.vmi || null;
  const risk = eaRiskMap(d, mat, je, vmi);
  const inferred = eaInferIndustry(d, tb);
  const indId = o.industry && o.industry !== "auto" ? o.industry : inferred.id;
  const pack = INDUSTRY_PACKS.find((p) => p.id === indId) || INDUSTRY_PACKS[2];
  const industry = { id: pack.id, lt: pack.lt, en: pack.en, suggested: inferred.id, signals: inferred.signals, checks: eaIndustryChecks(d, mat, tb, pack.id) };
  const runner = o.runUserRule || (typeof runUserRule === "function" ? runUserRule : null);
  const companyRules = (runner && Array.isArray(o.userRules) ? o.userRules : []).map((r) => {
    let hits = []; try { hits = runner(r, d); } catch (e) { hits = []; }
    return { id: r.id, title: r.title, severity: r.severity, scope: r.scope, count: hits.length, sample: hits.slice(0, 3) };
  });
  const ea = { tb, materiality: mat, jeTests: je, riskMap: risk, vmi, industry, companyRules,
    analytics: eaAnalytics(d, mat), goingConcern: eaGoingConcern(mat, tb), plan: eaBuildPlan(risk, mat), generatedAt: new Date().toISOString().slice(0, 10) };
  ea.coverage = eaCoverage(d, je, mat);
  ea.opinion = eaOpinion(ea);
  return ea;
}

// ── Test coverage statistics: what share of the population the battery saw ──
function eaCoverage(d, je, mat) {
  const txs = (d && d.transactions) || [];
  let lines = 0, value = 0, flaggedTx = new Set();
  txs.forEach((t) => (t.lines || []).forEach((l) => { lines++; value += Math.max(l.debitAmount || 0, l.creditAmount || 0); }));
  je.forEach((t) => (t.hits || []).forEach((h) => { if (h.tx) flaggedTx.add(h.tx); }));
  const above = je.find((t) => t.id === "JE_ABOVE_PM");
  return { glTransactions: txs.length, glLines: lines, glValue: ea2(value), testsRun: je.length, txFlagged: flaggedTx.size, fullTestedAbovePM: above ? above.count : 0 };
}

// ── Deterministic indicative assessment (NOT an audit opinion under ISA 700;
//    a rules-based synthesis the auditor reviews). Bands and triggers are
//    fully disclosed so the conclusion is reproducible.
function eaOpinion(ea) {
  const reasons = [];
  const je = (id) => ea.jeTests.find((t) => t.id === id) || { count: 0, stats: {} };
  const unb = je("JE_UNBALANCED").count;
  const gc = ea.goingConcern.flags.length;
  const benford = (je("JE_BENFORD").stats || {}).verdict;
  const highJe = ea.jeTests.filter((t) => t.count > 0 && (t.severity === "High" || t.severity === "Critical")).length;
  const vmiBlock = ea.vmi && ea.vmi.gate ? ea.vmi.gate.blockingTotal : 0;
  const vmiCrit = ea.vmi && ea.vmi.sev ? ea.vmi.sev.Critical : 0;
  let band = "clean";
  if (unb > 0) { band = "adverse"; reasons.push({ lt: `${unb} nesubalansuoti DK įrašai (D≠K) — pažeistas dvejybinis įrašas`, en: `${unb} unbalanced GL entries (D≠C) — double-entry broken` }); }
  if (vmiBlock > 0) { if (band === "clean") band = "qualified"; reasons.push({ lt: `${vmiBlock} blokuojančios SAF-T klaidos (i.SAF-T vartai: atmesta)`, en: `${vmiBlock} blocking SAF-T errors (i.SAF-T gate: rejected)` }); }
  if (gc > 0) { if (band === "clean") band = "emphasis"; reasons.push({ lt: `${gc} veiklos tęstinumo indikatoriai (TAS 570)`, en: `${gc} going-concern indicators (ISA 570)` }); }
  if (benford === "nonconformity") { if (band === "clean") band = "emphasis"; reasons.push({ lt: "Benfordo pasiskirstymo neatitiktis (MAD > 0,015)", en: "Benford distribution nonconformity (MAD > 0.015)" }); }
  if (highJe >= 3 && band === "clean") { band = "emphasis"; reasons.push({ lt: `${highJe} aukšto reikšmingumo ŽĮ testai suveikė`, en: `${highJe} high-severity JE tests fired` }); }
  if (vmiCrit > 0 && band === "clean") { band = "emphasis"; reasons.push({ lt: `${vmiCrit} kritiniai VMI taisyklių radiniai`, en: `${vmiCrit} critical VMI rule findings` }); }
  const BANDS = {
    clean:     { c: "#69db7c", lt: "Be pastabų (indikatyviai)", en: "Unmodified (indicative)", noteLt: "Deterministiniai testai esminių iškraipymų požymių nenustatė.", noteEn: "Deterministic tests found no indicators of material misstatement." },
    emphasis:  { c: "#ffd43b", lt: "Be pastabų, su dalyko pabrėžimu (indikatyviai)", en: "Unmodified with emphasis of matter (indicative)", noteLt: "Yra sričių, kurias auditorius turi įvertinti papildomai.", noteEn: "There are matters the auditor must evaluate further." },
    qualified: { c: "#ffa94d", lt: "Sąlyginės išvados rizika (indikatyviai)", en: "Qualified-opinion risk (indicative)", noteLt: "Nustatyti reikšmingi, bet lokalizuoti neatitikimai.", noteEn: "Material but contained noncompliance identified." },
    adverse:   { c: "#ff6b6b", lt: "Neigiamos išvados rizika (indikatyviai)", en: "Adverse-opinion risk (indicative)", noteLt: "Pažeisti fundamentalūs apskaitos vientisumo principai.", noteEn: "Fundamental accounting-integrity principles are violated." },
  };
  return { band, ...BANDS[band], reasons, disclaimer: { lt: "Tai NĖRA audito išvada pagal TAS 700 — tai taisyklėmis pagrįsta indikacija atestuoto auditoriaus peržiūrai.", en: "This is NOT an ISA 700 audit opinion — it is a rules-based indication for review by a certified auditor." } };
}

function eaFacts(ea) {
  const f = [];
  const push = (v, l) => { if (v != null && isFinite(v)) f.push({ value: v, label: l, group: "ea" }); };
  push(ea.materiality.overall, "Overall materiality"); push(ea.materiality.performance, "Performance materiality"); push(ea.materiality.trivial, "Clearly trivial threshold");
  ea.jeTests.forEach((t) => push(t.count, "JE test " + t.id));
  push(ea.goingConcern.flags.length, "Going-concern flags");
  push(ea.analytics.flags.length, "Analytics deviations");
  if (ea.vmi) { push(ea.vmi.total, "VMI findings total"); push(ea.vmi.gate && ea.vmi.gate.blockingTotal, "VMI blocking errors"); push(ea.vmi.gate && ea.vmi.gate.warningCount, "VMI warnings"); push(ea.vmi.risk && ea.vmi.risk.score, "VMI risk score (audit)"); }
  if (ea.industry) push(ea.industry.checks.filter((c) => c.flag).length, "Industry flags");
  if (ea.coverage) { push(ea.coverage.glTransactions, "GL transactions tested"); push(ea.coverage.glLines, "GL lines tested"); push(ea.coverage.txFlagged, "Transactions flagged by JE battery"); }
  if (ea.opinion) push(ea.opinion.reasons.length, "Indicative-assessment trigger count");
  (ea.companyRules || []).forEach((r) => push(r.count, "Company rule " + r.id));
  return f;
}

function buildEAuditReportHTML(ea, lang, brandName, meta) {
  const lt = lang !== "en";
  const T = (en, l2) => (lt ? l2 : en);
  const esc = (s) => String(s == null ? "" : s).replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));
  const sevC = { Critical: "#c92a2a", High: "#e8590c", Medium: "#b08900", Low: "#2b8a3e" };
  const m = ea.materiality;
  let h = "<!DOCTYPE html><html><head><meta charset='utf-8'><title>" + esc(brandName) + " — E-Audit</title><style>@page{size:A4;margin:16mm}body{font:12px/1.55 'Segoe UI',Arial,sans-serif;color:#1a1a1a;padding:28px;max-width:880px;margin:0 auto}h1{font-weight:300;font-size:22px;margin:0}h2{font-size:14px;margin:20px 0 8px;border-bottom:1px solid #ddd;padding-bottom:4px}table{border-collapse:collapse;width:100%;margin:6px 0}td,th{border:1px solid #e3e3e3;padding:5px 8px;text-align:left;font-size:11px}.n{text-align:right}.sub{color:#666;font-size:11px}.ref{color:#888;font-size:10px}</style></head><body>";
  h += "<h1>" + esc(brandName) + " · " + T("E-Audit workpaper (ISA/TAS + VMI)", "E. audito darbo dokumentas (TAS + VMI)") + "</h1>";
  h += "<div class='sub'>" + esc((meta && meta.company) || "—") + " · " + esc((meta && meta.period) || "") + " · " + ea.generatedAt + " · engine v" + esc(ENGINE_VERSION) + (ea.industry ? " · " + T("industry", "šaka") + ": " + esc(lt ? ea.industry.lt : ea.industry.en) : "") + "</div>";
  if (ea.opinion) {
    h += "<div style='border:2px solid " + ea.opinion.c + ";padding:10px 14px;margin:14px 0'><b style='color:" + ea.opinion.c + "'>" + T("Indicative assessment", "Indikatyvus vertinimas") + ": " + esc(lt ? ea.opinion.lt : ea.opinion.en) + "</b>" +
      (ea.opinion.reasons.length ? "<ul style='margin:6px 0 0'>" + ea.opinion.reasons.map((r) => "<li>" + esc(lt ? r.lt : r.en) + "</li>").join("") + "</ul>" : "<div class='sub'>" + esc(lt ? ea.opinion.noteLt : ea.opinion.noteEn) + "</div>") +
      "<div class='ref' style='margin-top:6px'>" + esc(lt ? ea.opinion.disclaimer.lt : ea.opinion.disclaimer.en) + "</div></div>";
  }
  if (ea.coverage) h += "<div class='sub'>" + T("Coverage", "Aprėptis") + ": " + ea.coverage.glTransactions + " " + T("GL transactions", "DK operacijos") + " · " + ea.coverage.glLines + " " + T("lines", "eilutės") + " · Σ " + ea.coverage.glValue.toLocaleString() + " · " + ea.coverage.testsRun + " " + T("automated tests", "automatiniai testai") + " · " + ea.coverage.txFlagged + " " + T("flagged", "pažymėta") + "</div>";
  // executive summary — every number is engine-computed
  const jeCrit = ea.jeTests.filter((x) => x.count > 0 && (x.severity === "Critical" || x.severity === "High")).length;
  h += "<div style='border:1px solid #ccc;background:#f7f7f5;padding:10px 14px;margin:14px 0;font-size:12px'>" +
    "<b>" + T("Executive summary", "Santrauka vadovybei") + ":</b> " +
    (ea.vmi && ea.vmi.gate ? T("VMI gate: ", "VMI vartai: ") + "<b>" + esc(lt ? ea.vmi.gate.label[1] : ea.vmi.gate.label[0]) + "</b> (" + ea.vmi.gate.blockingTotal + " " + T("blocking", "blokuojančios") + ", " + ea.vmi.gate.warningCount + " " + T("warnings", "perspėjimai") + "; " + T("risk", "rizika") + " " + (ea.vmi.risk ? ea.vmi.risk.score : "—") + ") · " : "") +
    T("Materiality", "Reikšmingumas") + " " + m.overall.toLocaleString() + " (" + esc(lt ? m.basisLt : m.basis) + " " + m.pct + "%) · " +
    jeCrit + " " + T("high/critical JE tests fired", "aukšti/kritiniai ŽĮ testai suveikė") + " · " +
    ea.goingConcern.flags.length + " " + T("going-concern indicators", "veiklos tęstinumo indikatoriai") + (ea.companyRules && ea.companyRules.length ? " · " + ea.companyRules.reduce((s, r) => s + r.count, 0) + " " + T("company-rule hits", "įmonės taisyklių radiniai") : "") + ".</div>";
  h += "<h2>1. " + T("Materiality (TAS 320 · Vadovas V1-7)", "Reikšmingumas (TAS 320 · Vadovas V1-7)") + "</h2><table><tr><th>" + T("Basis", "Pagrindas") + "</th><th class='n'>" + T("Value", "Reikšmė") + "</th><th class='n'>%</th><th class='n'>" + T("Overall", "Bendrasis") + "</th></tr>";
  h += "<tr><td><b>" + esc(lt ? m.basisLt : m.basis) + "</b></td><td class='n'>" + m.baseValue + "</td><td class='n'>" + m.pct + "%</td><td class='n'><b>" + m.overall + "</b></td></tr></table>";
  h += "<div class='sub'>" + T("Performance materiality", "Veiklos reikšmingumas") + " (" + m.perfPct + "%): <b>" + m.performance + "</b> · " + T("Clearly trivial", "Aiškiai nereikšminga") + " (" + m.trivialPct + "%): <b>" + m.trivial + "</b></div>";
  if (ea.vmi) {
    h += "<h2>2. " + T("VMI compliance (SAF-T · 482 rules · VA-49)", "VMI atitiktis (SAF-T · 482 taisyklės · VA-49)") + "</h2>";
    h += "<table><tr><th>" + T("Gate", "Vartai") + "</th><th class='n'>" + T("Blocking", "Blokuoja") + "</th><th class='n'>" + T("Warnings", "Perspėjimai") + "</th><th class='n'>" + T("Risk", "Rizika") + "</th><th class='n'>C/H/M/L</th><th class='n'>" + T("Total", "Iš viso") + "</th></tr>";
    h += "<tr><td><b>" + esc(ea.vmi.gate ? (lt ? ea.vmi.gate.label[1] : ea.vmi.gate.label[0]) : "—") + "</b></td><td class='n'>" + (ea.vmi.gate ? ea.vmi.gate.blockingTotal : "—") + "</td><td class='n'>" + (ea.vmi.gate ? ea.vmi.gate.warningCount : "—") + "</td><td class='n'>" + (ea.vmi.risk ? ea.vmi.risk.score + " (" + ea.vmi.risk.band + ")" : "—") + "</td><td class='n'>" + (ea.vmi.sev ? ea.vmi.sev.Critical + "/" + ea.vmi.sev.High + "/" + ea.vmi.sev.Medium + "/" + ea.vmi.sev.Low : "—") + "</td><td class='n'>" + (ea.vmi.total != null ? ea.vmi.total : "—") + "</td></tr></table>";
    if (ea.vmi.risk && (ea.vmi.risk.perRule || []).length) {
      h += "<table><tr><th>#</th><th>" + T("Rule", "Taisyklė") + "</th><th class='n'>" + T("Hits", "Radiniai") + "</th><th class='n'>" + T("Risk contribution", "Rizikos indėlis") + "</th></tr>";
      ea.vmi.risk.perRule.slice(0, 8).forEach((r, i) => { h += "<tr><td>" + (i + 1) + "</td><td class='m'>" + esc(r.rule_id) + " — " + esc(lt ? r.title : (r.titleEn || r.title)) + "</td><td class='n'>" + r.hits + "</td><td class='n'>" + r.contrib + "</td></tr>"; });
      h += "</table>";
    }
  }
  h += "<h2>" + (ea.vmi ? 3 : 2) + ". " + T("Risk map (TAS 315/240 · V1-8)", "Rizikos žemėlapis (TAS 315/240 · V1-8)") + "</h2><table><tr><th>" + T("Area", "Sritis") + "</th><th>" + T("Level", "Lygis") + "</th><th>" + T("Factors", "Veiksniai") + "</th></tr>";
  ea.riskMap.forEach((a) => { h += "<tr><td>" + esc(lt ? a.lt : a.en) + "</td><td style='color:" + sevC[a.level] + ";font-weight:700'>" + a.level + "</td><td>" + esc(a.factors.join("; ") || "—") + "</td></tr>"; });
  h += "</table><h2>" + (ea.vmi ? 4 : 3) + ". " + T("Journal-entry testing (TAS 240 · V2-10)", "Žurnalo įrašų testai (TAS 240 · V2-10)") + "</h2><table><tr><th>" + T("Test", "Testas") + "</th><th>TAS</th><th class='n'>" + T("Hits", "Radiniai") + "</th><th>" + T("Note", "Pastaba") + "</th></tr>";
  ea.jeTests.forEach((t) => { const note = t.id === "JE_BENFORD" ? ("MAD " + (t.stats && t.stats.mad) + " → " + (t.stats && t.stats.verdict) + " (n=" + (t.stats && t.stats.n) + ")") : (t.id === "JE_PERIOD_END" && t.stats ? t.stats.sharePct + "% " + T("of all entries", "visų įrašų") : ""); h += "<tr><td>" + esc(lt ? t.lt : t.en) + "</td><td class='ref'>" + t.tas + "</td><td class='n' style='color:" + (t.count ? sevC[t.severity] : "#2b8a3e") + ";font-weight:700'>" + t.count + "</td><td class='sub'>" + esc(note) + "</td></tr>";
    if (t.count > 0) t.hits.slice(0, 6).forEach((hh) => { h += "<tr><td colspan='4' style='border-top:none;font-family:Consolas,monospace;font-size:10px;color:#555;padding:2px 8px 2px 22px'>· " + esc(Object.entries(hh).map(([k, v]) => k + " = " + v).join(" | ")) + "</td></tr>"; });
  });
  h += "</table>";
  if (ea.industry) {
    h += "<h2>" + (ea.vmi ? 5 : 4) + ". " + T("Industry checks — ", "Pramonės šakos patikros — ") + esc(lt ? ea.industry.lt : ea.industry.en) + (ea.industry.suggested !== ea.industry.id ? " <span class='ref'>(" + T("auto-suggested", "pasiūlyta automatiškai") + ": " + esc(ea.industry.suggested) + ")</span>" : "") + "</h2>";
    h += "<table><tr><th>" + T("Check", "Patikra") + "</th><th class='n'>" + T("Value", "Reikšmė") + "</th><th>" + T("Status", "Būsena") + "</th><th>" + T("Formula", "Formulė") + "</th></tr>";
    ea.industry.checks.forEach((c) => { h += "<tr><td>" + esc(lt ? c.lt : c.en) + "</td><td class='n'>" + esc(c.value) + "</td><td style='color:" + (c.flag ? "#c92a2a" : "#2b8a3e") + ";font-weight:700'>" + (c.flag ? "⚠" : "·") + "</td><td class='sub'>" + esc(c.formula) + "</td></tr>"; });
    h += "</table><div class='ref'>" + T("Signals", "Signalai") + ": " + esc(ea.industry.signals.join("; ")) + "</div>";
  }
  if (ea.companyRules && ea.companyRules.length) {
    h += "<h2>" + (ea.vmi ? 6 : 5) + ". " + T("Company rules (user-defined)", "Įmonės taisyklės (vartotojo apibrėžtos)") + "</h2><table><tr><th>" + T("Rule", "Taisyklė") + "</th><th>" + T("Severity", "Reikšmingumas") + "</th><th class='n'>" + T("Hits", "Radiniai") + "</th></tr>";
    ea.companyRules.forEach((r) => { h += "<tr><td>" + esc(r.title) + " <span class='ref'>(" + esc(r.scope) + ")</span></td><td>" + esc(r.severity) + "</td><td class='n' style='font-weight:700;color:" + (r.count ? "#b08900" : "#2b8a3e") + "'>" + r.count + "</td></tr>"; });
    h += "</table>";
  }
  if (ea.analytics.flags.length) { h += "<h2>" + (ea.vmi ? 7 : 6) + ". " + T("Analytics deviations (TAS 520)", "Analitiniai nuokrypiai (TAS 520)") + "</h2><table><tr><th>" + T("Area", "Sritis") + "</th><th>" + T("Month", "Mėnuo") + "</th><th class='n'>" + T("Amount", "Suma") + "</th><th class='n'>" + T("Mean", "Vidurkis") + "</th><th class='n'>z</th></tr>"; ea.analytics.flags.slice(0, 20).forEach((f) => { h += "<tr><td>" + esc(f.sritis) + "</td><td>" + f.men + "</td><td class='n'>" + f.suma + "</td><td class='n'>" + f.vidurkis + "</td><td class='n'>" + f.z + "</td></tr>"; }); h += "</table>"; }
  if (ea.goingConcern.flags.length) { h += "<h2>" + (ea.vmi ? 8 : 7) + ". " + T("Going-concern indicators (TAS 570 · V1-14)", "Veiklos tęstinumo indikatoriai (TAS 570 · V1-14)") + "</h2><ul>"; ea.goingConcern.flags.forEach((f) => { h += "<li>" + esc(f.test) + ": <b>" + esc(f.value) + "</b> <span class='ref'>(" + esc(f.ref) + ")</span></li>"; }); h += "</ul>"; }
  h += "<h2>" + (ea.vmi ? 9 : 8) + ". " + T("Audit program (V2-9/10)", "Audito programa (V2-9/10)") + "</h2>";
  ea.plan.forEach((p) => { h += "<div style='margin:6px 0'><b>" + esc(p.sritis) + "</b> — " + p.lygis + "<ul style='margin:4px 0'>" + p.procedūros.map((x) => "<li>" + esc(x) + "</li>").join("") + "</ul></div>"; });
  h += "<h2>" + T("References", "Nuorodos") + "</h2><div class='ref'>IFAC, „Tarptautinių audito standartų taikymo atliekant mažų ir vidutinių įmonių auditą vadovas“, 3 leid., I–II tomai (LT vert. Lietuvos auditorių rūmai) · TAS 240, 315, 320, 330, 505, 520, 530, 570 · LR finansinės apskaitos įstatymas Nr. XIV-680 · LR audito įstatymas · LR ABĮ.</div>";
  return h + "</body></html>";
}

// ═════════════════════════════════════════════════════════════════════════
// E-INVOICING ENGINE — EN 16931 / Peppol BIS Billing 3.0 / Lithuanian layer.
// Validator: UBL 2.1 Invoice & CreditNote, ~55 rules across three packs
// (EN core + BR-CO calculations + VAT categories; Peppol BIS; LT checksums
// and 2026 rates). Generator: SAF-T sales invoice → Peppol BIS 3.0 XML,
// self-validated. Everything runs client-side; nothing leaves the machine.
// ═════════════════════════════════════════════════════════════════════════
const PEPPOL_CUSTOMIZATION_ID = "urn:cen.eu:en16931:2017#compliant#urn:fdc:peppol.eu:2017:poacc:billing:3.0";
const PEPPOL_PROFILE_ID = "urn:fdc:peppol.eu:2017:poacc:billing:01:1.0";
const EI_TOL = 0.011, EI_TOL_DOC = 0.021;
const EI_TYPE_CODES = ["380", "381", "384", "389"];
const eiR2 = (v) => Math.round((v + Number.EPSILON) * 100) / 100;
const eiNum = (s) => { const v = parseFloat(String(s == null ? "" : s).replace(/\s/g, "").replace(",", ".")); return isFinite(v) ? v : null; };

// GS1 GLN (13 digits) mod-10 checksum — Peppol endpoint scheme 0088.
function glnValid(s) {
  const d = String(s || "").replace(/\D/g, "");
  if (d.length !== 13) return false;
  let sum = 0;
  for (let i = 0; i < 12; i++) sum += (+d[i]) * (i % 2 ? 3 : 1);
  return (10 - (sum % 10)) % 10 === +d[12];
}
// Lithuanian registry-code checksum (mod 11, two-pass weights 1..9 / 3..9,1..)
// — applies to 9-digit JAR codes and the digit body of LT VAT numbers.
function lt11(s) {
  const d = String(s || "").replace(/\D/g, "").split("").map(Number);
  const n = d.length;
  if (n !== 9 && n !== 11 && n !== 12) return false;
  const body = d.slice(0, n - 1), chk = d[n - 1];
  const pass = (start) => { let sum = 0; for (let i = 0; i < body.length; i++) { let w = start + i; while (w > 9) w -= 9; sum += body[i] * w; } return sum % 11; };
  let r = pass(1);
  if (r === 10) { r = pass(3); if (r === 10) r = 0; }
  return r === chk;
}
function ltVatValid(v) {
  const m = /^LT(\d{9}|\d{12})$/.exec(String(v || "").replace(/\s/g, "").toUpperCase());
  return !!m && lt11(m[1]);
}
function ibanValid(s) {
  const t = String(s || "").replace(/\s/g, "").toUpperCase();
  if (!/^[A-Z]{2}\d{2}[A-Z0-9]{11,30}$/.test(t)) return false;
  if (t.slice(0, 2) === "LT" && t.length !== 20) return false;
  const r = t.slice(4) + t.slice(0, 4);
  let rem = 0;
  for (const ch of r) { const v = ch >= "A" ? ch.charCodeAt(0) - 55 : +ch; rem = (rem * (v > 9 ? 100 : 10) + v) % 97; }
  return rem === 1;
}

// namespace-tolerant readers — work on browser DOM and the hydrated Lite tree
const eiLocal = (n) => String(n.localName || n.nodeName || "").split(":").pop();
function eiKids(n) { const out = []; const cn = n.childNodes || []; for (let i = 0; i < cn.length; i++) if (cn[i].nodeType === 1) out.push(cn[i]); return out; }
function eiAll(node, name, out) { out = out || []; eiKids(node).forEach((c) => { if (eiLocal(c) === name) out.push(c); eiAll(c, name, out); }); return out; }
const eiFirst = (node, name) => eiAll(node, name)[0] || null;
const eiText = (node, name) => { const e = eiFirst(node, name); return e ? String(e.textContent || "").trim() : ""; };
const eiAttr = (n, a) => (n && n.getAttribute ? n.getAttribute(a) : null) || "";

function eiParty(container) {
  if (!container) return { name: "", country: "", vat: "", reg: "", endpoint: null };
  const party = eiFirst(container, "Party") || container;
  const legal = eiFirst(party, "PartyLegalEntity");
  const taxScheme = eiAll(party, "PartyTaxScheme").map((x) => eiText(x, "CompanyID")).filter(Boolean);
  const ep = eiFirst(party, "EndpointID");
  return {
    name: (legal && eiText(legal, "RegistrationName")) || eiText(eiFirst(party, "PartyName") || party, "Name") || "",
    country: eiText(eiFirst(party, "PostalAddress") || party, "IdentificationCode").toUpperCase(),
    vat: (taxScheme.find((v) => /^[A-Z]{2}/.test(v.toUpperCase())) || taxScheme[0] || "").toUpperCase().replace(/\s/g, ""),
    reg: (legal && eiText(legal, "CompanyID")) || "",
    endpoint: ep ? { value: String(ep.textContent || "").trim(), scheme: eiAttr(ep, "schemeID") } : null,
  };
}

function parseUblInvoice(input) {
  let doc = input;
  if (typeof input === "string") {
    if (typeof DOMParser === "undefined") return { _parseError: "No DOM parser in this environment — pass a parsed document." };
    doc = new DOMParser().parseFromString(input, "text/xml");
    if (doc.querySelector && doc.querySelector("parsererror")) return { _parseError: "XML parse error" };
  }
  const root = doc.documentElement || doc;
  if (!root) return { _parseError: "Empty document" };
  const rootName = eiLocal(root);
  if (rootName !== "Invoice" && rootName !== "CreditNote") return { _parseError: "Root must be Invoice or CreditNote (UBL 2.1), got <" + rootName + ">" };
  const isCredit = rootName === "CreditNote";
  const lineName = isCredit ? "CreditNoteLine" : "InvoiceLine";
  const qtyName = isCredit ? "CreditedQuantity" : "InvoicedQuantity";
  const lines = eiAll(root, lineName).map((L, i) => {
    const item = eiFirst(L, "Item");
    const cat = item ? eiFirst(item, "ClassifiedTaxCategory") : null;
    return {
      id: eiText(L, "ID") || String(i + 1),
      qty: eiNum(eiText(L, qtyName)),
      net: eiNum(eiKids(L).filter((c) => eiLocal(c) === "LineExtensionAmount").map((c) => c.textContent)[0]),
      name: item ? eiText(item, "Name") : "",
      catId: cat ? eiText(cat, "ID").toUpperCase() : "",
      pct: cat ? eiNum(eiText(cat, "Percent")) : null,
      price: eiNum(eiText(eiFirst(L, "Price") || L, "PriceAmount")),
    };
  });
  const lmt = eiFirst(root, "LegalMonetaryTotal");
  const tt = eiKids(root).filter((c) => eiLocal(c) === "TaxTotal")[0] || eiFirst(root, "TaxTotal");
  const subtotals = (tt ? eiAll(tt, "TaxSubtotal") : []).map((s) => {
    const cat = eiFirst(s, "TaxCategory");
    return { taxable: eiNum(eiText(s, "TaxableAmount")), tax: eiNum(eiText(s, "TaxAmount")), catId: cat ? eiText(cat, "ID").toUpperCase() : "", pct: cat ? eiNum(eiText(cat, "Percent")) : null, reason: cat ? eiText(cat, "TaxExemptionReason") : "" };
  });
  const g = (name) => (lmt ? eiNum(eiText(lmt, name)) : null);
  return {
    isCredit, id: eiText(root, "ID"), issueDate: eiText(root, "IssueDate"),
    typeCode: eiText(root, isCredit ? "CreditNoteTypeCode" : "InvoiceTypeCode"),
    currency: eiText(root, "DocumentCurrencyCode").toUpperCase(),
    customizationId: eiText(root, "CustomizationID"), profileId: eiText(root, "ProfileID"),
    supplier: eiParty(eiFirst(root, "AccountingSupplierParty")),
    customer: eiParty(eiFirst(root, "AccountingCustomerParty")),
    ibans: eiAll(root, "PayeeFinancialAccount").map((a) => eiText(a, "ID")).filter(Boolean),
    paymentTerms: !!eiFirst(root, "PaymentTerms"), dueDate: eiText(root, "DueDate"),
    lines, subtotals,
    taxTotal: tt ? eiNum(eiKids(tt).filter((c) => eiLocal(c) === "TaxAmount").map((c) => c.textContent)[0]) : null,
    totals: { lineExt: g("LineExtensionAmount"), allow: g("AllowanceTotalAmount") || 0, charge: g("ChargeTotalAmount") || 0, taxExcl: g("TaxExclusiveAmount"), taxIncl: g("TaxInclusiveAmount"), prepaid: g("PrepaidAmount") || 0, rounding: g("PayableRoundingAmount") || 0, payable: g("PayableAmount") },
  };
}

function validateEInvoice(inv) {
  const F = [];
  const add = (id, std, sev, lt, en, detail, fix) => F.push({ rule_id: id, std, severity: sev, titleLt: lt, titleEn: en, detail: detail || "", fix: fix || "" });
  if (inv._parseError) { add("EI-PARSE", "EN16931", "Critical", "Dokumentas nenuskaitytas", "Document not parseable", inv._parseError, "Pataisykite XML struktūrą."); return F; }
  const near = (a, b, tol) => a != null && b != null && Math.abs(a - b) <= (tol || EI_TOL);

  // ── EN 16931 core (BR-…) ──
  if (!inv.id) add("BR-02", "EN16931", "Critical", "Privalomas sąskaitos numeris", "Invoice number is mandatory", "", "Užpildykite cbc:ID.");
  if (!/^\d{4}-\d{2}-\d{2}$/.test(inv.issueDate)) add("BR-03", "EN16931", "Critical", "Privaloma išrašymo data (YYYY-MM-DD)", "Issue date mandatory (YYYY-MM-DD)", inv.issueDate, "Užpildykite cbc:IssueDate ISO formatu.");
  if (!EI_TYPE_CODES.includes(inv.typeCode)) add("BR-CL-01", "EN16931", "High", "Netinkamas dokumento tipo kodas", "Invalid type code (UNTDID 1001)", "TypeCode = " + (inv.typeCode || "—"), "Naudokite 380 (sąskaita) / 381 (kreditinė) / 384 / 389.");
  if (inv.isCredit && inv.typeCode && inv.typeCode !== "381") add("BR-CL-02", "EN16931", "High", "Kreditinis dokumentas turi turėti kodą 381", "CreditNote must use type 381", "TypeCode = " + inv.typeCode, "Nustatykite 381.");
  if (!/^[A-Z]{3}$/.test(inv.currency)) add("BR-05", "EN16931", "Critical", "Privaloma valiuta (ISO 4217)", "Currency mandatory (ISO 4217)", inv.currency, "Užpildykite cbc:DocumentCurrencyCode.");
  if (!inv.supplier.name) add("BR-06", "EN16931", "Critical", "Privalomas pardavėjo pavadinimas", "Seller name mandatory", "", "Užpildykite PartyLegalEntity/RegistrationName.");
  if (!/^[A-Z]{2}$/.test(inv.supplier.country)) add("BR-09", "EN16931", "Critical", "Privaloma pardavėjo šalis (ISO 3166-1)", "Seller country mandatory", inv.supplier.country, "Užpildykite PostalAddress/Country/IdentificationCode.");
  if (!inv.customer.name) add("BR-07", "EN16931", "Critical", "Privalomas pirkėjo pavadinimas", "Buyer name mandatory", "", "Užpildykite pirkėjo RegistrationName.");
  if (!inv.lines.length) add("BR-16", "EN16931", "Critical", "Sąskaitoje privaloma bent viena eilutė", "At least one invoice line required", "", "Pridėkite InvoiceLine.");
  inv.lines.forEach((l) => {
    if (l.net == null) add("BR-24", "EN16931", "Critical", "Eilutės grynoji suma privaloma", "Line net amount mandatory", "Linija " + l.id, "Užpildykite LineExtensionAmount.");
    if (!l.name) add("BR-25", "EN16931", "High", "Eilutės prekės/paslaugos pavadinimas privalomas", "Item name mandatory", "Linija " + l.id, "Užpildykite Item/Name.");
    if (l.qty == null) add("BR-22", "EN16931", "High", "Eilutės kiekis privalomas", "Invoiced quantity mandatory", "Linija " + l.id, "Užpildykite InvoicedQuantity.");
    if (l.price != null && l.price < 0) add("BR-27", "EN16931", "High", "Kaina negali būti neigiama", "Item price must not be negative", "Linija " + l.id + ": " + l.price, "Neigiamoms korekcijoms naudokite kreditinę sąskaitą.");
    if (!l.catId) add("BR-CO-04", "EN16931", "Critical", "Eilutei privaloma PVM kategorija", "Line VAT category mandatory", "Linija " + l.id, "Užpildykite ClassifiedTaxCategory/ID.");
  });

  // ── BR-CO calculation rules ──
  const T = inv.totals, lineSum = eiR2(inv.lines.reduce((s, l) => s + (l.net || 0), 0));
  if (T.lineExt != null && !near(T.lineExt, lineSum, EI_TOL_DOC)) add("BR-CO-10", "EN16931", "Critical", "Eilučių suma nesutampa", "Sum of line amounts mismatch", `LineExtensionAmount ${T.lineExt} ≠ Σ eilučių ${lineSum}`, "Perskaičiuokite LineExtensionAmount.");
  if (T.taxExcl != null && T.lineExt != null && !near(T.taxExcl, eiR2(T.lineExt - T.allow + T.charge), EI_TOL_DOC)) add("BR-CO-13", "EN16931", "Critical", "Suma be PVM nesutampa", "Tax-exclusive amount mismatch", `${T.taxExcl} ≠ ${T.lineExt} − ${T.allow} + ${T.charge}`, "TaxExclusive = eilutės − nuolaidos + priemokos.");
  const subTaxSum = eiR2(inv.subtotals.reduce((s, x) => s + (x.tax || 0), 0));
  if (inv.taxTotal != null && !near(inv.taxTotal, subTaxSum, EI_TOL_DOC)) add("BR-CO-14", "EN16931", "Critical", "PVM suma nesutampa su kategorijų suma", "Tax total ≠ Σ category tax", `${inv.taxTotal} ≠ ${subTaxSum}`, "TaxTotal/TaxAmount = Σ TaxSubtotal/TaxAmount.");
  if (T.taxIncl != null && T.taxExcl != null && inv.taxTotal != null && !near(T.taxIncl, eiR2(T.taxExcl + inv.taxTotal), EI_TOL_DOC)) add("BR-CO-15", "EN16931", "Critical", "Suma su PVM nesutampa", "Tax-inclusive amount mismatch", `${T.taxIncl} ≠ ${T.taxExcl} + ${inv.taxTotal}`, "TaxInclusive = TaxExclusive + PVM.");
  if (T.payable != null && T.taxIncl != null && !near(T.payable, eiR2(T.taxIncl - T.prepaid + T.rounding), EI_TOL_DOC)) add("BR-CO-16", "EN16931", "Critical", "Mokėtina suma nesutampa", "Amount due mismatch", `${T.payable} ≠ ${T.taxIncl} − ${T.prepaid} + ${T.rounding}`, "Payable = TaxInclusive − Prepaid + Rounding.");
  if (!inv.subtotals.length && inv.lines.length) add("BR-CO-18", "EN16931", "Critical", "Privaloma bent viena PVM suskirstymo grupė", "At least one VAT breakdown required", "", "Pridėkite TaxTotal/TaxSubtotal.");
  inv.subtotals.forEach((s) => {
    if (s.pct != null && s.taxable != null && s.tax != null && !near(s.tax, eiR2(s.taxable * s.pct / 100))) add("BR-CO-17", "EN16931", "Critical", "Kategorijos PVM ≠ bazė × tarifas", "Category VAT ≠ base × rate", `${s.catId} ${s.pct}%: ${s.tax} ≠ ${eiR2((s.taxable || 0) * s.pct / 100)}`, "Perskaičiuokite TaxSubtotal/TaxAmount.");
  });
  // line sums per (category, rate)
  const grp = {};
  inv.lines.forEach((l) => { const k = l.catId + "@" + (l.pct == null ? "" : l.pct); grp[k] = eiR2((grp[k] || 0) + (l.net || 0)); });
  Object.entries(grp).forEach(([k, sum]) => {
    const [cat, pct] = k.split("@");
    const sub = inv.subtotals.find((s) => s.catId === cat && String(s.pct == null ? "" : s.pct) === pct);
    if (!sub) add("BR-" + cat + "-08", "EN16931", "Critical", "Trūksta PVM suskirstymo kategorijai", "Missing VAT breakdown for category", `${cat} ${pct}% (eilučių suma ${sum})`, "Pridėkite atitinkamą TaxSubtotal.");
    else if (!near(sub.taxable, sum, EI_TOL_DOC)) add("BR-" + cat + "-08", "EN16931", "Critical", "Kategorijos bazė ≠ eilučių sumai", "Category taxable ≠ line sum", `${cat} ${pct}%: ${sub.taxable} ≠ ${sum}`, "Suderinkite TaxableAmount su eilučių sumomis.");
  });
  // category semantics
  const cats = [...new Set(inv.lines.map((l) => l.catId).concat(inv.subtotals.map((s) => s.catId)).filter(Boolean))];
  inv.lines.forEach((l) => { if (l.catId === "S" && !(l.pct > 0)) add("BR-S-05", "EN16931", "Critical", "Kategorijai S tarifas turi būti > 0", "Category S requires rate > 0", "Linija " + l.id, "Nurodykite teigiamą Percent."); });
  inv.subtotals.forEach((s) => {
    if ((s.catId === "Z" || s.catId === "E" || s.catId === "AE" || s.catId === "K" || s.catId === "G") && !near(s.tax || 0, 0)) add("BR-" + s.catId + "-09", "EN16931", "Critical", "Šios kategorijos PVM suma turi būti 0", "Category tax amount must be 0", `${s.catId}: ${s.tax}`, "Nustatykite TaxAmount = 0.");
    if ((s.catId === "E" || s.catId === "AE") && !s.reason) add("BR-" + s.catId + "-10", "EN16931", "High", "Privaloma neapmokestinimo priežastis", "Exemption reason required", s.catId, "Užpildykite TaxExemptionReason.");
  });
  if (cats.includes("AE") && (!inv.supplier.vat || !inv.customer.vat)) add("BR-AE-02", "EN16931", "Critical", "Atvirkštiniam apmokestinimui būtini abiejų šalių PVM kodai", "Reverse charge requires both VAT IDs", "", "Užpildykite pardavėjo ir pirkėjo PVM kodus.");
  if (cats.includes("K")) {
    if (!inv.supplier.vat || !inv.customer.vat) add("BR-K-02", "EN16931", "Critical", "ES tiekimui būtini abiejų šalių PVM kodai", "Intra-EU supply requires both VAT IDs", "", "Užpildykite abu PVM kodus.");
    else if (inv.customer.vat.slice(0, 2) === inv.supplier.vat.slice(0, 2)) add("BR-K-03", "EN16931", "High", "ES tiekimas tos pačios šalies pirkėjui", "Intra-EU category with same-country buyer", inv.customer.vat, "Patikrinkite kategoriją (K skirta kitos ES šalies pirkėjui).");
  }
  if (cats.includes("O") && cats.length > 1) add("BR-O-11", "EN16931", "Critical", "Kategorija O nemaišoma su kitomis", "Category O cannot be mixed", cats.join(", "), "Išskaidykite į atskirus dokumentus.");
  if (T.payable != null && T.payable > 0 && !inv.dueDate && !inv.paymentTerms) add("BR-CO-25", "EN16931", "High", "Reikalinga mokėjimo data arba sąlygos", "Due date or payment terms required", "", "Pridėkite DueDate arba PaymentTerms.");

  // ── Peppol BIS 3.0 ──
  if (inv.customizationId !== PEPPOL_CUSTOMIZATION_ID) add("PEPPOL-EN16931-R004", "PEPPOL", "Critical", "Neteisingas CustomizationID (BIS Billing 3.0)", "Wrong CustomizationID for BIS Billing 3.0", inv.customizationId || "—", "Nustatykite: " + PEPPOL_CUSTOMIZATION_ID);
  if (inv.profileId !== PEPPOL_PROFILE_ID) add("PEPPOL-EN16931-R007", "PEPPOL", "High", "Neteisingas ProfileID", "Wrong ProfileID", inv.profileId || "—", "Nustatykite: " + PEPPOL_PROFILE_ID);
  [["supplier", inv.supplier], ["customer", inv.customer]].forEach(([who, p]) => {
    if (!p.endpoint || !p.endpoint.value) add("PEPPOL-R020", "PEPPOL", "High", "Trūksta " + (who === "supplier" ? "pardavėjo" : "pirkėjo") + " Peppol adreso (EndpointID)", "Missing " + who + " EndpointID", "", "Užpildykite EndpointID su schemeID (pvz., 0200 — LT JAR).");
    else if (!p.endpoint.scheme) add("PEPPOL-R021", "PEPPOL", "High", "EndpointID be schemeID", "EndpointID without schemeID", p.endpoint.value, "Pridėkite schemeID iš EAS sąrašo.");
    else if (p.endpoint.scheme === "0088" && !glnValid(p.endpoint.value)) add("PEPPOL-COMMON-R040", "PEPPOL", "High", "Neteisinga GLN kontrolinė suma", "Invalid GLN check digit", p.endpoint.value, "Patikrinkite 13 skaitmenų GLN (mod 10).");
    else if (p.endpoint.scheme === "0200" && !lt11(p.endpoint.value)) add("PEPPOL-LT-0200", "PEPPOL", "High", "Neteisinga JAR kodo kontrolinė suma (schema 0200)", "Invalid LT registry code checksum (scheme 0200)", p.endpoint.value, "Patikrinkite 9 skaitmenų JAR kodą.");
  });

  // ── Lithuanian layer ──
  [["S", inv.supplier], ["B", inv.customer]].forEach(([who, p]) => {
    if (p.vat && p.vat.slice(0, 2) === "LT" && !ltVatValid(p.vat)) add("LT-EI-VAT-" + who, "LT", "High", "Neteisingas LT PVM kodas (mod 11)", "Invalid LT VAT number (mod 11)", p.vat, "Patikrinkite PVM mokėtojo kodą (LT + 9 arba 12 skaitmenų).");
    if (p.reg && /^\d{9}$/.test(p.reg) && !lt11(p.reg)) add("LT-EI-JAR-" + who, "LT", "Medium", "Neteisinga įmonės kodo kontrolinė suma", "Invalid LT company-code checksum", p.reg, "Patikrinkite 9 skaitmenų JAR kodą.");
  });
  inv.ibans.forEach((ib) => { if (!ibanValid(ib)) add("LT-EI-IBAN", "LT", "High", "Neteisingas IBAN (mod 97)", "Invalid IBAN (mod 97)", ib, "Patikrinkite sąskaitos numerį; LT IBAN — 20 ženklų."); });
  const post26 = inv.issueDate >= "2026-01-01";
  const allowed = post26 ? [21, 12, 5, 0] : [21, 12, 9, 5, 0];
  [...new Set(inv.lines.map((l) => l.pct).concat(inv.subtotals.map((s) => s.pct)))].forEach((r) => {
    if (r == null) return;
    if (!allowed.includes(r)) {
      const transitional = post26 && r === 9;
      add(transitional ? "LT-EI-RATE-9" : "LT-EI-RATE", "LT", transitional ? "High" : "Critical",
        transitional ? "9% tarifas po 2026-01-01 (reforma: 9% → 12%)" : "Neegzistuojantis LT PVM tarifas",
        transitional ? "9% rate after 2026-01-01 (reform: 9% → 12%)" : "Non-existent LT VAT rate",
        r + "% · data " + inv.issueDate, transitional ? "Patikrinkite, ar sandoriui netaikoma pereinamoji nuostata; standartiškai — 12%." : "LT tarifai: " + allowed.join("/") + "%.");
    }
  });
  if (inv.supplier.country === "LT" && inv.customer.country === "LT" && inv.currency && inv.currency !== "EUR") add("LT-EI-CUR", "LT", "Medium", "Vidaus sandoris ne eurais", "Domestic transaction not in EUR", inv.currency, "Vidaus B2B/B2G sąskaitoms naudokite EUR.");
  return F;
}

function computeEInvoiceGate(findings) {
  const errs = (std) => findings.filter((f) => f.std === std && (f.severity === "Critical" || f.severity === "High"));
  const en = errs("EN16931"), pep = errs("PEPPOL"), lt = errs("LT");
  const enOk = en.length === 0, pepOk = enOk && pep.length === 0, ltOk = lt.length === 0;
  return {
    en: { ok: enOk, errors: en.length }, peppol: { ok: pepOk, errors: pep.length }, lt: { ok: ltOk, errors: lt.length },
    label: [enOk ? (pepOk ? "EN 16931 VALID · PEPPOL-READY" : "EN 16931 VALID · NOT PEPPOL-READY") : "NOT EN 16931 VALID",
            enOk ? (pepOk ? "ATITINKA EN 16931 · PARUOŠTA PEPPOL" : "ATITINKA EN 16931 · NEPARUOŠTA PEPPOL") : "NEATITINKA EN 16931"],
  };
}

// ── Generator: SAF-T sales invoice → Peppol BIS Billing 3.0 UBL ──
function buildPeppolInvoice(saftInv, parsed, opts) {
  const o = opts || {};
  const esc = (s) => String(s == null ? "" : s).replace(/[&<>"']/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&apos;" }[c]));
  const h = (parsed && parsed.header) || {}, co = h.company || {};
  const cust = ((parsed && parsed.customers) || []).find((c) => c.customerID === saftInv.customerID) || {};
  const net = eiR2((saftInv.documentTotals && (saftInv.documentTotals.netTotal != null ? saftInv.documentTotals.netTotal : 0)) || 0);
  const gross = saftInv.documentTotals && saftInv.documentTotals.grossTotal;
  let rate = o.rate;
  if (rate == null && gross != null && net > 0) { const implied = ((gross - net) / net) * 100; rate = [21, 12, 9, 5, 0].reduce((b, r) => Math.abs(r - implied) < Math.abs(b - implied) ? r : b, 21); }
  if (rate == null) rate = 21;
  const buyerCountry = (cust.country || cust.addressCountry || "LT").toUpperCase();
  const cat = rate > 0 ? "S" : (buyerCountry !== "LT" ? "K" : "Z");
  const reason = cat === "K" ? "Intra-Community supply, Art. 138 of Directive 2006/112/EC" : "";
  const tax = eiR2(net * rate / 100), incl = eiR2(net + tax);
  const issue = saftInv.invoiceDate || new Date().toISOString().slice(0, 10);
  const sellerVat = (o.sellerVat || co.taxRegistrationNumber || co.vatNumber || "").toUpperCase().replace(/\s/g, "");
  const sellerReg = String(co.registrationNumber || h.registrationNumber || "");
  const bv = String(cust.taxRegistrationNumber || "").toUpperCase().replace(/\s/g, "");
  const buyerVat = /^[A-Z]{2}/.test(bv) ? bv : "";
  const buyerRegSrc = String(cust.registrationNumber || (buyerVat ? "" : cust.taxRegistrationNumber) || "");
  const buyerReg = /^\d{9}$/.test(buyerRegSrc) ? buyerRegSrc : "";
  const ep = (reg) => /^\d{9}$/.test(reg) && lt11(reg) ? `<cbc:EndpointID schemeID="0200">${esc(reg)}</cbc:EndpointID>` : "";
  const vatBlock = (vat) => /^[A-Z]{2}/.test(vat) ? `<cac:PartyTaxScheme><cbc:CompanyID>${esc(vat)}</cbc:CompanyID><cac:TaxScheme><cbc:ID>VAT</cbc:ID></cac:TaxScheme></cac:PartyTaxScheme>` : "";
  const party = (name, country, vat, reg) => `<cac:Party>${ep(reg)}<cac:PartyName><cbc:Name>${esc(name)}</cbc:Name></cac:PartyName><cac:PostalAddress><cac:Country><cbc:IdentificationCode>${esc(country)}</cbc:IdentificationCode></cac:Country></cac:PostalAddress>${vatBlock(vat)}<cac:PartyLegalEntity><cbc:RegistrationName>${esc(name)}</cbc:RegistrationName>${reg ? `<cbc:CompanyID>${esc(reg)}</cbc:CompanyID>` : ""}</cac:PartyLegalEntity></cac:Party>`;
  const xml = `<?xml version="1.0" encoding="UTF-8"?>
<Invoice xmlns="urn:oasis:names:specification:ubl:schema:xsd:Invoice-2" xmlns:cac="urn:oasis:names:specification:ubl:schema:xsd:CommonAggregateComponents-2" xmlns:cbc="urn:oasis:names:specification:ubl:schema:xsd:CommonBasicComponents-2">
<cbc:CustomizationID>${PEPPOL_CUSTOMIZATION_ID}</cbc:CustomizationID>
<cbc:ProfileID>${PEPPOL_PROFILE_ID}</cbc:ProfileID>
<cbc:ID>${esc(saftInv.invoiceNo || "INV-1")}</cbc:ID>
<cbc:IssueDate>${esc(issue)}</cbc:IssueDate>
<cbc:InvoiceTypeCode>380</cbc:InvoiceTypeCode>
<cbc:DocumentCurrencyCode>EUR</cbc:DocumentCurrencyCode>
<cac:AccountingSupplierParty>${party(co.name || "—", "LT", sellerVat, sellerReg)}</cac:AccountingSupplierParty>
<cac:AccountingCustomerParty>${party(cust.name || saftInv.customerID || "—", buyerCountry, buyerVat, buyerReg)}</cac:AccountingCustomerParty>
<cac:PaymentTerms><cbc:Note>14 d. / 14 days</cbc:Note></cac:PaymentTerms>
<cac:TaxTotal><cbc:TaxAmount currencyID="EUR">${tax.toFixed(2)}</cbc:TaxAmount><cac:TaxSubtotal><cbc:TaxableAmount currencyID="EUR">${net.toFixed(2)}</cbc:TaxableAmount><cbc:TaxAmount currencyID="EUR">${tax.toFixed(2)}</cbc:TaxAmount><cac:TaxCategory><cbc:ID>${cat}</cbc:ID><cbc:Percent>${rate}</cbc:Percent>${reason ? `<cbc:TaxExemptionReason>${esc(reason)}</cbc:TaxExemptionReason>` : ""}<cac:TaxScheme><cbc:ID>VAT</cbc:ID></cac:TaxScheme></cac:TaxCategory></cac:TaxSubtotal></cac:TaxTotal>
<cac:LegalMonetaryTotal><cbc:LineExtensionAmount currencyID="EUR">${net.toFixed(2)}</cbc:LineExtensionAmount><cbc:TaxExclusiveAmount currencyID="EUR">${net.toFixed(2)}</cbc:TaxExclusiveAmount><cbc:TaxInclusiveAmount currencyID="EUR">${incl.toFixed(2)}</cbc:TaxInclusiveAmount><cbc:PayableAmount currencyID="EUR">${incl.toFixed(2)}</cbc:PayableAmount></cac:LegalMonetaryTotal>
<cac:InvoiceLine><cbc:ID>1</cbc:ID><cbc:InvoicedQuantity unitCode="C62">1</cbc:InvoicedQuantity><cbc:LineExtensionAmount currencyID="EUR">${net.toFixed(2)}</cbc:LineExtensionAmount><cac:Item><cbc:Name>${esc(o.itemName || ("Pardavimas pagal sąskaitą " + (saftInv.invoiceNo || "")))}</cbc:Name><cac:ClassifiedTaxCategory><cbc:ID>${cat}</cbc:ID><cbc:Percent>${rate}</cbc:Percent><cac:TaxScheme><cbc:ID>VAT</cbc:ID></cac:TaxScheme></cac:ClassifiedTaxCategory></cac:Item><cac:Price><cbc:PriceAmount currencyID="EUR">${net.toFixed(2)}</cbc:PriceAmount></cac:Price></cac:InvoiceLine>
</Invoice>`;
  return { xml, meta: { rate, cat, net, tax, payable: incl, buyer: cust.name || saftInv.customerID || "—", peppolEndpoints: !!(ep(sellerReg) && ep(buyerReg)) } };
}

// ═════════════════════════════════════════════════════════════════════════
// ERP INTEGRATION LAYER — batch e-invoicing on top of the EN 16931 engine.
// Sources: the loaded SAF-T sales ledger, or a raw ERP register export
// (CSV) mapped through per-vendor field profiles. Output: validated
// Peppol XML files, a manifest with gates and hashes, and a ZIP bundle
// ready for hand-over to an Access Point or the E. saskaita portal.
// ═════════════════════════════════════════════════════════════════════════
const EI_CRC_TABLE = (() => { const t = new Uint32Array(256); for (let n = 0; n < 256; n++) { let c = n; for (let k = 0; k < 8; k++) c = c & 1 ? 0xEDB88320 ^ (c >>> 1) : c >>> 1; t[n] = c >>> 0; } return t; })();
function crc32(bytes) { let c = 0xFFFFFFFF; for (let i = 0; i < bytes.length; i++) c = EI_CRC_TABLE[(c ^ bytes[i]) & 0xFF] ^ (c >>> 8); return (c ^ 0xFFFFFFFF) >>> 0; }

// Minimal ZIP writer (method STORE, UTF-8 names) — enough for any unzip tool.
function buildZip(files) {
  const enc = typeof TextEncoder !== "undefined" ? new TextEncoder() : { encode: (s) => Uint8Array.from(Buffer.from(s, "utf8")) };
  const parts = files.map((f) => ({ name: enc.encode(f.name), data: typeof f.data === "string" ? enc.encode(f.data) : f.data }));
  let size = 22; parts.forEach((p) => { size += 30 + p.name.length + p.data.length + 46 + p.name.length; });
  const out = new Uint8Array(size); const dv = new DataView(out.buffer);
  let off = 0; const central = [];
  const w16 = (v) => { dv.setUint16(off, v & 0xFFFF, true); off += 2; };
  const w32 = (v) => { dv.setUint32(off, v >>> 0, true); off += 4; };
  parts.forEach((p) => {
    const crc = crc32(p.data); const lhOff = off;
    w32(0x04034B50); w16(20); w16(0x0800); w16(0); w16(0); w16(0x2121);
    w32(crc); w32(p.data.length); w32(p.data.length); w16(p.name.length); w16(0);
    out.set(p.name, off); off += p.name.length;
    out.set(p.data, off); off += p.data.length;
    central.push({ p, crc, lhOff });
  });
  const cdStart = off;
  central.forEach(({ p, crc, lhOff }) => {
    w32(0x02014B50); w16(20); w16(20); w16(0x0800); w16(0); w16(0); w16(0x2121);
    w32(crc); w32(p.data.length); w32(p.data.length); w16(p.name.length); w16(0); w16(0); w16(0); w16(0); w32(0); w32(lhOff);
    out.set(p.name, off); off += p.name.length;
  });
  const cdSize = off - cdStart;
  w32(0x06054B50); w16(0); w16(0); w16(central.length); w16(central.length); w32(cdSize); w32(cdStart); w16(0);
  return out;
}

// CSV with delimiter sniffing (; , tab), quoted fields, "" escapes, CRLF.
function parseInvoiceCsv(text) {
  const t = String(text || "").replace(/^\uFEFF/, "");
  const first = t.slice(0, t.indexOf("\n") < 0 ? t.length : t.indexOf("\n"));
  const delim = [";", ",", "\t"].map((d) => [d, first.split(d).length]).sort((a, b) => b[1] - a[1])[0][0];
  const rows = []; let row = [], field = "", q = false;
  for (let i = 0; i < t.length; i++) {
    const ch = t[i];
    if (q) { if (ch === '"') { if (t[i + 1] === '"') { field += '"'; i++; } else q = false; } else field += ch; }
    else if (ch === '"') q = true;
    else if (ch === delim) { row.push(field); field = ""; }
    else if (ch === "\n") { row.push(field.replace(/\r$/, "")); field = ""; if (row.some((c) => c !== "")) rows.push(row); row = []; }
    else field += ch;
  }
  if (field !== "" || row.length) { row.push(field.replace(/\r$/, "")); if (row.some((c) => c !== "")) rows.push(row); }
  return { delimiter: delim, headers: (rows[0] || []).map((h) => String(h).trim()), rows: rows.slice(1) };
}
function eiNormDate(s) {
  const v = String(s || "").trim();
  let m = /^(\d{4})[-./](\d{1,2})[-./](\d{1,2})/.exec(v);
  if (m) return m[1] + "-" + m[2].padStart(2, "0") + "-" + m[3].padStart(2, "0");
  m = /^(\d{1,2})[-./](\d{1,2})[-./](\d{4})/.exec(v);
  if (m) return m[3] + "-" + m[2].padStart(2, "0") + "-" + m[1].padStart(2, "0");
  return "";
}

// Field-mapping profiles — curated synonym priorities per popular LT ERP.
const ERP_PROFILES = [
  { id: "rivile", name: "Rivilė GAMA", hints: { invoiceNo: ["dok_nr", "dok nr", "dokumento nr", "sask"], invoiceDate: ["data"], customerName: ["pirkejas", "klientas", "pavadinimas"], customerCode: ["im_kodas", "imones kodas", "kodas"], customerVat: ["pvm_kodas", "pvm kodas"], customerCountry: ["salis"], net: ["suma_be_pvm", "suma be pvm", "be pvm"], gross: ["suma_su_pvm", "suma su pvm", "su pvm", "viso"], rate: ["tarifas", "pvm proc", "pvm %"] } },
  { id: "b1lt", name: "B1.lt", hints: { invoiceNo: ["dokumento numeris", "dokumentas", "saskaitos nr", "numeris"], invoiceDate: ["dokumento data", "data"], customerName: ["partneris", "pirkejas", "klientas"], customerCode: ["partnerio kodas", "imones kodas", "kodas"], customerVat: ["pvm moketojo kodas", "pvm kodas"], customerCountry: ["salis"], net: ["suma be pvm", "be pvm"], gross: ["suma su pvm", "su pvm", "viso"], rate: ["pvm tarifas", "tarifas", "pvm %"] } },
  { id: "d365bc", name: "Microsoft Dynamics 365 Business Central", hints: { invoiceNo: ["document no", "invoice no", "no"], invoiceDate: ["posting date", "document date", "date"], customerName: ["sell-to customer name", "customer name", "customer"], customerCode: ["sell-to customer no", "customer no"], customerVat: ["vat registration no", "vat reg"], customerCountry: ["country/region code", "country"], net: ["vat base amount", "net amount", "amount"], gross: ["amount including vat", "incl. vat", "total"], rate: ["vat %", "vat rate"] } },
  { id: "generic", name: "Generic / kita", hints: { invoiceNo: ["invoice", "sask", "dok", "numeris", "nr"], invoiceDate: ["date", "data"], customerName: ["customer", "klientas", "pirkejas", "name", "pavadinimas"], customerCode: ["company code", "reg", "imones kodas", "kodas"], customerVat: ["vat", "pvm"], customerCountry: ["country", "salis"], net: ["net", "be pvm", "suma"], gross: ["gross", "total", "su pvm", "viso"], rate: ["rate", "tarif", "%"] } },
];
function eiTryMap(profile, headers) {
  const used = new Set(); const map = {};
  const norm = headers.map((h) => cpNorm(h));
  Object.entries(profile.hints).forEach(([field, hints]) => {
    for (const hint of hints) {
      const idx = norm.findIndex((h, i) => !used.has(i) && h.indexOf(hint) >= 0);
      if (idx >= 0) { map[field] = idx; used.add(idx); return; }
    }
  });
  return { map, score: Object.keys(map).length };
}
function detectErpProfile(headers) {
  let best = null;
  ERP_PROFILES.forEach((p) => { const r = eiTryMap(p, headers); if (!best || r.score > best.score) best = { id: p.id, name: p.name, ...r }; });
  return best;
}
function mapErpRows(headers, rows, profileId) {
  const chosen = profileId && profileId !== "auto" ? ERP_PROFILES.find((p) => p.id === profileId) : null;
  const det = chosen ? { id: chosen.id, name: chosen.name, ...eiTryMap(chosen, headers) } : detectErpProfile(headers);
  const g = (row, f) => det.map[f] != null ? String(row[det.map[f]] == null ? "" : row[det.map[f]]).trim() : "";
  const invoices = []; let skipped = 0;
  rows.forEach((row) => {
    const no = g(row, "invoiceNo"), net = eiNum(g(row, "net"));
    if (!no && net == null) { skipped++; return; }
    const country = (g(row, "customerCountry").toUpperCase().match(/^[A-Z]{2}/) || ["LT"])[0];
    invoices.push({
      invoiceNo: no || ("ROW-" + (invoices.length + 1)), invoiceDate: eiNormDate(g(row, "invoiceDate")),
      customerName: g(row, "customerName"), customerCode: g(row, "customerCode"),
      customerVat: g(row, "customerVat").toUpperCase().replace(/\s/g, ""), country,
      net: net == null ? 0 : net, gross: eiNum(g(row, "gross")), rate: eiNum(g(row, "rate")),
    });
  });
  return { profile: det, mapping: Object.fromEntries(Object.entries(det.map).map(([f, i]) => [f, headers[i]])), invoices, skipped };
}

// Batch pipeline. source: {kind:"saft", parsed} | {kind:"rows", rows, seller}.
async function runPeppolBatch(source, opts) {
  const o = opts || {};
  const parseXml = o.parseXml || ((x) => parseUblInvoice(x));
  const jobs = [];
  if (source.kind === "saft") {
    const parsed = source.parsed || {};
    (((parsed.sales || {}).items) || []).forEach((inv) => jobs.push({ saftInv: inv, parsedLike: parsed }));
  } else {
    const seller = source.seller || {};
    (source.rows || []).forEach((r) => jobs.push({
      saftInv: { invoiceNo: r.invoiceNo, invoiceDate: r.invoiceDate || new Date().toISOString().slice(0, 10), customerID: r.customerCode || r.customerVat || r.customerName || "C", documentTotals: { netTotal: r.net, grossTotal: r.gross != null ? r.gross : (r.rate != null ? eiR2(r.net * (1 + r.rate / 100)) : undefined) } },
      parsedLike: { header: { company: { name: seller.name || "", registrationNumber: seller.registrationNumber || "", taxRegistrationNumber: seller.taxRegistrationNumber || "" } }, customers: [{ customerID: r.customerCode || r.customerVat || r.customerName || "C", name: r.customerName || r.customerCode || "—", country: r.country || "LT", taxRegistrationNumber: r.customerVat || r.customerCode || "", registrationNumber: r.customerCode || "" }] },
    }));
  }
  const limit = o.limit || 2000;
  const results = [];
  for (const job of jobs.slice(0, limit)) {
    const out = buildPeppolInvoice(job.saftInv, job.parsedLike, o.gen || {});
    let findings, gate;
    try { const inv = await parseXml(out.xml); findings = validateEInvoice(inv); gate = computeEInvoiceGate(findings); }
    catch (e) { findings = [{ rule_id: "EI-PARSE", std: "EN16931", severity: "Critical", titleLt: "Klaida", titleEn: "Error", detail: String(e && e.message || e) }]; gate = computeEInvoiceGate(findings); }
    const fileName = "peppol-" + String(job.saftInv.invoiceNo || results.length + 1).replace(/[^\w.-]+/g, "_") + ".xml";
    results.push({ invoiceNo: job.saftInv.invoiceNo || "—", buyer: out.meta.buyer, cat: out.meta.cat, rate: out.meta.rate, payable: out.meta.payable, xml: out.xml, fileName, findings, gate, ready: gate.en.ok && gate.peppol.ok && gate.lt.ok });
  }
  const summary = { total: results.length, ready: results.filter((r) => r.ready).length, enValid: results.filter((r) => r.gate.en.ok).length };
  summary.blocked = summary.total - summary.ready;
  return { results, summary, truncated: jobs.length > limit };
}

function buildBatchManifest(batch, hashes) {
  return JSON.stringify({
    generatedAt: new Date().toISOString(), engine: "TaxAI e-invoicing v" + ENGINE_VERSION,
    standard: "EN 16931 · Peppol BIS Billing 3.0", summary: batch.summary,
    files: batch.results.map((r) => ({ name: r.fileName, invoiceNo: r.invoiceNo, buyer: r.buyer, category: r.cat, rate: r.rate, payable: r.payable, gates: { en: r.gate.en.ok, peppol: r.gate.peppol.ok, lt: r.gate.lt.ok }, findings: r.findings.map((f) => f.rule_id), sha256: (hashes && hashes[r.fileName]) || null })),
  }, null, 2);
}
function batchSummaryCsv(batch) {
  const head = "invoiceNo;buyer;category;rate;payable;EN16931;Peppol;LT;findings";
  return [head].concat(batch.results.map((r) => [r.invoiceNo, '"' + String(r.buyer).replace(/"/g, '""') + '"', r.cat, r.rate, r.payable, r.gate.en.ok ? "OK" : "FAIL", r.gate.peppol.ok ? "OK" : "FAIL", r.gate.lt.ok ? "OK" : "FAIL", r.findings.map((f) => f.rule_id).join("|")].join(";"))).join("\n");
}

