// Board-ready forensic report: opens a print-formatted window (→ Save as PDF).
function exportForensicReport({ company, period, intel, runResult, findings, threatMarkdown, caseFlags, lang, personalRules }) {
  const esc = s => String(s == null ? "" : s).replace(/[&<>]/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
  const c = intel?.risk?.band === "CRITICAL" ? "#c0392b" : intel?.risk?.band === "HIGH" ? "#d35400" : intel?.risk?.band === "MEDIUM" ? "#b7950b" : "#1e8449";
  const factorsRows = (intel?.risk?.factors || []).map(f => `<tr><td>${esc(f.label)}</td><td style="text-align:right;font-weight:700">+${f.points}</td><td style="color:#555">${esc(f.detail)}</td></tr>`).join("");
  const findingRows = (findings || []).slice(0, 80).map(f => `<tr><td>${esc(f.rule_id || "")}</td><td><b style="color:${f.severity === "Critical" ? "#c0392b" : f.severity === "High" ? "#d35400" : "#b7950b"}">${esc(f.severity)}</b></td><td>${esc(f.category)}</td><td>${esc(f.title)}</td></tr>`).join("");
  const cycles = (intel?.graph?.cycles || []).slice(0, 8).map(cy => `<li>${esc((cy.labels || cy.path).map(p => typeof p === "string" ? p.replace(/^(reg|name|customer|supplier|company):/, "") : p).join(" → "))} — min €${(cy.minFlow || 0).toLocaleString()}</li>`).join("");
  const flagged = Object.entries(caseFlags || {}).filter(([, v]) => v.flagged).map(([k, v]) => `<tr><td>${esc(k)}</td><td>${esc(v.status || "open")}</td><td>${esc(v.assignee || "")}</td><td>${esc(v.note || "")}</td></tr>`).join("");
  const mdToHtml = md => esc(md || "").replace(/^### (.*)$/gm, "<h3>$1</h3>").replace(/^## (.*)$/gm, "<h2>$1</h2>").replace(/^# (.*)$/gm, "<h1>$1</h1>").replace(/\*\*(.*?)\*\*/g, "<b>$1</b>").replace(/^- (.*)$/gm, "• $1").replace(/\n/g, "<br>");

  const prRules = personalRules?.rules || [];
  const prRows = prRules.map(r => `<tr><td>${esc(r.id)}</td><td><b style="color:${r.severity === "Block" ? "#c0392b" : r.severity === "Reject" ? "#d35400" : "#b7950b"}">${esc(r.severity)}</b></td><td>${esc(r.kind)}</td><td><b style="color:${r.status === "FAIL" ? "#c0392b" : r.status === "PASS" ? "#1e8449" : "#888"}">${r.status === "FAIL" ? "FLAGGED" : r.status === "PASS" ? "CLEAR" : "N/A"}</b></td><td>${esc(r.title)}${r.observed?.length ? `<br><span style="color:#666">${esc(r.observed.join(" · "))}</span>` : ""}${r.interpretation ? `<br><span style="color:#444">→ ${esc(r.interpretation)}</span>` : ""}${r.lawRef ? ` <span style="color:#888">[${esc(r.lawRef)}]</span>` : ""}</td></tr>`).join("");
  const prSecN = 6 + (flagged ? 1 : 0) + (threatMarkdown ? 1 : 0) + 1;
  const prBlock = prRules.length ? `<h2>${prSecN} · Adaptive Rules · AI <span style="font-weight:400;color:#888;font-size:13px">(industry: ${esc(personalRules.industry || "")} · confidence ${esc(personalRules.industryConfidence || "")})</span></h2>
  <p>${esc(personalRules.industryRationale || "")}</p>
  <p style="font-size:11px;color:#666">Company-specific rules designed by AI over the deterministic metric registry, then scored deterministically. Flagged ${personalRules.counts?.fail || 0} · Clear ${personalRules.counts?.pass || 0} · N/A ${personalRules.counts?.na || 0}.</p>
  <table><thead><tr><th>Rule</th><th>Severity</th><th>Kind</th><th>Status</th><th>Detail</th></tr></thead><tbody>${prRows}</tbody></table>` : "";

  const html = `<!doctype html><html><head><meta charset="utf-8"><title>TAXAI Forensic Report — ${esc(company)}</title>
  <style>
    body{font-family:-apple-system,Segoe UI,Roboto,sans-serif;color:#1a1a1a;max-width:900px;margin:0 auto;padding:40px;line-height:1.55}
    h1{font-size:26px;margin:0 0 4px} h2{font-size:18px;border-bottom:2px solid #eee;padding-bottom:6px;margin-top:32px} h3{font-size:14px;margin-top:18px}
    .meta{color:#666;font-size:13px;margin-bottom:24px}
    .score{display:inline-block;padding:8px 18px;border-radius:8px;background:${c}1a;color:${c};font-weight:800;font-size:22px}
    table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}
    th,td{text-align:left;padding:6px 8px;border-bottom:1px solid #eee;vertical-align:top}
    th{background:#fafafa;font-size:11px;text-transform:uppercase;color:#888}
    .disc{margin-top:30px;padding:14px;background:#fff8e6;border:1px solid #f0d68a;border-radius:8px;font-size:11px;color:#7a5c00}
    @media print{body{padding:0}}
  </style></head><body>
  <h1>TAXAI · Forensic Intelligence Report</h1>
  <div class="meta"><b>${esc(company)}</b> · ${esc(period)} · Generated ${new Date().toLocaleString()}</div>
  <h2>1 · Risk Summary</h2>
  <p>Composite risk score: <span class="score">${intel?.risk?.score ?? "—"}/100 · ${esc(intel?.risk?.band || "")}</span></p>
  <p>${esc(intel?.risk?.interpretation || "")}</p>
  <table><thead><tr><th>Risk factor</th><th>Points</th><th>Detail</th></tr></thead><tbody>${factorsRows || '<tr><td colspan=3>No material risk factors.</td></tr>'}</tbody></table>
  <h2>2 · Statistical Forensics</h2>
  <p>Benford: ${intel?.benford?.applicable ? `MAD ${intel.benford.mad}, χ² ${intel.benford.chi2} (crit ${intel.benford.chi2Critical}) — ${esc(intel.benford.conformity)}` : "n/a (sample &lt; 50)"}</p>
  <p>Outliers: ${intel?.anomalies?.outliers?.length || 0} · Duplicate clusters: ${intel?.anomalies?.duplicateClusters?.length || 0} · Round-number bias: ${intel?.anomalies?.roundNumberBias?.elevated ? "ELEVATED" : "normal"} · Period-end clustering: ${intel?.anomalies?.periodEndClustering?.elevated ? "ELEVATED" : "normal"}</p>
  <h2>3 · Network Analysis</h2>
  <p>${intel?.graph?.nodeCount || 0} entities · ${intel?.graph?.edgeCount || 0} money flows · ${intel?.graph?.cycleCount || 0} circular cycles · concentration HHI ${intel?.graph?.concentration?.hhi ?? "—"} (${esc(intel?.graph?.concentration?.interpretation || "")})</p>
  ${cycles ? `<p><b>Detected circular flows (round-trip risk):</b></p><ul style="font-size:12px">${cycles}</ul>` : ""}
  <h2>4 · Temporal Forensics</h2>
  <p>${intel?.temporal?.applicable ? `Velocity anomalies: ${intel.temporal.velocitySpikes.length} · Backdated (&gt;30d): ${intel.temporal.backdating.length} · Weekend posting: ${intel.temporal.weekendPostings?.pct ?? "—"}% · After-hours: ${intel.temporal.afterHours?.pct ?? "—"}%` : "Insufficient dated events."}</p>
  <h2>5 · Entity Intelligence</h2>
  <p>Probable duplicate entities: ${intel?.entityRes?.duplicates?.length || 0} · Shared bank accounts: ${intel?.entityRes?.sharedBankAccounts?.length || 0} · Shell-flagged: ${intel?.entityRes?.shellIndicators?.length || 0}</p>
  <h2>6 · Compliance Findings (482-rule engine)</h2>
  <p>Total ${runResult?.summary?.total || 0} — Block ${runResult?.bySeverity?.Block || 0}, Reject ${runResult?.bySeverity?.Reject || 0}, Warn ${runResult?.bySeverity?.Warn || 0}</p>
  <table><thead><tr><th>Rule</th><th>Severity</th><th>Category</th><th>Finding</th></tr></thead><tbody>${findingRows || '<tr><td colspan=4>No findings.</td></tr>'}</tbody></table>
  ${flagged ? `<h2>7 · Investigation Case File</h2><table><thead><tr><th>Item</th><th>Status</th><th>Assignee</th><th>Note</th></tr></thead><tbody>${flagged}</tbody></table>` : ""}
  ${threatMarkdown ? `<h2>${flagged ? "8" : "7"} · AI Threat Assessment</h2><div style="font-size:12px">${mdToHtml(threatMarkdown)}</div>` : ""}
  ${prBlock}
  <div class="disc"><b>Disclaimer.</b> Deterministic engine outputs (risk factors, Benford, anomalies, graph, temporal) are reproducible computations from the SAF-T file. AI narrative is decision-support, not an accusation — signals warrant investigation, not proof of wrongdoing. Figures are accounting approximations; verify against filed statements (PLN204, balansas) and applicable law before action. Not a substitute for a licensed advisor or an official VMI audit.</div>
  <script>window.onload=()=>{setTimeout(()=>window.print(),300)}</script>
  </body></html>`;
  const w = window.open("", "_blank");
  if (w) { w.document.write(html); w.document.close(); }
}

const SC = s => ({ Critical: "#ff6b6b", High: "#ffa94d", Medium: "#ffd43b", Low: "#69db7c" }[s] || "#aaa");

// ═══════════════════════════════════════════════════
// PAGE BANNER — cinematic black-and-white canvas header used across all
// in-app pages (not just the landing). Three deterministic motion variants:
//   "network"  → drifting data-network with cursor reaction
//   "particles"→ rising particle field
//   "scan"     → scanning rule-grid
// All pure-canvas (no external images/video) so they always render, look
// high-quality, and stay perfectly on-brand in monochrome.
// ═══════════════════════════════════════════════════
// ═══════════════════════════════════════════════════
// PERFORMANCE: shared animation helpers
//   • prefersReducedMotion() — honor the OS "reduce motion" setting
//   • useCanvasAnim(ref, draw) — runs an rAF loop that AUTO-PAUSES when the
//     canvas is scrolled off-screen (IntersectionObserver) or the tab is
//     hidden (visibilitychange), caps device-pixel-ratio, and debounces
//     resize. This is the single biggest perf win: idle canvases cost 0 CPU.
// ═══════════════════════════════════════════════════
function prefersReducedMotion() {
  try { return window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches; } catch { return false; }
}
function useCanvasAnim(ref, makeDraw, deps = []) {
  useEffect(() => {
    const canvas = ref.current; if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    const reduce = prefersReducedMotion();
    let raf = 0, w = 0, h = 0, dpr = 1, visible = true, tabVisible = !document.hidden, running = false;
    const size = () => { dpr = Math.min(devicePixelRatio || 1, 1.5); w = canvas.clientWidth; h = canvas.clientHeight; canvas.width = Math.max(1, Math.round(w * dpr)); canvas.height = Math.max(1, Math.round(h * dpr)); ctx.setTransform(dpr, 0, 0, dpr, 0, 0); };
    const api = { get w() { return w; }, get h() { return h; }, ctx, canvas, reduce };
    const draw = makeDraw(api);
    let t = 0;
    const loop = () => { t += 1; draw.frame(t); raf = requestAnimationFrame(loop); };
    const start = () => { if (running) return; if (!visible || !tabVisible) return; running = true; raf = requestAnimationFrame(loop); };
    const stop = () => { running = false; if (raf) cancelAnimationFrame(raf); raf = 0; };
    // initial sizing + one static paint (so reduced-motion / paused still shows something)
    size(); draw.init && draw.init(); draw.frame(0);
    if (reduce) { /* static frame only, no loop */ }
    else start();
    // pause when off-screen
    const io = new IntersectionObserver((es) => { visible = es[0].isIntersecting; if (reduce) return; visible ? start() : stop(); }, { threshold: 0.01 });
    io.observe(canvas);
    // pause when tab hidden
    const onVis = () => { tabVisible = !document.hidden; if (reduce) return; tabVisible ? start() : stop(); };
    document.addEventListener("visibilitychange", onVis);
    // debounced resize
    let rz; const onResize = () => { clearTimeout(rz); rz = setTimeout(() => { size(); draw.init && draw.init(); draw.frame(0); }, 150); };
    addEventListener("resize", onResize);
    return () => { stop(); io.disconnect(); document.removeEventListener("visibilitychange", onVis); removeEventListener("resize", onResize); clearTimeout(rz); draw.cleanup && draw.cleanup(); };
  }, deps); // eslint-disable-line
}

function PageBanner({ variant = "network", height = 150, label, title, sub, right, video }) {
  const ref = useRef(null);
  const [vidOn, setVidOn] = useState(false); // true once a banner video has decoded its first frame
  useCanvasAnim(ref, ({ ctx, canvas }) => {
    let items = [], mx = -999, my = -999;
    const mm = e => { const r = canvas.getBoundingClientRect(); mx = e.clientX - r.left; my = e.clientY - r.top; };
    const ml = () => { mx = -999; my = -999; };
    canvas.addEventListener("mousemove", mm); canvas.addEventListener("mouseleave", ml);
    return {
      init() {
        const w = canvas.clientWidth, h = canvas.clientHeight; items = [];
        if (variant === "network") { const n = Math.min(46, Math.round(w / 26)); for (let i = 0; i < n; i++) items.push({ x: Math.random() * w, y: Math.random() * h, vx: (Math.random() - .5) * .25, vy: (Math.random() - .5) * .25, r: Math.random() * 1.4 + .5, p: Math.random() * 6.28 }); }
        else if (variant === "particles") { const n = Math.min(80, Math.round(w / 14)); for (let i = 0; i < n; i++) items.push({ x: Math.random() * w, y: Math.random() * h, z: Math.random(), vy: Math.random() * .3 + .1 }); }
        else { const cell = 22, cols = Math.ceil(w / cell), rows = Math.ceil(h / cell); for (let y = 0; y < rows; y++) for (let x = 0; x < cols; x++) items.push({ x: x * cell, y: y * cell, s: Math.random(), on: Math.random() > .8, cell }); }
      },
      frame(tf) {
        const w = canvas.clientWidth, h = canvas.clientHeight; const t = tf * 0.016; ctx.clearRect(0, 0, w, h);
        if (variant === "network") {
          for (const n of items) { n.x += n.vx; n.y += n.vy; if (n.x < 0 || n.x > w) n.vx *= -1; if (n.y < 0 || n.y > h) n.vy *= -1; const dxm = mx - n.x, dym = my - n.y, dm = Math.hypot(dxm, dym); if (dm < 110) { n.x -= dxm * .003; n.y -= dym * .003; } }
          for (let i = 0; i < items.length; i++) for (let j = i + 1; j < items.length; j++) { const a = items[i], b = items[j], d = Math.hypot(a.x - b.x, a.y - b.y); if (d < 120) { ctx.strokeStyle = `rgba(255,255,255,${(1 - d / 120) * .35})`; ctx.lineWidth = .5; ctx.beginPath(); ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y); ctx.stroke(); } }
          for (const n of items) { const tw = .5 + Math.sin(t * .9 + n.p) * .4; const near = Math.hypot(mx - n.x, my - n.y) < 110; ctx.beginPath(); ctx.arc(n.x, n.y, n.r * (near ? 1.7 : 1), 0, 7); ctx.fillStyle = `rgba(255,255,255,${near ? .9 : .35 + tw * .4})`; ctx.fill(); }
        } else if (variant === "particles") {
          for (const p of items) { p.y -= p.vy * (.4 + p.z); if (p.y < -4) { p.y = h + 4; p.x = Math.random() * w; } ctx.beginPath(); ctx.arc(p.x + Math.sin(t + p.z * 6) * 5, p.y, .5 + p.z * 1.6, 0, 7); ctx.fillStyle = `rgba(255,255,255,${.12 + p.z * .5})`; ctx.fill(); }
        } else {
          const scan = (t * 55) % (h + 140) - 70;
          for (const c of items) { ctx.strokeStyle = "rgba(255,255,255,0.045)"; ctx.lineWidth = .5; ctx.strokeRect(c.x, c.y, c.cell, c.cell); if (c.on) { const pulse = .18 + Math.sin(t * 1.8 + c.s * 8) * .12; let a = pulse; const dist = Math.abs(c.y - scan); if (dist < 50) a = Math.min(1, pulse + (1 - dist / 50) * .7); ctx.fillStyle = `rgba(255,255,255,${a})`; ctx.fillRect(c.x + c.cell * .28, c.y + c.cell * .28, c.cell * .44, c.cell * .44); } }
          ctx.fillStyle = "rgba(255,255,255,0.4)"; ctx.fillRect(0, scan, w, 1);
        }
      },
      cleanup() { canvas.removeEventListener("mousemove", mm); canvas.removeEventListener("mouseleave", ml); },
    };
  }, [variant]);
  return (
    <div style={{ position: "relative", minHeight: height, marginBottom: 28, border: "1px solid rgba(255,255,255,0.12)", overflow: "visible", background: "#050506" }}>
      <div style={{ position: "absolute", inset: 0, overflow: "hidden", pointerEvents: "none" }}>
        <canvas ref={ref} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", filter: "grayscale(1) contrast(1.1)", pointerEvents: "auto", opacity: vidOn ? 0 : 1, transition: "opacity .6s ease" }} />
        {video && <VideoBackdrop src={video} overlay={false} onReady={() => setVidOn(true)} onFail={() => setVidOn(false)} />}
        <div style={{ position: "absolute", inset: 0, background: "linear-gradient(90deg,#000 8%,rgba(0,0,0,.35) 55%,rgba(0,0,0,.7) 100%)" }} />
      </div>
      {/* Real document flow: text block and actions share a wrapping row —
          actions drop BELOW the text when space runs out, never over it. */}
      <div style={{ position: "relative", zIndex: 2, minHeight: height, boxSizing: "border-box", display: "flex", alignItems: "center", justifyContent: "space-between", gap: "14px 28px", flexWrap: "wrap", padding: "20px 32px" }}>
        <div style={{ flex: "1 1 380px", minWidth: 260 }}>
          {label && <div style={{ fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".22em", textTransform: "uppercase", color: "#a4a4a0", display: "flex", alignItems: "center", gap: 12, marginBottom: 12 }}><span style={{ width: 32, height: 1, background: "#a4a4a0" }} />{label}</div>}
          {title && <h2 style={{ fontFamily: "var(--f)", fontWeight: 300, fontSize: "clamp(30px,4vw,48px)", lineHeight: 1, letterSpacing: "-.02em", color: "#fff", margin: 0 }}>{title}</h2>}
          {sub && <p style={{ fontSize: 13.5, color: "#bcbcb8", fontFamily: "var(--s)", margin: "10px 0 0", maxWidth: 640, lineHeight: 1.55 }}>{sub}</p>}
        </div>
        {right && <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "flex-end", alignItems: "center", flex: "0 1 auto", maxWidth: "100%" }}>{right}</div>}
      </div>
    </div>
  );
}

// ── Optional self-hosted video backdrops ──────────────────────────────
// Drop royalty-free B&W-friendly clips (Coverr/Pexels/Mixkit) into /public:
//   /hero.mp4          — home hero (full-bleed)
//   /banner-home.mp4   — home "Live intelligence" band
//   /banner-saft.mp4   — SAF-T / Compliance Engine header
//   /banner-agents.mp4 — Agents header
//   /banner-kpi.mp4    — KPI header
//   /banner-intel.mp4  — Intelligence Command Center header
//   /banner-logs.mp4   — Audit Log header
// Missing files are harmless: each spot keeps its canvas animation.
// Video is muted+looped+playsInline, lazy (preload metadata), paused when
// off-screen, and disabled under prefers-reduced-motion — so it never hurts
// performance. `src` defaults to "/hero.mp4".
function VideoBackdrop({ src = "/hero.mp4", fallback = null, overlay = true, onReady, onFail }) {
  const vref = useRef(null);
  const [ok, setOk] = useState(true);
  useEffect(() => {
    const v = vref.current; if (!v) return;
    if (prefersReducedMotion()) { try { v.pause(); } catch {} return; }
    const io = new IntersectionObserver((es) => { if (!v) return; if (es[0].isIntersecting) { v.play().catch(() => {}); } else { try { v.pause(); } catch {} } }, { threshold: 0.01 });
    io.observe(v);
    return () => io.disconnect();
  }, []);
  if (!ok) return fallback;
  return (
    <>
      <video ref={vref} muted loop playsInline preload="metadata" onLoadedData={() => { if (onReady) onReady(); }} onError={() => { setOk(false); if (onFail) onFail(); }}
        style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", filter: "grayscale(1) contrast(1.12) brightness(.85)" }}>
        <source src={src} type="video/mp4" onError={() => { setOk(false); if (onFail) onFail(); }} />
      </video>
      {overlay && <div style={{ position: "absolute", inset: 0, background: "radial-gradient(120% 120% at 75% 25%, rgba(0,0,0,.15), rgba(0,0,0,.6) 70%, #000)", pointerEvents: "none" }} />}
    </>
  );
}

// Full-bleed cinematic network backdrop for the home hero (B&W, cursor-reactive, auto-pausing).
function HomeHeroCanvas() {
  const ref = useRef(null);
  useCanvasAnim(ref, ({ ctx, canvas }) => {
    let nodes = [], mx = -999, my = -999;
    const mm = e => { const r = canvas.getBoundingClientRect(); mx = e.clientX - r.left; my = e.clientY - r.top; };
    const ml = () => { mx = -999; my = -999; };
    canvas.addEventListener("mousemove", mm); canvas.addEventListener("mouseleave", ml);
    return {
      init() { const w = canvas.clientWidth, h = canvas.clientHeight; nodes = []; const n = Math.min(80, Math.round(w / 20)); for (let i = 0; i < n; i++) nodes.push({ x: Math.random() * w, y: Math.random() * h, vx: (Math.random() - .5) * .28, vy: (Math.random() - .5) * .28, r: Math.random() * 1.6 + .6, p: Math.random() * 6.28 }); },
      frame(tf) {
        const w = canvas.clientWidth, h = canvas.clientHeight; const t = tf * 0.016; ctx.clearRect(0, 0, w, h);
        for (const nd of nodes) { nd.x += nd.vx; nd.y += nd.vy; if (nd.x < 0 || nd.x > w) nd.vx *= -1; if (nd.y < 0 || nd.y > h) nd.vy *= -1; const dxm = mx - nd.x, dym = my - nd.y, dm = Math.hypot(dxm, dym); if (dm < 130) { nd.x -= dxm * .004; nd.y -= dym * .004; } }
        for (let i = 0; i < nodes.length; i++) for (let j = i + 1; j < nodes.length; j++) { const a = nodes[i], b = nodes[j], d = Math.hypot(a.x - b.x, a.y - b.y); if (d < 150) { ctx.strokeStyle = `rgba(255,255,255,${(1 - d / 150) * .4})`; ctx.lineWidth = .55; ctx.beginPath(); ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y); ctx.stroke(); } }
        for (const nd of nodes) { const tw = .5 + Math.sin(t + nd.p) * .4; const near = Math.hypot(mx - nd.x, my - nd.y) < 130; ctx.beginPath(); ctx.arc(nd.x, nd.y, nd.r * (near ? 1.8 : 1), 0, 7); ctx.fillStyle = `rgba(255,255,255,${near ? .95 : .35 + tw * .45})`; ctx.fill(); }
      },
      cleanup() { canvas.removeEventListener("mousemove", mm); canvas.removeEventListener("mouseleave", ml); },
    };
  }, []);
  return <canvas ref={ref} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", filter: "grayscale(1) contrast(1.08)" }} />;
}


// ═══════════════════════════════════════════════════
// MAIN APP
// ═══════════════════════════════════════════════════
// Animated count-up number for the home hero (respects reduced-motion)
function CountUp({ to, dur = 1500, suffix = "" }) {
  const [n, setN] = useState(0);
  useEffect(() => {
    if (typeof prefersReducedMotion === "function" && prefersReducedMotion()) { setN(to); return; }
    let raf, start;
    const tick = (ts) => {
      if (!start) start = ts;
      const p = Math.min(1, (ts - start) / dur);
      const eased = 1 - Math.pow(1 - p, 3);
      setN(Math.round(to * eased));
      if (p < 1) raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [to, dur]);
  return <>{n}{suffix}</>;
}

// ────────────────────────────────────────────────────────────────────
// KPI DASHBOARD — benchmarked, goal-aware, easy to read.
// Each metric shows its value, position within the sector band (a gauge),
// the sector median, an editable target, and a plain-language verdict.
// ────────────────────────────────────────────────────────────────────
// ─── ADVANCED ANALYTICS BOARD (12-month graphical layer) ─────────────
// Renders below the KPI cards. Every series comes from computeMonthlySeries —
// real calendar months of the fiscal year, credit-note-aware, zero-padded.
const CHT = {
  grid: "rgba(255,255,255,0.07)", axis: "#8c8c88", font: 10,
  rev: "#7cc4ff", pur: "#9a8cff", gross: "#69db7c", neg: "#ff8a8a",
  outV: "#ffd43b", inV: "#74c0fc", net: "#fff", pay: "#63e6be",
  sev: { Critical: "#ff6b6b", High: "#ffa94d", Medium: "#ffd43b", Low: "#69db7c" },
};
function TaxaiTip({ active, payload, label, lang, money }) {
  if (!active || !payload || !payload.length) return null;
  return <div style={{ background: "#0b0b0d", border: "1px solid rgba(255,255,255,0.25)", padding: "9px 12px", fontFamily: "var(--m)", fontSize: 11, boxShadow: "0 6px 18px rgba(0,0,0,0.6)" }}>
    <div style={{ color: "#fff", fontWeight: 700, marginBottom: 5, letterSpacing: ".04em" }}>{label}</div>
    {payload.map((p, i) => p.value == null ? null : <div key={i} style={{ color: p.color || "#d2d2ce", padding: "1px 0" }}>
      <span style={{ display: "inline-block", width: 8, height: 8, background: p.color, marginRight: 7 }} />
      {p.name}: <b style={{ color: "#fff" }}>{money === false ? Number(p.value).toLocaleString() : "€" + Number(p.value).toLocaleString(undefined, { maximumFractionDigits: 0 })}</b>
    </div>)}
  </div>;
}
function ChartCard({ title, sub, h = 240, children, span }) {
  const PL_LINE = "rgba(255,255,255,0.12)";
  return <div style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", padding: "14px 16px 8px", gridColumn: span ? "1 / -1" : undefined }}>
    <div style={{ fontSize: 10, color: "#bcbcb8", fontFamily: "var(--m)", textTransform: "uppercase", letterSpacing: ".1em", marginBottom: 2 }}>{title}</div>
    {sub && <div style={{ fontSize: 9.5, color: "#7a7a76", fontFamily: "var(--m)", marginBottom: 6 }}>{sub}</div>}
    <div style={{ width: "100%", height: h }}>{children}</div>
  </div>;
}
function KpiAnalyticsBoard({ lang, parsed, findings, supplierBalances }) {
  const PL_LINE = "rgba(255,255,255,0.12)";
  const L = (en, lt) => (lang === "lt" ? lt : en);
  const ms = useMemo(() => { try { return parsed ? computeMonthlySeries(parsed) : null; } catch { return null; } }, [parsed]);
  const [tableOpen, setTableOpen] = useState(false);
  if (!ms) return null;
  const data = ms.months.map((r) => ({ ...r, name: monthLabel(r.ym, lang) }));
  const axis = { stroke: CHT.axis, fontSize: CHT.font, fontFamily: "var(--m)", tickLine: false, axisLine: { stroke: CHT.grid } };
  const sevAgg = (() => { const a = { Critical: 0, High: 0, Medium: 0, Low: 0 }; (findings || []).forEach((f) => { if (a[f.severity] != null) a[f.severity]++; }); return Object.entries(a).filter(([, v]) => v > 0).map(([k, v]) => ({ name: k, value: v })); })();
  const supTop = (supplierBalances || []).slice(0, 5).map((s) => ({ name: (s.name || s.id || "—").slice(0, 22), value: Math.round(s.bal) }));
  const heat = (() => { const max = Math.max(1, ...data.map((r) => r.glCount + r.salesCount + r.purchaseCount + r.payCount)); return data.map((r) => ({ ym: r.ym, name: r.name, n: r.glCount + r.salesCount + r.purchaseCount + r.payCount, a: (r.glCount + r.salesCount + r.purchaseCount + r.payCount) / max })); })();
  const lgd = { wrapperStyle: { fontSize: 10, fontFamily: "var(--m)", color: "#8c8c88" } };
  return <div style={{ marginTop: 28 }}>
    <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 6, flexWrap: "wrap" }}>
      <div style={{ fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", display: "flex", alignItems: "center", gap: 10 }}><span style={{ width: 22, height: 1, background: "#8c8c88" }} />{L("Analytics — 12 months", "Analitika — 12 mėnesių")}</div>
      <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#7cc4ff", border: "1px solid rgba(124,196,255,0.4)", padding: "3px 9px" }}>{ms.window.from} → {ms.window.to}</span>
      <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88" }}>{L("active months", "aktyvūs mėnesiai")}: {ms.activeMonths}/12{ms.peakMonth ? ` · ${L("peak", "pikas")}: ${ms.peakMonth}` : ""}</span>
    </div>
    {/* activity heat strip */}
    <div style={{ display: "grid", gridTemplateColumns: "repeat(12,1fr)", gap: 3, marginBottom: 14 }}>
      {heat.map((h2) => <div key={h2.ym} title={`${h2.ym} · ${h2.n} ${L("records", "įrašų")}`} style={{ height: 26, background: h2.n ? `rgba(124,196,255,${0.12 + 0.7 * h2.a})` : "rgba(255,255,255,0.04)", border: `1px solid ${PL_LINE}`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "var(--m)", fontSize: 8, color: h2.a > 0.5 ? "#000" : "#8c8c88", cursor: "default" }}>{h2.name.split(" ")[0]}</div>)}
    </div>
    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(420px,1fr))", gap: 12 }}>
      <ChartCard title={L("Revenue vs purchases by month", "Pajamos ir pirkimai pagal mėnesį")} sub={L("Σ invoice net per real document month · credit notes subtract · line = gross result", "Σ sąskaitų neto pagal realų dokumento mėnesį · kreditinės atimamos · linija = bendrasis rezultatas")} span>
        <ResponsiveContainer>
          <ComposedChart data={data} margin={{ top: 8, right: 8, left: 0, bottom: 0 }}>
            <CartesianGrid stroke={CHT.grid} vertical={false} />
            <XAxis dataKey="name" {...axis} interval={0} />
            <YAxis {...axis} tickFormatter={eurShort} width={52} />
            <Tooltip content={<TaxaiTip lang={lang} />} cursor={{ fill: "rgba(255,255,255,0.04)" }} />
            <Legend {...lgd} />
            <ReferenceLine y={0} stroke="rgba(255,255,255,0.25)" />
            <Bar dataKey="revenue" name={L("Revenue", "Pajamos")} fill={CHT.rev} maxBarSize={26} />
            <Bar dataKey="purchases" name={L("Purchases", "Pirkimai")} fill={CHT.pur} maxBarSize={26} />
            <Line type="monotone" dataKey="grossResult" name={L("Gross result", "Bendrasis rezultatas")} stroke={CHT.gross} strokeWidth={2} dot={{ r: 2.5 }} />
          </ComposedChart>
        </ResponsiveContainer>
      </ChartCard>
      <ChartCard title={L("VAT position by month", "PVM pozicija pagal mėnesį")} sub={L("output vs deductible input VAT · white line = net payable to VMI", "pardavimo ir atskaitomas pirkimo PVM · balta linija = mokėtina VMI")}>
        <ResponsiveContainer>
          <ComposedChart data={data} margin={{ top: 8, right: 8, left: 0, bottom: 0 }}>
            <CartesianGrid stroke={CHT.grid} vertical={false} />
            <XAxis dataKey="name" {...axis} interval={1} />
            <YAxis {...axis} tickFormatter={eurShort} width={52} />
            <Tooltip content={<TaxaiTip lang={lang} />} />
            <Legend {...lgd} />
            <Area type="monotone" dataKey="outputVat" name={L("Output VAT", "Pardavimo PVM")} stroke={CHT.outV} fill={CHT.outV} fillOpacity={0.18} strokeWidth={1.5} />
            <Area type="monotone" dataKey="inputVat" name={L("Input VAT", "Pirkimo PVM")} stroke={CHT.inV} fill={CHT.inV} fillOpacity={0.18} strokeWidth={1.5} />
            <Line type="monotone" dataKey="netVat" name={L("Net VAT", "Mokėtinas PVM")} stroke={CHT.net} strokeWidth={2} dot={false} />
            <ReferenceLine y={0} stroke="rgba(255,255,255,0.25)" />
          </ComposedChart>
        </ResponsiveContainer>
      </ChartCard>
      <ChartCard title={L("Cumulative result & cash flow proxy", "Kaupiamasis rezultatas ir pinigų srautas")} sub={L("running Σ(revenue−purchases) · payments in/out from SAF-T Payments", "kaupiama Σ(pajamos−pirkimai) · mokėjimai iš SAF-T Payments")}>
        <ResponsiveContainer>
          <ComposedChart data={data} margin={{ top: 8, right: 8, left: 0, bottom: 0 }}>
            <CartesianGrid stroke={CHT.grid} vertical={false} />
            <XAxis dataKey="name" {...axis} interval={1} />
            <YAxis {...axis} tickFormatter={eurShort} width={52} />
            <Tooltip content={<TaxaiTip lang={lang} />} />
            <Legend {...lgd} />
            <Bar dataKey="payIn" name={L("Payments in", "Įplaukos")} fill={CHT.pay} maxBarSize={18} />
            <Bar dataKey="payOut" name={L("Payments out", "Išmokos")} fill={CHT.neg} maxBarSize={18} />
            <Line type="monotone" dataKey="cumResult" name={L("Cumulative result", "Kaupiamasis rezultatas")} stroke={CHT.gross} strokeWidth={2} dot={false} />
            <ReferenceLine y={0} stroke="rgba(255,255,255,0.25)" />
          </ComposedChart>
        </ResponsiveContainer>
      </ChartCard>
      <ChartCard title={L("Document & posting volumes", "Dokumentų ir įrašų apimtys")} sub={L("counts per month — sales/purchase invoices, GL transactions, payments", "kiekiai per mėnesį — pardavimo/pirkimo SF, DK operacijos, mokėjimai")}>
        <ResponsiveContainer>
          <BarChart data={data} margin={{ top: 8, right: 8, left: 0, bottom: 0 }}>
            <CartesianGrid stroke={CHT.grid} vertical={false} />
            <XAxis dataKey="name" {...axis} interval={1} />
            <YAxis {...axis} width={40} allowDecimals={false} />
            <Tooltip content={<TaxaiTip lang={lang} money={false} />} cursor={{ fill: "rgba(255,255,255,0.04)" }} />
            <Legend {...lgd} />
            <Bar dataKey="salesCount" name={L("Sales inv.", "Pardavimo SF")} stackId="v" fill={CHT.rev} maxBarSize={22} />
            <Bar dataKey="purchaseCount" name={L("Purchase inv.", "Pirkimo SF")} stackId="v" fill={CHT.pur} maxBarSize={22} />
            <Bar dataKey="glCount" name={L("GL transactions", "DK operacijos")} stackId="v" fill="rgba(255,255,255,0.35)" maxBarSize={22} />
            <Bar dataKey="payCount" name={L("Payments", "Mokėjimai")} stackId="v" fill={CHT.pay} maxBarSize={22} />
          </BarChart>
        </ResponsiveContainer>
      </ChartCard>
      <ChartCard title={L("GL debit/credit turnover", "DK debeto/kredito apyvarta")} sub={L("monthly Σ of all journal lines — symmetry confirms double entry", "mėnesio Σ visų žurnalo eilučių — simetrija patvirtina dvejybinį įrašą")}>
        <ResponsiveContainer>
          <LineChart data={data} margin={{ top: 8, right: 8, left: 0, bottom: 0 }}>
            <CartesianGrid stroke={CHT.grid} vertical={false} />
            <XAxis dataKey="name" {...axis} interval={1} />
            <YAxis {...axis} tickFormatter={eurShort} width={52} />
            <Tooltip content={<TaxaiTip lang={lang} />} />
            <Legend {...lgd} />
            <Line type="monotone" dataKey="glDebit" name={L("Debit Σ", "Debetas Σ")} stroke={CHT.rev} strokeWidth={2} dot={false} />
            <Line type="monotone" dataKey="glCredit" name={L("Credit Σ", "Kreditas Σ")} stroke={CHT.outV} strokeWidth={2} strokeDasharray="5 3" dot={false} />
          </LineChart>
        </ResponsiveContainer>
      </ChartCard>
      {(sevAgg.length > 0 || supTop.length > 0) && <ChartCard title={L("Findings mix · supplier concentration", "Radinių sudėtis · tiekėjų koncentracija")} sub={L("left: engine findings by severity · right: top-5 payable balances", "kairėje: variklio radiniai pagal reikšmingumą · dešinėje: top-5 mokėtini likučiai")}>
        <div style={{ display: "flex", height: "100%" }}>
          <div style={{ flex: 1, minWidth: 0 }}>
            <ResponsiveContainer>
              <PieChart>
                <Pie data={sevAgg} dataKey="value" nameKey="name" innerRadius="52%" outerRadius="78%" paddingAngle={2} stroke="#0b0b0d">
                  {sevAgg.map((s, i) => <Cell key={i} fill={CHT.sev[s.name] || "#888"} />)}
                </Pie>
                <Tooltip content={<TaxaiTip lang={lang} money={false} />} />
                <Legend {...lgd} verticalAlign="bottom" />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div style={{ flex: 1.3, minWidth: 0 }}>
            <ResponsiveContainer>
              <BarChart data={supTop} layout="vertical" margin={{ top: 4, right: 12, left: 4, bottom: 0 }}>
                <CartesianGrid stroke={CHT.grid} horizontal={false} />
                <XAxis type="number" {...axis} tickFormatter={eurShort} />
                <YAxis type="category" dataKey="name" {...axis} width={120} />
                <Tooltip content={<TaxaiTip lang={lang} />} cursor={{ fill: "rgba(255,255,255,0.04)" }} />
                <Bar dataKey="value" name={L("Payable balance", "Mokėtinas likutis")} fill={CHT.pur} maxBarSize={14} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </ChartCard>}
    </div>
    {/* exact monthly figures */}
    <div style={{ marginTop: 12, border: `1px solid ${PL_LINE}`, background: "var(--bg2)" }}>
      <button onClick={() => setTableOpen((o) => !o)} style={{ width: "100%", textAlign: "left", background: "transparent", border: "none", color: "#bcbcb8", fontFamily: "var(--m)", fontSize: 10, textTransform: "uppercase", letterSpacing: ".1em", padding: "11px 16px", cursor: "pointer" }}>{tableOpen ? "▾ " : "▸ "}{L("Exact monthly figures (12 × full ledger)", "Tikslūs mėnesio skaičiai (12 × visa knyga)")}</button>
      {tableOpen && <div style={{ overflowX: "auto", padding: "0 8px 10px" }}>
        <table style={{ width: "100%", borderCollapse: "collapse", fontFamily: "var(--m)", fontSize: 10.5 }}>
          <thead><tr>{[L("Month", "Mėnuo"), L("Revenue", "Pajamos"), L("Purchases", "Pirkimai"), L("Gross", "Rezultatas"), L("Cumulative", "Kaupiamasis"), L("Output VAT", "Pard. PVM"), L("Input VAT", "Pirk. PVM"), L("Net VAT", "Mokėtinas"), "SF↑", "SF↓", "GL", L("Pay in", "Įplaukos"), L("Pay out", "Išmokos")].map((h2, i) => <th key={i} style={{ textAlign: i ? "right" : "left", padding: "7px 9px", color: "#8c8c88", borderBottom: `1px solid ${PL_LINE}`, fontWeight: 600, whiteSpace: "nowrap" }}>{h2}</th>)}</tr></thead>
          <tbody>
            {data.map((r) => <tr key={r.ym}>
              <td style={{ padding: "5px 9px", color: "#fff", borderBottom: "1px solid rgba(255,255,255,0.05)", whiteSpace: "nowrap" }}>{r.ym}</td>
              {[r.revenue, r.purchases, r.grossResult, r.cumResult, r.outputVat, r.inputVat, r.netVat].map((v, i) => <td key={i} style={{ padding: "5px 9px", textAlign: "right", color: i === 2 || i === 3 ? (v < 0 ? CHT.neg : CHT.gross) : "#d2d2ce", borderBottom: "1px solid rgba(255,255,255,0.05)" }}>{Number(v).toLocaleString()}</td>)}
              {[r.salesCount, r.purchaseCount, r.glCount].map((v, i) => <td key={"c" + i} style={{ padding: "5px 9px", textAlign: "right", color: "#8c8c88", borderBottom: "1px solid rgba(255,255,255,0.05)" }}>{v}</td>)}
              {[r.payIn, r.payOut].map((v, i) => <td key={"p" + i} style={{ padding: "5px 9px", textAlign: "right", color: "#d2d2ce", borderBottom: "1px solid rgba(255,255,255,0.05)" }}>{Number(v).toLocaleString()}</td>)}
            </tr>)}
            <tr>
              <td style={{ padding: "7px 9px", color: "#fff", fontWeight: 700 }}>Σ</td>
              {[ms.totals.revenue, ms.totals.purchases, ms.totals.grossResult, "", ms.totals.outputVat, ms.totals.inputVat, ms.totals.netVat].map((v, i) => <td key={i} style={{ padding: "7px 9px", textAlign: "right", color: "#fff", fontWeight: 700 }}>{v === "" ? "" : Number(v).toLocaleString()}</td>)}
              {[ms.totals.salesCount, ms.totals.purchaseCount, ""].map((v, i) => <td key={"c" + i} style={{ padding: "7px 9px", textAlign: "right", color: "#fff", fontWeight: 700 }}>{v === "" ? "" : v}</td>)}
              {[ms.totals.payIn, ms.totals.payOut].map((v, i) => <td key={"p" + i} style={{ padding: "7px 9px", textAlign: "right", color: "#fff", fontWeight: 700 }}>{Number(v).toLocaleString()}</td>)}
            </tr>
          </tbody>
        </table>
        <div style={{ fontSize: 9.5, color: "#7a7a76", fontFamily: "var(--s)", padding: "8px 9px 0", lineHeight: 1.5 }}>{ms.derivation}</div>
      </div>}
    </div>
  </div>;
}

function KpiDashboard({ lang, kpis, sector, setSector, targets, setTarget, parsed, findings, supplierBalances }) {
  const PL_LINE = "rgba(255,255,255,0.12)", PL_SOFT = "rgba(255,255,255,0.06)";
  const L = (en, lt) => (lang === "lt" ? lt : en);
  const [editing, setEditing] = useState(null);
  const [draft, setDraft] = useState("");
  if (!kpis) return null;

  const TIER = {
    best:  { c: "#69db7c", en: "Top of range", lt: "Diapazono viršuje" },
    good:  { c: "#9ae6a4", en: "Above median", lt: "Virš medianos" },
    watch: { c: "#ffd43b", en: "Below median", lt: "Žemiau medianos" },
    poor:  { c: "#ff8a8a", en: "Off benchmark", lt: "Už ribų" },
  };
  const TGT = {
    met:  { c: "#69db7c", en: "On target", lt: "Pasiektas tikslas" },
    near: { c: "#ffd43b", en: "Near target", lt: "Beveik tikslas" },
    off:  { c: "#ff8a8a", en: "Off target", lt: "Nepasiektas" },
  };
  const summary = summarizeKpis(kpis, sector, targets);

  const startEdit = (key) => { setEditing(key); setDraft(targets[key] != null ? String(targets[key]) : ""); };
  const commit = (key) => { const v = parseFloat(draft.replace(",", ".")); setTarget(key, isNaN(v) ? null : v); setEditing(null); };

  // gauge: low─median─high track, company marker, optional target flag
  const Gauge = ({ s, meta }) => {
    if (!s.band || !s.inBand) return <div style={{ height: 28 }} />;
    const tier = TIER[s.inBand.tier];
    const pos = Math.round(s.inBand.pos * 100);
    const medPos = Math.round(((s.band.median - s.band.low) / ((s.band.high - s.band.low) || 1)) * 100);
    let tgtPos = null;
    if (s.target != null) tgtPos = Math.round(Math.max(0, Math.min(1, (s.target - s.band.low) / ((s.band.high - s.band.low) || 1))) * 100);
    return (
      <div style={{ marginTop: 10 }}>
        <div style={{ position: "relative", height: 6, background: "rgba(255,255,255,0.07)", borderRadius: 3 }}>
          {/* favorable side shading omitted for clarity; median tick + markers below */}
          <div style={{ position: "absolute", left: `calc(${medPos}% - 1px)`, top: -3, width: 2, height: 12, background: "rgba(255,255,255,0.4)" }} title={L("sector median", "sektoriaus mediana")} />
          {tgtPos != null && <div style={{ position: "absolute", left: `calc(${tgtPos}% - 5px)`, top: -10, fontSize: 9, color: "#7cc4ff" }} title={L("your target", "jūsų tikslas")}>▼</div>}
          <div style={{ position: "absolute", left: `calc(${pos}% - 5px)`, top: -3.5, width: 11, height: 11, borderRadius: "50%", background: tier.c, border: "2px solid #0b0b0d", boxShadow: `0 0 0 1px ${tier.c}` }} />
        </div>
        <div style={{ display: "flex", justifyContent: "space-between", marginTop: 5, fontSize: 9, color: "#7a7a76", fontFamily: "var(--m)" }}>
          <span>{formatKpi(s.band.low, meta.fmt)}</span>
          <span>{L("med", "med")} {formatKpi(s.band.median, meta.fmt)}</span>
          <span>{formatKpi(s.band.high, meta.fmt)}</span>
        </div>
      </div>
    );
  };

  return (
    <div>
      {/* header */}
      <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 16, flexWrap: "wrap" }}>
        <div style={{ fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", display: "flex", alignItems: "center", gap: 10 }}><span style={{ width: 22, height: 1, background: "#8c8c88" }} />{L("KPI Intelligence", "KPI žvalgyba")}</div>
        <div style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontSize: 10, color: "#8c8c88", fontFamily: "var(--m)", textTransform: "uppercase", letterSpacing: ".08em" }}>{L("Benchmark sector", "Lyginimo sektorius")}</span>
          <select value={sector} onChange={(e) => setSector(e.target.value)} style={{ background: "var(--bg2)", color: "#fff", border: `1px solid ${PL_LINE}`, fontFamily: "var(--m)", fontSize: 12, padding: "6px 10px", cursor: "pointer" }}>
            {availableSectors().map((s) => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
      </div>

      {/* summary band */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(150px,1fr))", borderTop: `1px solid ${PL_LINE}`, borderLeft: `1px solid ${PL_LINE}`, marginBottom: 22 }}>
        {[
          [L("At or above median", "Ties mediana ar virš"), `${summary.aboveMedian}/${summary.benched}`, summary.aboveMedian >= summary.benched / 2 ? "#69db7c" : "#ffd43b"],
          [L("Targets met", "Pasiekti tikslai"), summary.targetsSet ? `${summary.targetsMet}/${summary.targetsSet}` : "—", summary.targetsSet && summary.targetsMet === summary.targetsSet ? "#69db7c" : "#ffd43b"],
          [L("Benchmarked KPIs", "Lyginami KPI"), String(summary.benched), "#fff"],
          [L("Targets set", "Nustatyti tikslai"), String(summary.targetsSet), "#7cc4ff"],
        ].map(([k, v, c], i) =>
          <div key={i} style={{ padding: "16px 18px", borderRight: `1px solid ${PL_LINE}`, borderBottom: `1px solid ${PL_LINE}` }}>
            <div style={{ fontSize: 9, color: "#8c8c88", fontFamily: "var(--m)", textTransform: "uppercase", letterSpacing: ".08em", marginBottom: 8 }}>{k}</div>
            <div style={{ fontSize: 26, fontWeight: 300, fontFamily: "var(--f)", color: c }}>{v}</div>
          </div>)}
      </div>

      {/* category groups */}
      {KPI_CATS.map((cat) => {
        const metas = KPI_META.filter((m) => m.cat === cat.key);
        if (!metas.length) return null;
        return <div key={cat.key} style={{ marginBottom: 22 }}>
          <div style={{ fontSize: 10, color: "#fff", fontFamily: "var(--m)", fontWeight: 700, textTransform: "uppercase", letterSpacing: ".14em", marginBottom: 10 }}>{L(cat.en, cat.lt)}</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(280px,1fr))", gap: 12 }}>
            {metas.map((meta) => {
              const s = scoreKpi(meta, kpis, sector, targets);
              const tier = s.inBand ? TIER[s.inBand.tier] : null;
              const tgt = s.targetStatus ? TGT[s.targetStatus] : null;
              return <div key={meta.key} style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", padding: "14px 16px", display: "flex", flexDirection: "column" }}>
                <div style={{ display: "flex", alignItems: "flex-start", gap: 8 }}>
                  <div style={{ fontSize: 10.5, color: "#bcbcb8", fontFamily: "var(--m)", textTransform: "uppercase", letterSpacing: ".06em", flex: 1 }}>{L(meta.en, meta.lt)}</div>
                  {tier && <span style={{ fontSize: 8.5, fontFamily: "var(--m)", fontWeight: 700, color: tier.c, border: `1px solid ${tier.c}`, borderRadius: 3, padding: "1px 6px", textTransform: "uppercase", whiteSpace: "nowrap" }}>{L(tier.en, tier.lt)}</span>}
                </div>
                <div style={{ fontSize: 30, fontWeight: 300, color: "#fff", fontFamily: "var(--f)", lineHeight: 1.1, marginTop: 6 }}>{formatKpi(s.val, meta.fmt)}</div>
                <Gauge s={s} meta={meta} />
                {/* target row */}
                <div style={{ marginTop: 12, paddingTop: 10, borderTop: `1px solid ${PL_SOFT}`, display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
                  {editing === meta.key ? <>
                    <input autoFocus value={draft} onChange={(e) => setDraft(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") commit(meta.key); if (e.key === "Escape") setEditing(null); }} placeholder={L("target", "tikslas")} style={{ width: 70, background: "#000", border: `1px solid #7cc4ff`, color: "#fff", fontFamily: "var(--m)", fontSize: 12, padding: "4px 8px", outline: "none" }} />
                    <button onClick={() => commit(meta.key)} style={{ background: "#7cc4ff", color: "#000", border: "none", fontFamily: "var(--m)", fontSize: 9.5, fontWeight: 700, padding: "4px 9px", cursor: "pointer", textTransform: "uppercase" }}>{L("Set", "Nustatyti")}</button>
                    {targets[meta.key] != null && <button onClick={() => { setTarget(meta.key, null); setEditing(null); }} style={{ background: "none", color: "#8c8c88", border: "none", fontFamily: "var(--m)", fontSize: 9.5, cursor: "pointer", textTransform: "uppercase" }}>{L("Clear", "Išvalyti")}</button>}
                  </> : <>
                    {s.target != null ? <>
                      <span style={{ fontSize: 10.5, color: "#bcbcb8", fontFamily: "var(--m)" }}>{L("Target", "Tikslas")}: <span style={{ color: "#7cc4ff" }}>{formatKpi(s.target, meta.fmt)}</span></span>
                      {tgt && <span style={{ fontSize: 8.5, fontFamily: "var(--m)", fontWeight: 700, color: tgt.c, border: `1px solid ${tgt.c}`, borderRadius: 3, padding: "1px 6px", textTransform: "uppercase" }}>{L(tgt.en, tgt.lt)}{s.targetPct != null ? ` · ${s.targetPct}%` : ""}</span>}
                      <button onClick={() => startEdit(meta.key)} style={{ marginLeft: "auto", background: "none", color: "#8c8c88", border: "none", fontFamily: "var(--m)", fontSize: 9.5, cursor: "pointer", textTransform: "uppercase" }}>{L("Edit", "Keisti")}</button>
                    </> : <button onClick={() => startEdit(meta.key)} style={{ background: "none", color: "#7cc4ff", border: `1px dashed rgba(124,196,255,0.4)`, borderRadius: 3, fontFamily: "var(--m)", fontSize: 9.5, fontWeight: 600, padding: "4px 10px", cursor: "pointer", textTransform: "uppercase" }}>+ {L("Set a goal", "Nustatyti tikslą")}</button>}
                  </>}
                </div>
              </div>;
            })}
          </div>
        </div>;
      })}

      <div style={{ marginTop: 8, fontSize: 10.5, color: "#7a7a76", fontFamily: "var(--s)", lineHeight: 1.55 }}>
        {L("Benchmark bands are illustrative baselines per sector and should be replaced with your own aggregated data; the value, median tick, and your target (▼) are shown on each gauge. Figures are accounting approximations — verify against the filed statements.",
           "Lyginimo diapazonai yra orientaciniai pagal sektorių ir turėtų būti pakeisti jūsų agreguotais duomenimis; reikšmė, medianos žyma ir jūsų tikslas (▼) rodomi kiekvienoje skalėje. Skaičiai yra apskaitos aproksimacijos — patikrinkite su pateiktomis ataskaitomis.")}
      </div>

      {/* ── ADVANCED GRAPHICAL LAYER: real 12-month series from the file ── */}
      <KpiAnalyticsBoard lang={lang} parsed={parsed} findings={findings} supplierBalances={supplierBalances} />
    </div>
  );
}

// ────────────────────────────────────────────────────────────────────
// MONTHLY VAT-CLOSE WORKFLOW AGENT
// A multi-step, stateful process with human sign-off gates. It ingests a
// monthly i.SAF, reconciles it against the loaded SAF-T ledger, surfaces
// discrepancies for review, drafts FR0600 notes, and produces a client
// memo. Deterministic numbers stand alone; AI only phrases narrative.
// ────────────────────────────────────────────────────────────────────
function VatCloseWorkflow({ lang, data, kpis, callAI, audit, state, setState, presetIsaf, presetRecon, presetIsafName }) {
  const PL_LINE = "rgba(255,255,255,0.12)", PL_SOFT = "rgba(255,255,255,0.06)";
  const fileRef = useRef(null);
  const [busy, setBusy] = useState(false);
  const L = (en, lt) => (lang === "lt" ? lt : en);
  const bP = { background: "#fff", color: "#000", border: "none", padding: "9px 18px", fontSize: 11, fontWeight: 700, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" };
  const bG = { background: "transparent", color: "#d2d2ce", border: `1px solid ${PL_LINE}`, padding: "9px 16px", fontSize: 11, fontWeight: 600, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" };
  const set = (patch) => setState((s) => ({ ...s, ...patch }));
  const r2 = (n) => Math.round((n || 0) * 100) / 100;
  const eur = (n) => (n || 0).toLocaleString() + " €";

  const STEPS = [
    { key: "ledger", en: "Ledger check", lt: "Knygos patikra" },
    { key: "intake", en: "i.SAF intake", lt: "i.SAF įkėlimas" },
    { key: "reconcile", en: "Reconcile", lt: "Sutikrinimas" },
    { key: "review", en: "Review discrepancies", lt: "Peržiūrėti neatitikimus" },
    { key: "fr0600", en: "FR0600 notes", lt: "FR0600 pastabos" },
    { key: "memo", en: "Client memo", lt: "Kliento atmintinė" },
  ];
  const step = state.step;
  const recon = state.recon;

  // advance helpers
  const goTo = (n) => set({ step: n });
  const ingestISAF = (file) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const parsed = parseISAF(e.target.result);
        if (parsed._parseError) { alert(L("i.SAF parse error: ", "i.SAF klaida: ") + parsed._parseError); return; }
        const rec = reconcileISAF(parsed, data);
        audit?.log?.("WF_VATCLOSE_ISAF", `${file.name} · ${rec.findings.length} findings`);
        set({ isaf: parsed, isafName: file.name, recon: rec, decisions: {}, step: 3 });
      } catch (err) { alert(L("Error: ", "Klaida: ") + err.message); }
    };
    reader.readAsText(file);
  };
  const useExisting = () => {
    if (!presetRecon || !presetIsaf) return;
    set({ isaf: presetIsaf, isafName: presetIsafName || "i.SAF", recon: presetRecon, decisions: {}, step: 3 });
  };

  // FR0600 deterministic figures from the reconciled VAT position
  const fr = recon?.summary?.vat ? (() => {
    const v = recon.summary.vat;
    const corrections = [];
    recon.findings.forEach((f) => {
      if (f.severity === "Block" || f.severity === "Reject") corrections.push({ id: f.id, sev: f.severity, title: f.title });
    });
    return {
      outputLedger: v.outputSAFT, inputLedger: v.inputSAFT, netLedger: v.netSAFT,
      outputISAF: v.outputISAF, inputISAF: v.inputISAF, netISAF: v.netISAF,
      netDelta: v.netDelta, corrections,
    };
  })() : null;

  const reviewDecisions = state.decisions || {};
  const findings = recon?.findings || [];
  const reviewedCount = findings.filter((f) => reviewDecisions[f.id]).length;
  const allReviewed = findings.length === 0 || reviewedCount === findings.length;

  const draftMemo = async () => {
    setBusy(true);
    try {
      const v = recon.summary.vat;
      const period = data?.header?.fiscalYearFrom ? `${data.header.fiscalYearFrom?.slice(0, 10)} → ${data.header.fiscalYearTo?.slice(0, 10)}` : (state.isaf?.header?.periodFrom || "");
      const entity = data?.header?.company?.name || "the entity";
      const decisionsSummary = findings.map((f) => `- [${f.severity}] ${f.title}: ${reviewDecisions[f.id] === "resolved" ? "RESOLVED" : reviewDecisions[f.id] === "accepted" ? "accepted/known" : "open"}`).join("\n");
      const sys = L(
        "You are a tax advisor drafting a concise monthly VAT-close memo for a client. Use ONLY the figures and findings provided. Be practical, professional, and brief. Do not invent numbers. End with a one-line note that this is informational, not legal advice.",
        "Esate mokesčių konsultantas, rengiantis glaustą mėnesinę PVM uždarymo atmintinę klientui. Naudokite TIK pateiktus skaičius ir radinius. Būkite praktiškas, profesionalus ir glaustas. Nesugalvokite skaičių. Pabaigoje pridėkite eilutę, kad tai informacinio pobūdžio informacija, ne teisinė konsultacija."
      );
      const payload = `ENTITY: ${entity}\nPERIOD: ${period}\nVAT POSITION (ledger basis): output ${eur(v.outputSAFT)}, input ${eur(v.inputSAFT)}, net ${eur(v.netSAFT)}\ni.SAF DECLARED: output ${eur(v.outputISAF)}, input ${eur(v.inputISAF)}, net ${eur(v.netISAF)}\nNET DELTA (i.SAF − ledger): ${eur(v.netDelta)}\nDISCREPANCIES (${findings.length}):\n${decisionsSummary || "none"}\n\nWrite: (1) one-paragraph summary of the close, (2) the discrepancies found and their resolution status, (3) the net VAT position and what to file, (4) recommended next actions.`;
      const md = await callAI(sys, payload, []);
      const facts = buildGroundingFacts({ kpis, reconResult: recon });
      const ver = verifyNarrative(md, facts);
      set({ memo: md, memoVer: ver, memoGround: null });
      audit?.log?.("WF_VATCLOSE_MEMO", entity);
    } catch (e) {
      set({ memo: L("Could not draft the memo via AI. The deterministic figures above remain valid; you can write the memo manually.\n\nError: ", "Nepavyko parengti atmintinės per AI. Deterministiniai skaičiai galioja; atmintinę galite parašyti rankiniu būdu.\n\nKlaida: ") + e.message, memoVer: null });
    }
    setBusy(false);
  };

  const reset = () => setState({ step: 0, isaf: null, isafName: "", recon: null, decisions: {}, memo: null, memoVer: null, memoGround: null, closedAt: null });

  // ── render ──
  const ledgerReady = !!(data && data.header);
  const Dot = ({ s }) => <span style={{ width: 10, height: 10, borderRadius: "50%", flexShrink: 0, background: s === "done" ? "#69db7c" : s === "active" ? "#7cc4ff" : "rgba(255,255,255,0.18)", boxShadow: s === "active" ? "0 0 0 4px rgba(124,196,255,0.15)" : "none" }} />;

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 12, flexWrap: "wrap" }}>
        <div style={{ fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", display: "flex", alignItems: "center", gap: 10 }}><span style={{ width: 22, height: 1, background: "#8c8c88" }} />02·H — {L("Monthly VAT Close", "Mėnesinis PVM uždarymas")}</div>
        {state.closedAt && <span style={{ marginLeft: "auto", padding: "5px 12px", border: "1px solid #69db7c", color: "#69db7c", fontSize: 11, fontWeight: 700, fontFamily: "var(--m)" }}>{L("CLOSED", "UŽDARYTA")}</span>}
        {(state.step > 0 || state.closedAt) && <button onClick={reset} style={{ ...bG, marginLeft: state.closedAt ? 0 : "auto" }}>↺ {L("Restart", "Iš naujo")}</button>}
      </div>
      <p style={{ fontSize: 13, color: "#bcbcb8", fontFamily: "var(--s)", marginBottom: 20, lineHeight: 1.65, maxWidth: 820 }}>
        {L("A guided, multi-step close: ingest the monthly i.SAF, reconcile it against the SAF-T ledger, review each discrepancy, then produce FR0600 notes and a client memo. You sign off at each gate; the figures are computed deterministically.",
           "Vedamas, kelių žingsnių uždarymas: įkelkite mėnesinį i.SAF, sutikrinkite su SAF-T knyga, peržiūrėkite kiekvieną neatitikimą, parenkite FR0600 pastabas ir kliento atmintinę. Jūs patvirtinate kiekviename žingsnyje; skaičiai apskaičiuojami deterministiškai.")}
      </p>

      {/* stepper */}
      <div style={{ display: "flex", gap: 0, marginBottom: 22, flexWrap: "wrap", border: `1px solid ${PL_LINE}`, borderRadius: 2 }}>
        {STEPS.map((s, i) => {
          const status = state.closedAt ? "done" : i < step ? "done" : i === step ? "active" : "todo";
          return <div key={s.key} onClick={() => { if (i <= step) goTo(i); }} style={{ flex: "1 1 130px", display: "flex", alignItems: "center", gap: 8, padding: "11px 13px", borderRight: i < STEPS.length - 1 ? `1px solid ${PL_LINE}` : "none", background: i === step && !state.closedAt ? "var(--bg2)" : "transparent", cursor: i <= step ? "pointer" : "default" }}>
            <Dot s={status} />
            <div>
              <div style={{ fontSize: 9, color: "#7a7a76", fontFamily: "var(--m)", fontWeight: 600 }}>{String(i + 1).padStart(2, "0")}</div>
              <div style={{ fontSize: 11.5, color: status === "todo" ? "#7a7a76" : "#fff", fontFamily: "var(--m)", fontWeight: status === "active" ? 700 : 400 }}>{L(s.en, s.lt)}</div>
            </div>
          </div>;
        })}
      </div>

      {/* active step body */}
      <div style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", padding: "20px 22px" }}>
        {/* STEP 0 — ledger */}
        {step === 0 && <div>
          <h4 style={{ fontSize: 16, color: "#fff", fontFamily: "var(--f)", margin: "0 0 10px" }}>{L("1 · Confirm the SAF-T ledger", "1 · Patvirtinkite SAF-T knygą")}</h4>
          {ledgerReady ? <>
            <div style={{ fontSize: 13, color: "#d2d2ce", fontFamily: "var(--s)", lineHeight: 1.7 }}>
              {L("Loaded entity", "Įkelta įmonė")}: <strong style={{ color: "#fff" }}>{data.header.company?.name || "—"}</strong><br />
              {L("Period", "Periodas")}: {data.header.fiscalYearFrom?.slice(0, 10)} → {data.header.fiscalYearTo?.slice(0, 10)}<br />
              {kpis?.kpis && <>{L("Ledger VAT position", "Knygos PVM pozicija")}: output {eur(kpis.kpis.salesVat)} · input {eur(kpis.kpis.inputVat)} · net {eur(kpis.kpis.netVatPosition)}</>}
            </div>
            <button onClick={() => goTo(1)} style={{ ...bP, marginTop: 16 }}>{L("Start close →", "Pradėti uždarymą →")}</button>
          </> : <div style={{ fontSize: 13, color: "#ffa94d", fontFamily: "var(--m)" }}>{L("Load a SAF-T file first (above), then return here.", "Pirma įkelkite SAF-T failą (viršuje), tada grįžkite čia.")}</div>}
        </div>}

        {/* STEP 1 — intake */}
        {step === 1 && <div>
          <h4 style={{ fontSize: 16, color: "#fff", fontFamily: "var(--f)", margin: "0 0 10px" }}>{L("2 · Provide the monthly i.SAF", "2 · Pateikite mėnesinį i.SAF")}</h4>
          <p style={{ fontSize: 13, color: "#bcbcb8", fontFamily: "var(--s)", marginBottom: 16, lineHeight: 1.6 }}>{L("Upload the i.SAF (VAT invoice register) for the period to reconcile against the ledger.", "Įkelkite šio periodo i.SAF (PVM sąskaitų registrą), kad sutikrintumėte su knyga.")}</p>
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap", alignItems: "center" }}>
            <button onClick={() => fileRef.current?.click()} style={bP}>{L("Upload i.SAF (XML)", "Įkelti i.SAF (XML)")} →</button>
            {presetRecon && <button onClick={useExisting} style={bG}>{L("Use the i.SAF already reconciled", "Naudoti jau sutikrintą i.SAF")}</button>}
            <button onClick={() => goTo(0)} style={{ ...bG, border: "none", color: "#8c8c88" }}>← {L("Back", "Atgal")}</button>
          </div>
          <input ref={fileRef} type="file" accept=".xml" style={{ display: "none" }} onChange={(e) => ingestISAF(e.target?.files?.[0])} />
        </div>}

        {/* STEP 2 — reconcile */}
        {step === 2 && <div><div style={{ fontSize: 13, color: "#8c8c88" }}>{L("Reconciling…", "Sutikrinama…")}</div></div>}

        {/* STEP 3 — reconcile result */}
        {step === 3 && recon && <div>
          <h4 style={{ fontSize: 16, color: "#fff", fontFamily: "var(--f)", margin: "0 0 12px" }}>{L("3 · Reconciliation result", "3 · Sutikrinimo rezultatas")}</h4>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(150px,1fr))", borderTop: `1px solid ${PL_LINE}`, borderLeft: `1px solid ${PL_LINE}`, marginBottom: 16 }}>
            {[[L("Output VAT Δ", "Pardavimo PVM Δ"), recon.summary.vat.outputDelta], [L("Input VAT Δ", "Pirkimo PVM Δ"), recon.summary.vat.inputDelta], [L("Net VAT Δ", "Grynoji PVM Δ"), recon.summary.vat.netDelta], [L("Discrepancies", "Neatitikimai"), recon.findings.length, true]].map(([k, val, count], i) =>
              <div key={i} style={{ padding: "14px 16px", borderRight: `1px solid ${PL_LINE}`, borderBottom: `1px solid ${PL_LINE}` }}>
                <div style={{ fontSize: 9, color: "#8c8c88", fontFamily: "var(--m)", textTransform: "uppercase", letterSpacing: ".08em", marginBottom: 8 }}>{k}</div>
                <div style={{ fontSize: 20, fontWeight: 300, fontFamily: "var(--f)", color: count ? "#fff" : Math.abs(val) > 0.02 ? "#ff8a8a" : "#69db7c" }}>{count ? val : (val > 0 ? "+" : "") + eur(val)}</div>
              </div>)}
          </div>
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            <button onClick={() => goTo(4)} style={bP}>{L("Review discrepancies →", "Peržiūrėti neatitikimus →")}</button>
            <button onClick={() => goTo(1)} style={{ ...bG, border: "none", color: "#8c8c88" }}>← {L("Different i.SAF", "Kitas i.SAF")}</button>
          </div>
        </div>}

        {/* STEP 4 — review */}
        {step === 4 && recon && <div>
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12, flexWrap: "wrap" }}>
            <h4 style={{ fontSize: 16, color: "#fff", fontFamily: "var(--f)", margin: 0 }}>{L("4 · Review & sign off", "4 · Peržiūra ir patvirtinimas")}</h4>
            <span style={{ fontSize: 11, color: "#8c8c88", fontFamily: "var(--m)" }}>{reviewedCount}/{findings.length} {L("reviewed", "peržiūrėta")}</span>
            {findings.length > 0 && <button onClick={() => { const d = {}; findings.forEach((f) => d[f.id] = "accepted"); set({ decisions: d }); }} style={{ ...bG, marginLeft: "auto" }}>{L("Accept all as known", "Patvirtinti visus kaip žinomus")}</button>}
          </div>
          {findings.length === 0 ? <div style={{ border: "1px solid #69db7c", padding: 14, color: "#69db7c", fontFamily: "var(--m)", fontSize: 13 }}>✓ {L("No discrepancies — the register matches the ledger.", "Neatitikimų nėra — registras atitinka knygą.")}</div>
            : findings.map((f) => {
              const SEVC = { Block: "#ff6b6b", Reject: "#ffa94d", Warn: "#ffd43b" };
              const dec = reviewDecisions[f.id];
              return <div key={f.id} style={{ borderLeft: `2px solid ${SEVC[f.severity]}`, background: "#000", padding: "12px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap", marginBottom: 5 }}>
                  <span style={{ fontFamily: "var(--m)", fontSize: 11, fontWeight: 700, color: "#fff" }}>{f.id}</span>
                  <span style={{ fontFamily: "var(--m)", fontSize: 9, fontWeight: 700, padding: "1px 7px", border: `1px solid ${SEVC[f.severity]}`, color: SEVC[f.severity], textTransform: "uppercase" }}>{f.severity}</span>
                  <div style={{ marginLeft: "auto", display: "flex", gap: 6 }}>
                    <button onClick={() => set({ decisions: { ...reviewDecisions, [f.id]: "resolved" } })} style={{ background: dec === "resolved" ? "#69db7c" : "transparent", color: dec === "resolved" ? "#000" : "#69db7c", border: "1px solid #69db7c", fontFamily: "var(--m)", fontSize: 9.5, fontWeight: 700, padding: "3px 9px", cursor: "pointer", textTransform: "uppercase" }}>{L("Resolved", "Išspręsta")}</button>
                    <button onClick={() => set({ decisions: { ...reviewDecisions, [f.id]: "accepted" } })} style={{ background: dec === "accepted" ? "#ffd43b" : "transparent", color: dec === "accepted" ? "#000" : "#ffd43b", border: "1px solid #ffd43b", fontFamily: "var(--m)", fontSize: 9.5, fontWeight: 700, padding: "3px 9px", cursor: "pointer", textTransform: "uppercase" }}>{L("Known", "Žinoma")}</button>
                  </div>
                </div>
                <div style={{ fontSize: 13.5, color: "#fff", fontFamily: "var(--f)" }}>{f.title}</div>
                <div style={{ fontSize: 12, color: "#bcbcb8", fontFamily: "var(--s)", lineHeight: 1.5, marginTop: 3 }}>{f.detail}</div>
                {f.evidence?.length > 0 && <div style={{ fontSize: 11, color: "#9f9f9b", fontFamily: "var(--m)", marginTop: 4 }}>{f.evidence.slice(0, 4).join(" · ")}</div>}
              </div>;
            })}
          <div style={{ display: "flex", gap: 12, marginTop: 14, alignItems: "center", flexWrap: "wrap" }}>
            <button onClick={() => goTo(5)} disabled={!allReviewed} style={{ ...bP, opacity: allReviewed ? 1 : 0.45, cursor: allReviewed ? "pointer" : "not-allowed" }}>{L("Approve & continue →", "Patvirtinti ir tęsti →")}</button>
            {!allReviewed && <span style={{ fontSize: 11, color: "#ffa94d", fontFamily: "var(--m)" }}>{L("Mark every discrepancy before continuing.", "Pažymėkite kiekvieną neatitikimą prieš tęsiant.")}</span>}
            <button onClick={() => goTo(3)} style={{ ...bG, border: "none", color: "#8c8c88" }}>← {L("Back", "Atgal")}</button>
          </div>
        </div>}

        {/* STEP 5 — FR0600 notes */}
        {step === 5 && fr && <div>
          <h4 style={{ fontSize: 16, color: "#fff", fontFamily: "var(--f)", margin: "0 0 12px" }}>{L("5 · FR0600 notes (VAT return basis)", "5 · FR0600 pastabos (PVM deklaracija)")}</h4>
          <div style={{ overflowX: "auto", marginBottom: 14 }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12.5, fontFamily: "var(--m)" }}>
              <thead><tr style={{ color: "#8c8c88", textAlign: "left" }}>
                <th style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_LINE}`, fontSize: 10, textTransform: "uppercase" }}>{L("Line", "Eilutė")}</th>
                <th style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_LINE}`, fontSize: 10, textTransform: "uppercase" }}>{L("Ledger (file)", "Knyga (failas)")}</th>
                <th style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_LINE}`, fontSize: 10, textTransform: "uppercase" }}>{L("i.SAF declared", "i.SAF deklaruota")}</th>
                <th style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_LINE}`, fontSize: 10, textTransform: "uppercase" }}>Δ</th>
              </tr></thead>
              <tbody>
                {[[L("Output VAT", "Pardavimo PVM"), fr.outputLedger, fr.outputISAF], [L("Input VAT", "Pirkimo PVM"), fr.inputLedger, fr.inputISAF], [L("Net VAT payable", "Mokėtinas PVM"), fr.netLedger, fr.netISAF]].map(([k, a, b], i) => {
                  const d = r2(b - a);
                  return <tr key={i} style={{ color: "#d2d2ce" }}>
                    <td style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_SOFT}`, color: "#fff" }}>{k}</td>
                    <td style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_SOFT}` }}>{eur(a)}</td>
                    <td style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_SOFT}` }}>{eur(b)}</td>
                    <td style={{ padding: "7px 8px", borderBottom: `1px solid ${PL_SOFT}`, color: Math.abs(d) > 0.02 ? "#ff8a8a" : "#69db7c" }}>{d > 0 ? "+" : ""}{eur(d)}</td>
                  </tr>;
                })}
              </tbody>
            </table>
          </div>
          {fr.corrections.length > 0 && <div style={{ border: `1px solid ${PL_LINE}`, borderLeft: "3px solid #ffa94d", padding: "12px 14px", marginBottom: 14 }}>
            <div style={{ fontSize: 10, color: "#ffa94d", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase", marginBottom: 8 }}>{L("Corrections to resolve before filing", "Taisymai prieš deklaravimą")}</div>
            {fr.corrections.map((c) => <div key={c.id} style={{ fontSize: 12, color: "#d2d2ce", fontFamily: "var(--s)", padding: "2px 0" }}>· <strong style={{ color: "#fff" }}>{c.id}</strong> ({c.sev}) — {c.title} {reviewDecisions[c.id] === "resolved" ? <span style={{ color: "#69db7c", fontFamily: "var(--m)", fontSize: 11 }}>✓ {L("resolved", "išspręsta")}</span> : <span style={{ color: "#ffd43b", fontFamily: "var(--m)", fontSize: 11 }}>{L("acknowledged", "pažymėta")}</span>}</div>)}
          </div>}
          <p style={{ fontSize: 11.5, color: "#9f9f9b", fontFamily: "var(--s)", lineHeight: 1.55, marginBottom: 14 }}>{L("The return is filed on the ledger basis; the Δ column shows where the i.SAF register differs and must be aligned. Verify against the official FR0600 before submission.", "Deklaracija teikiama pagal knygą; Δ stulpelis rodo, kur i.SAF skiriasi ir turi būti suderinta. Patikrinkite pagal oficialią FR0600 prieš teikimą.")}</p>
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            <button onClick={() => goTo(6)} style={bP}>{L("Draft client memo →", "Rengti kliento atmintinę →")}</button>
            <button onClick={() => goTo(4)} style={{ ...bG, border: "none", color: "#8c8c88" }}>← {L("Back", "Atgal")}</button>
          </div>
        </div>}

        {/* STEP 6 — memo */}
        {step === 6 && <div>
          <h4 style={{ fontSize: 16, color: "#fff", fontFamily: "var(--f)", margin: "0 0 12px" }}>{L("6 · Client memo", "6 · Kliento atmintinė")}</h4>
          {!state.memo && <div style={{ display: "flex", gap: 12, alignItems: "center", flexWrap: "wrap" }}>
            <button onClick={draftMemo} disabled={busy} style={{ ...bP, opacity: busy ? 0.5 : 1 }}>{busy ? L("Drafting…", "Rengiama…") : L("Generate memo", "Sugeneruoti atmintinę") + " →"}</button>
            <button onClick={() => goTo(5)} style={{ ...bG, border: "none", color: "#8c8c88" }}>← {L("Back", "Atgal")}</button>
          </div>}
          {state.memo && <>
            <div style={{ border: `1px solid ${PL_LINE}`, background: "#000", padding: "16px 18px" }}><Md text={state.memo} /></div>
            {state.memoVer && <DefensibilityPanel verification={state.memoVer} lang={lang} />}
            <div style={{ display: "flex", gap: 12, marginTop: 16, flexWrap: "wrap" }}>
              {!state.closedAt && <button onClick={() => { set({ closedAt: new Date().toISOString() }); audit?.log?.("WF_VATCLOSE_COMPLETE", data?.header?.company?.name || ""); }} style={bP}>{L("Mark VAT close complete ✓", "Pažymėti uždarymą baigtą ✓")}</button>}
              {state.closedAt && <span style={{ padding: "8px 14px", border: "1px solid #69db7c", color: "#69db7c", fontFamily: "var(--m)", fontSize: 11, fontWeight: 700 }}>✓ {L("Closed", "Uždaryta")} · {new Date(state.closedAt).toLocaleString(lang === "lt" ? "lt-LT" : "en-GB")}</span>}
              <button onClick={() => {
                const v = recon.summary.vat;
                const lines = [`MONTHLY VAT CLOSE — ${data?.header?.company?.name || ""}`, `Period: ${data?.header?.fiscalYearFrom?.slice(0,10)} → ${data?.header?.fiscalYearTo?.slice(0,10)}`, ``, `VAT POSITION (ledger): output ${eur(v.outputSAFT)}, input ${eur(v.inputSAFT)}, net ${eur(v.netSAFT)}`, `i.SAF declared: output ${eur(v.outputISAF)}, input ${eur(v.inputISAF)}, net ${eur(v.netISAF)}`, `Net delta: ${eur(v.netDelta)}`, ``, `DISCREPANCIES (${findings.length}):`, ...findings.map((f) => `- [${f.severity}] ${f.id} ${f.title} — ${reviewDecisions[f.id] || "open"}`), ``, `MEMO:`, state.memo].join("\n");
                const blob = new Blob([lines], { type: "text/plain" }); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = `vat-close-${(data?.header?.company?.name || "entity").replace(/\s+/g, "-")}.txt`; a.click();
                audit?.log?.("WF_VATCLOSE_EXPORT", "");
              }} style={bG}>↧ {L("Export close package", "Eksportuoti paketą")}</button>
              <button onClick={() => { set({ memo: null, memoVer: null }); }} style={{ ...bG, border: "none", color: "#8c8c88" }}>↻ {L("Redraft", "Perrašyti")}</button>
            </div>
          </>}
        </div>}
      </div>
    </div>
  );
}

// Lists the legal provisions a grounded answer relied on, with the exact
// article text, and flags any citation that did not resolve to the corpus.
function SourcesPanel({ grounding, lang }) {
  const PL_LINE = "rgba(255,255,255,0.12)";
  if (!grounding || (!grounding.sources?.length && !grounding.hasUnresolved)) return null;
  const L = (en, lt) => (lang === "lt" ? lt : en);
  const ok = !grounding.hasUnresolved;
  return (
    <div style={{ marginTop: 14, border: `1px solid ${PL_LINE}`, background: "var(--bg2)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 14px", borderBottom: grounding.sources?.length ? `1px solid ${PL_LINE}` : "none", flexWrap: "wrap" }}>
        <span style={{ fontSize: 10, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".14em", textTransform: "uppercase" }}>{L("Sources", "Šaltiniai")}</span>
        <span style={{ fontSize: 11, color: "#bcbcb8", fontFamily: "var(--m)" }}>{(grounding.sources || []).length} {L("provisions", "nuostatos")}</span>
        <span style={{ marginLeft: "auto", display: "inline-flex", alignItems: "center", gap: 6, fontSize: 10.5, fontFamily: "var(--m)", color: ok ? "#69db7c" : "#ffd43b" }}>
          <span style={{ width: 8, height: 8, borderRadius: "50%", background: ok ? "#69db7c" : "#ffd43b" }} />
          {grounding.citeTotal > 0
            ? L(`${grounding.groundedCount}/${grounding.citeTotal} citations resolve to source`, `${grounding.groundedCount}/${grounding.citeTotal} citatos turi šaltinį`)
            : L("grounded in retrieved law", "pagrįsta rasta teise")}
        </span>
      </div>
      {(grounding.sources || []).map((s, i) =>
        <div key={s.id} style={{ display: "flex", gap: 10, padding: "10px 14px", borderBottom: i < grounding.sources.length - 1 ? `1px solid rgba(255,255,255,0.06)` : "none" }}>
          <span style={{ flexShrink: 0, fontSize: 10, fontFamily: "var(--m)", fontWeight: 700, color: "#7cc4ff", border: "1px solid rgba(124,196,255,0.4)", borderRadius: 3, padding: "1px 6px", height: "fit-content" }}>{i + 1}</span>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 11.5, color: "#fff", fontFamily: "var(--m)", fontWeight: 700 }}>{s.law} · {s.article}</div>
            <div style={{ fontSize: 12, color: "#d2d2ce", fontFamily: "var(--s)", lineHeight: 1.5, marginTop: 3 }}>{lang === "lt" ? s.text : (s.textEn || s.text)}</div>
            {s.penalty && <div style={{ fontSize: 10.5, color: "#ffa94d", fontFamily: "var(--m)", marginTop: 3 }}>⚠ {L("Sanction", "Sankcija")}: {s.penalty}</div>}
          </div>
        </div>)}
      {grounding.hasUnresolved && <div style={{ padding: "9px 14px", fontSize: 11, color: "#ffd43b", fontFamily: "var(--m)", borderTop: `1px solid rgba(255,255,255,0.06)` }}>
        ⚠ {L("Unverified citation(s)", "Nepatvirtinta citata(-os)")}: {grounding.unresolved.join(", ")} — {L("not found in the corpus; verify manually.", "nerasta korpuse; patikrinkite rankiniu būdu.")}
      </div>}
    </div>
  );
}

// ── Per-finding explanation engine ──────────────────────────────────────────
// Turns any finding from any engine (VAT, structural, XSD, duplicate,
// classifier, schema validation) into a clear three-part explanation:
// WHAT was found (with the actual values), WHY it matters (rule meaning +
// legal basis), and HOW to fix it — short numbered steps. The splitter is
// abbreviation-aware, so Lithuanian legal shorthand (proc., str., Nr., 5 d.)
// never breaks a step mid-sentence.
function fixSteps(fix) {
  let s = String(fix || "").trim();
  if (!s) return [];
  s = s.replace(/\b(proc|str|nr|art|kl|pvz|žr|vnt|mln|mlrd|tūkst|kt|pan|sąsk|mėn|d|p|t|y|g|e)\./gi, "$1\u0001");
  s = s.replace(/\.(?=\S)/g, "\u0001"); // dots not followed by a space: URLs, decimals, e.g./i.e.
  const parts = s.match(/[^.;!?]+[.;!?]?/g) || [s];
  const steps = parts
    .map((p) => p.replace(/\u0001/g, ".").trim().replace(/^[;,]\s*/, ""))
    .filter((p) => p.replace(/[.;!?()\s]/g, "").length > 2)
    .map((p) => (/[.;!?]$/.test(p) ? p.replace(/;$/, ".") : p + "."));
  return steps.slice(0, 6);
}
function explainFinding(f, lang) {
  const m = (f && f.ruleMeta) || {};
  const lt = lang === "lt";
  const what = String((f && f.evidence && f.evidence[0]) || (f && f.detail) || "");
  const why = lt ? (m.descriptionLt || "") : (m.descriptionEn || m.descriptionLt || "");
  const how = fixSteps(lt ? (m.fixLt || m.fixEn) : (m.fixEn || m.fixLt));
  if (!how.length) how.push(lt ? "Peržiūrėkite šį įrašą pagal pagrindžiančius dokumentus." : "Review this item against the supporting documentation.");
  const urgent = !!(f && (f.severity === "Critical" || f.severity === "High"));
  return { what, why, legal: m.legal || "", how, urgent,
    lead: urgent ? (lt ? "Būtina ištaisyti prieš teikiant" : "Must be corrected before submission")
                 : (lt ? "Rekomenduojama peržiūrėti" : "Recommended review") };
}

// ── Remediation confidence (deterministic) ──────────────────────────────────
// How confident the engine is that a finding is a true positive needing action.
// Driven by the rule family: schema (XSD), structural (SCHEMA), duplicate-key
// (DUBL) and classifier (CLS) checks are deterministic and near-certain;
// indicative tax-risk "signals" are lower and invite a sample review. The
// volume of hits nudges the score. No AI — fully reproducible.
function findingConfidence(f) {
  const m = (f && f.ruleMeta) || {};
  const fam = String(m.family || "").toUpperCase();
  const kind = String(m.kind || "").toLowerCase();
  const hits = (f && Array.isArray(f.evidence)) ? f.evidence.length : 0;
  let base, basisEn, basisLt;
  if (fam === "XSD") { base = 97; basisEn = "Schema (XSD) check — deterministic, near-certain."; basisLt = "Schemos (XSD) patikra — deterministinė, beveik tikra."; }
  else if (fam === "SCHEMA") { base = 96; basisEn = "Structural requirement — deterministic."; basisLt = "Struktūrinis reikalavimas — deterministinis."; }
  else if (fam === "DUBL") { base = 91; basisEn = "Duplicate-key match — deterministic."; basisLt = "Pasikartojančio rakto atitiktis — deterministinė."; }
  else if (fam === "CLS") { base = 90; basisEn = "Official VMI classifier lookup — deterministic."; basisLt = "Oficialaus VMI klasifikatoriaus patikra — deterministinė."; }
  else if (kind === "signal") { base = 74; basisEn = "Indicative tax-risk signal — verify the flagged sample."; basisLt = "Indikatyvus mokestinės rizikos signalas — patikrinkite pažymėtą imtį."; }
  else if (typeof isAutoFixableRule === "function" && isAutoFixableRule(f && f.rule_id)) { base = 90; basisEn = "Deterministic, auto-fixable rule."; basisLt = "Deterministinė, automatiškai taisoma taisyklė."; }
  else { base = 82; basisEn = "Deterministic rule check."; basisLt = "Deterministinė taisyklės patikra."; }
  if (hits >= 5) base += 3; else if (hits <= 1 && kind === "signal") base -= 6;
  if ((f && f.severity) === "Critical" && base < 90) base += 2;
  const score = Math.max(40, Math.min(99, Math.round(base)));
  const band = score >= 90 ? "high" : score >= 70 ? "medium" : "low";
  return { score, band, basisEn, basisLt };
}
const CONF_COLOR = { high: "#69db7c", medium: "#ffd43b", low: "#ffa94d" };
function confBandLabel(band, lang) {
  const lt = lang === "lt";
  return band === "high" ? (lt ? "aukštas" : "high") : band === "medium" ? (lt ? "vidutinis" : "medium") : (lt ? "žemas" : "low");
}

// Stable identifier for a finding (rule + the specific evidence line).
function findingKey(f) {
  if (!f) return "";
  const ev = (f.evidence && f.evidence[0]) || f.detail || "";
  return `${f.rule_id || "?"}::${ev}`.slice(0, 220);
}

// Full-page finding detail: clearly defines the rule, what was flagged, what
// to fix, the legal basis, and an auditor's note (in-accordance + justification)
// that persists and can be re-edited — mirroring an auditor working paper.
// ── Overflow menu for action bars: native <details> keeps it stateless and
//    keyboard-accessible; clicking any item inside closes the panel. ──
// ── E-Invoice Studio: EN 16931 + Peppol BIS 3.0 validator & SAF-T→Peppol generator ──
function EInvoiceStudio({ lang, fileData, setToast, audit }) {
  const [xmlIn, setXmlIn] = useState("");
  const [valRes, setValRes] = useState(null);
  const [genSel, setGenSel] = useState("");
  const [genRes, setGenRes] = useState(null);
  const [csvInfo, setCsvInfo] = useState(null);
  const [csvProfile, setCsvProfile] = useState("auto");
  const [batch, setBatch] = useState(null);
  const [batchBusy, setBatchBusy] = useState(false);
  const onCsv = (e) => { const f = e.target.files && e.target.files[0]; if (!f) return; const r = new FileReader(); r.onload = (ev) => { try { const p = parseInvoiceCsv(String(ev.target.result || "")); const m = mapErpRows(p.headers, p.rows, csvProfile); setCsvInfo({ headers: p.headers, rows: p.rows, mapRes: m }); setBatch(null); } catch (err) { setToast && setToast("CSV: " + String(err && err.message || err).slice(0, 120)); } }; r.readAsText(f); e.target.value = ""; };
  const remap = (pid) => { setCsvProfile(pid); setBatch(null); setCsvInfo((ci) => ci ? { ...ci, mapRes: mapErpRows(ci.headers, ci.rows, pid) } : ci); };
  const sellerFromSaft = () => { const co = (fileData && fileData.parsed && fileData.parsed.header && fileData.parsed.header.company) || {}; return { name: co.name, registrationNumber: co.registrationNumber, taxRegistrationNumber: co.taxRegistrationNumber }; };
  const runBatch = async (src2) => { setBatchBusy(true); try { const b = await runPeppolBatch(src2, {}); setBatch(b); audit && audit.log("EINV_BATCH", src2.kind + " · " + b.summary.total); } catch (e) { setToast && setToast("Batch: " + String(e && e.message || e).slice(0, 120)); } setBatchBusy(false); };
  const sha256hex = async (s) => { const d = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(s)); return Array.from(new Uint8Array(d)).map((b) => b.toString(16).padStart(2, "0")).join(""); };
  const dlZip = async () => { if (!batch) return; try { const hashes = {}; for (const r of batch.results) hashes[r.fileName] = await sha256hex(r.xml); const files = batch.results.map((r) => ({ name: r.fileName, data: r.xml })).concat([{ name: "manifest.json", data: buildBatchManifest(batch, hashes) }, { name: "summary.csv", data: batchSummaryCsv(batch) }]); const zip = buildZip(files); const b = new Blob([zip], { type: "application/zip" }); const u = URL.createObjectURL(b); const a = document.createElement("a"); a.href = u; a.download = "taxai-peppol-batch.zip"; a.click(); setTimeout(() => URL.revokeObjectURL(u), 30000); audit && audit.log("EXPORT", "Peppol batch ZIP · " + batch.summary.total); } catch (e) { setToast && setToast("ZIP: " + String(e && e.message || e).slice(0, 120)); } };
  const btnP = (dis) => ({ padding: "9px 16px", background: "#fff", color: "#000", border: "none", fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer", opacity: dis ? 0.4 : 1 });
  const btnG = () => ({ display: "inline-flex", alignItems: "center", gap: 8, padding: "9px 16px", border: `1px solid rgba(255,255,255,0.12)`, color: "#fff", fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer", background: "transparent" });
  const LINE = "rgba(255,255,255,0.12)";
  const SC2 = { Critical: "#ff6b6b", High: "#ffa94d", Medium: "#ffd43b", Low: "#69db7c" };
  const sales = (fileData && fileData.parsed && fileData.parsed.sales && fileData.parsed.sales.items) || [];
  const runVal = (txt) => { try { const inv = parseUblInvoice(txt); const findings = validateEInvoice(inv); setValRes({ inv, findings, gate: computeEInvoiceGate(findings) }); audit && audit.log("EINV_VALIDATE", (inv.id || "?") + " · " + findings.length + " findings"); } catch (e) { setToast && setToast("Validator: " + String(e && e.message || e).slice(0, 120)); } };
  const onFile = (e) => { const f = e.target.files && e.target.files[0]; if (!f) return; const r = new FileReader(); r.onload = (ev) => { const t = String(ev.target.result || ""); setXmlIn(t); runVal(t); }; r.readAsText(f); e.target.value = ""; };
  const dl = (name, content) => { const b = new Blob([content], { type: "application/xml" }); const u = URL.createObjectURL(b); const a = document.createElement("a"); a.href = u; a.download = name; a.click(); setTimeout(() => URL.revokeObjectURL(u), 30000); };
  const Gate = ({ g }) => <div style={{ display: "flex", gap: 8, flexWrap: "wrap", margin: "12px 0" }}>
    {[["EN 16931", g.en], ["Peppol BIS 3.0", g.peppol], ["LT", g.lt]].map(([lb, x]) => <span key={lb} style={{ fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", padding: "6px 12px", border: `1px solid ${x.ok ? "#69db7c" : "#ff6b6b"}`, color: x.ok ? "#69db7c" : "#ff6b6b" }}>{x.ok ? "✓" : "✕"} {lb}{x.errors ? ` · ${x.errors}` : ""}</span>)}
  </div>;
  const Findings = ({ fs }) => fs.length === 0 ? <div style={{ color: "#69db7c", fontFamily: "var(--m)", fontSize: 12 }}>✓ {lang === "lt" ? "Pažeidimų nerasta — dokumentas atitinka visus tris paketus." : "No violations — the document passes all three packs."}</div>
    : <div>{fs.map((f, i) => <div key={i} style={{ padding: "7px 0", borderBottom: "1px solid rgba(255,255,255,0.07)" }}>
      <div style={{ display: "flex", gap: 10, alignItems: "baseline", flexWrap: "wrap" }}>
        <span style={{ fontSize: 9.5, padding: "2px 8px", border: `1px solid ${SC2[f.severity]}`, color: SC2[f.severity], fontFamily: "var(--m)", fontWeight: 700 }}>{f.severity}</span>
        <span style={{ fontFamily: "var(--m)", fontSize: 11, color: "#7cc4ff" }}>{f.rule_id}</span>
        <span style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#666" }}>{f.std}</span>
        <span style={{ color: "#fff", fontFamily: "var(--s)", fontSize: 13 }}>{lang === "lt" ? f.titleLt : f.titleEn}</span>
      </div>
      {f.detail && <div style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#9f9f9b", padding: "2px 0 0 4px" }}>{f.detail}</div>}
      {f.fix && <div style={{ fontFamily: "var(--s)", fontSize: 11.5, color: "#8c8c88", padding: "1px 0 0 4px" }}>🔧 {f.fix}</div>}
    </div>)}</div>;
  return <div style={{ maxWidth: 1100, margin: "26px auto 0" }}>
    <div style={{ background: "var(--bg2)", border: `1px solid ${LINE}`, padding: 24, marginBottom: 20 }}>
      <div style={{ fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".18em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 8 }}>{lang === "lt" ? "E. SĄSKAITŲ STUDIJA — EN 16931 · PEPPOL BIS 3.0 · LT" : "E-INVOICE STUDIO — EN 16931 · PEPPOL BIS 3.0 · LT"}</div>
      <p style={{ fontSize: 13, color: "#bcbcb8", fontFamily: "var(--s)", lineHeight: 1.6, margin: "0 0 14px", maxWidth: 880 }}>{lang === "lt" ? "Validatorius tikrina UBL 2.1 sąskaitas trimis paketais: EN 16931 (privalomi laukai, BR-CO skaičiavimai, PVM kategorijos S/Z/E/AE/K/G/O), Peppol BIS 3.0 (CustomizationID/ProfileID, Peppol adresai, GLN kontrolinės sumos) ir LT sluoksnis (JAR bei PVM kodų mod-11, IBAN mod-97, 2026 m. tarifai 21/12/5). Viskas vykdoma šioje naršyklėje — dokumentai niekur nesiunčiami." : "The validator checks UBL 2.1 invoices with three packs: EN 16931 (mandatory fields, BR-CO calculations, VAT categories S/Z/E/AE/K/G/O), Peppol BIS 3.0 (CustomizationID/ProfileID, endpoints, GLN check digits) and the LT layer (JAR & VAT mod-11, IBAN mod-97, 2026 rates 21/12/5). Everything runs in this browser — documents never leave it."}</p>
      <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 10 }}>
        <label style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "9px 16px", border: `1px solid ${LINE}`, color: "#fff", fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" }}>↑ {lang === "lt" ? "Įkelti UBL XML" : "Upload UBL XML"}<input type="file" accept=".xml" onChange={onFile} style={{ display: "none" }} /></label>
        <button onClick={() => runVal(xmlIn)} disabled={!xmlIn.trim()} style={{ padding: "9px 16px", background: "#fff", color: "#000", border: "none", fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer", opacity: xmlIn.trim() ? 1 : 0.4 }}>{lang === "lt" ? "Tikrinti →" : "Validate →"}</button>
      </div>
      <textarea value={xmlIn} onChange={(e) => setXmlIn(e.target.value)} placeholder={lang === "lt" ? "Įklijuokite UBL 2.1 Invoice / CreditNote XML…" : "Paste UBL 2.1 Invoice / CreditNote XML…"} spellCheck={false} style={{ width: "100%", minHeight: 110, background: "#000", border: `1px solid ${LINE}`, color: "#d2d2ce", fontFamily: "var(--m)", fontSize: 10.5, padding: 12, boxSizing: "border-box", outline: "none", resize: "vertical" }} />
      {valRes && <><Gate g={valRes.gate} /><Findings fs={valRes.findings} /></>}
    </div>
    <div style={{ background: "var(--bg2)", border: `1px solid ${LINE}`, padding: 24 }}>
      <div style={{ fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".18em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 8 }}>{lang === "lt" ? "GENERATORIUS — SAF-T → PEPPOL BIS 3.0" : "GENERATOR — SAF-T → PEPPOL BIS 3.0"}</div>
      {sales.length === 0 ? <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 13 }}>{lang === "lt" ? "Įkelkite SAF-T failą skiltyje „SAF-T“ — generatorius siūlys jūsų pardavimo sąskaitas, o pirkėją prijungs iš kontrahentų registro." : "Load a SAF-T file in the SAF-T section — the generator will offer your sales invoices, joining the buyer from the masterfiles."}</div>
        : <>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 10 }}>
            <select value={genSel} onChange={(e) => { setGenSel(e.target.value); setGenRes(null); }} style={{ background: "#000", border: `1px solid ${LINE}`, color: "#fff", fontFamily: "var(--m)", fontSize: 11.5, padding: "8px 10px", minWidth: 280 }}>
              <option value="">{lang === "lt" ? "— pasirinkite sąskaitą —" : "— choose an invoice —"}</option>
              {sales.slice(0, 400).map((i, k) => <option key={k} value={String(k)}>{(i.invoiceNo || ("#" + (k + 1))) + " · " + (i.invoiceDate || "—") + " · " + ((i.documentTotals && i.documentTotals.netTotal) != null ? i.documentTotals.netTotal : "—") + " EUR"}</option>)}
            </select>
            <button onClick={() => { try { const inv = sales[+genSel]; const out = buildPeppolInvoice(inv, fileData.parsed, {}); const pInv = parseUblInvoice(out.xml); const findings = validateEInvoice(pInv); setGenRes({ ...out, findings, gate: computeEInvoiceGate(findings) }); audit && audit.log("EINV_GENERATE", inv.invoiceNo || ""); } catch (e) { setToast && setToast("Generator: " + String(e && e.message || e).slice(0, 120)); } }} disabled={genSel === ""} style={{ padding: "9px 16px", background: "#fff", color: "#000", border: "none", fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer", opacity: genSel === "" ? 0.4 : 1 }}>{lang === "lt" ? "Generuoti →" : "Generate →"}</button>
            {genRes && <button onClick={() => dl("peppol-" + ((sales[+genSel] && sales[+genSel].invoiceNo) || "invoice") + ".xml", genRes.xml)} style={{ padding: "9px 16px", background: "transparent", color: "#fff", border: `1px solid ${LINE}`, fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" }}>↓ XML</button>}
          </div>
          {genRes && <>
            <div style={{ fontFamily: "var(--m)", fontSize: 11.5, color: "#bcbcb8", marginBottom: 4 }}>{lang === "lt" ? "Pirkėjas" : "Buyer"}: <span style={{ color: "#fff" }}>{genRes.meta.buyer}</span> · {lang === "lt" ? "kategorija" : "category"} <b>{genRes.meta.cat}</b> {genRes.meta.rate}% · {lang === "lt" ? "mokėtina" : "payable"} <b>{genRes.meta.payable}</b> EUR{!genRes.meta.peppolEndpoints && <span style={{ color: "#ffd43b" }}> · {lang === "lt" ? "Peppol adresui trūksta galiojančio pirkėjo JAR kodo" : "a valid buyer JAR code is missing for the Peppol endpoint"}</span>}</div>
            <Gate g={genRes.gate} />
            <Findings fs={genRes.findings} />
          </>}
        </>}
    </div>
    <div style={{ background: "var(--bg2)", border: `1px solid ${LINE}`, padding: 24, marginTop: 20 }}>
      <div style={{ fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".18em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 8 }}>{lang === "lt" ? "ERP INTEGRACIJA — PAKETINIS KONVEJERIS" : "ERP INTEGRATION — BATCH PIPELINE"}</div>
      <p style={{ fontSize: 13, color: "#bcbcb8", fontFamily: "var(--s)", lineHeight: 1.6, margin: "0 0 14px", maxWidth: 880 }}>{lang === "lt" ? "Automatizuokite generavimą ir atitiktį tiesiai iš ERP: paleiskite visą SAF-T pardavimo žurnalą arba įkelkite ERP registro eksportą (CSV — Rivilė GAMA, B1.lt, Microsoft Dynamics 365 Business Central ar bet kuri kita sistema; laukai atpažįstami automatiškai). Kiekviena sąskaita konvertuojama į Peppol BIS 3.0, patikrinama trimis paketais ir supakuojama perdavimui." : "Automate generation and compliance straight from your ERP: run the whole SAF-T sales ledger, or upload an ERP register export (CSV — Rivilė GAMA, B1.lt, Microsoft Dynamics 365 Business Central or any other; fields auto-detected). Every invoice is converted to Peppol BIS 3.0, validated by the three packs and bundled for transmission."}</p>
      <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center", marginBottom: 12 }}>
        <button onClick={() => runBatch({ kind: "saft", parsed: fileData.parsed })} disabled={batchBusy || sales.length === 0} style={btnP(batchBusy || sales.length === 0)}>{batchBusy ? "…" : (lang === "lt" ? `Iš SAF-T (${sales.length})` : `From SAF-T (${sales.length})`)} →</button>
        <span style={{ color: "#555", fontFamily: "var(--m)", fontSize: 10 }}>{lang === "lt" ? "ARBA" : "OR"}</span>
        <label style={btnG()}>↑ CSV{csvInfo ? ` · ${csvInfo.mapRes.invoices.length}` : ""}<input type="file" accept=".csv,.txt" onChange={onCsv} style={{ display: "none" }} /></label>
        <select value={csvProfile} onChange={(e) => remap(e.target.value)} style={{ background: "#000", border: `1px solid ${LINE}`, color: "#fff", fontFamily: "var(--m)", fontSize: 11, padding: "8px 10px" }}>
          <option value="auto">{lang === "lt" ? "Profilis: auto" : "Profile: auto"}</option>
          {ERP_PROFILES.map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        {csvInfo && <button onClick={() => runBatch({ kind: "rows", rows: csvInfo.mapRes.invoices, seller: sellerFromSaft() })} disabled={batchBusy || !csvInfo.mapRes.invoices.length} style={btnP(batchBusy || !csvInfo.mapRes.invoices.length)}>{lang === "lt" ? "Vykdyti CSV →" : "Run CSV →"}</button>}
      </div>
      {csvInfo && <div style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#9f9f9b", marginBottom: 10 }}>{(lang === "lt" ? "Profilis: " : "Profile: ") + csvInfo.mapRes.profile.name + " · " + Object.entries(csvInfo.mapRes.mapping).map(([f, h]) => `${f}→${h}`).join(" · ")}{csvInfo.mapRes.skipped ? ` · ${lang === "lt" ? "praleista" : "skipped"} ${csvInfo.mapRes.skipped}` : ""}</div>}
      {batch && <>
        <div style={{ display: "flex", gap: 18, flexWrap: "wrap", margin: "6px 0 10px" }}>
          {[[lang === "lt" ? "Iš viso" : "Total", batch.summary.total, "#fff"], ["Peppol-ready", batch.summary.ready, "#69db7c"], ["EN 16931", batch.summary.enValid, "#7cc4ff"], [lang === "lt" ? "Blokuota" : "Blocked", batch.summary.blocked, batch.summary.blocked ? "#ff6b6b" : "#69db7c"]].map(([lb, v, c]) => <div key={lb}><div style={{ fontSize: 9.5, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase" }}>{lb}</div><div style={{ fontSize: 24, color: c, fontFamily: "var(--f)", fontWeight: 300 }}>{v}</div></div>)}
          <button onClick={dlZip} style={{ ...btnP(false), marginLeft: "auto", alignSelf: "center" }}>↓ ZIP ({lang === "lt" ? "XML + manifestas + CSV" : "XML + manifest + CSV"})</button>
        </div>
        <div style={{ maxHeight: 260, overflowY: "auto", border: "1px solid rgba(255,255,255,0.07)" }}>
          {batch.results.slice(0, 300).map((r, i) => <div key={i} style={{ display: "flex", gap: 10, alignItems: "baseline", padding: "6px 10px", borderBottom: "1px solid rgba(255,255,255,0.05)", flexWrap: "wrap" }}>
            <span style={{ color: r.ready ? "#69db7c" : "#ff6b6b", fontFamily: "var(--m)", fontWeight: 700, minWidth: 14 }}>{r.ready ? "✓" : "✕"}</span>
            <span style={{ fontFamily: "var(--m)", fontSize: 11.5, color: "#fff", minWidth: 110 }}>{r.invoiceNo}</span>
            <span style={{ fontFamily: "var(--s)", fontSize: 12, color: "#bcbcb8", minWidth: 160 }}>{r.buyer}</span>
            <span style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#8c8c88" }}>{r.cat} {r.rate}% · {r.payable} EUR</span>
            {!r.ready && <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#ffa94d" }}>{r.findings.slice(0, 2).map((f) => f.rule_id).join(", ")}{r.findings.length > 2 ? "…" : ""}</span>}
          </div>)}
        </div>
        <div style={{ fontFamily: "var(--s)", fontSize: 11.5, color: "#8c8c88", marginTop: 10, lineHeight: 1.6 }}>{lang === "lt" ? "Perdavimas: paruoštus XML įkelkite į „E. sąskaita“ portalą (B2G), perduokite per savo Peppol prieigos tašką arba siųskite pirkėjui kartu su PDF. Manifeste — kiekvieno failo vartai, radiniai ir SHA-256 maišos." : "Transmission: upload the ready XML to the E. saskaita portal (B2G), hand over via your Peppol Access Point, or send to the buyer alongside the PDF. The manifest carries each file\u2019s gates, findings and SHA-256 hashes."}</div>
      </>}
      <details style={{ marginTop: 14 }}>
        <summary style={{ cursor: "pointer", fontFamily: "var(--m)", fontSize: 10.5, color: "#8c8c88", letterSpacing: ".08em", textTransform: "uppercase" }}>{lang === "lt" ? "Įterpimas į ERP (SDK)" : "Embed in your ERP (SDK)"}</summary>
        <pre style={{ background: "#000", border: `1px solid ${LINE}`, padding: 12, fontFamily: "var(--m)", fontSize: 10.5, color: "#9fd29f", overflowX: "auto", marginTop: 8 }}>{"// window.TaxAI (kai TaxAI atidarytas tame pačiame lange / iframe)\nconst r = TaxAI.einvoice.generate(\n  { invoiceNo: \"S-1\", invoiceDate: \"2026-06-01\", customerName: \"UAB X\",\n    customerCode: \"123456786\", country: \"LT\", net: 1000, rate: 21 },\n  { name: \"Mano UAB\", registrationNumber: \"123456786\", taxRegistrationNumber: \"LT123456786\" });\n// r.xml · r.gate → { en, peppol, lt } · r.findings\n\n// postMessage (iš ERP iframe):\nparent.postMessage({ type: \"taxai:einvoice-validate\", id: 1, xml: ublXml }, \"*\");\nwindow.addEventListener(\"message\", (e) => { if (e.data.type === \"taxai:result\") console.log(e.data); });"}</pre>
      </details>
    </div>
  </div>;
}

// ── Knowledge Bank: Confluence-style wiki (pages · templates · tasks · files) ──
function KnowledgeBank({ lang, setToast, audit }) {
  const LINE = "rgba(255,255,255,0.12)";
  const KB_STATUS = { draft: [lang === "lt" ? "Juodraštis" : "Draft", "#8c8c88"], review: [lang === "lt" ? "Peržiūrima" : "In review", "#ffd43b"], approved: [lang === "lt" ? "Patvirtinta" : "Approved", "#69db7c"] };
  const seed = () => {
    const w = kbNewPage({ title: lang === "lt" ? "Žinių bankas — pradžia" : "Knowledge Bank — start", template: "blank", author: "TaxAI" });
    w.icon = "▤";
    w.content = (lang === "lt"
      ? "# Sveiki atvykę į Žinių banką\n\n[[TOC]]\n\nViskas saugoma **šioje naršyklėje** (puslapiai — localStorage, failai — IndexedDB).\n\n## Galimybės\n- Šablonai (ataskaitos, kursai, SOP), medis su vaikais, etiketės, ★, komentarai, versijos\n- Vidinės nuorodos: [[PVM 2026 atmintinė]] — spustelėkite!\n- Rašydami spauskite **/** eilutės pradžioje — greitasis meniu\n\n::: info\nPanelės: ::: info / warn / success / note — kaip Confluence makrokomandos.\n:::\n\n## Pabandykite\n- [ ] Sukurti puslapį iš šablono (+)\n- [ ] Įterpti panelę per /\n- [ ] Pažymėti šią užduotį"
      : "# Welcome to the Knowledge Bank\n\n[[TOC]]\n\nEverything stays **in this browser** (pages in localStorage, files in IndexedDB).\n\n## Features\n- Templates (reports, courses, SOPs), page tree, labels, ★, comments, versions\n- Wiki links: [[PVM 2026 atmintinė]] — click it!\n- Press **/** at a line start while editing — quick insert menu\n\n::: info\nPanels: ::: info / warn / success / note — Confluence-style macros.\n:::\n\n## Try it\n- [ ] Create a page from a template (+)\n- [ ] Insert a panel via /\n- [ ] Tick this task");
    const v = kbNewPage({ title: "PVM 2026 atmintinė", template: "vat-memo", author: "TaxAI" });
    return [w, v];
  };
  const [pages, setPages] = useState(() => { try { const raw = localStorage.getItem("taxai_kb_pages"); if (raw) { const p = JSON.parse(raw); if (Array.isArray(p) && p.length) return p; } } catch (e) {} return seed(); });
  const [sel, setSel] = useState(null);
  const [tab, setTab] = useState("pages");
  const [mode, setMode] = useState("view");
  const [draft, setDraft] = useState({ title: "", content: "" });
  const [q, setQ] = useState("");
  const [creating, setCreating] = useState(null);
  const [newTitle, setNewTitle] = useState("");
  const [newTpl, setNewTpl] = useState("blank");
  const [customTpls, setCustomTpls] = useState(() => { try { return JSON.parse(localStorage.getItem("taxai_kb_templates") || "[]"); } catch (e) { return []; } });
  const [labelIn, setLabelIn] = useState("");
  const [commentIn, setCommentIn] = useState("");
  const [showHist, setShowHist] = useState(false);
  const [moving, setMoving] = useState(false);
  const [slashOpen, setSlashOpen] = useState(false);
  const [collapsed, setCollapsed] = useState(() => { try { return JSON.parse(localStorage.getItem("taxai_kb_collapsed") || "[]"); } catch (e) { return []; } });
  const [atts, setAtts] = useState([]);
  const [todos, setTodos] = useState(() => { try { return JSON.parse(localStorage.getItem("taxai_kb_todos") || "[]"); } catch (e) { return []; } });
  const [todoIn, setTodoIn] = useState("");
  const [user, setUser] = useState(() => { try { return localStorage.getItem("taxai_kb_user") || ""; } catch (e) { return ""; } });
  const taRef = useRef(null);
  const viewRef = useRef(null);
  useEffect(() => { try { localStorage.setItem("taxai_kb_pages", JSON.stringify(pages)); } catch (e) {} }, [pages]);
  useEffect(() => { try { localStorage.setItem("taxai_kb_todos", JSON.stringify(todos)); } catch (e) {} }, [todos]);
  useEffect(() => { try { localStorage.setItem("taxai_kb_user", user); } catch (e) {} }, [user]);
  useEffect(() => { try { localStorage.setItem("taxai_kb_templates", JSON.stringify(customTpls)); } catch (e) {} }, [customTpls]);
  useEffect(() => { try { localStorage.setItem("taxai_kb_collapsed", JSON.stringify(collapsed)); } catch (e) {} }, [collapsed]);
  const page = pages.find((p) => p.id === sel) || pages[0] || null;
  useEffect(() => { let dead = false; setAtts([]); if (page) kbIdb.byPage(page.id).then((x) => { if (!dead) setAtts(x); }).catch(() => {}); return () => { dead = true; }; }, [sel, pages.length]);
  const dirty = mode === "edit" && page && (draft.content !== page.content || draft.title !== page.title);
  const goPage = (id) => { if (dirty && !window.confirm(lang === "lt" ? "Yra neišsaugotų pakeitimų. Tęsti be išsaugojimo?" : "Unsaved changes. Continue without saving?")) return; setSel(id); setMode("view"); setTab("pages"); setShowHist(false); setMoving(false); };
  const upd = (id, fn, hist) => setPages((ps) => ps.map((p) => { if (p.id !== id) return p; const c = { ...p }; if (hist) kbPushHistory(c); fn(c); c.updated = Date.now(); return c; }));
  const kids = (pid) => pages.filter((p) => p.parentId === pid).sort((x, y) => x.created - y.created);
  const crumbs = (p) => { const out = []; let cur = p, g = 0; while (cur && g++ < 12) { out.unshift(cur); cur = pages.find((x) => x.id === cur.parentId); } return out; };
  const startEdit = () => { if (!page) return; setDraft({ title: page.title, content: page.content }); setMode("edit"); };
  const save = () => { if (!page) return; upd(page.id, (c) => { c.title = draft.title || c.title; c.content = draft.content; if (user) c.author = c.author || user; }, true); setMode("view"); setToast && setToast(lang === "lt" ? "Išsaugota" : "Saved"); audit && audit.log("KB_SAVE", draft.title); };
  const create = () => { const all = kbAllTemplates(customTpls); const tt = all.find((x) => x.id === newTpl); const np = kbNewPage({ title: newTitle.trim(), parentId: creating && creating.parentId, template: tt && !tt.custom ? newTpl : "blank", author: user }); if (tt && tt.custom) { np.content = tt.content; np.icon = tt.icon; if (!newTitle.trim()) np.title = tt.lt; } setPages((ps) => [...ps, np]); setSel(np.id); setCreating(null); setNewTitle(""); setMode("edit"); setDraft({ title: np.title, content: np.content }); setTab("pages"); audit && audit.log("KB_CREATE", np.title); };
  const removePage = () => { if (!page) return; const ids = [page.id].concat(kbDescendants(pages, page.id)); if (!window.confirm((lang === "lt" ? "Ištrinti puslapį" : "Delete page") + " „" + page.title + "“" + (ids.length > 1 ? " (+" + (ids.length - 1) + ")" : "") + "?")) return; ids.forEach((pid) => { kbIdb.byPage(pid).then((x) => x.forEach((y) => kbIdb.del(y.id))).catch(() => {}); }); setPages((ps) => ps.filter((p) => !ids.includes(p.id))); setSel(null); };
  const dl = (name, content, type) => { const bl = new Blob([content], { type: type || "text/plain" }); const u = URL.createObjectURL(bl); const el = document.createElement("a"); el.href = u; el.download = name; el.click(); setTimeout(() => URL.revokeObjectURL(u), 30000); };
  const onAttach = (e) => { const fs2 = Array.from(e.target.files || []); fs2.forEach((f) => { const rec = { id: kbUid() + "_a", pageId: page.id, name: f.name, type: f.type, size: f.size, blob: f, ts: Date.now() }; kbIdb.put(rec).then((ok) => { if (ok) setAtts((x) => [...x, rec]); else setToast && setToast("IndexedDB unavailable"); }).catch(() => setToast && setToast("Attach failed")); }); e.target.value = ""; };
  const openAtt = (x) => { const u = URL.createObjectURL(x.blob); const el = document.createElement("a"); el.href = u; el.download = x.name; el.click(); setTimeout(() => URL.revokeObjectURL(u), 30000); };
  const insertMd = (before, after) => { const ta = taRef.current; if (!ta) { setDraft((d) => ({ ...d, content: d.content + before + (after || "") })); return; } const s = ta.selectionStart, e = ta.selectionEnd, v = draft.content; const st = v.slice(s, e); setDraft((d) => ({ ...d, content: v.slice(0, s) + before + st + (after || "") + v.slice(e) })); setTimeout(() => { ta.focus(); ta.selectionStart = ta.selectionEnd = s + before.length + st.length + (after || "").length; }, 0); };
  const toggleTaskOnPage = (pid, idx) => upd(pid, (c) => { c.content = kbToggleTask(c.content, idx); }, false);
  const wikiClick = (e) => {
    const aEl = e.target && e.target.closest ? e.target.closest("a") : null;
    const href = aEl && aEl.getAttribute("href");
    if (!href || href.indexOf("#kb=") !== 0) return;
    e.preventDefault(); e.stopPropagation();
    const title = decodeURIComponent(href.slice(4));
    const hit = pages.find((p) => cpNorm(p.title) === cpNorm(title));
    if (hit) goPage(hit.id);
    else if (window.confirm((lang === "lt" ? "Puslapio nėra. Sukurti" : "Page not found. Create") + " „" + title + "“?")) { const np = kbNewPage({ title, template: "blank", author: user }); setPages((ps) => [...ps, np]); goPage(np.id); }
  };
  const scrollToHeading = (text) => { const root = viewRef.current; if (!root) return; const el = Array.prototype.slice.call(root.querySelectorAll("h1,h2,h3")).find((h) => h.textContent.trim() === text); if (el) el.scrollIntoView({ behavior: "smooth", block: "start" }); };
  const renderLines = (lines, baseKey, pid, ctr) => {
    const out = []; let buf = [];
    const flush = () => { if (buf.length) { out.push(<div key={baseKey + "m" + out.length}><Md text={kbResolveWikiLinks(buf.join("\n"))} /></div>); buf = []; } };
    for (let li = 0; li < lines.length; li++) {
      const line = lines[li];
      const pm = /^:::\s*(info|warn|success|note)\s*$/.exec(line.trim());
      if (pm) {
        flush(); const inner = []; li++;
        while (li < lines.length && !/^:::\s*$/.test(lines[li].trim())) { inner.push(lines[li]); li++; }
        const [c, ic] = KB_PANELS[pm[1]];
        out.push(<div key={baseKey + "p" + out.length} style={{ border: `1px solid ${LINE}`, borderLeft: `3px solid ${c}`, background: "rgba(255,255,255,0.03)", padding: "10px 16px", margin: "10px 0" }}><span style={{ color: c, fontFamily: "var(--m)", fontSize: 11, marginRight: 8 }}>{ic}</span>{renderLines(inner, baseKey + "p" + out.length + "_", pid, ctr)}</div>);
        continue;
      }
      if (/^\s*\[\[TOC\]\]\s*$/i.test(line)) {
        flush(); const toc = kbToc(page.content);
        out.push(<div key={baseKey + "toc" + out.length} style={{ border: `1px solid ${LINE}`, padding: "10px 16px", margin: "10px 0" }}>
          <div style={{ fontFamily: "var(--m)", fontSize: 9.5, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 6 }}>{lang === "lt" ? "Turinys" : "Contents"}</div>
          {toc.map((tt, k) => <div key={k} style={{ paddingLeft: (tt.level - 1) * 14 }}><span onClick={() => scrollToHeading(tt.text)} style={{ cursor: "pointer", color: "#7cc4ff", fontFamily: "var(--s)", fontSize: 12.5 }}>{tt.text}</span></div>)}
        </div>);
        continue;
      }
      const m = /^\s*[-*] \[( |x|X)\] (.*)$/.exec(line);
      if (m) { flush(); const i = ctr.i++; const done = m[1] !== " "; out.push(<label key={baseKey + "t" + i} style={{ display: "flex", gap: 9, alignItems: "baseline", padding: "3px 0", cursor: "pointer", fontFamily: "var(--s)", fontSize: 14, color: done ? "#7a7a76" : "#e8e8e4", textDecoration: done ? "line-through" : "none" }}><input type="checkbox" checked={done} onChange={() => toggleTaskOnPage(pid, i)} style={{ accentColor: "#7cc4ff" }} /><span onClickCapture={wikiClick}><Md text={kbResolveWikiLinks(m[2])} /></span></label>); continue; }
      buf.push(line);
    }
    flush();
    return out;
  };
  const btn = { padding: "7px 13px", border: `1px solid ${LINE}`, background: "transparent", color: "#d2d2ce", fontFamily: "var(--m)", fontSize: 10, fontWeight: 700, letterSpacing: ".07em", textTransform: "uppercase", cursor: "pointer" };
  const btnS = { ...btn, background: "#fff", color: "#000", border: "1px solid #fff" };
  const inp = { background: "#000", border: `1px solid ${LINE}`, color: "#fff", fontFamily: "var(--s)", fontSize: 13, padding: "8px 11px", outline: "none" };
  const tasks = kbCollectTasks(pages);
  const results = q.trim() ? kbSearch(pages, q) : null;
  const stats = page ? kbTaskStats(page.content) : { open: 0, done: 0, total: 0 };
  const backlinks = page ? kbBacklinks(pages, page) : [];
  const flatRow = (p) => <div key={p.id} onClick={() => goPage(p.id)} style={{ display: "flex", gap: 7, alignItems: "center", padding: "4px 14px", cursor: "pointer", fontFamily: "var(--s)", fontSize: 12, color: "#bcbcb8" }} onMouseEnter={(e) => e.currentTarget.style.background = "rgba(255,255,255,0.04)"} onMouseLeave={(e) => e.currentTarget.style.background = "transparent"}><span style={{ fontSize: 11 }}>{p.icon || "▢"}</span><span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.title}</span></div>;
  const Row = ({ p, depth }) => {
    const ch = kids(p.id); const isCol = collapsed.includes(p.id); const ts2 = kbTaskStats(p.content);
    const active = page && page.id === p.id && tab === "pages";
    return <div>
      <div onClick={() => goPage(p.id)} style={{ display: "flex", gap: 6, alignItems: "center", padding: "6px 10px", paddingLeft: 8 + depth * 13, cursor: "pointer", background: active ? "var(--bg2)" : "transparent", borderLeft: active ? "2px solid #7cc4ff" : "2px solid transparent" }}
        onMouseEnter={(e) => { if (!active) e.currentTarget.style.background = "rgba(255,255,255,0.04)"; }} onMouseLeave={(e) => { if (!active) e.currentTarget.style.background = "transparent"; }}>
        <span onClick={(e) => { e.stopPropagation(); if (ch.length) setCollapsed((c) => c.includes(p.id) ? c.filter((x) => x !== p.id) : [...c, p.id]); }} style={{ width: 12, fontFamily: "var(--m)", fontSize: 9, color: "#666", cursor: ch.length ? "pointer" : "default" }}>{ch.length ? (isCol ? "▸" : "▾") : ""}</span>
        <span style={{ fontSize: 12 }}>{p.icon || "▢"}</span>
        <span style={{ fontFamily: "var(--s)", fontSize: 12.5, color: "#e8e8e4", flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.title}</span>
        {p.status && KB_STATUS[p.status] && <span title={KB_STATUS[p.status][0]} style={{ width: 7, height: 7, borderRadius: "50%", background: KB_STATUS[p.status][1] }} />}
        {ts2.open > 0 && <span style={{ fontFamily: "var(--m)", fontSize: 8.5, color: "#7cc4ff" }}>{ts2.open}☐</span>}
        {p.fav && <span style={{ fontSize: 10, color: "#ffd43b" }}>★</span>}
        <span title={lang === "lt" ? "Naujas vaiko puslapis" : "New child page"} onClick={(e) => { e.stopPropagation(); setCreating({ parentId: p.id }); setNewTpl("blank"); setNewTitle(""); }} style={{ fontFamily: "var(--m)", fontSize: 11, color: "#8c8c88", padding: "0 3px" }}>+</span>
      </div>
      {!isCol && ch.map((k) => <Row key={k.id} p={k} depth={depth + 1} />)}
    </div>;
  };
  const onBackup = () => dl("taxai-kb-backup.json", JSON.stringify({ exportedAt: new Date().toISOString(), pages, todos }, null, 2), "application/json");
  const onImport = (e) => {
    Array.from(e.target.files || []).forEach((f) => {
      const r = new FileReader();
      r.onload = (ev) => {
        const txt = String(ev.target.result || "");
        try {
          if (/\.json$/i.test(f.name)) {
            const data = JSON.parse(txt);
            const res = kbMergeBackup(pages, (data && data.pages) || []);
            setPages(res.pages);
            if (data && Array.isArray(data.todos)) setTodos((t0) => kbMergeBackup(t0.map(x => ({...x, updated: 0})), data.todos.map(x => ({...x, updated: 1}))).pages);
            setToast && setToast((lang === "lt" ? "Importuota: +" : "Imported: +") + res.added + " · ↻" + res.updated);
          } else {
            const np = kbNewPage({ title: kbTitleFromMd(txt, f.name), template: "blank", author: user, content: txt });
            setPages((ps) => [...ps, np]); goPage(np.id);
          }
        } catch (err) { setToast && setToast("Import: " + String(err && err.message || err).slice(0, 90)); }
      };
      r.readAsText(f);
    });
    e.target.value = "";
  };
  const onTaKey = (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === "s") { e.preventDefault(); save(); return; }
    if (e.key === "Escape") { e.preventDefault(); if (slashOpen) setSlashOpen(false); else setMode("view"); return; }
    if (e.key === "/") { const ta = e.currentTarget; const v = ta.value, s = ta.selectionStart; if (s === 0 || v[s - 1] === "\n") { e.preventDefault(); setSlashOpen(true); } }
  };
  return <div style={{ display: "flex", height: "100%", overflow: "hidden" }}>
    <div style={{ width: 272, flexShrink: 0, borderRight: `1px solid ${LINE}`, display: "flex", flexDirection: "column", background: "rgba(255,255,255,0.015)" }}>
      <div style={{ padding: "16px 14px 10px" }}>
        <div style={{ fontFamily: "var(--m)", fontSize: 10, letterSpacing: ".18em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 10 }}>▤ {lang === "lt" ? "Žinių bankas" : "Knowledge Bank"}</div>
        <input value={q} onChange={(e) => setQ(e.target.value)} placeholder={lang === "lt" ? "Ieškoti…" : "Search…"} style={{ ...inp, width: "100%", boxSizing: "border-box", fontSize: 12, padding: "7px 10px" }} />
      </div>
      <div onClick={() => { if (!dirty || window.confirm(lang === "lt" ? "Yra neišsaugotų pakeitimų. Tęsti?" : "Unsaved changes. Continue?")) { setTab("tasks"); setMode("view"); } }} style={{ display: "flex", gap: 8, alignItems: "center", padding: "7px 14px", cursor: "pointer", background: tab === "tasks" ? "var(--bg2)" : "transparent", borderLeft: tab === "tasks" ? "2px solid #69db7c" : "2px solid transparent", fontFamily: "var(--s)", fontSize: 12.5, color: "#e8e8e4" }}>✓ {lang === "lt" ? "Užduotys" : "Tasks"} <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88" }}>{tasks.filter((t) => !t.done).length + todos.filter((t) => !t.done).length}</span></div>
      <div style={{ flex: 1, overflowY: "auto", paddingBottom: 10 }}>
        {results ? <div style={{ padding: "4px 0" }}>
          {results.length === 0 && <div style={{ padding: "8px 14px", color: "#8c8c88", fontFamily: "var(--s)", fontSize: 12 }}>{lang === "lt" ? "Nieko nerasta." : "No matches."}</div>}
          {results.map((r) => <div key={r.page.id} onClick={() => goPage(r.page.id)} style={{ padding: "7px 14px", cursor: "pointer" }} onMouseEnter={(e) => e.currentTarget.style.background = "rgba(255,255,255,0.05)"} onMouseLeave={(e) => e.currentTarget.style.background = "transparent"}>
            <div style={{ fontFamily: "var(--s)", fontSize: 12.5, color: "#fff" }}>{r.page.icon} {r.page.title}</div>
            <div style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#8c8c88" }}>{r.hits} {lang === "lt" ? "atitikmenys" : "matches"}{r.inTitle ? " · " + (lang === "lt" ? "pavadinime" : "in title") : ""}</div>
          </div>)}
        </div> : <>
          {pages.some((p) => p.fav) && <>
            <div style={{ padding: "8px 14px 2px", fontFamily: "var(--m)", fontSize: 9, letterSpacing: ".14em", color: "#666", textTransform: "uppercase" }}>★ {lang === "lt" ? "Mėgstami" : "Favourites"}</div>
            {pages.filter((p) => p.fav).slice(0, 8).map(flatRow)}
          </>}
          <div style={{ padding: "8px 14px 2px", fontFamily: "var(--m)", fontSize: 9, letterSpacing: ".14em", color: "#666", textTransform: "uppercase" }}>🕐 {lang === "lt" ? "Naujausi" : "Recent"}</div>
          {pages.slice().sort((x, y) => y.updated - x.updated).slice(0, 4).map(flatRow)}
          <div style={{ display: "flex", alignItems: "center", padding: "10px 14px 4px" }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 9, letterSpacing: ".14em", color: "#666", textTransform: "uppercase" }}>{lang === "lt" ? "Puslapiai" : "Pages"}</span>
            <button onClick={() => { setCreating({ parentId: null }); setNewTpl("blank"); setNewTitle(""); }} style={{ ...btn, marginLeft: "auto", padding: "3px 9px" }}>+</button>
          </div>
          {kids(null).map((p) => <Row key={p.id} p={p} depth={0} />)}
        </>}
      </div>
      <div style={{ padding: "10px 14px", borderTop: `1px solid ${LINE}`, display: "flex", flexDirection: "column", gap: 8 }}>
        <input value={user} onChange={(e) => setUser(e.target.value)} placeholder={lang === "lt" ? "Jūsų vardas (autorius)" : "Your name (author)"} style={{ ...inp, width: "100%", boxSizing: "border-box", fontSize: 11.5, padding: "6px 9px" }} />
        <div style={{ display: "flex", gap: 8 }}>
          <button onClick={onBackup} style={{ ...btn, flex: 1, padding: "5px 8px", fontSize: 9 }}>⤓ {lang === "lt" ? "Atsarginė" : "Backup"}</button>
          <label style={{ ...btn, flex: 1, padding: "5px 8px", fontSize: 9, textAlign: "center" }}>⤒ {lang === "lt" ? "Importas" : "Import"}<input type="file" multiple accept=".json,.md,.markdown,.txt" onChange={onImport} style={{ display: "none" }} /></label>
        </div>
      </div>
    </div>
    <div style={{ flex: 1, overflowY: "auto", padding: "22px 34px 60px" }}>
      {creating && <div style={{ border: `1px solid ${LINE}`, background: "var(--bg2)", padding: 18, marginBottom: 22, maxWidth: 780 }}>
        <div style={{ fontFamily: "var(--m)", fontSize: 10, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 10 }}>{lang === "lt" ? "Naujas puslapis" : "New page"}{creating.parentId ? " · " + (lang === "lt" ? "vaikas" : "child of") + " „" + ((pages.find((x) => x.id === creating.parentId) || {}).title || "") + "“" : ""}</div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          <input autoFocus value={newTitle} onChange={(e) => setNewTitle(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") create(); }} placeholder={lang === "lt" ? "Pavadinimas" : "Title"} style={{ ...inp, flex: "1 1 220px" }} />
          <select value={newTpl} onChange={(e) => setNewTpl(e.target.value)} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11.5 }}>
            {kbAllTemplates(customTpls).map((t) => <option key={t.id} value={t.id}>{t.icon} {lang === "lt" ? t.lt : t.en}{t.custom ? " ·" : ""}</option>)}
          </select>
          {(kbAllTemplates(customTpls).find((t) => t.id === newTpl) || {}).custom && <button onClick={() => { setCustomTpls((c) => c.filter((t) => t.id !== newTpl)); setNewTpl("blank"); }} style={{ ...btn, color: "#ff8a8a" }}>✕</button>}
          <button onClick={create} style={btnS}>{lang === "lt" ? "Sukurti" : "Create"}</button>
          <button onClick={() => setCreating(null)} style={btn}>{lang === "lt" ? "Atšaukti" : "Cancel"}</button>
        </div>
      </div>}
      {tab === "tasks" ? <div style={{ maxWidth: 820 }}>
        <h2 style={{ fontFamily: "var(--f)", fontWeight: 300, fontSize: 30, color: "#fff", margin: "0 0 6px" }}>✓ {lang === "lt" ? "Užduotys" : "Tasks"}</h2>
        <div style={{ fontFamily: "var(--s)", fontSize: 12.5, color: "#8c8c88", marginBottom: 20 }}>{lang === "lt" ? "Surinkta iš visų puslapių langelių + greitosios užduotys." : "Aggregated from every page's checkboxes + quick todos."}</div>
        <input value={todoIn} onChange={(e) => setTodoIn(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter" && todoIn.trim()) { setTodos((t) => [...t, { id: kbUid(), text: todoIn.trim(), done: false }]); setTodoIn(""); } }} placeholder={lang === "lt" ? "Greita užduotis… (Enter)" : "Quick todo… (Enter)"} style={{ ...inp, width: "100%", maxWidth: 460, boxSizing: "border-box", marginBottom: 14 }} />
        {todos.map((t) => <div key={t.id} style={{ display: "flex", gap: 9, alignItems: "baseline", padding: "4px 0" }}>
          <input type="checkbox" checked={t.done} onChange={() => setTodos((ts) => ts.map((x) => x.id === t.id ? { ...x, done: !x.done } : x))} style={{ accentColor: "#69db7c" }} />
          <span style={{ fontFamily: "var(--s)", fontSize: 13.5, color: t.done ? "#7a7a76" : "#e8e8e4", textDecoration: t.done ? "line-through" : "none", flex: 1 }}>{t.text}</span>
          <span onClick={() => setTodos((ts) => ts.filter((x) => x.id !== t.id))} style={{ cursor: "pointer", color: "#666", fontFamily: "var(--m)", fontSize: 11 }}>✕</span>
        </div>)}
        {tasks.length > 0 && <div style={{ fontFamily: "var(--m)", fontSize: 9.5, letterSpacing: ".14em", color: "#666", textTransform: "uppercase", margin: "20px 0 8px" }}>{lang === "lt" ? "Iš puslapių" : "From pages"}</div>}
        {tasks.map((t, i) => <div key={i} style={{ display: "flex", gap: 9, alignItems: "baseline", padding: "4px 0" }}>
          <input type="checkbox" checked={t.done} onChange={() => toggleTaskOnPage(t.pageId, t.idx)} style={{ accentColor: "#7cc4ff" }} />
          <span style={{ fontFamily: "var(--s)", fontSize: 13.5, color: t.done ? "#7a7a76" : "#e8e8e4", textDecoration: t.done ? "line-through" : "none", flex: 1 }}>{t.text}</span>
          <span onClick={() => goPage(t.pageId)} style={{ cursor: "pointer", color: "#7cc4ff", fontFamily: "var(--m)", fontSize: 10.5 }}>{t.pageTitle} →</span>
        </div>)}
      </div>
      : !page ? <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 13 }}>{lang === "lt" ? "Pasirinkite arba sukurkite puslapį." : "Select or create a page."}</div>
      : <div style={{ maxWidth: 920 }}>
        <div style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88", marginBottom: 10 }}>{crumbs(page).map((c, i, arr) => <span key={c.id}><span onClick={() => goPage(c.id)} style={{ cursor: "pointer", color: i === arr.length - 1 ? "#d2d2ce" : "#8c8c88" }}>{c.title}</span>{i < arr.length - 1 ? "  /  " : ""}</span>)}</div>
        <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap", marginBottom: 6 }}>
          {mode === "edit"
            ? <input value={draft.title} onChange={(e) => setDraft((d) => ({ ...d, title: e.target.value }))} onKeyDown={(e) => { if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === "s") { e.preventDefault(); save(); } }} style={{ ...inp, fontFamily: "var(--f)", fontSize: 26, fontWeight: 300, flex: "1 1 300px" }} />
            : <h2 style={{ fontFamily: "var(--f)", fontWeight: 300, fontSize: 32, color: "#fff", margin: 0, flex: "1 1 300px" }}>{page.icon} {page.title}</h2>}
          <span onClick={() => upd(page.id, (c) => { const order = [undefined, "draft", "review", "approved"]; c.status = order[(order.indexOf(c.status) + 1) % order.length]; }, false)} title={lang === "lt" ? "Būsena (spustelėkite)" : "Status (click)"} style={{ cursor: "pointer", fontFamily: "var(--m)", fontSize: 9.5, padding: "3px 10px", border: `1px solid ${page.status && KB_STATUS[page.status] ? KB_STATUS[page.status][1] : LINE}`, color: page.status && KB_STATUS[page.status] ? KB_STATUS[page.status][1] : "#666", letterSpacing: ".08em" }}>{page.status && KB_STATUS[page.status] ? KB_STATUS[page.status][0] : "—"}</span>
          <span onClick={() => upd(page.id, (c) => { c.fav = !c.fav; }, false)} style={{ cursor: "pointer", fontSize: 17, color: page.fav ? "#ffd43b" : "#555" }}>★</span>
          {mode === "view" ? <button onClick={startEdit} style={btnS}>{lang === "lt" ? "Redaguoti" : "Edit"}</button>
            : <><button onClick={save} style={btnS}>{lang === "lt" ? "Išsaugoti" : "Save"} ⌃S</button><button onClick={() => setMode("view")} style={btn}>Esc</button></>}
        </div>
        {stats.total > 0 && <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 8, maxWidth: 360 }}>
          <div style={{ flex: 1, height: 4, background: "rgba(255,255,255,0.08)" }}><div style={{ width: (100 * stats.done / stats.total) + "%", height: "100%", background: "#69db7c", transition: "width .3s" }} /></div>
          <span style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#8c8c88" }}>{stats.done}/{stats.total}</span>
        </div>}
        <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap", marginBottom: 16 }}>
          <span style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#666" }}>{new Date(page.updated).toISOString().slice(0, 10)}{page.author ? " · " + page.author : ""} · v{(page.history || []).length + 1}</span>
          {(page.labels || []).map((l) => <span key={l} style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#7cc4ff", border: `1px solid ${LINE}`, padding: "2px 8px" }}>#{l} <span onClick={() => upd(page.id, (c) => { c.labels = c.labels.filter((x) => x !== l); }, false)} style={{ cursor: "pointer", color: "#666" }}>×</span></span>)}
          <input value={labelIn} onChange={(e) => setLabelIn(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter" && labelIn.trim()) { const v = labelIn.trim().replace(/^#/, ""); upd(page.id, (c) => { if (!c.labels.includes(v)) c.labels = [...c.labels, v]; }, false); setLabelIn(""); } }} placeholder="#" style={{ ...inp, width: 84, fontSize: 10.5, padding: "3px 8px", fontFamily: "var(--m)" }} />
          <span style={{ flex: 1 }} />
          <button onClick={() => dl(page.title.replace(/[^\w.-]+/g, "_") + ".md", page.content, "text/markdown")} style={btn}>↓ MD</button>
          <button onClick={() => { const w = window.open("", "_blank"); if (w) { w.document.write(kbExportHTML(page, taxaiBrand().name)); w.document.close(); } else dl(page.title.replace(/[^\w.-]+/g, "_") + ".html", kbExportHTML(page, taxaiBrand().name), "text/html"); }} style={btn}>↓ HTML</button>
          <button onClick={() => { setCustomTpls((c) => [...c, { id: "custom_" + kbUid(), lt: page.title, en: page.title, icon: page.icon || "▢", content: page.content }]); setToast && setToast(lang === "lt" ? "Šablonas išsaugotas" : "Template saved"); }} style={btn} title={lang === "lt" ? "Išsaugoti kaip šabloną" : "Save as template"}>💾</button>
          <button onClick={() => { const np = kbNewPage({ title: page.title + (lang === "lt" ? " (kopija)" : " (copy)"), parentId: page.parentId, template: "blank", author: user }); np.content = page.content; np.icon = page.icon; np.labels = [...(page.labels || [])]; setPages((ps) => [...ps, np]); goPage(np.id); }} style={btn}>{lang === "lt" ? "Kopija" : "Copy"}</button>
          <button onClick={() => setMoving((m) => !m)} style={{ ...btn, color: moving ? "#7cc4ff" : "#d2d2ce" }}>⇥</button>
          <button onClick={() => setShowHist((s) => !s)} style={{ ...btn, color: showHist ? "#7cc4ff" : "#d2d2ce" }}>⟲ {(page.history || []).length}</button>
          <button onClick={removePage} style={{ ...btn, color: "#ff8a8a" }}>🗑</button>
        </div>
        {moving && <div style={{ border: `1px solid ${LINE}`, background: "var(--bg2)", padding: 12, marginBottom: 14, display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
          <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88", letterSpacing: ".1em" }}>{lang === "lt" ? "PERKELTI Į" : "MOVE TO"}</span>
          <select onChange={(e) => { const v = e.target.value || null; if (kbCanMove(pages, page.id, v)) { upd(page.id, (c) => { c.parentId = v; }, false); setMoving(false); } }} defaultValue={page.parentId || ""} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11.5 }}>
            <option value="">{lang === "lt" ? "(šaknis)" : "(root)"}</option>
            {pages.filter((p) => kbCanMove(pages, page.id, p.id)).map((p) => <option key={p.id} value={p.id}>{p.title}</option>)}
          </select>
        </div>}
        {showHist && (page.history || []).length > 0 && <div style={{ border: `1px solid ${LINE}`, background: "var(--bg2)", padding: 14, marginBottom: 16 }}>
          <div style={{ fontFamily: "var(--m)", fontSize: 9.5, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 8 }}>{lang === "lt" ? "Versijų istorija" : "Version history"}</div>
          {(page.history || []).map((h, i) => <div key={i} style={{ display: "flex", gap: 12, alignItems: "baseline", padding: "4px 0", fontFamily: "var(--m)", fontSize: 11, color: "#bcbcb8" }}>
            <span>{new Date(h.ts).toISOString().replace("T", " ").slice(0, 16)}</span><span style={{ flex: 1, color: "#8c8c88" }}>{h.title}</span>
            <span onClick={() => { if (window.confirm(lang === "lt" ? "Atkurti šią versiją?" : "Restore this version?")) { upd(page.id, (c) => { c.title = h.title; c.content = h.content; }, true); setShowHist(false); } }} style={{ cursor: "pointer", color: "#7cc4ff" }}>{lang === "lt" ? "Atkurti" : "Restore"}</span>
          </div>)}
        </div>}
        {mode === "edit" ? <div style={{ position: "relative" }}>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 8 }}>
            {[["B", "**", "**"], ["I", "*", "*"], ["H2", "\n## ", ""], ["•", "\n- ", ""], ["☐", "\n- [ ] ", ""], ["1.", "\n1. ", ""], ["⌗", "\n| A | B |\n|---|---|\n|  |  |\n", ""], ["</>", "\n```\n", "\n```\n"], ["[[", "[[", "]]"], ["―", "\n---\n", ""]].map(([lb, bb, aa]) => <button key={lb} onClick={() => insertMd(bb, aa)} style={{ ...btn, padding: "4px 9px", fontSize: 10 }}>{lb}</button>)}
            <span style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#666", alignSelf: "center" }}>/ {lang === "lt" ? "meniu eilutės pradžioje" : "menu at line start"}</span>
          </div>
          {slashOpen && <div style={{ position: "absolute", zIndex: 5, top: 38, left: 0, background: "#0a0a0a", border: `1px solid ${LINE}`, boxShadow: "0 10px 30px rgba(0,0,0,0.6)", width: 250, maxHeight: 280, overflowY: "auto" }}>
            {KB_SLASH.map((it, i) => <div key={i} onClick={() => { setSlashOpen(false); insertMd(it.snip === "" ? new Date().toISOString().slice(0, 10) : it.snip, ""); }} style={{ display: "flex", gap: 10, alignItems: "baseline", padding: "8px 12px", cursor: "pointer", fontFamily: "var(--s)", fontSize: 12.5, color: "#e8e8e4" }} onMouseEnter={(e) => e.currentTarget.style.background = "var(--bg2)"} onMouseLeave={(e) => e.currentTarget.style.background = "transparent"}><span style={{ fontFamily: "var(--m)", fontSize: 11, width: 18 }}>{it.ic}</span>{lang === "lt" ? it.lt : it.en}</div>)}
          </div>}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(330px,1fr))", gap: 14 }}>
            <textarea ref={taRef} value={draft.content} onChange={(e) => setDraft((d) => ({ ...d, content: e.target.value }))} onKeyDown={onTaKey} spellCheck={false} style={{ ...inp, minHeight: 440, fontFamily: "var(--m)", fontSize: 12, lineHeight: 1.7, resize: "vertical" }} />
            <div onClickCapture={wikiClick} style={{ border: `1px solid ${LINE}`, padding: "4px 16px", minHeight: 440, overflowY: "auto" }}><Md text={kbResolveWikiLinks(draft.content)} /></div>
          </div>
          <div style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#666", marginTop: 6 }}>{(draft.content.trim().split(/\s+/).filter(Boolean)).length} {lang === "lt" ? "ž." : "words"} · {draft.content.length} {lang === "lt" ? "simb." : "chars"} · ~{Math.max(1, Math.ceil((draft.content.trim().split(/\s+/).filter(Boolean)).length / 200))} min</div>
        </div> : <div ref={viewRef} onClickCapture={wikiClick}>{renderLines(String(page.content || "").split("\n"), "r", page.id, { i: 0 })}</div>}
        {backlinks.length > 0 && <div style={{ marginTop: 26, borderTop: `1px solid ${LINE}`, paddingTop: 12 }}>
          <div style={{ fontFamily: "var(--m)", fontSize: 9.5, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 6 }}>🔗 {lang === "lt" ? "Nuorodos į šį puslapį" : "Linked from"} ({backlinks.length})</div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>{backlinks.map((b2) => <span key={b2.id} onClick={() => goPage(b2.id)} style={{ cursor: "pointer", fontFamily: "var(--s)", fontSize: 12, color: "#7cc4ff", border: `1px solid ${LINE}`, padding: "3px 10px" }}>{b2.icon} {b2.title}</span>)}</div>
        </div>}
        <div style={{ marginTop: 26, borderTop: `1px solid ${LINE}`, paddingTop: 14 }}>
          <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 8 }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 9.5, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase" }}>📎 {lang === "lt" ? "Priedai" : "Attachments"} ({atts.length})</span>
            <label style={{ ...btn, padding: "4px 10px" }}>+ {lang === "lt" ? "Failas" : "File"}<input type="file" multiple onChange={onAttach} style={{ display: "none" }} /></label>
            <span style={{ fontFamily: "var(--s)", fontSize: 10.5, color: "#666" }}>{lang === "lt" ? "IndexedDB — tinka ir knygoms." : "IndexedDB — books welcome."}</span>
          </div>
          {atts.map((x) => <div key={x.id} style={{ display: "flex", gap: 10, alignItems: "baseline", padding: "3px 0", fontFamily: "var(--m)", fontSize: 11, color: "#bcbcb8" }}>
            <span style={{ color: "#fff" }}>{x.name}</span><span style={{ color: "#666" }}>{(x.size / 1024).toFixed(0)} KB</span>
            <span onClick={() => openAtt(x)} style={{ cursor: "pointer", color: "#7cc4ff" }}>↓</span>
            <span onClick={() => { kbIdb.del(x.id); setAtts((y) => y.filter((z) => z.id !== x.id)); }} style={{ cursor: "pointer", color: "#666" }}>✕</span>
          </div>)}
        </div>
        <div style={{ marginTop: 22, borderTop: `1px solid ${LINE}`, paddingTop: 14, maxWidth: 720 }}>
          <div style={{ fontFamily: "var(--m)", fontSize: 9.5, letterSpacing: ".14em", color: "#8c8c88", textTransform: "uppercase", marginBottom: 8 }}>💬 {lang === "lt" ? "Komentarai" : "Comments"} ({(page.comments || []).length})</div>
          {(page.comments || []).map((c) => <div key={c.id} style={{ padding: "6px 0", borderBottom: "1px solid rgba(255,255,255,0.06)" }}>
            <div style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#8c8c88" }}>{c.author || "—"} · {new Date(c.ts).toISOString().slice(0, 16).replace("T", " ")} <span onClick={() => upd(page.id, (x) => { x.comments = x.comments.filter((y) => y.id !== c.id); }, false)} style={{ cursor: "pointer", color: "#555" }}>✕</span></div>
            <div style={{ fontFamily: "var(--s)", fontSize: 13, color: "#e8e8e4" }}>{c.text}</div>
          </div>)}
          <input value={commentIn} onChange={(e) => setCommentIn(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter" && commentIn.trim()) { upd(page.id, (c) => { c.comments = [...(c.comments || []), { id: kbUid() + "_c", author: user || "—", text: commentIn.trim(), ts: Date.now() }]; }, false); setCommentIn(""); } }} placeholder={lang === "lt" ? "Komentaras… (Enter)" : "Comment… (Enter)"} style={{ ...inp, width: "100%", boxSizing: "border-box", marginTop: 10 }} />
        </div>
      </div>}
    </div>
  </div>;
}

function MenuGroup({ label, children }) {
  return <details style={{ position: "relative" }}>
    <summary style={{ listStyle: "none", display: "inline-flex", alignItems: "center", gap: 7, padding: "8px 14px", border: "1px solid rgba(255,255,255,0.18)", color: "#fff", background: "transparent", fontFamily: "var(--m)", fontSize: 10.5, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer", userSelect: "none", whiteSpace: "nowrap" }}>{label}<span style={{ fontSize: 8, opacity: .7 }}>▼</span></summary>
    <div onClick={(e) => { const el = e.target; if (el && el.closest && el.closest("button")) e.currentTarget.parentElement.removeAttribute("open"); }} style={{ position: "absolute", top: "calc(100% + 6px)", right: 0, zIndex: 70, minWidth: 250, background: "#0a0a0a", border: "1px solid rgba(255,255,255,0.18)", boxShadow: "0 16px 44px rgba(0,0,0,0.65)", padding: 8, display: "flex", flexDirection: "column", alignItems: "stretch", gap: 6 }}>{children}</div>
  </details>;
}

function FindingDetail({ finding, lang, note, onSave, onBack, company, period }) {
  const PL_LINE = "rgba(255,255,255,0.12)", PL_SOFT = "rgba(255,255,255,0.06)";
  const L = (en, lt) => (lang === "lt" ? lt : en);
  const m = finding.ruleMeta || {};
  const CONF = findingConfidence(finding);
  const CONFc = CONF_COLOR[CONF.band];
  const SCc = { Critical: "#ff6b6b", High: "#ffa94d", Medium: "#ffd43b", Low: "#69db7c" }[finding.severity] || "#aaa";
  const [accord, setAccord] = useState(note?.disposition === "accordance");
  const [notAccord, setNotAccord] = useState(note?.disposition === "not");
  const [just, setJust] = useState(note?.justification || "");
  const [saved, setSaved] = useState(false);

  // parse the evidence row into field/value pairs (from the @field template)
  // Prefer the rendered fail message (human labels like "Operacija", "Sąskaita")
  // over raw hit-object keys (tx, rec, acct); fall back to the raw row.
  const labeledPairs = ((finding.evidence?.[0] || "").split("|").map((p) => { const ix = p.indexOf("="); return ix > -1 ? [p.slice(0, ix).trim(), p.slice(ix + 1).trim()] : null; }).filter(Boolean));
  const fields = labeledPairs.length ? labeledPairs
    : (finding.evidenceRow && typeof finding.evidenceRow === "object" ? Object.entries(finding.evidenceRow) : []);

  const disposition = accord ? "accordance" : notAccord ? "not" : null;
  const save = () => { onSave({ disposition, justification: just }); setSaved(true); setTimeout(() => setSaved(false), 2200); };
  const exportPaper = () => {
    const lines = [
      `AUDIT FINDING — ${finding.rule_id}`,
      company ? `Entity: ${company}` : "", period ? `Period: ${period}` : "", "",
      `Rule: ${lang === "lt" ? m.titleLt : m.titleEn}`,
      `Severity: ${finding.severity}    Category: ${finding.category}    Refers to: ${m.refType || "—"}`,
      `Legal basis: ${m.legal || "—"}`,
      `Confidence: ${CONF.score}% (${CONF.band}) — ${lang === "lt" ? CONF.basisLt : CONF.basisEn}`, "",
      `What the rule checks:`, (lang === "lt" ? m.descriptionLt : (m.descriptionEn || m.descriptionLt || "")) || "(see rule description)", "",
      `Flagged record:`, ...fields.map(([k, v]) => `  ${k} = ${v}`), "",
      `How to fix:`, ...(fixSteps(lang === "lt" ? (m.fixLt || m.fixEn) : (m.fixEn || m.fixLt)).map((s, ix) => `  ${ix + 1}. ${s}`)), "",
      `AUDITOR NOTE`,
      `In accordance: ${disposition === "accordance" ? "YES" : disposition === "not" ? "NO" : "(not set)"}`,
      `Justification: ${just || "(none)"}`,
      note?.updatedAt ? `Last updated: ${new Date(note.updatedAt).toLocaleString()}` : "",
    ].filter((x) => x !== "").join("\n");
    const blob = new Blob([lines], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a"); a.href = url; a.download = `finding-${finding.rule_id}.txt`; a.click();
  };

  const Field = ({ label, children }) => <div><div style={{ fontSize: 9.5, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase", marginBottom: 5 }}>{label}</div><div style={{ fontSize: 13.5, color: "#fff", fontFamily: "var(--s)" }}>{children}</div></div>;

  return (
    <div style={{ maxWidth: 980, margin: "0 auto" }}>
      <button onClick={onBack} style={{ display: "inline-flex", alignItems: "center", gap: 8, background: "none", border: `1px solid ${PL_LINE}`, color: "#d2d2ce", fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".06em", padding: "7px 14px", cursor: "pointer", textTransform: "uppercase", marginBottom: 18 }}>← {L("Back to findings", "Atgal į radinius")}</button>

      {/* breadcrumb + title */}
      <div style={{ fontFamily: "var(--m)", fontSize: 11, color: "#8c8c88", letterSpacing: ".08em", marginBottom: 10 }}>{L("AUDIT", "AUDITAS")} · {L("FINDING", "RADINYS")} · {finding.rule_id}</div>
      <h2 style={{ fontSize: 26, fontWeight: 300, color: "#fff", fontFamily: "var(--f)", lineHeight: 1.2, margin: "0 0 16px" }}>{lang === "lt" ? m.titleLt : (m.titleEn || finding.title)}</h2>

      {/* metadata row */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(150px,1fr))", gap: 18, padding: "16px 18px", border: `1px solid ${PL_LINE}`, background: "var(--bg2)", marginBottom: 18 }}>
        <Field label={L("Type", "Tipas")}>RulesFinding</Field>
        <Field label={L("Severity", "Reikšmingumas")}><span style={{ color: SCc, fontWeight: 600 }}>{finding.severity}</span></Field>
        <Field label={L("Category", "Kategorija")}>{finding.category}</Field>
        <Field label={L("Refers to", "Susiję su")}>{m.refType || "—"}</Field>
        <Field label={L("Data types", "Duomenų tipai")}>{m.dataTypes || "—"}</Field>
        <Field label={L("Confidence", "Pasitikėjimas")}><span style={{ color: CONFc, fontWeight: 700 }}>{CONF.score}%</span> <span style={{ color: "#8c8c88", fontSize: 11 }}>· {confBandLabel(CONF.band, lang)}</span></Field>
      </div>

      {/* what the rule checks */}
      <Section title={L("What this rule checks", "Ką tikrina ši taisyklė")}>
        <p style={{ fontSize: 13.5, color: "#d2d2ce", fontFamily: "var(--s)", lineHeight: 1.65, margin: 0 }}>{(lang === "lt" ? m.descriptionLt : (m.descriptionEn || m.descriptionLt)) || finding.title}</p>
        {m.legal && <div style={{ marginTop: 10, fontSize: 11.5, color: "#9ae6a4", fontFamily: "var(--m)" }}>§ {L("Legal basis", "Teisinis pagrindas")}: {m.legal}</div>}
      </Section>

      {/* what's flagged */}
      <Section title={L("What was flagged", "Kas pažymėta")} accent="#ff8a8a">
        {finding.evidence?.[0] ? <p style={{ fontSize: 12.5, color: "#ffc9c9", fontFamily: "var(--m)", lineHeight: 1.6, margin: "0 0 14px", wordBreak: "break-word" }}>{finding.evidence[0]}</p> : null}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))", gap: 14 }}>
          {fields.map(([k, v], i) => <div key={i} style={{ padding: "10px 12px", background: "#000", border: `1px solid ${PL_SOFT}` }}>
            <div style={{ fontSize: 9.5, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".08em", textTransform: "uppercase", marginBottom: 4 }}>{k}</div>
            <div style={{ fontSize: 14, color: "#fff", fontFamily: "var(--m)", wordBreak: "break-word" }}>{String(v)}</div>
          </div>)}
        </div>
        {finding.evidence && finding.evidence.length > 1 && <div style={{ marginTop: 16 }}>
          <div style={{ fontSize: 9.5, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase", marginBottom: 8 }}>{L("Affected records — drill down", "Pažymėti įrašai — detalizacija")} · {finding.evidence.length}</div>
          <div style={{ border: `1px solid ${PL_SOFT}`, background: "#000", maxHeight: 280, overflowY: "auto" }}>
            {finding.evidence.slice(0, 60).map((ev, i) => <div key={i} style={{ padding: "7px 12px", borderBottom: `1px solid ${PL_SOFT}`, fontFamily: "var(--m)", fontSize: 11, color: "#bcbcb8", lineHeight: 1.6, wordBreak: "break-word" }}>{typeof ev === "string" ? ev : JSON.stringify(ev)}</div>)}
          </div>
          {finding.evidence.length > 60 && <div style={{ fontSize: 10.5, color: "#8c8c88", fontFamily: "var(--m)", marginTop: 6 }}>{L(`+ ${finding.evidence.length - 60} more`, `+ dar ${finding.evidence.length - 60}`)}</div>}
        </div>}
      </Section>

      {/* how to fix — clear numbered steps, severity-aware */}
      <Section title={L("How to fix it", "Kaip ištaisyti")} accent="#7cc4ff">
        {(() => { const ex = explainFinding(finding, lang); return <>
          <div style={{ display: "inline-block", padding: "4px 10px", marginBottom: 12, border: `1px solid ${ex.urgent ? "#ff8a8a" : "#69db7c"}`, color: ex.urgent ? "#ff8a8a" : "#69db7c", fontFamily: "var(--m)", fontSize: 10, fontWeight: 700, letterSpacing: ".08em", textTransform: "uppercase" }}>{ex.lead}</div>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10, padding: "8px 12px", border: `1px solid ${PL_LINE}`, background: "#000", flexWrap: "wrap" }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88", letterSpacing: ".08em", textTransform: "uppercase" }}>{L("Confidence", "Pasitikėjimas")}</span>
            <span style={{ fontFamily: "var(--m)", fontSize: 13, fontWeight: 700, color: CONFc }}>{CONF.score}%</span>
            <div style={{ flex: 1, minWidth: 120, height: 4, background: "rgba(255,255,255,0.08)" }}><div style={{ height: 4, width: `${CONF.score}%`, background: CONFc }} /></div>
            <span style={{ fontFamily: "var(--s)", fontSize: 11.5, color: "#9f9f9b", flexBasis: "100%" }}>{lang === "lt" ? CONF.basisLt : CONF.basisEn}</span>
          </div>
          {m.legal && <div style={{ fontSize: 11.5, color: "#9ae6a4", fontFamily: "var(--m)", marginBottom: 12 }}>§ {L("Reference", "Nuoroda")}: {m.legal}</div>}
          {ex.how.length === 1
            ? <p style={{ fontSize: 13.5, color: "#e6e6e2", fontFamily: "var(--s)", lineHeight: 1.7, margin: 0 }}>{ex.how[0]}</p>
            : <ol style={{ margin: 0, paddingLeft: 22 }}>{ex.how.map((s, i) => <li key={i} style={{ fontSize: 13.5, color: "#e6e6e2", fontFamily: "var(--s)", lineHeight: 1.7, marginBottom: 6 }}>{s}</li>)}</ol>}
        </>; })()}
      </Section>

      {/* auditor note */}
      <div style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", padding: "18px 20px", marginTop: 18 }}>
        <div style={{ fontSize: 15, color: "#fff", fontFamily: "var(--f)", marginBottom: 14 }}>{L("Auditor note", "Auditoriaus pastaba")}</div>
        <div style={{ display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap", marginBottom: 14 }}>
          <span style={{ fontSize: 12.5, color: "#d2d2ce", fontFamily: "var(--s)" }}>{L("In accordance?", "Atitinka?")}</span>
          <button onClick={() => { setAccord(true); setNotAccord(false); }} style={{ padding: "6px 14px", border: `1px solid ${accord ? "#69db7c" : PL_LINE}`, background: accord ? "#69db7c" : "transparent", color: accord ? "#000" : "#69db7c", fontFamily: "var(--m)", fontSize: 11, fontWeight: 700, cursor: "pointer", textTransform: "uppercase", letterSpacing: ".06em" }}>✓ {L("Yes — in accordance", "Taip — atitinka")}</button>
          <button onClick={() => { setNotAccord(true); setAccord(false); }} style={{ padding: "6px 14px", border: `1px solid ${notAccord ? "#ff8a8a" : PL_LINE}`, background: notAccord ? "#ff8a8a" : "transparent", color: notAccord ? "#000" : "#ff8a8a", fontFamily: "var(--m)", fontSize: 11, fontWeight: 700, cursor: "pointer", textTransform: "uppercase", letterSpacing: ".06em" }}>✕ {L("No — needs action", "Ne — reikia veiksmų")}</button>
          {note?.updatedAt && <span style={{ marginLeft: "auto", fontSize: 10.5, color: "#8c8c88", fontFamily: "var(--m)" }}>{L("Last saved", "Išsaugota")}: {new Date(note.updatedAt).toLocaleString(lang === "lt" ? "lt-LT" : "en-GB")}</span>}
        </div>
        <div style={{ fontSize: 11, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".08em", textTransform: "uppercase", marginBottom: 6 }}>{L("Justification", "Pagrindimas")}</div>
        <textarea value={just} onChange={(e) => setJust(e.target.value)} placeholder={L("Record your reasoning, the documents reviewed, and any conclusion…", "Įrašykite savo argumentus, peržiūrėtus dokumentus ir išvadą…")} style={{ width: "100%", minHeight: 120, background: "#000", border: `1px solid ${PL_LINE}`, color: "#fff", fontFamily: "var(--s)", fontSize: 13, padding: "12px 14px", lineHeight: 1.6, resize: "vertical", outline: "none", boxSizing: "border-box" }} />
        <div style={{ display: "flex", gap: 12, marginTop: 14, alignItems: "center", flexWrap: "wrap" }}>
          <button onClick={save} style={{ background: "#fff", color: "#000", border: "none", padding: "9px 20px", fontSize: 11, fontWeight: 700, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" }}>{note?.updatedAt ? L("Update note", "Atnaujinti pastabą") : L("Save note", "Išsaugoti pastabą")}</button>
          <button onClick={exportPaper} style={{ background: "transparent", color: "#d2d2ce", border: `1px solid ${PL_LINE}`, padding: "9px 16px", fontSize: 11, fontWeight: 600, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" }}>↧ {L("Export working paper", "Eksportuoti darbo dokumentą")}</button>
          {saved && <span style={{ fontSize: 12, color: "#69db7c", fontFamily: "var(--m)" }}>✓ {L("Saved", "Išsaugota")}</span>}
        </div>
      </div>
    </div>
  );
}
function Section({ title, accent, children }) {
  const PL_LINE = "rgba(255,255,255,0.12)";
  return <div style={{ border: `1px solid ${PL_LINE}`, borderLeft: `3px solid ${accent || PL_LINE}`, background: "var(--bg2)", padding: "14px 18px", marginBottom: 14 }}>
    <div style={{ fontSize: 10.5, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase", marginBottom: 10 }}>{title}</div>
    {children}
  </div>;
}

// Compact, collapsible panel that shows how well an AI narrative is grounded
// in the deterministic results. Purely a transparency aid for the reviewer.
function DefensibilityPanel({ verification, lang }) {
  const [open, setOpen] = useState(false);
  const PL_LINE = "rgba(255,255,255,0.12)";
  if (!verification || !verification.claims?.length) return null;
  const { score, band, counts, claims, factCount } = verification;
  const C = { verified: "#69db7c", review: "#ffd43b", unsupported: "#ff8a8a" };
  const bandColor = score >= 80 ? "#69db7c" : score >= 60 ? "#ffd43b" : score >= 40 ? "#ffa94d" : "#ff8a8a";
  const L = (en, lt) => (lang === "lt" ? lt : en);
  const statusLabel = (s) => s === "verified" ? L("Verified", "Patvirtinta") : s === "review" ? L("Review", "Peržiūrėti") : L("Unsupported", "Nepagrįsta");
  return (
    <div style={{ marginTop: 22, border: `1px solid ${PL_LINE}`, background: "var(--bg2)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 16px", flexWrap: "wrap" }}>
        <div style={{ fontSize: 10, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".14em", textTransform: "uppercase" }}>{L("Defensibility", "Pagrįstumas")}</div>
        <div style={{ display: "flex", alignItems: "baseline", gap: 8 }}>
          <span style={{ fontSize: 26, fontWeight: 300, color: bandColor, fontFamily: "var(--f)", lineHeight: 1 }}>{score}</span>
          <span style={{ fontSize: 11, color: "#8c8c88", fontFamily: "var(--m)" }}>/ 100 · {band}</span>
        </div>
        <div style={{ display: "flex", gap: 12, marginLeft: "auto", flexWrap: "wrap" }}>
          {[["verified", counts.verified], ["review", counts.review], ["unsupported", counts.unsupported]].map(([k, n]) =>
            <span key={k} style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 11, fontFamily: "var(--m)", color: "#bcbcb8" }}>
              <span style={{ width: 8, height: 8, borderRadius: "50%", background: C[k], display: "inline-block" }} />{n} {statusLabel(k)}
            </span>)}
        </div>
        <button onClick={() => setOpen(o => !o)} style={{ background: "none", border: `1px solid ${PL_LINE}`, color: "#d2d2ce", fontFamily: "var(--m)", fontSize: 10, letterSpacing: ".08em", padding: "5px 12px", cursor: "pointer", textTransform: "uppercase" }}>
          {open ? L("Hide claims", "Slėpti") : L("Inspect claims", "Tikrinti teiginius")}
        </button>
      </div>
      <div style={{ padding: "0 16px 12px", fontSize: 11.5, color: "#9f9f9b", fontFamily: "var(--s)", lineHeight: 1.55 }}>
        {L(
          `Each statement is checked against the ${factCount} deterministic values computed from your file. “Verified” means a figure matches a computed value; “Unsupported” means no matching value was found — verify it manually; “Review” marks interpretive or legal statements. This is a transparency aid, not a guarantee.`,
          `Kiekvienas teiginys tikrinamas pagal ${factCount} deterministiškai apskaičiuotas reikšmes iš jūsų failo. „Patvirtinta“ — skaičius sutampa su apskaičiuota reikšme; „Nepagrįsta“ — atitikmuo nerastas, patikrinkite rankiniu būdu; „Peržiūrėti“ — interpretaciniai ar teisiniai teiginiai. Tai skaidrumo priemonė, ne garantija.`
        )}
      </div>
      {open && <div style={{ borderTop: `1px solid ${PL_LINE}` }}>
        {claims.map((c, i) =>
          <div key={i} style={{ display: "flex", gap: 10, padding: "10px 16px", borderBottom: i < claims.length - 1 ? `1px solid ${PL_LINE}` : "none" }}>
            <span style={{ width: 8, height: 8, borderRadius: "50%", background: C[c.status], marginTop: 5, flexShrink: 0 }} />
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 12.5, color: "#e6e6e2", fontFamily: "var(--s)", lineHeight: 1.5 }}>{c.text}</div>
              <div style={{ fontSize: 10, color: "#8c8c88", fontFamily: "var(--m)", marginTop: 3 }}>
                {statusLabel(c.status)} · {c.confidence}%{c.grounding ? ` · ${c.grounding}` : ""}{c.numbers?.length ? ` · ${c.numbers.join(", ")}` : ""}
              </div>
            </div>
          </div>)}
      </div>}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
// INTEGRATIONS TAB — ERP hub UI (Module 1)
// gallery · connections · mapping studio · tax-code mapper · monitor · agent
// ════════════════════════════════════════════════════════════════════
// ─── Live Bridge UI atoms ─────────────────────────────────────────────
function ErpRing({ pct, color = "#69db7c", size = 56, label, sub }) {
  const r = (size - 8) / 2, C = 2 * Math.PI * r, off = C * (1 - Math.max(0, Math.min(1, pct)));
  return <div style={{ position: "relative", width: size, height: size, flexShrink: 0 }}>
    <svg width={size} height={size} style={{ transform: "rotate(-90deg)", display: "block" }}>
      <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke="rgba(255,255,255,0.1)" strokeWidth="3" />
      <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={color} strokeWidth="3" strokeDasharray={C} strokeDashoffset={off} style={{ transition: "stroke-dashoffset .9s linear, stroke .4s" }} />
    </svg>
    <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
      <span style={{ fontFamily: "var(--m)", fontSize: 12.5, fontWeight: 700, color: "#fff", letterSpacing: ".02em" }}>{label}</span>
      {sub != null && <span style={{ fontFamily: "var(--m)", fontSize: 7.5, color: "#8c8c88", letterSpacing: ".06em", marginTop: 1 }}>{sub}</span>}
    </div>
  </div>;
}
function ErpSpark({ vals = [], color = "#74c0fc", w = 86, h = 22 }) {
  if (!vals.length) return <div style={{ width: w, height: h }} />;
  const mx = Math.max(...vals, 1), mn = Math.min(...vals, 0);
  const pts = vals.map((v, i) => `${(i / Math.max(1, vals.length - 1)) * (w - 2) + 1},${h - 2 - ((v - mn) / Math.max(1, mx - mn)) * (h - 5)}`).join(" ");
  return <svg width={w} height={h} style={{ display: "block" }}><polyline points={pts} fill="none" stroke={color} strokeWidth="1.4" opacity="0.9" /></svg>;
}
function ErpRail({ active }) {
  return <svg width="34" height="12" style={{ flexShrink: 0, opacity: active ? 1 : 0.45 }}><line x1="0" y1="6" x2="34" y2="6" stroke={active ? "#69db7c" : "rgba(255,255,255,0.28)"} strokeWidth="1.4" strokeDasharray="3 4" style={active ? { animation: "erpFlow .5s linear infinite" } : {}} /></svg>;
}

function IntegrationsTab({ lang, t, audit, erp, setErp, demo, setDemo, onPromote, setToast, hasSaft }) {
  const PL_LINE = "rgba(255,255,255,0.12)", PL_SOFT = "rgba(255,255,255,0.06)";
  const lbl = { fontSize: 10.5, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase" };
  const bP = { background: "#fff", color: "#000", border: "none", padding: "9px 18px", fontSize: 11, fontWeight: 700, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" };
  const bG = { background: "transparent", color: "#d2d2ce", border: `1px solid ${PL_LINE}`, padding: "9px 16px", fontSize: 11, fontWeight: 600, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" };
  const inp = { background: "var(--bg)", color: "#fff", border: `1px solid ${PL_LINE}`, padding: "8px 11px", fontSize: 12.5, fontFamily: "var(--s)", outline: "none", width: "100%" };
  const LT = lang === "lt";

  const [sub, setSub] = useState(erp.connections.length ? "board" : "connect");
  const [wiz, setWiz] = useState(null);            // catalog entry being connected
  const [creds, setCreds] = useState({});
  const [wizStep, setWizStep] = useState(1);
  const [wizChecks, setWizChecks] = useState([]);
  const [wizSample, setWizSample] = useState(null);
  const [wizMap, setWizMap] = useState(null);
  const [wizUse, setWizUse] = useState({});
  const [wizPilot, setWizPilot] = useState({ on: true, sec: 120 });
  const [wizFlight, setWizFlight] = useState(null);
  const [detectText, setDetectText] = useState("");
  const [detectRes, setDetectRes] = useState(null);
  const [liveSync, setLiveSync] = useState({});
  const [events, setEvents] = useState([]);
  const [nowT, setNowT] = useState(Date.now());
  const busyRef = useRef({ any: "" }); const lastRunRef = useRef({});
  const pushEvent = (kind, msg) => setEvents((ev) => [{ t: Date.now(), kind, msg }, ...ev].slice(0, 60));
  const [busy, setBusy] = useState("");            // connectorId currently syncing
  const [mapConnId, setMapConnId] = useState("");
  const [mapEntity, setMapEntity] = useState("invoicesAR");
  const [mapDraft, setMapDraft] = useState(null);  // {field: path} editable copy

  const connections = erp.connections;
  const helpers = useMemo(() => ({ classifyVatRate, isValidLtIban, isLtVatNumber, ISO_4217, taxMap: erp.taxMap }), [erp.taxMap]);
  const connFor = (id) => connections.find((c) => c.id === id);
  const startConnect = (entry) => { setWiz(entry); setCreds({}); setWizStep(1); setWizChecks([]); setWizSample(null); setWizMap(null); setWizUse({}); setWizFlight(null); setWizPilot({ on: true, sec: demo ? 120 : 900 }); };
  const credFields = (auth) => auth === "oauth2" ? [["clientId", "Client ID"], ["clientSecret", "Client secret"], ["tenant", LT ? "Nuomininkas / aplinka" : "Tenant / environment"]] : auth === "apikey" ? [["apiKey", "API key"]] : auth === "basic" ? [["username", LT ? "Naudotojas" : "Username"], ["password", LT ? "Slaptažodis" : "Password"]] : auth === "cert" ? [["keyRef", LT ? "Rakto nuoroda (agentas)" : "Key reference (agent)"]] : [];

  // ── SmartConnect: handshake → auto-map → rehearsal → save ──────────
  const runHandshake = async () => {
    setWizStep(2); setWizChecks([]);
    const entry = wiz; const cfg = { credentials: creds, baseUrl: creds.baseUrl, demo };
    const conn = makeConnector(entry, cfg);
    const seed = parseInt(djb2(entry.id).slice(0, 6), 16);
    const labels = LT ? ["Galinis taškas", "TLS kanalas", "Autentifikacija · " + entry.auth.toUpperCase(), "API versija", "Teisės (skaitymas)", "Užklausų limitas", "Pavyzdinis įrašas"] : ["Endpoint", "TLS channel", "Authentication · " + entry.auth.toUpperCase(), "API version", "Permissions (read)", "Rate-limit policy", "Sample record"];
    const out = [];
    const step = async (i, fn) => { const t0 = Date.now(); let ok = true, note = ""; try { note = (await fn()) || ""; } catch (e) { ok = false; note = e.message; } out.push({ label: labels[i], ok, ms: Date.now() - t0, note }); setWizChecks([...out]); return ok; };
    let sample = null;
    await step(0, async () => { await new Promise((r) => setTimeout(r, 90 + (seed % 70))); return demo ? (LT ? "demo smėliadėžė" : "demo sandbox") : (creds.baseUrl || ERP_RELAY); });
    await step(1, async () => { await new Promise((r) => setTimeout(r, 60 + (seed % 50))); return "TLS 1.3"; });
    const okAuth = await step(2, async () => { const h = await conn.healthCheck(); if (!h.ok) throw new Error(h.error || "auth failed"); return h.mode + " · " + h.latencyMs + " ms"; });
    await step(3, async () => { await new Promise((r) => setTimeout(r, 50 + (seed % 40))); return entry.adapter === "d365bc" ? "API v2.0 (OData)" : "REST v1"; });
    await step(4, async () => { await new Promise((r) => setTimeout(r, 60 + (seed % 60))); return LT ? "dokumentai · partneriai · DK" : "documents · partners · GL"; });
    await step(5, async () => { await new Promise((r) => setTimeout(r, 40 + (seed % 30))); return "120 ms/req"; });
    const okSample = await step(6, async () => {
      if (demo || cfg.demo) sample = conn.sampleRaw("invoicesAR")[0] || null;
      else { const pg = await conn.pull("invoicesAR", null, null); sample = (pg.raw || [])[0] || null; }
      if (!sample) throw new Error(LT ? "negauta įrašų" : "no records returned");
      return "1 " + (LT ? "sąskaita" : "invoice");
    });
    if (okAuth && okSample && sample) {
      setWizSample(sample);
      const am = autoMapEntity(sample, "invoicesAR"); setWizMap(am);
      const shipped = mapsFor(entry, {}).invoicesAR || {}; const pre = {};
      Object.entries((am && am.confidence) || {}).forEach(([f, c]) => { const det = f.indexOf("line.") === 0 ? ((am.map.line || {})[f.slice(5)]) : am.map[f]; const ship = f === "linesPath" ? shipped.linesPath : f.indexOf("line.") === 0 ? ((shipped.line || {})[f.slice(5)]) : shipped[f]; if (det && det !== ship && c >= 70) pre[f] = true; });
      setWizUse(pre);
      setTimeout(() => setWizStep(3), 380);
    }
  };
  const wizOverrides = () => { if (!wizMap) return {}; const o = {}; Object.keys(wizUse).forEach((f) => { if (!wizUse[f]) return; if (f === "linesPath") o.linesPath = wizMap.map.linesPath; else if (f.indexOf("line.") === 0) { o.line = o.line || {}; o.line[f.slice(5)] = (wizMap.map.line || {})[f.slice(5)]; } else o[f] = wizMap.map[f]; }); return Object.keys(o).length ? { invoicesAR: o } : {}; };
  const runPreflight = async () => {
    setWizStep(4); setWizFlight({ pending: true });
    try {
      const conn = makeConnector(wiz, { credentials: creds, baseUrl: creds.baseUrl, mapOverrides: wizOverrides(), demo: true });
      const tmp = emptyCanonicalStore();
      await runConnectorSync(conn, tmp, {}, {});
      tmp._taxMap = erp.taxMap;
      const f = validateCanonicalBatch(tmp, helpers);
      setWizFlight({ findings: f, recon: computeSourceRecon(tmp, wiz.id), rows: ENTITY_KINDS.reduce((s, k) => s + (tmp[k] || []).length, 0) });
    } catch (e) { setWizFlight({ error: e.message }); }
  };
  const setPilot = (id, patch) => setErp((e) => ({ ...e, connections: e.connections.map((c) => c.id !== id ? c : { ...c, config: { ...c.config, autopilot: { on: true, sec: 120, ...(c.config.autopilot || {}), ...patch } } }) }));
  const saveConnection = () => {
    const c = { id: wiz.id, entry: wiz, config: { credentials: creds, baseUrl: creds.baseUrl || "", mapOverrides: wizOverrides(), demo, autopilot: { ...wizPilot } }, addedAt: new Date().toISOString() };
    setErp((e) => ({ ...e, connections: [...e.connections.filter((x) => x.id !== wiz.id), c] }));
    audit.log("ERP_CONNECT", `${wiz.name} (${wiz.protocol}/${wiz.auth}) ${demo ? "demo" : "live→" + ERP_RELAY} · autopilot ${wizPilot.on ? wizPilot.sec + "s" : "off"}`);
    pushEvent("ok", `${wiz.name}: ${LT ? "prijungta" : "connected"}${wizPilot.on ? " · autopilot " + wizPilot.sec + " s" : ""}`);
    setToast(LT ? `Prijungta: ${wiz.name}` : `Connected: ${wiz.name}`);
    setWiz(null); setSub("board");
    setTimeout(() => syncNow(c), 60);
  };
  const runDetect = () => {
    const t2 = detectText.trim(); if (!t2) return;
    try { const j = JSON.parse(t2); setDetectRes({ kind: "json", ranked: fingerprintRaw(Array.isArray(j) ? j[0] : j) }); return; } catch { }
    const heads = t2.split(/\r?\n/)[0].split(/[;,\t]/).map((s) => s.trim()).filter(Boolean);
    if (heads.length >= 3) { const idMap = { rivile: "rivile", b1lt: "b1lt", d365bc: "d365-bc" }; const ranked = ERP_PROFILES.filter((p) => idMap[p.id]).map((p) => { const r = eiTryMap(p, heads); return { id: idMap[p.id], name: ERP_CATALOG.find((e) => e.id === idMap[p.id]).name, pct: Math.min(99, Math.round(r.score / 9 * 100)) }; }).sort((a, b) => b.pct - a.pct); setDetectRes({ kind: "csv", ranked }); return; }
    setDetectRes({ kind: "none" });
  };
  const removeConnection = (id) => { setErp((e) => ({ ...e, connections: e.connections.filter((x) => x.id !== id) })); audit.log("ERP_DISCONNECT", id); };

  const syncNow = async (c, auto = false) => {
    if (busyRef.current.any) return;
    busyRef.current.any = c.id; setBusy(c.id);
    const t0 = Date.now();
    setLiveSync((s) => ({ ...s, [c.id]: { ...(s[c.id] || {}), phase: "running", byEntity: {}, startedAt: t0 } }));
    pushEvent("sync", `${c.entry.name}: ${auto ? "autopilot" : LT ? "rankinis" : "manual"} sync`);
    try {
      const connector = makeConnector(c.entry, { ...c.config, demo: demo || c.config.demo });
      const store = { ...erp.store, _seen: { ...erp.store._seen }, _sources: [...erp.store._sources] };
      ENTITY_KINDS.forEach((k) => { store[k] = [...(erp.store[k] || [])]; });
      const syncState = JSON.parse(JSON.stringify(erp.syncState));
      const res = await runConnectorSync(connector, store, syncState, { log: audit.log, onEvent: (ev) => setLiveSync((s) => { const L = { ...(s[c.id] || {}) }; L.byEntity = { ...(L.byEntity || {}), [ev.entity]: ev.error ? "✗" : ev.added }; return { ...s, [c.id]: L }; }) });
      store._taxMap = erp.taxMap;
      const findings = validateCanonicalBatch(store, helpers);
      setErp((e) => ({ ...e, store, syncState, findings }));
      const n = Object.values(res.byEntity).reduce((s, x) => s + x, 0);
      const dur = Date.now() - t0;
      lastRunRef.current[c.id] = Date.now();
      setLiveSync((s) => { const L = { ...(s[c.id] || {}) }; L.phase = "ok"; L.lastMs = dur; L.failStreak = 0; L.durations = [...(L.durations || []), dur].slice(-14); return { ...s, [c.id]: L }; });
      pushEvent("ok", `${c.entry.name}: +${n} ${LT ? "įr." : "rec"} · ${findings.length} ${LT ? "rad." : "findings"} · ${dur} ms`);
      if (!auto) setToast(LT ? `${c.entry.name}: ${n} įrašų · ${findings.length} radinių` : `${c.entry.name}: ${n} records · ${findings.length} findings`);
    } catch (err) {
      const fs2 = (((liveSync[c.id] || {}).failStreak) || 0) + 1;
      setLiveSync((s) => ({ ...s, [c.id]: { ...(s[c.id] || {}), phase: "error", failStreak: fs2, lastErr: err.message } }));
      pushEvent("err", `${c.entry.name}: ${err.message}`);
      if (fs2 >= 3) { setPilot(c.id, { on: false }); pushEvent("err", `${c.entry.name}: ${LT ? "autopilotas pristabdytas po 3 klaidų iš eilės" : "autopilot paused after 3 consecutive failures"}`); }
      if (!auto) setToast((LT ? "Sinchronizavimo klaida: " : "Sync error: ") + err.message);
      audit.log("ERP_SYNC_ERROR", `${c.entry.name}: ${err.message}`);
    }
    busyRef.current.any = ""; setBusy("");
  };

  // Mapping studio derived state
  const mapConn = connFor(mapConnId) || connections[0];
  const mapEntry = mapConn?.entry;
  const baseMap = mapEntry ? mapsFor(mapEntry, mapConn.config)[mapEntity] || {} : {};
  const effMap = mapDraft || baseMap;
  const sampleRaws = useMemo(() => { if (!mapEntry) return []; try { return makeConnector(mapEntry, { ...mapConn.config, demo: true }).sampleRaw(mapEntity); } catch { return []; } }, [mapEntry && mapEntry.id, mapEntity]);
  const previewRows = useMemo(() => {
    if (!mapEntry || !sampleRaws.length) return [];
    try {
      if (mapEntity === "invoicesAR" || mapEntity === "invoicesAP") return sampleRaws.map((r) => { const c = transformInvoice(effMap, r, mapEntry, mapEntity === "invoicesAR" ? "AR" : "AP"); return { invoiceNo: c.invoiceNo, date: c.invoiceDate, party: c.party.name || c.party.id, net: c.totals.net, vat: c.totals.vat, gross: c.totals.gross, lines: c.lines.length }; });
      if (mapEntity === "customers" || mapEntity === "suppliers") return sampleRaws.map((r) => { const p = transformParty(effMap, r); return { id: p.id, name: p.name, vatNo: p.vatNo, country: p.country, iban: p.iban }; });
      return sampleRaws.map((r) => ({ json: JSON.stringify(r).slice(0, 90) }));
    } catch (e) { return [{ error: e.message }]; }
  }, [effMap, sampleRaws, mapEntity, mapEntry && mapEntry.id]);
  const autoRes = useMemo(() => { try { return sampleRaws[0] ? autoMapEntity(sampleRaws[0], mapEntity) : null; } catch { return null; } }, [sampleRaws, mapEntity]);
  const autoConf = (autoRes && autoRes.confidence) || {};
  const applyAutoMap = () => { if (!autoRes) return; const d = JSON.parse(JSON.stringify(effMap)); Object.entries(autoRes.map).forEach(([k, v]) => { if (k === "line") { d.line = { ...(d.line || {}) }; Object.entries(v).forEach(([lk, lv]) => { if ((autoConf["line." + lk] || 0) >= 70) d.line[lk] = lv; }); } else if ((autoConf[k] || 0) >= 70) d[k] = v; }); setMapDraft(d); audit.log("ERP_AUTOMAP", `${mapEntry.name} · ${mapEntity} · coverage ${autoRes.coverage}%`); };
  const flatFields = (m) => Object.entries(m).filter(([k, v]) => typeof v === "string" && k !== "label").map(([k, v]) => [k, v]).concat(Object.entries(m.line || {}).map(([k, v]) => ["line." + k, v]));
  const setMapField = (k, v) => { const d = JSON.parse(JSON.stringify(effMap)); if (k.startsWith("line.")) { d.line = d.line || {}; d.line[k.slice(5)] = v; } else d[k] = v; setMapDraft(d); };
  const saveMapping = () => {
    setErp((e) => ({ ...e, connections: e.connections.map((c) => c.id !== mapConn.id ? c : { ...c, config: { ...c.config, mapOverrides: { ...c.config.mapOverrides, [mapEntity]: effMap } } }) }));
    audit.log("ERP_MAPPING_SAVED", `${mapConn.entry.name} · ${mapEntity}`);
    setToast(LT ? "Atvaizdavimas išsaugotas" : "Mapping saved"); setMapDraft(null);
  };

  // Tax-code mapper derived state
  const rawCodes = useMemo(() => { const seen = {}; const out = []; (erp.store.taxCodes || []).forEach((tc) => { if (!seen[tc.rawCode]) { seen[tc.rawCode] = 1; out.push(tc); } }); return out; }, [erp.store.taxCodes]);
  const CLS_LIST = useMemo(() => [...CLS_TAX].sort(), []);
  const setTaxMap = (rawCode, sti) => setErp((e) => { const taxMap = { ...e.taxMap }; if (sti) taxMap[rawCode] = sti; else delete taxMap[rawCode]; const store = { ...e.store, _taxMap: taxMap }; return { ...e, taxMap, store, findings: validateCanonicalBatch(store, { ...helpers, taxMap }) }; });

  const counts = ENTITY_KINDS.map((k) => [k, (erp.store[k] || []).length]);
  const totalRows = counts.reduce((s, [, n]) => s + n, 0);
  const sevOrder = { Block: 0, Reject: 1, Warn: 2 };
  const sortedFindings = [...erp.findings].sort((a, b) => (sevOrder[a.severity] ?? 9) - (sevOrder[b.severity] ?? 9));

  const [csvText, setCsvText] = useState("");
  const [csvMap, setCsvMap] = useState(null);
  // ── Autopilot: 1 s heartbeat → due connections sync themselves ─────
  useEffect(() => { const t2 = setInterval(() => setNowT(Date.now()), 1000); return () => clearInterval(t2); }, []);
  useEffect(() => {
    if (busyRef.current.any) return;
    for (const c of connections) {
      const ap = c.config.autopilot; if (!ap || !ap.on) continue;
      const last = lastRunRef.current[c.id] || (erp.syncState[c.id]?.lastSync ? new Date(erp.syncState[c.id].lastSync).getTime() : 0);
      if (Date.now() - last >= ap.sec * 1000) { syncNow(c, true); break; }
    }
  }, [nowT]);
  const pilotsOn = connections.filter((c) => c.config.autopilot && c.config.autopilot.on).length;
  const recons = useMemo(() => (erp.store._sources || []).filter((s) => s !== "csv").map((id) => ({ id, name: (ERP_CATALOG.find((e) => e.id === id) || { name: id }).name, ...computeSourceRecon(erp.store, id) })), [erp.store]);
  const conflicts = useMemo(() => detectErpConflicts(erp.store), [erp.store]);
  const sevCount = useMemo(() => { const m = { Block: 0, Reject: 0, Warn: 0 }; erp.findings.forEach((f) => { m[f.severity] = (m[f.severity] || 0) + 1; }); return m; }, [erp.findings]);
  const SUBS = [["board", LT ? "Pultas" : "Live board"], ["connect", LT ? "Prijungti" : "Connect"], ["mapping", LT ? "Atvaizdavimas" : "Mapping studio"], ["taxmap", LT ? "PVM kodai" : "Tax codes"], ["csv", "CSV"], ["monitor", LT ? "Stebėsena" : "Monitor"], ["agent", LT ? "Agentas / relė" : "Agent / relay"]];

  return <div style={{ maxWidth: 1240 }}>
    <style>{`@keyframes erpFlow{to{stroke-dashoffset:-14}}`}</style>
    <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", gap: 16, marginBottom: 18, flexWrap: "wrap" }}>
      <div>
        <div style={{ fontSize: 26, fontWeight: 800, color: "#fff", fontFamily: "var(--s)", letterSpacing: "-.01em" }}>{LT ? "ERP gyvasis tiltas" : "ERP Live Bridge"}</div>
        <div style={{ fontSize: 12.5, color: "#8c8c88", fontFamily: "var(--s)", marginTop: 4 }}>Rivilė GAMA · B1.lt · Dynamics 365 BC — {LT ? "vienas kanoninis modelis, deterministinis konvejeris į SAF-T variklius" : "one canonical model, a deterministic pipeline into the SAF-T engines"}</div>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        {pilotsOn > 0 && <span style={{ display: "flex", alignItems: "center", gap: 6, fontFamily: "var(--m)", fontSize: 10, letterSpacing: ".08em", color: "#69db7c" }}><span style={{ width: 6, height: 6, borderRadius: "50%", background: "#69db7c", animation: "pulse 1.6s ease infinite" }} />{pilotsOn} AUTOPILOT</span>}
        <span style={{ ...lbl }}>{LT ? "Režimas" : "Mode"}</span>
        <button onClick={() => setDemo(!demo)} style={{ ...bG, borderColor: demo ? PL_LINE : "#69db7c", color: demo ? "#d2d2ce" : "#69db7c" }}>{demo ? "DEMO" : "LIVE → /api/erp"}</button>
      </div>
    </div>

    <div style={{ display: "flex", gap: 0, borderBottom: `1px solid ${PL_LINE}`, marginBottom: 18, flexWrap: "wrap" }}>
      {SUBS.map(([k, l]) => <button key={k} onClick={() => setSub(k)} style={{ background: "transparent", border: "none", borderBottom: `2px solid ${sub === k ? "#fff" : "transparent"}`, color: sub === k ? "#fff" : "#8c8c88", padding: "10px 16px", fontSize: 11.5, fontWeight: 700, fontFamily: "var(--m)", letterSpacing: ".08em", textTransform: "uppercase", cursor: "pointer" }}>{l}{k === "board" && connections.length ? ` (${connections.length})` : ""}{k === "monitor" && erp.findings.length ? ` (${erp.findings.length})` : ""}</button>)}
      <span style={{ marginLeft: "auto", display: "flex", gap: 7, alignItems: "center", color: busy ? "#74c0fc" : pilotsOn ? "#69db7c" : "#8c8c88", fontFamily: "var(--m)", fontSize: 10.5, padding: "10px 4px", letterSpacing: ".06em" }}>{busy ? (LT ? "● SINCHRONIZUOJAMA" : "● SYNCING") : pilotsOn ? `● ${pilotsOn} AUTOPILOT` : (LT ? "○ RANKINIS" : "○ MANUAL")}</span>
    </div>

    {/* ── CONNECT — three deep connectors + sample fingerprinting ── */}
    {sub === "connect" && <div style={{ maxWidth: 980 }}>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(280px,1fr))", gap: 12, marginBottom: 18 }}>
        {ERP_CATALOG.map((e) => { const conn = connFor(e.id); return <div key={e.id} style={{ border: `1px solid ${conn ? "rgba(105,219,124,.45)" : PL_LINE}`, background: "var(--bg2)", padding: "18px 18px 16px", display: "flex", flexDirection: "column", gap: 10 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 9, fontWeight: 700, letterSpacing: ".1em", color: "#69db7c", border: "1px solid #69db7c", padding: "2px 6px" }}>{LT ? "GILUS" : "DEEP"}</span>
            <span style={lbl}>{e.protocol.toUpperCase()} · {e.auth.toUpperCase()}</span>
          </div>
          <div style={{ color: "#fff", fontFamily: "var(--s)", fontSize: 16.5, fontWeight: 700 }}>{e.name}</div>
          <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11.5, lineHeight: 1.5, flex: 1 }}>{e.id === "rivile" ? (LT ? "Lietuviški laukų pavadinimai, EIP REST profilis." : "Lithuanian field names, EIP REST profile.") : e.id === "b1lt" ? (LT ? "Dokumentai ir partneriai kaip JSON." : "Documents and partners as JSON.") : (LT ? "Oficialus Microsoft API v2.0 (OData)." : "Official Microsoft API v2.0 (OData).")}</div>
          {conn ? <div style={{ display: "flex", gap: 8, alignItems: "center" }}><span style={{ ...lbl, color: "#69db7c" }}>{LT ? "✓ prijungta" : "✓ connected"}</span><div style={{ flex: 1 }} /><button onClick={() => setSub("board")} style={{ ...bG, padding: "6px 12px" }}>{LT ? "Į pultą" : "Open board"}</button></div>
            : <button onClick={() => startConnect(e)} style={{ ...bP, alignSelf: "flex-start" }}>{LT ? "Prijungti →" : "Connect →"}</button>}
        </div>; })}
      </div>
      <Section title={LT ? "Atpažinti iš pavyzdžio" : "Detect from a sample"} accent="#74c0fc">
        <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 12.5, lineHeight: 1.5, marginBottom: 10 }}>{LT ? "Įklijuokite vieną JSON įrašą iš API atsakymo arba pirmą CSV eilutę su antraštėmis — deterministiniai pirštų atspaudai pasakys, kuri sistema tai yra." : "Paste one JSON record from an API response or the first CSV header line — deterministic fingerprints tell you which system it is."}</div>
        <textarea value={detectText} onChange={(e) => setDetectText(e.target.value)} placeholder={'{"number":"RIVI-AR-2026-00001", "suma_be_pvm": 100, ...}   |   Dok_Nr;Data;Pirkejas;Suma_be_PVM;…'} style={{ ...inp, height: 84, fontFamily: "var(--m)", fontSize: 10.5, resize: "vertical" }} />
        <div style={{ display: "flex", gap: 10, marginTop: 10, alignItems: "center", flexWrap: "wrap" }}>
          <button onClick={runDetect} style={bG}>{LT ? "Atpažinti" : "Detect"}</button>
          {detectRes && detectRes.kind === "none" && <span style={{ fontFamily: "var(--m)", fontSize: 11, color: "#ffd43b" }}>{LT ? "Neatpažinta — per mažai požymių." : "Not recognized — too few signals."}</span>}
        </div>
        {detectRes && detectRes.ranked && <div style={{ marginTop: 12 }}>{detectRes.ranked.map((r) => <div key={r.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "7px 0", borderTop: `1px solid ${PL_SOFT}` }}>
          <span style={{ width: 230, color: "#d2d2ce", fontFamily: "var(--s)", fontSize: 13, flexShrink: 0 }}>{r.name}</span>
          <div style={{ flex: 1, height: 5, background: "rgba(255,255,255,.07)" }}><div style={{ width: r.pct + "%", height: "100%", background: r.pct >= 60 ? "#69db7c" : r.pct >= 35 ? "#ffd43b" : "#555", transition: "width .4s" }} /></div>
          <span style={{ width: 44, textAlign: "right", fontFamily: "var(--m)", fontSize: 11, color: "#fff", flexShrink: 0 }}>{r.pct}%</span>
          {r.pct >= 40 && !connFor(r.id) && <button onClick={() => startConnect(ERP_CATALOG.find((e) => e.id === r.id))} style={{ ...bG, padding: "5px 12px" }}>{LT ? "Prijungti" : "Connect"}</button>}
        </div>)}</div>}
      </Section>
      {!demo && <div style={{ color: "#8c8c88", fontFamily: "var(--m)", fontSize: 10.5, lineHeight: 1.6 }}>{LT ? "LIVE režimui reikia /api/erp relės — žr. skirtuką „Agentas / relė“." : "LIVE mode needs the /api/erp relay — see the Agent / relay tab."}</div>}
    </div>}

    {/* ── SMARTCONNECT (overlay): access → handshake → field map → rehearsal ── */}
    {wiz && <div onClick={() => setWiz(null)} style={{ position: "fixed", inset: 0, zIndex: 10002, background: "rgba(0,0,0,0.72)", backdropFilter: "blur(6px)", display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: "min(700px,94vw)", maxHeight: "88vh", overflowY: "auto", background: "var(--bg2)", border: "1px solid rgba(255,255,255,0.18)", boxShadow: "0 24px 80px rgba(0,0,0,.7)", padding: "22px 24px" }}>
        <div style={{ display: "flex", alignItems: "baseline", gap: 12, flexWrap: "wrap" }}>
          <div style={{ fontSize: 18, fontWeight: 800, color: "#fff", fontFamily: "var(--s)" }}>{wiz.name}</div>
          <div style={lbl}>{wiz.protocol.toUpperCase()} · {wiz.auth.toUpperCase()} · {LT ? "GILI INTEGRACIJA" : "DEEP INTEGRATION"}</div>
        </div>
        <div style={{ display: "flex", gap: 8, margin: "14px 0 18px", alignItems: "center", flexWrap: "wrap" }}>
          {(LT ? ["Prieiga", "Patikra", "Žemėlapis", "Repeticija"] : ["Access", "Handshake", "Field map", "Rehearsal"]).map((s2, i) => <div key={s2} style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 9.5, fontWeight: 700, letterSpacing: ".08em", color: wizStep === i + 1 ? "#000" : wizStep > i + 1 ? "#69db7c" : "#8c8c88", background: wizStep === i + 1 ? "#fff" : "transparent", border: `1px solid ${wizStep > i + 1 ? "#69db7c" : wizStep === i + 1 ? "#fff" : PL_LINE}`, padding: "3px 9px" }}>{i + 1} · {s2.toUpperCase()}</span>
            {i < 3 && <span style={{ width: 16, height: 1, background: PL_LINE }} />}
          </div>)}
        </div>

        {wizStep === 1 && <div>
          {!demo && <div style={{ marginBottom: 12 }}><div style={{ ...lbl, marginBottom: 6 }}>Base URL</div><input value={creds.baseUrl || ""} onChange={(e) => setCreds({ ...creds, baseUrl: e.target.value })} placeholder="https://tenant.example.com" style={inp} /></div>}
          {!demo && credFields(wiz.auth).map(([k, l]) => <div key={k} style={{ marginBottom: 12 }}><div style={{ ...lbl, marginBottom: 6 }}>{l}</div><input type={/secret|password|Key/i.test(k) ? "password" : "text"} value={creds[k] || ""} onChange={(e) => setCreds({ ...creds, [k]: e.target.value })} style={inp} /></div>)}
          {demo && <div style={{ color: "#74c0fc", fontFamily: "var(--m)", fontSize: 11, letterSpacing: ".06em", marginBottom: 14, lineHeight: 1.6 }}>{LT ? "DEMO režimas: prisijungimo duomenų nereikia — viskas vyksta deterministinėje smėliadėžėje, suformuotoje kaip tikri šios sistemos kroviniai." : "DEMO mode: no credentials needed — everything runs in a deterministic sandbox shaped like this system's real payloads."}</div>}
          {!demo && <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11.5, lineHeight: 1.5, margin: "4px 0 14px" }}>{LT ? "Prisijungimo duomenys laikomi tik šios sesijos atmintyje ir siunčiami tik į jūsų /api/erp relę per TLS. Gamyboje naudokite credRef → Vercel env / vault (KMS)." : "Credentials live in this session's memory only and travel only to your /api/erp relay over TLS. In production use credRef → Vercel env / vault (KMS)."}</div>}
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={() => setWiz(null)} style={bG}>{LT ? "Atšaukti" : "Cancel"}</button>
            <div style={{ flex: 1 }} />
            <button onClick={runHandshake} style={bP}>{LT ? "Vykdyti patikrą →" : "Run handshake →"}</button>
          </div>
        </div>}

        {wizStep === 2 && <div>
          <div style={{ border: `1px solid ${PL_LINE}` }}>
            {wizChecks.map((c2, i) => <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "9px 14px", borderBottom: `1px solid ${PL_SOFT}` }}>
              <span style={{ fontFamily: "var(--m)", fontSize: 11, color: c2.ok ? "#69db7c" : "#ff6b6b", width: 14, flexShrink: 0 }}>{c2.ok ? "✓" : "✗"}</span>
              <span style={{ color: "#d2d2ce", fontFamily: "var(--s)", fontSize: 12.5, flex: 1 }}>{c2.label}</span>
              <span style={{ fontFamily: "var(--m)", fontSize: 10, color: c2.ok ? "#8c8c88" : "#ff6b6b", textAlign: "right" }}>{c2.note} · {c2.ms} ms</span>
            </div>)}
            {wizChecks.length < 7 && !wizChecks.some((c2) => !c2.ok) && <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "9px 14px" }}>
              <span style={{ width: 6, height: 6, borderRadius: "50%", background: "#74c0fc", animation: "pulse 1s ease infinite", flexShrink: 0 }} />
              <span style={{ color: "#8c8c88", fontFamily: "var(--m)", fontSize: 11 }}>{LT ? "Tikrinama…" : "Checking…"}</span>
            </div>}
          </div>
          {wizChecks.some((c2) => !c2.ok) && <div style={{ display: "flex", gap: 10, marginTop: 14 }}>
            <button onClick={() => setWizStep(1)} style={bG}>{LT ? "← Atgal" : "← Back"}</button>
            <button onClick={runHandshake} style={bP}>{LT ? "Kartoti patikrą" : "Retry handshake"}</button>
          </div>}
        </div>}

        {wizStep === 3 && wizMap && <div>
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12, flexWrap: "wrap" }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 11, color: "#69db7c" }}>{LT ? "Aprėptis" : "Coverage"} {wizMap.coverage}%</span>
            <span style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11.5 }}>{LT ? "Deterministinis žodyno + reikšmių formos balas — ne AI duomenų kelyje. Žmogus visada turi paskutinį žodį." : "Deterministic lexicon + value-shape score — no AI in the data path. The human always has the last word."}</span>
          </div>
          <div style={{ border: `1px solid ${PL_LINE}`, maxHeight: 250, overflowY: "auto" }}>
            <div style={{ display: "grid", gridTemplateColumns: "118px 1fr 1fr 42px 38px", background: "var(--bg2)", borderBottom: `1px solid ${PL_LINE}`, position: "sticky", top: 0 }}>{[LT ? "Laukas" : "Field", LT ? "Numatyta" : "Shipped", LT ? "Aptikta" : "Detected", "%", LT ? "Imti" : "Use"].map((h) => <div key={h} style={{ ...lbl, padding: "8px 10px", fontSize: 8.5 }}>{h}</div>)}</div>
            {(() => { const shipped = mapsFor(wiz, {}).invoicesAR || {}; return Object.keys(wizMap.confidence).map((f) => { const det = f === "linesPath" ? wizMap.map.linesPath : f.indexOf("line.") === 0 ? (wizMap.map.line || {})[f.slice(5)] : wizMap.map[f]; const ship = f === "linesPath" ? shipped.linesPath : f.indexOf("line.") === 0 ? (shipped.line || {})[f.slice(5)] : shipped[f]; const same = det === ship; const conf = wizMap.confidence[f]; return <div key={f} style={{ display: "grid", gridTemplateColumns: "118px 1fr 1fr 42px 38px", borderBottom: `1px solid ${PL_SOFT}`, alignItems: "center" }}>
              <div style={{ padding: "6px 10px", color: "#d2d2ce", fontFamily: "var(--m)", fontSize: 10 }}>{f}</div>
              <div style={{ padding: "6px 10px", color: "#8c8c88", fontFamily: "var(--m)", fontSize: 10, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }} title={ship || "—"}>{ship || "—"}</div>
              <div style={{ padding: "6px 10px", color: same ? "#69db7c" : "#ffd43b", fontFamily: "var(--m)", fontSize: 10, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }} title={det}>{det}{same ? " ✓" : ""}</div>
              <div style={{ padding: "6px 8px", fontFamily: "var(--m)", fontSize: 10, color: conf >= 70 ? "#69db7c" : conf >= 45 ? "#ffd43b" : "#8c8c88" }}>{conf}</div>
              <div style={{ padding: "4px 10px" }}>{!same && det ? <input type="checkbox" checked={!!wizUse[f]} onChange={(e) => setWizUse({ ...wizUse, [f]: e.target.checked })} /> : <span style={{ color: "#555", fontFamily: "var(--m)", fontSize: 10 }}>=</span>}</div>
            </div>; }); })()}
          </div>
          <div style={{ ...lbl, margin: "12px 0 6px" }}>{LT ? "Žalias pavyzdys" : "Raw sample"}</div>
          <pre style={{ background: "var(--bg)", border: `1px solid ${PL_LINE}`, padding: 10, color: "#bcbcb8", fontFamily: "var(--m)", fontSize: 9.5, lineHeight: 1.45, overflow: "auto", maxHeight: 120, margin: 0 }}>{JSON.stringify(wizSample, null, 2)}</pre>
          <div style={{ display: "flex", gap: 10, marginTop: 14 }}>
            <button onClick={() => setWizStep(1)} style={bG}>{LT ? "← Atgal" : "← Back"}</button>
            <div style={{ flex: 1 }} />
            <button onClick={runPreflight} style={bP}>{LT ? "Repeticija →" : "Rehearse →"}</button>
          </div>
        </div>}

        {wizStep === 4 && <div>
          {(!wizFlight || wizFlight.pending) && <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "16px 0" }}><span style={{ width: 6, height: 6, borderRadius: "50%", background: "#74c0fc", animation: "pulse 1s ease infinite" }} /><span style={{ color: "#8c8c88", fontFamily: "var(--m)", fontSize: 11 }}>{LT ? "Vykdoma repeticija deterministinėje smėliadėžėje…" : "Running rehearsal in the deterministic sandbox…"}</span></div>}
          {wizFlight && wizFlight.error && <div style={{ color: "#ff6b6b", fontFamily: "var(--m)", fontSize: 11.5, marginBottom: 12 }}>✗ {wizFlight.error}</div>}
          {wizFlight && wizFlight.findings && <div>
            <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11.5, lineHeight: 1.55, marginBottom: 12 }}>{LT ? `Repeticija: deterministinė sėkla, suformuota kaip ${wiz.name} kroviniai, perleista per visą konvejerį — atvaizdavimas, ribos taisyklės, sutikrinimas.` : `Rehearsal: a deterministic seed shaped as ${wiz.name} payloads, run through the full pipeline — mapping, boundary rules, reconciliation.`}</div>
            <div style={{ display: "flex", gap: 18, flexWrap: "wrap", marginBottom: 12 }}>
              {[[wizFlight.rows, LT ? "ĮRAŠAI" : "RECORDS"], [wizFlight.recon.docs, LT ? "DOKUMENTAI" : "DOCUMENTS"], ["€" + wizFlight.recon.net.toFixed(2), "NET"], ["€" + wizFlight.recon.vat.toFixed(2), "VAT"]].map(([n, l2]) => <div key={l2}><div style={{ fontFamily: "var(--m)", fontSize: 18, fontWeight: 700, color: "#fff" }}>{n}</div><div style={{ ...lbl, fontSize: 8.5 }}>{l2}</div></div>)}
            </div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 14, alignItems: "center" }}>
              {[["Block", "#ff6b6b"], ["Reject", "#ffd43b"], ["Warn", "#74c0fc"]].map(([sv, col2]) => { const n = wizFlight.findings.filter((f) => f.severity === sv).length; return <span key={sv} style={{ fontFamily: "var(--m)", fontSize: 10, padding: "3px 9px", border: `1px solid ${n ? col2 : PL_LINE}`, color: n ? col2 : "#555" }}>{sv.toUpperCase()} {n}</span>; })}
              <span style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11 }}>{LT ? "— sėkloje specialiai palikta defektų, kad matytumėte variklį veikiant" : "— the seed ships with planted defects so you can watch the engine work"}</span>
            </div>
            <div style={{ borderTop: `1px solid ${PL_LINE}`, paddingTop: 14, display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
              <label style={{ display: "flex", gap: 8, alignItems: "center", color: wizPilot.on ? "#69db7c" : "#8c8c88", fontFamily: "var(--m)", fontSize: 11, cursor: "pointer", letterSpacing: ".06em" }}><input type="checkbox" checked={wizPilot.on} onChange={(e) => setWizPilot({ ...wizPilot, on: e.target.checked })} />AUTOPILOT</label>
              <select disabled={!wizPilot.on} value={wizPilot.sec} onChange={(e) => setWizPilot({ ...wizPilot, sec: +e.target.value })} style={{ ...inp, width: "auto", fontFamily: "var(--m)", fontSize: 11, opacity: wizPilot.on ? 1 : 0.45 }}>{[[60, "1 min"], [120, "2 min"], [300, "5 min"], [900, "15 min"], [3600, "1 h"]].map(([v, l2]) => <option key={v} value={v}>{l2}</option>)}</select>
              <div style={{ flex: 1 }} />
              <button onClick={() => setWizStep(3)} style={bG}>{LT ? "← Atgal" : "← Back"}</button>
              <button onClick={saveConnection} style={bP}>{LT ? "Išsaugoti ir sinchronizuoti" : "Save & first sync"}</button>
            </div>
          </div>}
        </div>}
      </div>
    </div>}

    {/* ── LIVE BOARD — the bridge itself ── */}
    {sub === "board" && <div>
      {!connections.length ? <Section title={LT ? "Tiltas dar tuščias" : "The bridge is empty"}><div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 13.5, display: "flex", gap: 14, alignItems: "center", flexWrap: "wrap" }}><span>{LT ? "Prijunkite pirmą sistemą — pultas atgis." : "Connect your first system — the board comes alive."}</span><button onClick={() => setSub("connect")} style={bP}>{LT ? "Prijungti →" : "Connect →"}</button></div></Section> : <div>

        <div style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", padding: "14px 16px", marginBottom: 14, display: "flex", alignItems: "stretch", gap: 8, flexWrap: "wrap" }}>
          <div style={{ flex: "1 1 120px", padding: "6px 10px" }}>
            <div style={{ fontFamily: "var(--m)", fontSize: 22, fontWeight: 700, color: "#fff" }}>{connections.length}</div>
            <div style={{ ...lbl, fontSize: 8.5 }}>{LT ? "ŠALTINIAI" : "SOURCES"}</div>
            <div style={{ fontFamily: "var(--m)", fontSize: 9.5, color: pilotsOn ? "#69db7c" : "#8c8c88", marginTop: 3 }}>{pilotsOn ? pilotsOn + " autopilot" : (LT ? "rankinis" : "manual")}</div>
          </div>
          <div style={{ display: "flex", alignItems: "center" }}><ErpRail active={!!busy} /></div>
          <div style={{ flex: "1 1 150px", padding: "6px 10px" }}>
            <div style={{ fontFamily: "var(--m)", fontSize: 22, fontWeight: 700, color: "#fff" }}>{totalRows}</div>
            <div style={{ ...lbl, fontSize: 8.5 }}>{LT ? "KANONINIAI ĮRAŠAI" : "CANONICAL RECORDS"}</div>
            <div style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#8c8c88", marginTop: 3 }}>{erp.store._sources.join(" + ") || "—"}</div>
          </div>
          <div style={{ display: "flex", alignItems: "center" }}><ErpRail active={!!busy} /></div>
          <div style={{ flex: "1 1 150px", padding: "6px 10px" }}>
            <div style={{ fontFamily: "var(--m)", fontSize: 22, fontWeight: 700, color: erp.findings.length ? (sevCount.Block ? "#ff6b6b" : sevCount.Reject ? "#ffd43b" : "#74c0fc") : "#69db7c" }}>{erp.findings.length}</div>
            <div style={{ ...lbl, fontSize: 8.5 }}>{LT ? "RIBOS RADINIAI" : "BOUNDARY FINDINGS"}</div>
            <div style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#8c8c88", marginTop: 3 }}>B {sevCount.Block} · R {sevCount.Reject} · W {sevCount.Warn}</div>
          </div>
          <div style={{ display: "flex", alignItems: "center" }}><ErpRail active={!!busy} /></div>
          <div style={{ flex: "1 1 190px", padding: "6px 10px", display: "flex", flexDirection: "column", justifyContent: "center", gap: 6 }}>
            <div style={{ ...lbl, fontSize: 8.5 }}>{LT ? "SAF-T VARIKLIAI" : "SAF-T ENGINES"}</div>
            <button disabled={!totalRows} onClick={() => { audit.log("ERP_PROMOTED_TO_AUDIT", `${erp.store._sources.join("+")} · ${erp.store.invoicesAR.length} AR · ${erp.store.invoicesAP.length} AP`); onPromote(); }} style={{ ...bP, opacity: totalRows ? 1 : 0.5, padding: "8px 14px" }}>{LT ? "Siųsti į SAF-T auditą →" : "Send to SAF-T audit →"}</button>
          </div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(330px,1fr))", gap: 12, marginBottom: 16 }}>
          {connections.map((c) => { const st = erp.syncState[c.id]; const L = liveSync[c.id] || {}; const ap = c.config.autopilot || { on: false, sec: 120 };
            const last = lastRunRef.current[c.id] || (st && st.lastSync ? new Date(st.lastSync).getTime() : 0);
            const frac = busy === c.id ? 1 : ap.on && last ? Math.max(0, 1 - (nowT - last) / (ap.sec * 1000)) : (st && st.lastSync ? 1 : 0);
            const nextIn = ap.on && last ? Math.max(0, Math.ceil((last + ap.sec * 1000 - nowT) / 1000)) : null;
            const col = L.phase === "error" ? "#ff6b6b" : busy === c.id ? "#74c0fc" : ap.on ? "#69db7c" : "#8c8c88";
            const sysRows = ENTITY_KINDS.reduce((s, k) => s + (erp.store[k] || []).filter((x) => ((x.source && x.source.system) || x.system) === c.id).length, 0);
            return <div key={c.id} style={{ border: `1px solid ${L.phase === "error" ? "rgba(255,107,107,.5)" : PL_LINE}`, background: "var(--bg2)", padding: "14px 16px" }}>
              <div style={{ display: "flex", gap: 14, alignItems: "center" }}>
                <ErpRing pct={frac} color={col} label={erpInitials(c.id)} sub={busy === c.id ? "sync" : nextIn != null ? nextIn + "s" : (LT ? "ramybė" : "idle")} />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ color: "#fff", fontFamily: "var(--s)", fontSize: 14.5, fontWeight: 700, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{c.entry.name}</div>
                  <div style={{ ...lbl, marginTop: 2, fontSize: 9 }}>{(demo || c.config.demo) ? "DEMO" : "LIVE"} · {c.entry.protocol.toUpperCase()}{st && st.demoFallback ? " · FALLBACK" : ""}</div>
                  {busy === c.id && L.byEntity && <div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginTop: 5 }}>{Object.entries(L.byEntity).map(([k, v]) => <span key={k} style={{ fontFamily: "var(--m)", fontSize: 8.5, color: v === "✗" ? "#ff6b6b" : "#74c0fc", border: `1px solid ${PL_SOFT}`, padding: "1px 5px" }}>{k} {v}</span>)}</div>}
                  {L.phase === "error" && <div style={{ color: "#ff6b6b", fontFamily: "var(--m)", fontSize: 9.5, marginTop: 4, wordBreak: "break-word" }}>✗ {L.lastErr}</div>}
                </div>
              </div>
              <div style={{ display: "flex", gap: 16, alignItems: "flex-end", marginTop: 12 }}>
                <div><div style={{ fontFamily: "var(--m)", fontSize: 16, fontWeight: 700, color: "#fff" }}>{sysRows}</div><div style={{ ...lbl, fontSize: 8 }}>{LT ? "ĮRAŠAI" : "ROWS"}</div></div>
                <div><div style={{ fontFamily: "var(--m)", fontSize: 16, fontWeight: 700, color: "#d2d2ce" }}>{st && st.lastSync ? erpAgo(st.lastSync) : "—"}</div><div style={{ ...lbl, fontSize: 8 }}>{LT ? "PRIEŠ" : "LAST"}</div></div>
                <div><div style={{ fontFamily: "var(--m)", fontSize: 16, fontWeight: 700, color: "#d2d2ce" }}>{L.lastMs ? L.lastMs + "ms" : "—"}</div><div style={{ ...lbl, fontSize: 8 }}>SYNC</div></div>
                <div style={{ flex: 1 }} />
                <ErpSpark vals={L.durations || []} color={col} />
              </div>
              <div style={{ display: "flex", gap: 8, marginTop: 12, flexWrap: "wrap" }}>
                <button disabled={!!busy} onClick={() => syncNow(c)} style={{ ...bP, padding: "7px 13px", opacity: busy ? 0.5 : 1 }}>{busy === c.id ? (LT ? "Sinch…" : "Syncing…") : (LT ? "Sinchronizuoti" : "Sync now")}</button>
                <button onClick={() => setPilot(c.id, { on: !ap.on })} style={{ ...bG, padding: "7px 12px", borderColor: ap.on ? "#69db7c" : PL_LINE, color: ap.on ? "#69db7c" : "#8c8c88" }}>{ap.on ? (LT ? "Stabdyti autopilotą" : "Pause autopilot") : (LT ? "Įjungti autopilotą" : "Resume autopilot")}</button>
                <button onClick={() => { setMapConnId(c.id); setMapDraft(null); setSub("mapping"); }} style={{ ...bG, padding: "7px 12px" }}>{LT ? "Atvaizdavimas" : "Mapping"}</button>
                <button onClick={() => removeConnection(c.id)} style={{ ...bG, padding: "7px 12px", color: "#ff6b6b", borderColor: "rgba(255,107,107,.4)" }}>{LT ? "Šalinti" : "Remove"}</button>
              </div>
            </div>; })}
        </div>

        {recons.length > 0 && <Section title={LT ? "Sutikrinimo bokštas — 4 kontroliniai skaičiai pagal šaltinį" : "Reconciliation tower — 4 control numbers per source"}>
          <div style={{ overflowX: "auto" }}>
            <div style={{ display: "grid", gridTemplateColumns: "minmax(170px,1.4fr) 70px 100px 100px 100px 100px 100px 80px", gap: 8, fontFamily: "var(--m)", fontSize: 9.5, color: "#8c8c88", letterSpacing: ".06em", textTransform: "uppercase", paddingBottom: 6, minWidth: 860 }}><span>{LT ? "Sistema" : "System"}</span><span>{LT ? "Dok." : "Docs"}</span><span>NET €</span><span>VAT €</span><span>{LT ? "BENDRA €" : "GROSS €"}</span><span>DK D €</span><span>DK K €</span><span>Δ D−K</span></div>
            {recons.map((r) => <div key={r.id} style={{ display: "grid", gridTemplateColumns: "minmax(170px,1.4fr) 70px 100px 100px 100px 100px 100px 80px", gap: 8, padding: "7px 0", borderTop: `1px solid ${PL_SOFT}`, fontFamily: "var(--m)", fontSize: 11, alignItems: "center", minWidth: 860 }}>
              <span style={{ color: "#d2d2ce" }}>{r.name}</span>
              <span style={{ color: "#fff" }}>{r.ar}+{r.ap}</span>
              <span style={{ color: "#d2d2ce" }}>{r.net.toFixed(2)}</span>
              <span style={{ color: "#d2d2ce" }}>{r.vat.toFixed(2)}</span>
              <span style={{ color: "#d2d2ce" }}>{r.gross.toFixed(2)}</span>
              <span style={{ color: "#d2d2ce" }}>{r.glD.toFixed(2)}</span>
              <span style={{ color: "#d2d2ce" }}>{r.glK.toFixed(2)}</span>
              <span style={{ color: r.glDelta <= 0.02 ? "#69db7c" : "#ffd43b", border: `1px solid ${r.glDelta <= 0.02 ? "rgba(105,219,124,.4)" : "rgba(255,212,59,.4)"}`, padding: "2px 7px", justifySelf: "start" }}>{r.glDelta <= 0.02 ? "OK" : r.glDelta.toFixed(2)}</span>
            </div>)}
          </div>
          <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11, marginTop: 8, lineHeight: 1.5 }}>{LT ? "Palyginkite šiuos skaičius su ERP ataskaitomis už tą patį laikotarpį. DEMO sėkloje Δ specialiai ≠ 0 — pasodinti defektai, kad matytumėte variklį veikiant." : "Compare these numbers with the ERP's own reports for the same period. In the DEMO seed Δ ≠ 0 on purpose — planted defects so you can watch the engine work."}</div>
        </Section>}

        {conflicts.length > 0 && <Section title={`${LT ? "Konfliktai tarp sistemų" : "Cross-system conflicts"} (${conflicts.length})`} accent="#ffd43b">
          {conflicts.slice(0, 8).map((cf, i) => <div key={i} style={{ display: "flex", gap: 12, padding: "7px 0", borderTop: i ? `1px solid ${PL_SOFT}` : "none", fontFamily: "var(--m)", fontSize: 11, alignItems: "center", flexWrap: "wrap" }}>
            <span style={{ color: "#ffd43b" }}>{cf.kind}</span><span style={{ color: "#fff" }}>{cf.invoiceNo}</span>
            <span style={{ color: "#8c8c88" }}>{cf.sources.join("  ·  ")}</span>
            <span style={{ color: "#d2d2ce", marginLeft: "auto" }}>€ {cf.amounts.map((a) => a.toFixed(2)).join(" / ")}</span>
          </div>)}
        </Section>}

        <Section title={LT ? "Įvykiai" : "Events"}>
          {!events.length ? <div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 12.5 }}>{LT ? "Dar tylu — paleiskite sinchronizaciją." : "Quiet so far — run a sync."}</div> :
            events.slice(0, 14).map((ev, i) => <div key={ev.t + "-" + i} style={{ display: "flex", gap: 10, alignItems: "baseline", padding: "4px 0", borderTop: i ? `1px solid ${PL_SOFT}` : "none" }}>
              <span style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#666", flexShrink: 0 }}>{new Date(ev.t).toTimeString().slice(0, 8)}</span>
              <span style={{ width: 6, height: 6, borderRadius: "50%", flexShrink: 0, alignSelf: "center", background: ev.kind === "err" ? "#ff6b6b" : ev.kind === "ok" ? "#69db7c" : "#74c0fc" }} />
              <span style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#bcbcb8", wordBreak: "break-word" }}>{ev.msg}</span>
            </div>)}
        </Section>
      </div>}
    </div>}

    {/* ── MAPPING STUDIO ── */}
    {sub === "mapping" && <div>
      {!connections.length ? <Section title="Mapping studio"><div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 13.5 }}>{LT ? "Pirma prijunkite bent vieną sistemą." : "Connect at least one system first."}</div></Section> : <div>
        <div style={{ display: "flex", gap: 10, marginBottom: 14, flexWrap: "wrap", alignItems: "center" }}>
          <select value={mapConn?.id || ""} onChange={(e) => { setMapConnId(e.target.value); setMapDraft(null); }} style={{ ...inp, width: "auto", minWidth: 220 }}>{connections.map((c) => <option key={c.id} value={c.id}>{c.entry.name}</option>)}</select>
          <select value={mapEntity} onChange={(e) => { setMapEntity(e.target.value); setMapDraft(null); }} style={{ ...inp, width: "auto" }}>{["invoicesAR", "invoicesAP", "customers", "suppliers"].map((k) => <option key={k} value={k}>{k}</option>)}</select>
          <button onClick={applyAutoMap} disabled={!autoRes} style={{ ...bG, borderColor: "#74c0fc", color: "#74c0fc", opacity: autoRes ? 1 : 0.5 }}>{LT ? "⌁ Auto žemėlapis" : "⌁ Auto-map"}</button>
          {autoRes && <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88" }}>{LT ? "aprėptis" : "coverage"} {autoRes.coverage}% · ≥70% {LT ? "priimama" : "accepted"}</span>}
          <div style={{ flex: 1 }} />
          {mapDraft && <button onClick={() => setMapDraft(null)} style={bG}>{LT ? "Atstatyti" : "Reset"}</button>}
          <button onClick={saveMapping} style={bP}>{LT ? "Išsaugoti atvaizdavimą" : "Save mapping"}</button>
        </div>
        <div style={{ ...lbl, marginBottom: 8 }}>{(FIELD_MAPS[mapEntry?.adapter] || FIELD_MAPS["generic-rest"]).label}</div>
        <div style={{ display: "grid", gridTemplateColumns: "minmax(380px,1fr) minmax(380px,1.2fr)", gap: 16, alignItems: "start" }}>
          <div style={{ border: `1px solid ${PL_LINE}` }}>
            <div style={{ display: "grid", gridTemplateColumns: "150px 1fr 52px", background: "var(--bg2)", borderBottom: `1px solid ${PL_LINE}` }}>
              <div style={{ ...lbl, padding: "10px 12px" }}>{LT ? "Kanoninis laukas" : "Canonical field"}</div><div style={{ ...lbl, padding: "10px 12px" }}>{LT ? "Šaltinio kelias" : "Source path"}</div><div style={{ ...lbl, padding: "10px 8px", textAlign: "right" }}>{LT ? "Patik." : "Conf."}</div>
            </div>
            {flatFields(effMap).map(([k, v]) => <div key={k} style={{ display: "grid", gridTemplateColumns: "150px 1fr 52px", borderBottom: `1px solid ${PL_SOFT}` }}>
              <div style={{ padding: "8px 12px", color: "#d2d2ce", fontFamily: "var(--m)", fontSize: 11 }}>{k}</div>
              <input value={v} onChange={(e) => setMapField(k, e.target.value)} style={{ ...inp, border: "none", borderLeft: `1px solid ${PL_SOFT}`, background: "transparent", fontFamily: "var(--m)", fontSize: 11 }} />
              <div style={{ padding: "8px 8px", fontFamily: "var(--m)", fontSize: 9.5, textAlign: "right", color: (autoConf[k] || 0) >= 70 ? "#69db7c" : (autoConf[k] || 0) >= 45 ? "#ffd43b" : "#555" }}>{autoConf[k] != null ? autoConf[k] + "%" : "·"}</div>
            </div>)}
          </div>
          <div>
            <div style={{ ...lbl, marginBottom: 8 }}>{LT ? "Tiesioginė peržiūra: žali duomenys → kanoninis modelis" : "Live preview: raw → canonical"}</div>
            {previewRows.length > 0 && <DataTable columns={Object.keys(previewRows[0]).map((k) => ({ key: k, label: k, mono: true }))} data={previewRows} maxRows={5} />}
            <div style={{ ...lbl, margin: "14px 0 8px" }}>{LT ? "Žalių duomenų pavyzdys" : "Raw sample"}</div>
            <pre style={{ background: "var(--bg2)", border: `1px solid ${PL_LINE}`, padding: 12, color: "#bcbcb8", fontFamily: "var(--m)", fontSize: 10.5, lineHeight: 1.5, overflowX: "auto", maxHeight: 220, margin: 0 }}>{JSON.stringify(sampleRaws[0] || {}, null, 2)}</pre>
          </div>
        </div>
      </div>}
    </div>}

    {/* ── TAX-CODE MAPPER ── */}
    {sub === "taxmap" && <div>
      <Section title={LT ? "ERP PVM kodai → STI klasifikatoriai (i.SAF)" : "ERP tax codes → STI classifiers (i.SAF)"}>
        <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 12.5, lineHeight: 1.55, marginBottom: 12 }}>{LT ? "Pasiūlymai („siūloma“) yra euristiniai pagal procentą; deterministinė patikra tikrina tik tarifą pagal datuotą tarifų paketą. Galutinis klasifikatoriaus pasirinkimas — apskaitininko sprendimas." : "Suggestions ('suggested') are pct-based heuristics; deterministic validation only checks the rate against the dated rate pack. The final classifier choice is the accountant's decision."}</div>
        {!rawCodes.length ? <div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 13 }}>{LT ? "Sinchronizuokite bent vieną sistemą, kad matytumėte kodus." : "Sync at least one system to see codes."}</div> : <div style={{ border: `1px solid ${PL_LINE}` }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 90px 1fr 1fr", background: "var(--bg2)", borderBottom: `1px solid ${PL_LINE}` }}>{[LT ? "ERP kodas" : "ERP code", "%", LT ? "Aprašymas" : "Description", LT ? "STI klasifikatorius" : "STI classifier"].map((h) => <div key={h} style={{ ...lbl, padding: "10px 12px" }}>{h}</div>)}</div>
          {rawCodes.map((tc) => { const sug = suggestStiCode(tc); const val = erp.taxMap[tc.rawCode] || ""; return <div key={tc.rawCode} style={{ display: "grid", gridTemplateColumns: "1fr 90px 1fr 1fr", borderBottom: `1px solid ${PL_SOFT}`, alignItems: "center" }}>
            <div style={{ padding: "8px 12px", color: "#fff", fontFamily: "var(--m)", fontSize: 11.5 }}>{tc.rawCode}</div>
            <div style={{ padding: "8px 12px", color: "#d2d2ce", fontFamily: "var(--m)", fontSize: 11.5 }}>{tc.pct}%</div>
            <div style={{ padding: "8px 12px", color: "#8c8c88", fontFamily: "var(--s)", fontSize: 12 }}>{tc.description}{tc.reverseCharge ? " · 96 str." : ""}</div>
            <div style={{ padding: "6px 10px" }}>
              <select value={val} onChange={(e) => setTaxMap(tc.rawCode, e.target.value)} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11 }}>
                <option value="">{sug.code ? `${sug.code} (${LT ? "siūloma" : "suggested"} · ${sug.note})` : LT ? "— pasirinkti —" : "— choose —"}</option>
                {CLS_LIST.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>; })}
        </div>}
        {rawCodes.length > 0 && <button onClick={() => { rawCodes.forEach((tc) => { const s = suggestStiCode(tc); if (s.code && !erp.taxMap[tc.rawCode]) setTaxMap(tc.rawCode, s.code); }); audit.log("ERP_TAXMAP_AUTOFILL", `${rawCodes.length} codes`); }} style={{ ...bG, marginTop: 12 }}>{LT ? "Užpildyti pasiūlymais" : "Fill with suggestions"}</button>}
      </Section>
    </div>}

    {/* ── MONITOR ── */}
    {sub === "csv" && <div style={{ maxWidth: 1000 }}>
      <Section title={LT ? "CSV importas → kanoninis modelis" : "CSV import → canonical model"} accent="#74c0fc">
        <textarea value={csvText} onChange={(e) => { setCsvText(e.target.value); setCsvMap(null); }} placeholder={LT ? "Įklijuokite CSV (antraštės pirmoje eilutėje; skirtukai , ; arba TAB; kableliai dešimtainėms)…" : "Paste CSV (headers in first row; , ; or TAB; decimal commas OK)…"} style={{ ...inp, height: 110, fontFamily: "var(--m)", fontSize: 10.5, resize: "vertical" }} />
        <div style={{ display: "flex", gap: 10, marginTop: 10 }}>
          <button onClick={() => { const p2 = csvParse(csvText); if (!p2.headers.length) { setToast("CSV tuščias"); return; } const m2 = {}; p2.headers.forEach((h, i) => { m2[i] = guessCsvField(h); }); setCsvMap({ ...p2, map: m2 }); }} style={bP}>{LT ? "Analizuoti" : "Analyze"}</button>
          {csvMap && <span style={{ fontFamily: "var(--m)", fontSize: 11, color: "#8c8c88", alignSelf: "center" }}>{csvMap.rows.length} {LT ? "eil." : "rows"} · {csvMap.delimiter === "\t" ? "TAB" : `'${csvMap.delimiter}'`}</span>}
        </div>
        {csvMap && <div style={{ marginTop: 14 }}>
          <div style={{ ...lbl, marginBottom: 8 }}>{LT ? "Stulpelių atvaizdavimas (atspėta automatiškai)" : "Column mapping (auto-guessed)"}</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(170px,1fr))", gap: 8 }}>
            {csvMap.headers.map((h, i) => <div key={i}><div style={{ fontFamily: "var(--m)", fontSize: 10, color: "#d2d2ce", marginBottom: 4, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }} title={h}>{h || "(be antraštės)"}</div><select value={csvMap.map[i]} onChange={(e) => setCsvMap({ ...csvMap, map: { ...csvMap.map, [i]: e.target.value } })} style={{ ...inp, fontFamily: "var(--m)", fontSize: 10.5 }}>{CSV_FIELD_KEYS.map((k) => <option key={k} value={k}>{k}</option>)}</select></div>)}
          </div>
          {(() => { const prev = csvRowsToInvoices(csvMap.headers, csvMap.rows.slice(0, 60), csvMap.map, "AR").slice(0, 3); return prev.length ? <div style={{ marginTop: 12 }}><div style={{ ...lbl, marginBottom: 6 }}>{LT ? "Peržiūra" : "Preview"}</div>{prev.map((v) => <div key={v.invoiceNo} style={{ fontFamily: "var(--m)", fontSize: 11, color: "#bcbcb8", padding: "3px 0" }}>{v.invoiceNo} · {v.invoiceDate} · {v.party.name} ({v.party.vatNo || "—"}) · {v.lines.length} {LT ? "eil." : "ln"} · €{v.totals.gross.toFixed(2)}</div>)}</div> : null; })()}
          <div style={{ display: "flex", gap: 10, marginTop: 12 }}>
            {[["AR", LT ? "Importuoti kaip pardavimus (AR)" : "Import as sales (AR)"], ["AP", LT ? "Importuoti kaip pirkimus (AP)" : "Import as purchases (AP)"]].map(([dir, l]) => <button key={dir} onClick={() => {
              const invs = csvRowsToInvoices(csvMap.headers, csvMap.rows, csvMap.map, dir);
              setErp((s2) => { const store = { ...s2.store }; const key = dir === "AR" ? "invoicesAR" : "invoicesAP"; const seen = new Set(store[key].map((x) => x.source?.externalId || x.invoiceNo)); const fresh = invs.filter((v) => !seen.has(v.source.externalId)); store[key] = [...store[key], ...fresh]; const pk = dir === "AR" ? "customers" : "suppliers"; const pseen = new Set(store[pk].map((p2) => p2.id)); fresh.forEach((v) => { if (!pseen.has(v.party.id)) { store[pk] = [...store[pk], { ...v.party, iban: "" }]; pseen.add(v.party.id); } }); if (!store._sources.includes("csv")) store._sources = [...store._sources, "csv"]; const findings = validateCanonicalBatch(store, helpers); audit.log("ERP_CSV_IMPORT", `${fresh.length} ${dir} (+${invs.length - fresh.length} dupl.) → ${findings.length} findings`); setToast(`${LT ? "Importuota" : "Imported"}: ${fresh.length} ${dir}`); return { ...s2, store, findings }; });
            }} style={bG}>{l}</button>)}
          </div>
        </div>}
      </Section>
    </div>}

    {sub === "monitor" && <div>
      <Section title={LT ? "Duomenų kokybė" : "Data quality"} accent="#74c0fc">
        {(() => { const q = computeDataQuality(erp.store); return <div>
          <div style={{ display: "grid", gridTemplateColumns: "1.2fr 70px 110px 2fr", gap: 8, fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88", padding: "0 0 6px", letterSpacing: ".06em", textTransform: "uppercase" }}><span>{LT ? "Esybė" : "Entity"}</span><span>{LT ? "Eil." : "Rows"}</span><span>{LT ? "Pilnumas" : "Complete"}</span><span>{LT ? "Trūkstami laukai" : "Missing fields"}</span></div>
          {q.entities.map((e2) => <div key={e2.label} style={{ display: "grid", gridTemplateColumns: "1.2fr 70px 110px 2fr", gap: 8, padding: "6px 0", borderTop: `1px solid ${PL_SOFT}`, fontFamily: "var(--m)", fontSize: 11.5 }}><span style={{ color: "#d2d2ce" }}>{e2.label}</span><span style={{ color: "#fff" }}>{e2.rows}</span><span style={{ color: e2.completeness >= 95 ? "#69db7c" : e2.completeness >= 80 ? "#ffd43b" : "#ff6b6b" }}>{e2.completeness}%</span><span style={{ color: "#8c8c88", fontSize: 10 }}>{e2.missing}</span></div>)}
          <div style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#8c8c88", marginTop: 10 }}>{LT ? "Sąskaitų dublikatai" : "Invoice duplicates"}: {q.duplicates} · {LT ? "Valiutos" : "Currencies"}: {q.currencies || "—"} · {LT ? "Laikotarpis" : "Range"}: {q.dateRange}</div>
        </div>; })()}
      </Section>
      <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 14, flexWrap: "wrap" }}>
        <div style={{ ...lbl }}>{LT ? "Kanoninė saugykla" : "Canonical store"}: <span style={{ color: "#fff" }}>{totalRows}</span> {LT ? "įrašų iš" : "rows from"} <span style={{ color: "#fff" }}>{erp.store._sources.join(" + ") || "—"}</span></div>
        <div style={{ flex: 1 }} />
        <button disabled={!totalRows} onClick={() => { audit.log("ERP_PROMOTED_TO_AUDIT", `${erp.store._sources.join("+")} · ${erp.store.invoicesAR.length} AR · ${erp.store.invoicesAP.length} AP`); onPromote(); }} style={{ ...bP, opacity: totalRows ? 1 : 0.5 }}>{LT ? "Perduoti SAF-T auditui →" : "Promote to SAF-T audit →"}</button>
      </div>
      {hasSaft && <div style={{ color: "#74c0fc", fontFamily: "var(--m)", fontSize: 10.5, letterSpacing: ".06em", marginBottom: 12 }}>{LT ? "Pastaba: perdavimas pakeis šiuo metu įkeltą SAF-T duomenų rinkinį." : "Note: promoting will replace the currently loaded SAF-T dataset."}</div>}
      <Section title={LT ? "Sinchronizavimo būsena" : "Sync state"}>
        {Object.keys(erp.syncState).length === 0 ? <div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 13 }}>{LT ? "Dar nesinchronizuota." : "Nothing synced yet."}</div> :
          <DataTable columns={[{ key: "id", label: "System", mono: true }, { key: "lastSync", label: LT ? "Pask. sinch." : "Last sync", mono: true }, { key: "rows", label: LT ? "Įrašai" : "Rows", mono: true }, { key: "status", label: LT ? "Būsena" : "Status", mono: true, color: (r) => r.status === "error" ? "#ff6b6b" : r.status === "ok" ? "#69db7c" : "#d2d2ce" }, { key: "fb", label: "Fallback", mono: true }]} data={Object.entries(erp.syncState).map(([id, s]) => ({ id, lastSync: (s.lastSync || "—").replace("T", " ").slice(0, 19), rows: s.rows, status: s.status + (s.errors?.length ? ` (${s.errors.length})` : ""), fb: s.demoFallback ? "demo" : "—" }))} maxRows={20} />}
      </Section>
      <Section title={`${LT ? "Ribos patikros radiniai" : "Boundary findings"} (${erp.findings.length})`} accent={sortedFindings[0] ? SC(sortedFindings[0].severityUi) : undefined}>
        {!sortedFindings.length ? <div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 13 }}>{LT ? "Radinių nėra — sinchronizuokite sistemą." : "No findings — sync a system."}</div> :
          sortedFindings.map((f, i) => <div key={i} style={{ display: "flex", gap: 12, alignItems: "flex-start", padding: "10px 2px", borderBottom: `1px solid ${PL_SOFT}` }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 9, fontWeight: 700, letterSpacing: ".08em", color: "#000", background: SC(f.severityUi), padding: "2px 7px", flexShrink: 0 }}>{f.severityUi.toUpperCase()}</span>
            <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88", flexShrink: 0, paddingTop: 1 }}>{f.rule_id}</span>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ color: "#fff", fontFamily: "var(--s)", fontSize: 13, fontWeight: 600 }}>{LT ? (f.ruleMeta?.titleLt || f.title) : f.title}{f.hitCount > 1 ? ` ×${f.hitCount}` : ""}</div>
              <div style={{ color: "#8c8c88", fontFamily: "var(--m)", fontSize: 10.5, marginTop: 3, lineHeight: 1.5, wordBreak: "break-word" }}>{f.detail}</div>
              <div style={{ color: "#666", fontFamily: "var(--m)", fontSize: 9.5, marginTop: 3, letterSpacing: ".04em" }}>{f.legal_basis}</div>
            </div>
          </div>)}
      </Section>
    </div>}

    {/* ── AGENT / RELAY SPEC ── */}
    {sub === "agent" && <div>
      <Section title={LT ? "Vercel relė /api/erp (sutartis)" : "Vercel relay /api/erp (contract)"}>
        <pre style={{ background: "var(--bg)", border: `1px solid ${PL_LINE}`, padding: 14, color: "#bcbcb8", fontFamily: "var(--m)", fontSize: 10.5, lineHeight: 1.55, overflowX: "auto", margin: 0, whiteSpace: "pre-wrap" }}>{`POST ${ERP_RELAY}
{ system, protocol, action: "auth"|"health"|"pull"|"push",
  entity, since, cursor, baseUrl,
  credentials | { credRef: "env:NAME" }, payload? }
→ { ok, records[], nextCursor, done }  |  { ok, status, latencyMs }  |  { ok:false, error, transient }

${LT ? "Relė — be būsenos, nieko nesaugo, neloguoja krovinių. Tas pats šablonas kaip jūsų /api/ai tarpinė." : "The relay is stateless, stores nothing, logs no payloads. Same pattern as your existing /api/ai proxy."}`}</pre>
      </Section>
      <Section title={LT ? "Node.js sinchronizavimo agentas + webhook (projektinė specifikacija)" : "Node.js sync agent + webhook (design-only spec)"}>
        <pre style={{ background: "var(--bg)", border: `1px solid ${PL_LINE}`, padding: 14, color: "#bcbcb8", fontFamily: "var(--m)", fontSize: 10.5, lineHeight: 1.55, overflowX: "auto", margin: 0, whiteSpace: "pre-wrap" }}>{SYNC_AGENT_SPEC}</pre>
      </Section>
    </div>}
  </div>;
}

// ════════════════════════════════════════════════════════════════════
// E-INVOICING TAB — Lithuanian e-invoicing hub UI (Module 2)
// dashboard · compose · outbox · inbox · archive · settings/ViDA
// ════════════════════════════════════════════════════════════════════
// ─── In-app engine self-tests (deploy sign-off) ────────────────────────
function Fr0600Compare({ parsed, lang }) {
  const [open, setOpen] = useState(false);
  const [filed, setFiled] = useState({});
  const res = useMemo(() => (parsed ? computeFr0600(parsed) : null), [parsed]);
  if (!parsed || !res) return null;
  const L = (lt, en) => (lang === "lt" ? lt : en);
  const rows = (res.rows || []).filter((r) => r.value != null);
  let fld = 0, mism = 0;
  const data = rows.map((r) => {
    const raw = String(filed[r.box] ?? "").replace(",", ".").trim();
    const f = raw === "" ? null : parseFloat(raw);
    const ok = f != null && isFinite(f);
    const d = ok ? Math.round((f - r.value) * 100) / 100 : null;
    if (ok) { fld++; if (Math.abs(d) > 0.01) mism++; }
    return { box: r.box, label: r.label, value: r.value, f, d };
  });
  const LINE = "#3a3f4d";
  const btn = { background: "transparent", color: "inherit", border: `1px solid ${LINE}`, padding: "6px 10px", cursor: "pointer", fontFamily: "inherit", fontSize: 12 };
  return <>
    <button onClick={() => setOpen(true)} style={btn} title={L("Palyginti su pateikta deklaracija", "Compare with the filed return")}>{"\u21c4"} {L("FR0600 vs deklaruota", "FR0600 vs filed")}</button>
    {open ? createPortal(<div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.55)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center" }} onClick={() => setOpen(false)}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: "var(--bg2, #14161c)", border: `1px solid ${LINE}`, padding: 20, width: 780, maxWidth: "94vw", maxHeight: "84vh", overflow: "auto", color: "inherit" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <strong>{L("FR0600 palyginimas: apskai\u010diuota i\u0161 SAF-T vs deklaruota", "FR0600 comparison: computed from SAF-T vs filed")}</strong>
          <button data-frclose onClick={() => setOpen(false)} style={btn}>{"\u2715"}</button>
        </div>
        <div style={{ fontSize: 12, opacity: .8, marginBottom: 12 }}>{L("\u012eveskite pateiktos FR0600 reik\u0161mes \u2014 skirtumai skai\u010diuojami deterministi\u0161kai (tolerancija 0,01 EUR). Laukeliai 28/35/36 nenustatomi i\u0161 SAF-T.", "Enter the filed FR0600 values \u2014 differences are computed deterministically (0.01 EUR tolerance). Boxes 28/35/36 are not derivable from SAF-T.")}</div>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
          <thead><tr>
            <th style={{ textAlign: "left", borderBottom: `1px solid ${LINE}`, padding: 6 }}>{L("Laukelis", "Box")}</th>
            <th style={{ textAlign: "left", borderBottom: `1px solid ${LINE}`, padding: 6 }}>{L("Apra\u0161ymas", "Label")}</th>
            <th style={{ textAlign: "right", borderBottom: `1px solid ${LINE}`, padding: 6 }}>{L("I\u0161 SAF-T", "From SAF-T")}</th>
            <th style={{ textAlign: "right", borderBottom: `1px solid ${LINE}`, padding: 6 }}>{L("Deklaruota", "Filed")}</th>
            <th style={{ textAlign: "right", borderBottom: `1px solid ${LINE}`, padding: 6 }}>{"\u0394"}</th>
          </tr></thead>
          <tbody>
            {data.map((r) => <tr key={r.box}>
              <td style={{ padding: 6, borderBottom: `1px solid ${LINE}` }}>{r.box}</td>
              <td style={{ padding: 6, borderBottom: `1px solid ${LINE}`, opacity: .85 }}>{String(r.label || "").slice(0, 52)}</td>
              <td style={{ padding: 6, borderBottom: `1px solid ${LINE}`, textAlign: "right" }}>{r.value.toFixed(2)}</td>
              <td style={{ padding: 6, borderBottom: `1px solid ${LINE}`, textAlign: "right" }}>
                <input data-box={r.box} value={filed[r.box] ?? ""} onChange={(e) => setFiled({ ...filed, [r.box]: e.target.value })} placeholder={"\u2014"} style={{ width: 110, background: "transparent", color: "inherit", border: `1px solid ${LINE}`, padding: "3px 6px", textAlign: "right", fontFamily: "inherit" }} />
              </td>
              <td style={{ padding: 6, borderBottom: `1px solid ${LINE}`, textAlign: "right", color: r.d == null ? "inherit" : (Math.abs(r.d) > 0.01 ? "#ff6b6b" : "#7bd88f") }}>{r.d == null ? "\u2014" : r.d.toFixed(2)}</td>
            </tr>)}
          </tbody>
        </table>
        <div style={{ marginTop: 10, fontSize: 12 }}>
          {L("U\u017epildyta", "Filled")}: {fld} {" \u00b7 "} {L("Neatitikim\u0173", "Mismatches")}: <strong style={{ color: mism ? "#ff6b6b" : "#7bd88f" }}>{mism}</strong>
        </div>
      </div>
    </div>, document.body) : null}
  </>;
}

function PriorPeriodCompare({ parsed, lang }) {
  const [open, setOpen] = useState(false);
  const [prior, setPrior] = useState(null);
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");
  const [fname, setFname] = useState("");
  const L = (lt, en) => (lang === "lt" ? lt : en);
  const nextDay = (s) => { if (!/^\d{4}-\d{2}-\d{2}/.test(s || "")) return ""; const d = new Date(Date.UTC(+s.slice(0,4), +s.slice(5,7)-1, +s.slice(8,10)) + 86400000); return d.toISOString().slice(0,10); };
  const cmp = useMemo(() => {
    if (!parsed || !prior) return null;
    const r2 = (x) => Math.round(x * 100) / 100;
    const out = { header: [], gl: [], parties: [], stock: [], mism: 0 };
    const ch = parsed.header || {}, ph = prior.header || {};
    if (String(ch.registrationNumber || "") !== String(ph.registrationNumber || "")) { out.header.push({ k: L("\u012emon\u0117s kodas", "Registration no."), pri: ph.registrationNumber || "\u2014", cur: ch.registrationNumber || "\u2014", bad: true }); out.mism++; }
    const pe = String(ph.fiscalYearTo || ph.periodEnd || "").slice(0,10), cs = String(ch.fiscalYearFrom || ch.periodStart || "").slice(0,10);
    if (pe && cs && nextDay(pe) !== cs) { out.header.push({ k: L("Laikotarpi\u0173 sand\u016bra", "Period adjacency"), pri: pe, cur: cs, bad: true }); out.mism++; }
    else if (pe && cs) out.header.push({ k: L("Laikotarpi\u0173 sand\u016bra", "Period adjacency"), pri: pe, cur: cs, bad: false });
    const pacc = new Map(); (prior.accounts || []).forEach((a) => pacc.set(String(a.accountID || ""), a));
    const seen = new Set();
    (parsed.accounts || []).forEach((a) => {
      const id = String(a.accountID || ""); if (!id) return; seen.add(id);
      const od = a.openingDebitBalance || 0, oc = a.openingCreditBalance || 0;
      const p = pacc.get(id); const cd = p ? (p.closingDebitBalance || 0) : null, cc = p ? (p.closingCreditBalance || 0) : null;
      if (!p) { if (Math.abs(od) > 0.005 || Math.abs(oc) > 0.005) { out.gl.push({ id, name: a.accountDescription || "", kind: "missP", od: r2(od), oc: r2(oc) }); out.mism++; } return; }
      if (Math.abs(od - cd) > 0.01 || Math.abs(oc - cc) > 0.01) { out.gl.push({ id, name: a.accountDescription || "", kind: "diff", od: r2(od), cd: r2(cd), oc: r2(oc), cc: r2(cc), dD: r2(od - cd), dC: r2(oc - cc) }); out.mism++; }
    });
    (prior.accounts || []).forEach((p) => { const id = String(p.accountID || ""); if (!id || seen.has(id)) return; const cd = p.closingDebitBalance || 0, cc = p.closingCreditBalance || 0; if (Math.abs(cd) > 0.005 || Math.abs(cc) > 0.005) { out.gl.push({ id, name: p.accountDescription || "", kind: "missC", cd: r2(cd), cc: r2(cc) }); out.mism++; } });
    const partyScan = (curArr, priArr, idk, side) => {
      const pm = new Map(); (priArr || []).forEach((m) => { let s = 0; (m.accounts || []).forEach((ac) => { s += (ac.cd || 0) - (ac.cc || 0); }); pm.set(String(m[idk] || ""), s); });
      (curArr || []).forEach((m) => { const id = String(m[idk] || ""); if (!id || !pm.has(id)) return; let o = 0; (m.accounts || []).forEach((ac) => { o += (ac.od || 0) - (ac.oc || 0); }); const pc = pm.get(id); if (Math.abs(o - pc) > 0.01) { out.parties.push({ side, id, name: (m.name || "").slice(0, 30), open: r2(o), close: r2(pc), d: r2(o - pc) }); out.mism++; } });
    };
    partyScan(parsed.customers, prior.customers, "customerID", "C");
    partyScan(parsed.suppliers, prior.suppliers, "supplierID", "S");
    const pst = new Map(); (prior.physicalStock || []).forEach((e) => pst.set(String(e.productCode || ""), e));
    (parsed.physicalStock || []).forEach((e) => { const id = String(e.productCode || ""); const p = pst.get(id); if (!p) return; const oq = e.openingStockQuantity || 0, cq = p.closingStockQuantity || 0; const ov = e.openingStockValue, cv = p.closingStockValue; let bad = Math.abs(oq - cq) > 0.0001; if (ov != null && cv != null && Math.abs(ov - cv) > 0.01) bad = true; if (bad) { out.stock.push({ id, oq: r2(oq), cq: r2(cq), ov: ov == null ? null : r2(ov), cv: cv == null ? null : r2(cv) }); out.mism++; } });
    return out;
  }, [parsed, prior, lang]);
  if (!parsed) return null;
  const LINE = "#3a3f4d";
  const btn = { background: "transparent", color: "inherit", border: `1px solid ${LINE}`, padding: "6px 10px", cursor: "pointer", fontFamily: "inherit", fontSize: 12 };
  const td = { padding: 5, borderBottom: `1px solid ${LINE}` };
  const onFile = (e) => {
    const f = e.target.files && e.target.files[0]; if (!f) return;
    setErr(""); setBusy(true); setFname(f.name);
    const rd = new FileReader();
    rd.onload = () => { setTimeout(() => { try { const p = parseSAFTFull(String(rd.result || "")); if (p && p._parseError) { setErr(p._parseError); setPrior(null); } else setPrior(p); } catch (ex) { setErr(String(ex).slice(0, 160)); setPrior(null); } setBusy(false); }, 30); };
    rd.onerror = () => { setErr("read error"); setBusy(false); };
    rd.readAsText(f);
  };
  return <>
    <button onClick={() => setOpen(true)} style={btn} title={L("T\u0119stinumo patikra su ankstesnio laikotarpio SAF-T", "Continuity check against the prior-period SAF-T")}>{"\u21bb"} {L("Ankstesnis laikotarpis", "Prior period")}</button>
    {open ? createPortal(<div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.55)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center" }} onClick={() => setOpen(false)}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: "var(--bg2, #14161c)", border: `1px solid ${LINE}`, padding: 20, width: 880, maxWidth: "95vw", maxHeight: "86vh", overflow: "auto", color: "inherit", fontSize: 12 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <strong>{L("T\u0119stinumo patikra: ankstesnio laikotarpio SAF-T", "Continuity check: prior-period SAF-T")}</strong>
          <button data-ppclose onClick={() => setOpen(false)} style={btn}>{"\u2715"}</button>
        </div>
        <div style={{ opacity: .8, marginBottom: 10 }}>{L("\u012ekelkite ankstesnio laikotarpio SAF-T \u2014 uždarymo likučiai lyginami su einamojo laikotarpio atidarymo likučiais (DK, pirk\u0117jai/tiek\u0117jai, atsargos; tolerancija 0,01 EUR). Turtas \u2014 v\u0117lesn\u0117je versijoje.", "Upload the prior-period SAF-T \u2014 its closing balances are compared with the current opening balances (GL, customers/suppliers, stock; 0.01 EUR tolerance). Assets \u2014 in a later version.")}</div>
        <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 12 }}>
          <label style={{ ...btn, display: "inline-block" }}>
            {L("Pasirinkti fail\u0105", "Choose file")}
            <input data-prior-input type="file" accept=".xml" onChange={onFile} style={{ display: "none" }} />
          </label>
          <span style={{ opacity: .8 }}>{busy ? L("Skaitoma\u2026", "Reading\u2026") : (fname || "\u2014")}</span>
          {prior ? <button onClick={() => { setPrior(null); setFname(""); }} style={btn}>{L("I\u0161valyti", "Clear")}</button> : null}
          {err ? <span style={{ color: "#ff6b6b" }}>{err}</span> : null}
        </div>
        {cmp ? <>
          <div style={{ marginBottom: 10 }}>{L("T\u0119stinumo neatitikim\u0173", "Continuity mismatches")}: <strong style={{ color: cmp.mism ? "#ff6b6b" : "#7bd88f" }}>{cmp.mism}</strong></div>
          {cmp.header.map((h, i) => <div key={i} style={{ color: h.bad ? "#ff6b6b" : "#7bd88f", marginBottom: 4 }}>{h.k}: {h.pri} {"\u2192"} {h.cur}</div>)}
          {cmp.gl.length ? <>
            <div style={{ margin: "10px 0 4px", fontWeight: 600 }}>{L("DK s\u0105skaitos (atidarymas vs ankstesnis u\u017edarymas)", "GL accounts (opening vs prior closing)")} \u2014 {cmp.gl.length}</div>
            <table style={{ width: "100%", borderCollapse: "collapse" }}><thead><tr><th style={{...td,textAlign:"left"}}>ID</th><th style={{...td,textAlign:"left"}}>{L("Pavadinimas","Name")}</th><th style={{...td,textAlign:"right"}}>D: {L("dab.","cur")}/{L("ankst.","prior")}</th><th style={{...td,textAlign:"right"}}>{"\u0394"}D</th><th style={{...td,textAlign:"right"}}>K: {L("dab.","cur")}/{L("ankst.","prior")}</th><th style={{...td,textAlign:"right"}}>{"\u0394"}K</th></tr></thead><tbody>
              {cmp.gl.slice(0, 50).map((g, i) => <tr key={i}>
                <td style={td}>{g.id}</td><td style={{...td,opacity:.85}}>{String(g.name).slice(0,26)}{g.kind==="missP"?L(" (n\u0117ra ankstesniame)"," (missing in prior)"):g.kind==="missC"?L(" (n\u0117ra einamajame)"," (missing in current)"):""}</td>
                <td style={{...td,textAlign:"right"}}>{g.od != null ? g.od.toFixed(2) : "\u2014"} / {g.cd != null ? g.cd.toFixed(2) : "\u2014"}</td>
                <td style={{...td,textAlign:"right",color:"#ff6b6b"}}>{g.dD != null ? g.dD.toFixed(2) : "\u2014"}</td>
                <td style={{...td,textAlign:"right"}}>{g.oc != null ? g.oc.toFixed(2) : "\u2014"} / {g.cc != null ? g.cc.toFixed(2) : "\u2014"}</td>
                <td style={{...td,textAlign:"right",color:"#ff6b6b"}}>{g.dC != null ? g.dC.toFixed(2) : "\u2014"}</td>
              </tr>)}
            </tbody></table>
          </> : null}
          {cmp.parties.length ? <>
            <div style={{ margin: "10px 0 4px", fontWeight: 600 }}>{L("Pirk\u0117jai / tiek\u0117jai", "Customers / suppliers")} \u2014 {cmp.parties.length}</div>
            {cmp.parties.slice(0, 30).map((p, i) => <div key={i}>{p.side === "C" ? L("Pirk.", "Cust.") : L("Tiek.", "Supp.")} {p.id} {p.name}: {p.open.toFixed(2)} vs {p.close.toFixed(2)} ({"\u0394"} <span style={{ color: "#ff6b6b" }}>{p.d.toFixed(2)}</span>)</div>)}
          </> : null}
          {cmp.stock.length ? <>
            <div style={{ margin: "10px 0 4px", fontWeight: 600 }}>{L("Atsargos", "Stock")} \u2014 {cmp.stock.length}</div>
            {cmp.stock.slice(0, 30).map((s, i) => <div key={i}>{s.id}: {L("kiekis", "qty")} {s.oq} vs {s.cq}{s.ov != null && s.cv != null ? `; ${L("vert\u0117", "value")} ${s.ov.toFixed(2)} vs ${s.cv.toFixed(2)}` : ""}</div>)}
          </> : null}
        </> : (busy ? null : <div style={{ opacity: .6 }}>{L("Failas ne\u012fkeltas.", "No file loaded.")}</div>)}
      </div>
    </div>, document.body) : null}
  </>;
}

function VIESCheck({ lang }) {
  const [open, setOpen] = useState(false);
  const [num, setNum] = useState("");
  const [res, setRes] = useState(null);
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");
  const L = (lt, en) => (lang === "lt" ? lt : en);
  const LINE = "#3a3f4d";
  const btn = { background: "transparent", color: "inherit", border: `1px solid ${LINE}`, padding: "6px 10px", cursor: "pointer", fontFamily: "inherit", fontSize: 12 };
  const check = async () => {
    const v = num.toUpperCase().replace(/\s/g, "");
    const m = v.match(/^([A-Z]{2})([A-Z0-9+*]{2,14})$/);
    if (!m) { setErr(L("\u012eveskite kod\u0105 su \u0161alies prefiksu, pvz., LT123456715", "Enter a code with a country prefix, e.g., LT123456715")); setRes(null); return; }
    setBusy(true); setErr(""); setRes(null);
    try {
      const r = await fetch(`/api/vies?country=${m[1]}&number=${encodeURIComponent(m[2])}`);
      if (!r.ok) throw new Error("HTTP " + r.status);
      const j = await r.json();
      if (j && j.error) throw new Error(j.error);
      setRes(j);
    } catch (ex) {
      setErr(L("VIES tarpin\u0117 tarnyba nepasiekiama \u2014 \u012fdiekite api/vies.js \u0161alia api/ai.js ir perdiekite.", "VIES proxy unreachable \u2014 deploy api/vies.js next to api/ai.js and redeploy."));
    }
    setBusy(false);
  };
  return <>
    <button onClick={() => setOpen(true)} style={btn} title={L("PVM kodo patikra ES VIES registre (per js tarpin\u0119 tarnyb\u0105)", "Check a VAT number in the EU VIES registry (via the api proxy)")}>{"\u2713"} {L("VIES patikra", "VIES check")}</button>
    {open ? createPortal(<div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.55)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center" }} onClick={() => setOpen(false)}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: "var(--bg2, #14161c)", border: `1px solid ${LINE}`, padding: 20, width: 480, maxWidth: "92vw", color: "inherit", fontSize: 12 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <strong>{L("VIES patikra", "VIES check")}</strong>
          <button data-viesclose onClick={() => setOpen(false)} style={btn}>{"\u2715"}</button>
        </div>
        <div style={{ opacity: .8, marginBottom: 10 }}>{L("Tikrinama Europos Komisijos VIES sistemoje per j\u016bs\u0173 diegimo /api/vies tarpin\u0119 tarnyb\u0105 (realiu laiku, neka\u0161uojama \u012f fail\u0105).", "Validated against the European Commission VIES system through your deployment's /api/vies proxy (real-time).")}</div>
        <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
          <input data-vies-input value={num} onChange={(e) => setNum(e.target.value)} placeholder="LT123456715" style={{ flex: 1, background: "transparent", color: "inherit", border: `1px solid ${LINE}`, padding: "6px 8px", fontFamily: "inherit", fontSize: 12 }} />
          <button data-vies-check onClick={check} style={btn}>{busy ? L("Tikrinama\u2026", "Checking\u2026") : L("Tikrinti", "Check")}</button>
        </div>
        {err ? <div style={{ color: "#ff6b6b" }}>{err}</div> : null}
        {res ? <div>
          <div style={{ color: res.valid ? "#7bd88f" : "#ff6b6b", fontWeight: 600 }}>{res.valid ? L("Galioja \u2713", "Valid \u2713") : L("Negalioja \u2715", "Not valid \u2715")}</div>
          {res.name ? <div style={{ marginTop: 4 }}>{res.name}</div> : null}
          {res.address ? <div style={{ opacity: .8 }}>{res.address}</div> : null}
          {res.requestDate ? <div style={{ opacity: .6, marginTop: 4 }}>{L("U\u017eklausos data", "Request date")}: {String(res.requestDate).slice(0, 10)}</div> : null}
        </div> : null}
      </div>
    </div>, document.body) : null}
  </>;
}

function parseIVAZ(xmlStr) {
  try {
    const doc = new DOMParser().parseFromString(xmlStr, "text/xml");
    if (doc.querySelector("parsererror")) return { _parseError: "XML parse error" };
    const all = (el, tag) => Array.from(el.getElementsByTagNameNS("*", tag));
    const one = (el, ...tags) => { for (const t of tags) { const e = all(el, t)[0]; if (e) return e; } return null; };
    const tx = (el, ...tags) => { for (const t of tags) { const e = all(el, t)[0]; if (e && e.textContent != null && String(e.textContent).trim()) return String(e.textContent).trim(); } return ""; };
    const root = doc.documentElement;
    const creatorReg = tx(root, "CreatorRegistrationNumber", "RegistrationNumber", "RegistrationCode");
    let docEls = all(root, "TransportDocument");
    if (!docEls.length) docEls = all(root, "Vaztarastis");
    const docs = docEls.map((el) => {
      const cor = one(el, "Consignor", "ConsignorInfo", "Siuntejas");
      const cee = one(el, "Consignee", "ConsigneeInfo", "Gavejas");
      const refs = [];
      ["InvoiceNumber", "RelatedDocumentNumber", "DocumentReference"].forEach((t) => all(el, t).forEach((e) => { const v = String(e.textContent || "").trim(); if (v) refs.push(v); }));
      return {
        no: tx(el, "LocalTransportDocumentNumber", "TransportDocumentNumber", "DocumentNumber", "Number"),
        date: tx(el, "TransportDocumentDate", "DocumentDate", "IssueDate", "Date").slice(0, 10),
        loadDate: tx(el, "LoadDateTimePlanned", "LoadDateTime", "LoadDate", "DispatchDate").slice(0, 10),
        corReg: cor ? tx(cor, "RegistrationNumber", "CompanyCode", "PersonCode", "Code") : "",
        corName: cor ? tx(cor, "Name") : "",
        ceeReg: cee ? tx(cee, "RegistrationNumber", "CompanyCode", "PersonCode", "Code") : "",
        ceeName: cee ? tx(cee, "Name") : "",
        refs,
      };
    });
    return { creatorReg, docs };
  } catch (ex) { return { _parseError: String(ex).slice(0, 160) }; }
}

function IVazCompare({ parsed, lang }) {
  const [open, setOpen] = useState(false);
  const [ivaz, setIvaz] = useState(null);
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");
  const [fname, setFname] = useState("");
  const L = (lt, en) => (lang === "lt" ? lt : en);
  const cmp = useMemo(() => {
    if (!parsed || !ivaz) return null;
    const normR = (s) => String(s || "").toUpperCase().replace(/[^A-Z0-9]/g, "");
    const ent = normR(parsed.header?.registrationNumber);
    const from = String(parsed.header?.fiscalYearFrom || "").slice(0, 10);
    const to = String(parsed.header?.fiscalYearTo || "").slice(0, 10);
    const moveDays = new Set(); (parsed.stockMovements || []).forEach((m) => { const d = String(m.movementDate || m.transactionDate || "").slice(0, 10); if (d) moveDays.add(d); });
    const hasMoves = (parsed.stockMovements || []).length > 0;
    const salesNos = new Set(); (parsed.sales?.items || []).forEach((iv) => { const n = String(iv.invoiceNo || "").trim().toUpperCase(); if (n) salesNos.add(n); });
    const out = { dup: [], ent: [], per: [], move: [], ref: [], mism: 0, total: (ivaz.docs || []).length };
    const seen = new Map(); (ivaz.docs || []).forEach((d) => { const k = String(d.no || "").trim().toUpperCase(); if (!k) return; seen.set(k, (seen.get(k) || 0) + 1); });
    seen.forEach((c, k) => { if (c > 1) { out.dup.push({ no: k, c }); out.mism++; } });
    (ivaz.docs || []).forEach((d) => {
      const cr = normR(d.corReg), ce = normR(d.ceeReg);
      const isCor = ent && cr === ent;
      if (ent && (cr || ce) && !isCor && ce !== ent) { out.ent.push({ no: d.no || "\u2014", cor: d.corReg || "\u2014", cee: d.ceeReg || "\u2014" }); out.mism++; }
      const inPer = d.date && from && to && d.date >= from && d.date <= to;
      if (d.date && from && to && !inPer) { out.per.push({ no: d.no || "\u2014", date: d.date }); out.mism++; }
      if (hasMoves && isCor && inPer) { const dd = d.loadDate || d.date; if (dd && !moveDays.has(dd) && !moveDays.has(d.date)) { out.move.push({ no: d.no || "\u2014", date: dd }); out.mism++; } }
      (d.refs || []).forEach((r) => { const k = String(r).trim().toUpperCase(); if (k && !salesNos.has(k)) { out.ref.push({ no: d.no || "\u2014", ref: r }); out.mism++; } });
    });
    return out;
  }, [parsed, ivaz]);
  if (!parsed) return null;
  const LINE = "#3a3f4d";
  const btn = { background: "transparent", color: "inherit", border: `1px solid ${LINE}`, padding: "6px 10px", cursor: "pointer", fontFamily: "inherit", fontSize: 12 };
  const onFile = (e) => { const f = e.target.files && e.target.files[0]; if (!f) return; setErr(""); setBusy(true); setFname(f.name); const rd = new FileReader(); rd.onload = () => { setTimeout(() => { const p = parseIVAZ(String(rd.result || "")); if (p && p._parseError) { setErr(p._parseError); setIvaz(null); } else setIvaz(p); setBusy(false); }, 30); }; rd.onerror = () => { setErr("read error"); setBusy(false); }; rd.readAsText(f); };
  const sect = (title, rows, fmt) => rows.length ? <div style={{ marginTop: 10 }}><div style={{ fontWeight: 600, marginBottom: 4 }}>{title} \u2014 {rows.length}</div>{rows.slice(0, 30).map((r, i) => <div key={i} style={{ color: "#ff6b6b" }}>{fmt(r)}</div>)}</div> : null;
  return <>
    <button onClick={() => setOpen(true)} style={btn} title={L("Sutikrinti pateikt\u0105 i.VAZ va\u017etara\u0161\u010di\u0173 registr\u0105 su SAF-T", "Reconcile the filed i.VAZ waybill register with the SAF-T")}>{"\u21c4"} i.VAZ</button>
    {open ? createPortal(<div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.55)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center" }} onClick={() => setOpen(false)}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: "var(--bg2, #14161c)", border: `1px solid ${LINE}`, padding: 20, width: 880, maxWidth: "95vw", maxHeight: "86vh", overflow: "auto", color: "inherit", fontSize: 12 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <strong>{L("i.VAZ sutikrinimas su SAF-T", "i.VAZ reconciliation with SAF-T")}</strong>
          <button data-ivazclose onClick={() => setOpen(false)} style={btn}>{"\u2715"}</button>
        </div>
        <div style={{ opacity: .8, marginBottom: 10 }}>{L("\u012ekelkite pateikt\u0105 i.VAZ XML \u2014 tikrinama: va\u017etara\u0161\u010di\u0173 numeri\u0173 dubliai, ar \u012fmon\u0117 yra siunt\u0117jas/gav\u0117jas, datos rinkmenos laikotarpyje, i\u0161siuntimo dienos atsarg\u0173 jud\u0117jimai (kai SAF-T juos turi) ir nuorodos \u012f pardavimo SF. Muitin\u0117s deklaracij\u0173 sutikrinimas \u2014 b\u016bsima funkcija su atskiru failu.", "Upload the filed i.VAZ XML \u2014 checks: duplicate waybill numbers, entity present as consignor/consignee, dates within the file period, dispatch-day stock movements (when the SAF-T carries them) and references to sales invoices. Customs-declaration reconciliation \u2014 a future feature with its own file.")}</div>
        <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 12 }}>
          <label style={{ ...btn, display: "inline-block" }}>
            {L("Pasirinkti fail\u0105", "Choose file")}
            <input data-ivaz-input type="file" accept=".xml" onChange={onFile} style={{ display: "none" }} />
          </label>
          <span style={{ opacity: .8 }}>{busy ? L("Skaitoma\u2026", "Reading\u2026") : (fname || "\u2014")}</span>
          {ivaz ? <button onClick={() => { setIvaz(null); setFname(""); }} style={btn}>{L("I\u0161valyti", "Clear")}</button> : null}
          {err ? <span style={{ color: "#ff6b6b" }}>{err}</span> : null}
        </div>
        {cmp ? <>
          <div>{L("Va\u017etara\u0161\u010di\u0173", "Waybills")}: {cmp.total} {" \u00b7 "} {L("i.VAZ neatitikim\u0173", "i.VAZ mismatches")}: <strong style={{ color: cmp.mism ? "#ff6b6b" : "#7bd88f" }}>{cmp.mism}</strong></div>
          {sect(L("Dubliuoti numeriai", "Duplicate numbers"), cmp.dup, (r) => `${r.no} \u00d7${r.c}`)}
          {sect(L("\u012emon\u0117 n\u0117ra nei siunt\u0117jas, nei gav\u0117jas", "Entity is neither consignor nor consignee"), cmp.ent, (r) => `${r.no}: ${r.cor} \u2192 ${r.cee}`)}
          {sect(L("Data u\u017e rinkmenos laikotarpio", "Date outside the file period"), cmp.per, (r) => `${r.no}: ${r.date}`)}
          {sect(L("N\u0117ra atsarg\u0173 jud\u0117jimo i\u0161siuntimo dien\u0105 (per\u017ei\u016bra)", "No stock movement on dispatch day (review)"), cmp.move, (r) => `${r.no}: ${r.date}`)}
          {sect(L("Nuoroda \u012f neegzistuojan\u010di\u0105 pardavimo SF", "Reference to a non-existent sales invoice"), cmp.ref, (r) => `${r.no}: ${r.ref}`)}
          {!cmp.mism ? <div style={{ color: "#7bd88f", marginTop: 8 }}>{L("Registrai sutampa.", "Registers match.")}</div> : null}
        </> : (busy ? null : <div style={{ opacity: .6 }}>{L("Failas ne\u012fkeltas.", "No file loaded.")}</div>)}
      </div>
    </div>, document.body) : null}
  </>;
}

function SelfTestPanel({ lang }) {
  const LT = lang === "lt";
  const [busy, setBusy] = useState(false);
  const [res, setRes] = useState(null);
  const run = async () => {
    setBusy(true); setRes(null);
    try {
      const today = new Date().toISOString().slice(0, 10);
      const H1 = { classifyVatRate, isValidLtIban, isLtVatNumber, ISO_4217, taxMap: {} };
      const H2 = { classifyVatRate, isValidLtIban, isLtVatNumber, isLtRegistrationNumber, ISO_4217, today };
      const a = await runErpSelfTest(H1);
      const b = await runEinvSelfTest(H2, undefined);
      const c = await runExportSelfTest(H2);
      setRes({ ok: a.ok && b.ok && c.ok, conf: b.conformance, groups: [[LT ? "ERP centras" : "ERP hub", a.checks], [LT ? "E. sąskaitos" : "E-invoicing", b.checks], [LT ? "Eksportai · apsisukimas" : "Exports · round-trip", c.checks]] });
    } catch (err) { setRes({ ok: false, error: err.message, groups: [] }); }
    setBusy(false);
  };
  return <div style={{ marginTop: 26, border: "1px solid rgba(255,255,255,0.12)", background: "var(--bg2)", padding: "16px 18px" }}>
    <div style={{ display: "flex", alignItems: "center", gap: 14, flexWrap: "wrap" }}>
      <div style={{ color: "#fff", fontFamily: "var(--s)", fontSize: 14.5, fontWeight: 700 }}>{LT ? "Variklių savitikra" : "Engine self-tests"}</div>
      <button disabled={busy} onClick={run} style={{ background: "#fff", color: "#000", border: "none", padding: "8px 16px", fontSize: 11, fontWeight: 700, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer", opacity: busy ? 0.6 : 1 }}>{busy ? (LT ? "Vykdoma…" : "Running…") : (LT ? "Vykdyti visus" : "Run all")}</button>
      {res && !res.error && <span style={{ fontFamily: "var(--m)", fontSize: 12, fontWeight: 700, color: res.ok ? "#69db7c" : "#ff6b6b" }}>{res.ok ? (LT ? "✓ VISI TESTAI PRAĖJO" : "✓ ALL TESTS PASS") : (LT ? "✗ YRA KLAIDŲ" : "✗ FAILURES")}{res.conf ? ` · conformance ${res.conf.passed}/${res.conf.total}` : ""}</span>}
      {res?.error && <span style={{ fontFamily: "var(--m)", fontSize: 11, color: "#ff6b6b" }}>{res.error}</span>}
    </div>
    {res && res.groups.map(([g, checks]) => <div key={g} style={{ marginTop: 12 }}>
      <div style={{ fontSize: 10, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase", marginBottom: 5 }}>{g}</div>
      {checks.map((c, i) => <div key={i} style={{ display: "flex", gap: 10, padding: "4px 0", borderBottom: "1px solid rgba(255,255,255,0.06)", alignItems: "baseline" }}>
        <span style={{ fontFamily: "var(--m)", fontSize: 10, color: c.pass ? "#69db7c" : "#ff6b6b", width: 34, flexShrink: 0 }}>{c.pass ? "PASS" : "FAIL"}</span>
        <span style={{ fontFamily: "var(--s)", fontSize: 12, color: "#d2d2ce" }}>{c.name}</span>
        <span style={{ fontFamily: "var(--m)", fontSize: 9.5, color: "#666", marginLeft: "auto", textAlign: "right", maxWidth: 320, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }} title={c.detail}>{c.detail}</span>
      </div>)}
    </div>)}
    <div style={{ fontSize: 10, color: "#666", fontFamily: "var(--m)", marginTop: 10, letterSpacing: ".03em" }}>{LT ? "Apsisukimai: kanonas → SAF-T XML → parseSAFTFull → 250 taisyklių · e. sąskaitos → i.SAF XML → parseISAF → sutikrinimas." : "Round-trips: canonical → SAF-T XML → parseSAFTFull → 250 rules · e-invoices → i.SAF XML → parseISAF → reconciliation."}</div>
  </div>;
}

function EInvoicingTab({ lang, t, audit, einv, setEinv, erp, fileData, isafData, setToast }) {
  const PL_LINE = "rgba(255,255,255,0.12)", PL_SOFT = "rgba(255,255,255,0.06)";
  const lbl = { fontSize: 10.5, color: "#8c8c88", fontFamily: "var(--m)", letterSpacing: ".1em", textTransform: "uppercase" };
  const bP = { background: "#fff", color: "#000", border: "none", padding: "9px 18px", fontSize: 11, fontWeight: 700, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" };
  const bG = { background: "transparent", color: "#d2d2ce", border: `1px solid ${PL_LINE}`, padding: "9px 16px", fontSize: 11, fontWeight: 600, fontFamily: "var(--m)", letterSpacing: ".06em", textTransform: "uppercase", cursor: "pointer" };
  const inp = { background: "var(--bg)", color: "#fff", border: `1px solid ${PL_LINE}`, padding: "8px 11px", fontSize: 12.5, fontFamily: "var(--s)", outline: "none", width: "100%" };
  const LT = lang === "lt";
  const H = useMemo(() => ({ classifyVatRate, isValidLtIban, isLtVatNumber, isLtRegistrationNumber, ISO_4217, today: new Date().toISOString().slice(0, 10) }), []);
  const STC = (s) => ({ DRAFT: "#8c8c88", ISSUED: "#74c0fc", TRANSMITTED: "#ffd43b", DELIVERED: "#69db7c", ACCEPTED: "#69db7c", PAID: "#fff", REJECTED: "#ff6b6b", RECEIVED: "#74c0fc", MATCHED: "#69db7c" }[s] || "#aaa");

  const [sub, setSub] = useState("dashboard");
  const [draft, setDraft] = useState(null);
  const [val, setVal] = useState(null);
  const [showXml, setShowXml] = useState(false);
  const [openRow, setOpenRow] = useState("");
  const [busyId, setBusyId] = useState("");
  const [pasteXml, setPasteXml] = useState("");
  const [chain, setChain] = useState(null);
  const [conf, setConf] = useState(null);
  const [ruleQ, setRuleQ] = useState("");
  const [ai, setAi] = useState({ busy: false, text: "", verify: null });

  const liveOut = einv.outbox.filter((e) => e.state !== "REJECTED");
  const vida = useMemo(() => computeVidaReadiness(einv.profile, einv.settings, { outbox: einv.outbox, archive: einv.archive }), [einv.outbox, einv.archive, einv.profile, einv.settings]);
  const T_draft = draft ? computeEinvTotals(draft) : null;
  const norm = (s) => String(s || "").trim().toUpperCase();
  const downloadText = (txt2, name) => { const a = document.createElement("a"); a.href = URL.createObjectURL(new Blob([txt2], { type: "application/xml" })); a.download = name; a.click(); };

  // Coverage: issued e-invoices present in the loaded i.SAF register / SAF-T file
  const isafNos = useMemo(() => new Set(((isafData && isafData.sales) || []).map((x) => norm(x.invoiceNo))), [isafData]);
  const saftNos = useMemo(() => new Set((((fileData || {}).parsed || {}).sales?.items || []).map((x) => norm(x.invoiceNo))), [fileData]);
  const cover = (set) => { const n = liveOut.filter((e) => set.has(norm(e.inv.invoiceNo))).length; return { n, m: liveOut.length, pct: liveOut.length ? Math.round(n / liveOut.length * 100) : 0 }; };
  const covIsaf = cover(isafNos), covSaft = cover(saftNos);
  const accepted = einv.outbox.filter((e) => ["ACCEPTED", "DELIVERED", "PAID"].includes(e.state)).length;
  const accRate = liveOut.length ? Math.round(accepted / liveOut.length * 100) : 0;

  const updEntry = (id, patch) => setEinv((e) => ({ ...e, outbox: e.outbox.map((x) => x.inv.id === id ? { ...x, ...patch } : x) }));
  const setProfile = (k, v) => setEinv((e) => ({ ...e, profile: { ...e.profile, [k]: v } }));
  const setSettings = (k, v) => setEinv((e) => ({ ...e, settings: { ...e.settings, [k]: v } }));
  const setBuyer = (k, v) => setDraft((d) => ({ ...d, buyer: { ...d.buyer, [k]: v } }));
  const setLine = (i, k, v) => setDraft((d) => ({ ...d, lines: d.lines.map((l, j) => j === i ? { ...l, [k]: v } : l) }));

  const newDraft = () => { setDraft(newEInvoice(einv.profile, einv.seq, H.today)); setVal(null); setShowXml(false); setSub("compose"); };
  const pickBuyer = (v) => {
    if (!v) return;
    if (v.startsWith("pub:")) { const reg = v.slice(4); setDraft((d) => ({ ...d, buyer: { ...d.buyer, name: SABIS_DEMO_REGISTRY[reg], regNo: reg, vatNo: "", country: "LT", city: "Vilnius", isPublic: true, endpoint: { scheme: "0200", id: reg } } })); }
    else { const c = (erp.store.customers || []).find((x) => x.id === v); if (c) setDraft((d) => ({ ...d, buyer: { ...d.buyer, name: c.name, regNo: c.regNo || "", vatNo: c.vatNo || "", country: c.country || "LT", city: c.city || "", isPublic: false, endpoint: { scheme: "0200", id: c.regNo || "" } } })); }
    setVal(null);
  };
  const doValidate = () => { const v = validateEInvoiceDraft(draft, H); setVal(v); audit.log("EINV_VALIDATED", `${draft.invoiceNo} → ${v.findings.length} findings (${v.ok ? "OK" : "NOT OK"})`); };
  const doIssue = async () => {
    const v = validateEInvoiceDraft(draft, H); setVal(v);
    if (!v.ok) { setToast(LT ? "Sąskaita nepraeina patikros — pataisykite radinius" : "Invoice fails validation — fix the findings"); return; }
    const xml = buildUBLInvoice(draft);
    const arch2 = await appendToArchive(einv.archive, draft, xml);
    const entry = { inv: draft, xml, state: "ISSUED", issuedAt: new Date().toISOString(), events: [{ at: new Date().toISOString(), state: "ISSUED", detail: `Nr. ${draft.invoiceNo} · €${fmt2(v.totals.taxInc)}` }], mlr: null, routing: selectRoute(draft, einv.settings) };
    setEinv((e) => ({ ...e, seq: e.seq + 1, archive: arch2, outbox: [...e.outbox, entry] }));
    audit.log("EINV_ISSUED", `${draft.invoiceNo} · €${fmt2(v.totals.taxInc)} → archive #${arch2.length}`);
    setToast(LT ? `Išrašyta: ${draft.invoiceNo}` : `Issued: ${draft.invoiceNo}`);
    setDraft(null); setSub("outbox");
  };
  const doTransmit = async (entry) => {
    setBusyId(entry.inv.id);
    try {
      const res = await simulateTransmission(entry, einv.settings, einv.archive, H);
      updEntry(entry.inv.id, { state: res.state, events: res.events, mlr: res.mlr, routing: res.routing, sbdh: res.sbdh });
      audit.log(res.state === "REJECTED" ? "EINV_REJECTED" : "EINV_TRANSMITTED", `${entry.inv.invoiceNo} → ${res.routing.route} → ${res.state}${res.mlr ? ` (MLR ${res.mlr.status})` : ""}`);
      setToast(`${entry.inv.invoiceNo}: ${res.state}`);
    } catch (err) { setToast((LT ? "Siuntimo klaida: " : "Transmission error: ") + err.message); }
    setBusyId("");
  };
  const markPaid = (entry) => { updEntry(entry.inv.id, { state: "PAID", events: [...entry.events, { at: new Date().toISOString(), state: "PAID", detail: LT ? "Apmokėta" : "Paid" }] }); audit.log("EINV_PAID", entry.inv.invoiceNo); };

  const intakeInbound = async (xml, label) => {
    const inv = parseUBLInvoice(xml);
    if (inv._parseError) { setToast((LT ? "XML klaida: " : "XML error: ") + inv._parseError); return; }
    const v = validateEInvoiceDraft(inv, H);
    const m = matchInbound(inv, erp.store);
    const entry = { inv, xml, state: m.matched ? "MATCHED" : "RECEIVED", receivedAt: new Date().toISOString(), validation: { ok: v.ok, total: v.findings.length, bySeverity: v.bySeverity }, match: m };
    setEinv((e) => ({ ...e, inbox: [...e.inbox, entry] }));
    audit.log("EINV_INBOUND", `${inv.invoiceNo} (${label}) · ${m.level} · ${v.findings.length} findings`);
    setToast(LT ? `Gauta: ${inv.invoiceNo} · ${m.level}` : `Received: ${inv.invoiceNo} · ${m.level}`);
  };
  const demoInbound = () => {
    const bills = erp.store.invoicesAP || [];
    const withPay = bills.find((b) => (erp.store.payments || []).some((p) => (p.lines || []).some((l) => l.sourceDocumentId === b.invoiceNo)));
    const bill = withPay || bills[0];
    const supProfile = bill ? { name: bill.party?.name || "UAB Vilniaus tiekimas", regNo: bill.party?.regNo || "300099882", vatNo: bill.party?.vatNo || "LT130009988210", iban: "LT607044060008101234", city: "Vilnius", series: "VT" } : { name: "UAB Vilniaus tiekimas", regNo: "300099882", vatNo: "LT130009988210", iban: "LT607044060008101234", city: "Vilnius", series: "VT" };
    const inv = newEInvoice(supProfile, einv.inbox.length + 1, H.today);
    if (bill) { inv.invoiceNo = bill.invoiceNo; inv.issueDate = bill.invoiceDate || inv.issueDate; const src = (bill.lines && bill.lines.length) ? bill.lines : [{ description: "Prekės", qty: 1, unitPrice: bill.totals?.net || 100, tax: { pct: 21 } }]; inv.lines = src.map((bl, i) => { const rc = !!bl.tax?.reverseCharge; return { id: String(i + 1), description: bl.description || "Prekės", qty: bl.qty || 1, unitCode: "H87", unitPrice: einvR2(bl.unitPrice != null ? bl.unitPrice : ((bl.qty ? (bl.net ?? 0) / bl.qty : (bl.net ?? 0)))), pct: rc ? 0 : (bl.tax?.pct ?? 21), reverseCharge: rc, exempt: false, exemptReason: "" }; }); }
    inv.buyer = { name: einv.profile.name, regNo: einv.profile.regNo, vatNo: einv.profile.vatNo, country: "LT", city: einv.profile.city, street: "", postal: "", email: "", isPublic: false, endpoint: { scheme: "0200", id: einv.profile.regNo } };
    intakeInbound(buildUBLInvoice(inv), "demo");
  };
  const acceptInbound = async (entry) => {
    const arch2 = await appendToArchive(einv.archive, entry.inv, entry.xml);
    setEinv((e) => ({ ...e, archive: arch2, inbox: e.inbox.map((x) => x.inv.id === entry.inv.id ? { ...x, state: "ACCEPTED" } : x) }));
    audit.log("EINV_INBOUND_ACCEPTED", `${entry.inv.invoiceNo} → archive #${arch2.length}`);
  };

  const runConf = () => { const c = runEinvConformance(H, undefined); setConf(c); audit.log("EINV_CONFORMANCE", `${c.passed}/${c.total} (${c.score}%)`); };
  const aiSummary = async () => {
    setAi({ busy: true, text: "", verify: null });
    const facts = [
      { value: liveOut.length, label: LT ? "Išrašytos e. sąskaitos" : "Issued e-invoices", group: "einv" },
      { value: accRate, label: LT ? "Priėmimo rodiklis" : "Acceptance rate", group: "einv", isPct: true },
      { value: einv.inbox.length, label: LT ? "Gautos sąskaitos" : "Inbound invoices", group: "einv" },
      { value: einv.archive.length, label: LT ? "Archyvo įrašai" : "Archive entries", group: "einv" },
      { value: vida.days, label: LT ? "Dienų iki ViDA (2030-07-01)" : "Days to ViDA (2030-07-01)", group: "einv" },
      { value: covIsaf.pct, label: LT ? "i.SAF aprėptis" : "i.SAF coverage", group: "einv", isPct: true },
    ];
    const sys = `Tu esi TAXAI e. sąskaitų atitikties asistentas Lietuvoje. Atsakyk glaustai (≤180 žodžių), be sveikinimų. Remkis TIK šiais deterministiniais faktais ir teisės kontekstu žemiau — jokių kitų skaičių:\n${facts.map((f) => `- ${f.label}: ${f.value}${f.isPct ? "%" : ""}`).join("\n")}\nKontekstas: SABIS privaloma viešajam sektoriui; Peppol BIS 3.0; PVMĮ 58 str. rekvizitai; ViDA (ES) 2025/516 nuo 2030-07-01.`;
    const msg = LT ? "Parenk trumpą įmonės e. sąskaitų atitikties santrauką: SABIS, Peppol, PVMĮ 58 str., i.SAF aprėptis ir pasirengimas ViDA." : "Prepare a short e-invoicing compliance summary: SABIS, Peppol, PVMĮ art. 58, i.SAF coverage and ViDA readiness.";
    try { const text = await callAI(sys, msg); setAi({ busy: false, text, verify: verifyNarrative(text, facts) }); audit.log("EINV_AI_SUMMARY", `verify score pending`); }
    catch (err) { setAi({ busy: false, text: "", verify: null }); setToast("AI: " + err.message); }
  };

  const Chip = ({ c, children }) => <span style={{ fontFamily: "var(--m)", fontSize: 9, fontWeight: 700, letterSpacing: ".08em", color: c === "#fff" || c === "#ffd43b" || c === "#69db7c" ? "#000" : "#000", background: c, padding: "2px 7px" }}>{children}</span>;
  const Stat = ({ v, l, c }) => <div style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", padding: "12px 16px", minWidth: 120 }}><div style={{ fontFamily: "var(--m)", fontSize: 22, fontWeight: 700, color: c || "#fff" }}>{v}</div><div style={{ ...lbl, fontSize: 9, marginTop: 3 }}>{l}</div></div>;
  const SUBS = [["dashboard", LT ? "Apžvalga" : "Dashboard"], ["compose", LT ? "Nauja sąskaita" : "Compose"], ["outbox", LT ? "Siunčiamos" : "Outbox"], ["inbox", LT ? "Gautos" : "Inbox"], ["archive", LT ? "Archyvas" : "Archive"], ["rules", LT ? "Taisyklės" : "Rules"], ["settings", LT ? "Nustatymai · ViDA" : "Settings · ViDA"]];

  return <div style={{ maxWidth: 1240 }}>
    <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", gap: 16, marginBottom: 18, flexWrap: "wrap" }}>
      <div>
        <div style={{ fontSize: 26, fontWeight: 800, color: "#fff", fontFamily: "var(--s)", letterSpacing: "-.01em" }}>{LT ? "E. sąskaitos" : "E-Invoicing"}</div>
        <div style={{ fontSize: 12.5, color: "#8c8c88", fontFamily: "var(--s)", marginTop: 4 }}>EN 16931 · UBL 2.1 · Peppol BIS 3.0 · SABIS (B2G) · i.SAF / SAF-T {LT ? "tiltai" : "bridges"} · ViDA 2030</div>
      </div>
      <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
        <span style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#ffd43b", border: "1px solid rgba(255,212,59,.4)", padding: "5px 10px", letterSpacing: ".06em" }}>{LT ? "DEMO siuntimas — dokumentai realiai neperduodami" : "DEMO transmission — nothing is actually submitted"}</span>
        <button onClick={newDraft} style={bP}>{LT ? "+ Nauja sąskaita" : "+ New invoice"}</button>
      </div>
    </div>

    <div style={{ display: "flex", gap: 0, borderBottom: `1px solid ${PL_LINE}`, marginBottom: 18, flexWrap: "wrap" }}>
      {SUBS.map(([k, l]) => <button key={k} onClick={() => setSub(k)} style={{ background: "transparent", border: "none", borderBottom: `2px solid ${sub === k ? "#fff" : "transparent"}`, color: sub === k ? "#fff" : "#8c8c88", padding: "10px 16px", fontSize: 11.5, fontWeight: 700, fontFamily: "var(--m)", letterSpacing: ".08em", textTransform: "uppercase", cursor: "pointer" }}>{l}{k === "outbox" && einv.outbox.length ? ` (${einv.outbox.length})` : ""}{k === "inbox" && einv.inbox.length ? ` (${einv.inbox.length})` : ""}</button>)}
    </div>

    {/* ── DASHBOARD ── */}
    {sub === "dashboard" && <div>
      <div style={{ display: "flex", gap: 12, flexWrap: "wrap", marginBottom: 16 }}>
        <Stat v={liveOut.length} l={LT ? "Išrašyta" : "Issued"} />
        <Stat v={accRate + "%"} l={LT ? "Priimta / pristatyta" : "Accepted / delivered"} c={accRate >= 80 ? "#69db7c" : "#ffd43b"} />
        <Stat v={einv.outbox.filter((e) => e.state === "REJECTED").length} l={LT ? "Atmesta" : "Rejected"} c="#ff6b6b" />
        <Stat v={einv.inbox.length} l={LT ? "Gauta (AP)" : "Inbound (AP)"} />
        <Stat v={isafData ? `${covIsaf.n}/${covIsaf.m}` : "—"} l={LT ? "i.SAF aprėptis" : "i.SAF coverage"} c={isafData && covIsaf.pct < 100 ? "#ffd43b" : "#69db7c"} />
        <Stat v={fileData?.parsed ? `${covSaft.n}/${covSaft.m}` : "—"} l={LT ? "SAF-T aprėptis" : "SAF-T coverage"} />
        <Stat v={vida.days} l={LT ? "d. iki ViDA" : "days to ViDA"} c="#74c0fc" />
        <Stat v={EINV_RULE_COUNT} l={LT ? "taisyklių" : "rules"} c="#74c0fc" />
      </div>
      {!isafData && <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11.5, marginBottom: 14 }}>{LT ? "i.SAF aprėptis skaičiuojama įkėlus i.SAF registrą SAF-T peržiūros skiltyje." : "i.SAF coverage is computed once an i.SAF register is loaded in the SAF-T view."}</div>}
      <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 16, flexWrap: "wrap" }}>
        <button onClick={() => { const x = buildISafXml(einv.profile, einv.outbox, einv.inbox); downloadText(x, `isaf_${new Date().toISOString().slice(0, 7)}.xml`); audit.log("EINV_ISAF_EXPORT", `${einv.outbox.length} AR + ${einv.inbox.length} AP`); setToast("i.SAF XML ⬇"); }} style={bG}>i.SAF XML ⬇</button>
        {(() => { const gaps = detectSeqGaps(einv.outbox); return gaps.length ? <span title={gaps.map((g) => `${g.series}: ${g.missing.join(",")}`).join(" · ")} style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#ffd43b", border: "1px solid rgba(255,212,59,.4)", padding: "5px 10px", cursor: "help" }}>⚠ {LT ? "Numeracijos spragos" : "Sequence gaps"}: {gaps.map((g) => `${g.series}…×${g.missing.length}`).join(", ")}</span> : liveOut.length ? <span style={{ fontFamily: "var(--m)", fontSize: 10.5, color: "#69db7c" }}>✓ {LT ? "Numeracija be spragų (PVMĮ)" : "Gapless numbering (PVMĮ)"}</span> : null; })()}
      </div>


      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, alignItems: "start" }}>
        <Section title={LT ? "Atitikties patikra (fixtures)" : "Conformance check (fixtures)"}>
          <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 10 }}>
            <button onClick={runConf} style={bG}>{LT ? "Vykdyti patikrą" : "Run conformance"}</button>
            {conf && <span style={{ fontFamily: "var(--m)", fontSize: 13, fontWeight: 700, color: conf.score === 100 ? "#69db7c" : "#ffd43b" }}>{conf.passed}/{conf.total} · {conf.score}%</span>}
          </div>
          {conf && conf.results.map((r) => <div key={r.id} style={{ display: "flex", gap: 10, padding: "6px 0", borderBottom: `1px solid ${PL_SOFT}`, alignItems: "center" }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 10, color: r.passed ? "#69db7c" : "#ff6b6b", width: 16 }}>{r.passed ? "✓" : "✗"}</span>
            <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#8c8c88", width: 52 }}>{r.id}</span>
            <span style={{ fontFamily: "var(--s)", fontSize: 12, color: "#d2d2ce" }}>{r.name}</span>
          </div>)}
        </Section>
        <Section title={LT ? "AI atitikties santrauka (pagrįsta faktais)" : "AI compliance summary (fact-grounded)"}>
          <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 10 }}>
            <button disabled={ai.busy} onClick={aiSummary} style={{ ...bG, opacity: ai.busy ? 0.6 : 1 }}>{ai.busy ? (LT ? "Generuojama…" : "Generating…") : (LT ? "Generuoti santrauką" : "Generate summary")}</button>
            {ai.verify && <span style={{ fontFamily: "var(--m)", fontSize: 11, color: ai.verify.score >= 80 ? "#69db7c" : ai.verify.score >= 60 ? "#ffd43b" : "#ff6b6b" }}>{LT ? "Pagrįstumas" : "Grounding"}: {ai.verify.score}% · {ai.verify.band}</span>}
          </div>
          {ai.text && <div style={{ maxHeight: 260, overflowY: "auto" }}><Md text={ai.text} /></div>}
          {!ai.text && !ai.busy && <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 12 }}>{LT ? "Deterministiniai skaičiai pateikiami AI kaip vieninteliai leidžiami faktai; atsakymas tikrinamas verifyNarrative." : "Deterministic figures are passed to the AI as the only allowed facts; the answer is checked with verifyNarrative."}</div>}
        </Section>
      </div>
    </div>}

    {/* ── COMPOSE ── */}
    {sub === "compose" && <div>
      {!draft && <Section title={LT ? "Nėra juodraščio" : "No draft"}><button onClick={newDraft} style={bP}>{LT ? "+ Nauja sąskaita" : "+ New invoice"}</button></Section>}
      {draft && <div style={{ display: "grid", gridTemplateColumns: "minmax(420px,1.4fr) minmax(340px,1fr)", gap: 16, alignItems: "start" }}>
        <div>
          <Section title={LT ? "Sąskaita" : "Invoice"} accent="#74c0fc">
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10 }}>
              <div><div style={{ ...lbl, marginBottom: 5 }}>Nr.</div><input value={draft.invoiceNo} onChange={(e) => { setDraft({ ...draft, invoiceNo: e.target.value }); setVal(null); }} style={inp} /></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Data" : "Issue date"}</div><input value={draft.issueDate} onChange={(e) => { setDraft({ ...draft, issueDate: e.target.value }); setVal(null); }} style={inp} /></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Apmokėti iki" : "Due date"}</div><input value={draft.dueDate} onChange={(e) => { setDraft({ ...draft, dueDate: e.target.value }); setVal(null); }} style={inp} /></div>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginTop: 10 }}>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Tipas" : "Type"}</div><select value={draft.typeCode} onChange={(e) => { setDraft({ ...draft, typeCode: e.target.value }); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11 }}><option value="380">380 — {LT ? "Sąskaita (SF)" : "Invoice"}</option><option value="381">381 — {LT ? "Kreditinė (KS)" : "Credit note"}</option></select></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Valiuta" : "Currency"}</div><input value={draft.currency} onChange={(e) => { setDraft({ ...draft, currency: e.target.value.toUpperCase() }); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)" }} /></div>
              {draft.currency !== "EUR" ? <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Kursas → EUR" : "Rate → EUR"}</div><input value={draft.exchangeRate} onChange={(e) => { setDraft({ ...draft, exchangeRate: parseFloat(e.target.value) || 0 }); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)" }} /></div> : <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Avansas € (BT-113)" : "Prepaid € (BT-113)"}</div><input value={draft.payment.prepaid} onChange={(e) => { setDraft({ ...draft, payment: { ...draft.payment, prepaid: parseFloat(e.target.value) || 0 } }); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)" }} /></div>}
            </div>
            {draft.typeCode === "381" && <div style={{ marginTop: 10 }}><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Koreguojama sąskaita (BR-55)" : "Preceding invoice (BR-55)"}</div><input value={draft.precedingInvoiceNo} onChange={(e) => { setDraft({ ...draft, precedingInvoiceNo: e.target.value }); setVal(null); }} style={inp} placeholder="TX-2026-00001" /></div>}
          </Section>
          <Section title={LT ? "Pirkėjas" : "Buyer"}>
            <div style={{ marginBottom: 10 }}>
              <select defaultValue="" onChange={(e) => pickBuyer(e.target.value)} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11 }}>
                <option value="">{LT ? "— greitas pasirinkimas (ERP klientai / SABIS demo) —" : "— quick pick (ERP customers / SABIS demo) —"}</option>
                {Object.entries(SABIS_DEMO_REGISTRY).map(([reg, name]) => <option key={reg} value={"pub:" + reg}>{name} · {reg} (SABIS)</option>)}
                {(erp.store.customers || []).map((c) => <option key={c.id} value={c.id}>{c.name} · {c.vatNo || c.regNo || c.id}</option>)}
              </select>
              {!(erp.store.customers || []).length && <div style={{ ...lbl, fontSize: 8.5, marginTop: 5, textTransform: "none" }}>{LT ? "ERP klientų sąrašas tuščias — sinchronizuokite sistemą skiltyje „Integracijos“." : "ERP customer list is empty — sync a system in Integrations."}</div>}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1.4fr 1fr 1fr", gap: 10 }}>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Pavadinimas" : "Name"}</div><input value={draft.buyer.name} onChange={(e) => setBuyer("name", e.target.value)} style={inp} /></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "JA kodas" : "Company code"}</div><input value={draft.buyer.regNo} onChange={(e) => { setBuyer("regNo", e.target.value); setDraft((d) => ({ ...d, buyer: { ...d.buyer, regNo: e.target.value, endpoint: { ...d.buyer.endpoint, id: d.buyer.endpoint.scheme === "0200" ? e.target.value : d.buyer.endpoint.id } } })); }} style={inp} /></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "PVM kodas" : "VAT no."}</div><input value={draft.buyer.vatNo} onChange={(e) => setBuyer("vatNo", e.target.value)} style={inp} /></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Šalis" : "Country"}</div><input value={draft.buyer.country} onChange={(e) => setBuyer("country", e.target.value.toUpperCase())} style={inp} /></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>{LT ? "Miestas" : "City"}</div><input value={draft.buyer.city} onChange={(e) => setBuyer("city", e.target.value)} style={inp} /></div>
              <div><div style={{ ...lbl, marginBottom: 5 }}>El. paštas</div><input value={draft.buyer.email} onChange={(e) => setBuyer("email", e.target.value)} style={inp} /></div>
            </div>
            <div style={{ display: "flex", gap: 16, alignItems: "center", marginTop: 10, flexWrap: "wrap" }}>
              <label style={{ display: "flex", gap: 7, alignItems: "center", color: "#d2d2ce", fontFamily: "var(--s)", fontSize: 12.5, cursor: "pointer" }}><input type="checkbox" checked={draft.buyer.isPublic} onChange={(e) => setBuyer("isPublic", e.target.checked)} />{LT ? "Viešojo sektoriaus pirkėjas (→ SABIS privaloma)" : "Public-sector buyer (→ SABIS mandatory)"}</label>
              <label style={{ display: "flex", gap: 7, alignItems: "center", color: "#d2d2ce", fontFamily: "var(--s)", fontSize: 12.5, cursor: "pointer" }}><input type="checkbox" checked={draft.oss} onChange={(e) => setDraft({ ...draft, oss: e.target.checked })} />OSS (PVM 101-1 str.)</label>
              <div style={{ display: "flex", gap: 6, alignItems: "center" }}><span style={lbl}>Peppol</span>
                <select value={draft.buyer.endpoint.scheme} onChange={(e) => setBuyer("endpoint", { ...draft.buyer.endpoint, scheme: e.target.value })} style={{ ...inp, width: 90, fontFamily: "var(--m)", fontSize: 11 }}><option value="0200">0200</option><option value="9937">9937</option></select>
                <input value={draft.buyer.endpoint.id} onChange={(e) => setBuyer("endpoint", { ...draft.buyer.endpoint, id: e.target.value })} placeholder="participant id" style={{ ...inp, width: 150, fontFamily: "var(--m)", fontSize: 11 }} />
              </div>
            </div>
          </Section>
          <Section title={LT ? "Eilutės" : "Lines"}>
            {T_draft.lines.map((l, i) => <div key={i} style={{ display: "grid", gridTemplateColumns: "1.6fr 70px 100px 90px 60px 110px 28px", gap: 8, alignItems: "center", marginBottom: 8 }}>
              <input value={l.description} placeholder={LT ? "Aprašymas" : "Description"} onChange={(e) => { setLine(i, "description", e.target.value); setVal(null); }} style={inp} />
              <input value={l.qty} onChange={(e) => { setLine(i, "qty", parseFloat(e.target.value) || 0); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)" }} />
              <input value={l.unitPrice} onChange={(e) => { setLine(i, "unitPrice", parseFloat(e.target.value) || 0); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)" }} />
              <select value={l.reverseCharge ? "RC" : l.exempt ? "EX" : String(l.pct)} onChange={(e) => { const v = e.target.value; setDraft((d) => ({ ...d, lines: d.lines.map((x, j) => j !== i ? x : v === "RC" ? { ...x, reverseCharge: true, exempt: false, pct: 0 } : v === "EX" ? { ...x, reverseCharge: false, exempt: true, pct: 0, exemptReason: x.exemptReason || "Neapmokestinama (PVMĮ)" } : { ...x, reverseCharge: false, exempt: false, pct: parseFloat(v) }) })); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11 }}>
                {["21", "12", "5", "0"].map((p) => <option key={p} value={p}>{p}%</option>)}<option value="RC">RC 96 str.</option><option value="EX">{LT ? "Neapmok." : "Exempt"}</option>
              </select>
              <Chip c={{ S: "#74c0fc", AE: "#ffd43b", K: "#69db7c", E: "#8c8c88", Z: "#d2d2ce" }[l.cat]}>{l.cat}</Chip>
              <div style={{ fontFamily: "var(--m)", fontSize: 11.5, color: "#d2d2ce", textAlign: "right" }}>€{fmt2(l.net)} <span style={{ color: "#8c8c88" }}>+{fmt2(l.vat)}</span></div>
              <button onClick={() => { setDraft((d) => ({ ...d, lines: d.lines.filter((_, j) => j !== i) })); setVal(null); }} style={{ ...bG, padding: "4px 8px", color: "#ff6b6b", borderColor: "rgba(255,107,107,.35)" }}>×</button>
            </div>)}
            <button onClick={() => { setDraft((d) => ({ ...d, lines: [...d.lines, { id: String(d.lines.length + 1), description: "", qty: 1, unitCode: "H87", unitPrice: 0, pct: 21, reverseCharge: false, exempt: false, exemptReason: "" }] })); setVal(null); }} style={bG}>{LT ? "+ Eilutė" : "+ Line"}</button>
            <div style={{ display: "flex", justifyContent: "flex-end", gap: 22, marginTop: 12, fontFamily: "var(--m)", fontSize: 12.5 }}>
              <span style={{ color: "#8c8c88" }}>{LT ? "Be PVM" : "Net"}: <b style={{ color: "#fff" }}>€{fmt2(T_draft.taxEx)}</b></span>
              <span style={{ color: "#8c8c88" }}>PVM: <b style={{ color: "#fff" }}>€{fmt2(T_draft.taxTotal)}</b></span>
              <span style={{ color: "#8c8c88" }}>{LT ? "Iš viso" : "Total"}: <b style={{ color: "#69db7c" }}>€{fmt2(T_draft.taxInc)}</b></span>
            </div>
          </Section>
          <Section title={LT ? "Nuolaidos / priemokos (BG-20/21)" : "Allowances / charges (BG-20/21)"}>
            {[...draft.allowances.map((a, i) => ({ a, i, ch: false })), ...draft.charges.map((a, i) => ({ a, i, ch: true }))].map(({ a, i, ch }) => <div key={(ch ? "c" : "a") + i} style={{ display: "grid", gridTemplateColumns: "120px 100px 100px 1fr 28px", gap: 8, marginBottom: 8, alignItems: "center" }}>
              <select value={ch ? "charge" : "allow"} onChange={(e) => { const toCh = e.target.value === "charge"; if (toCh === ch) return; setDraft((d) => { const src = ch ? "charges" : "allowances", dst = toCh ? "charges" : "allowances"; const item = d[src][i]; return { ...d, [src]: d[src].filter((_, j) => j !== i), [dst]: [...d[dst], item] }; }); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11 }}><option value="allow">{LT ? "Nuolaida −" : "Allowance −"}</option><option value="charge">{LT ? "Priemoka +" : "Charge +"}</option></select>
              <input value={a.amount} onChange={(e) => { const v = parseFloat(e.target.value) || 0; setDraft((d) => ({ ...d, [ch ? "charges" : "allowances"]: d[ch ? "charges" : "allowances"].map((x, j) => j === i ? { ...x, amount: v } : x) })); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)" }} />
              <select value={a.cat === "S" ? "S" + a.pct : a.cat} onChange={(e) => { const v = e.target.value; const cat = v.startsWith("S") ? "S" : v; const pct = v.startsWith("S") ? parseFloat(v.slice(1)) : 0; setDraft((d) => ({ ...d, [ch ? "charges" : "allowances"]: d[ch ? "charges" : "allowances"].map((x, j) => j === i ? { ...x, cat, pct } : x) })); setVal(null); }} style={{ ...inp, fontFamily: "var(--m)", fontSize: 11 }}>{["S21", "S12", "S5", "Z", "E", "AE", "K", "G"].map((c) => <option key={c} value={c}>{c}</option>)}</select>
              <input value={a.reason} placeholder={LT ? "Priežastis (BR-33/38)" : "Reason (BR-33/38)"} onChange={(e) => { const v = e.target.value; setDraft((d) => ({ ...d, [ch ? "charges" : "allowances"]: d[ch ? "charges" : "allowances"].map((x, j) => j === i ? { ...x, reason: v } : x) })); setVal(null); }} style={inp} />
              <button onClick={() => { setDraft((d) => ({ ...d, [ch ? "charges" : "allowances"]: d[ch ? "charges" : "allowances"].filter((_, j) => j !== i) })); setVal(null); }} style={{ ...bG, padding: "4px 8px", color: "#ff6b6b", borderColor: "rgba(255,107,107,.35)" }}>×</button>
            </div>)}
            <button onClick={() => { setDraft((d) => ({ ...d, allowances: [...d.allowances, { amount: 0, reason: "", reasonCode: "", cat: "S", pct: 21 }] })); setVal(null); }} style={bG}>{LT ? "+ Nuolaida / priemoka" : "+ Allowance / charge"}</button>
            {(T_draft.allowSum > 0 || T_draft.chargeSum > 0 || T_draft.prepaid > 0) && <div style={{ display: "flex", justifyContent: "flex-end", gap: 22, marginTop: 10, fontFamily: "var(--m)", fontSize: 11.5, color: "#8c8c88", flexWrap: "wrap" }}>{T_draft.allowSum > 0 && <span>{LT ? "Nuolaidos" : "Allowances"}: <b style={{ color: "#fff" }}>−€{fmt2(T_draft.allowSum)}</b></span>}{T_draft.chargeSum > 0 && <span>{LT ? "Priemokos" : "Charges"}: <b style={{ color: "#fff" }}>+€{fmt2(T_draft.chargeSum)}</b></span>}{T_draft.prepaid > 0 && <span>{LT ? "Avansas" : "Prepaid"}: <b style={{ color: "#fff" }}>−€{fmt2(T_draft.prepaid)}</b></span>}<span>{LT ? "Mokėtina" : "Payable"}: <b style={{ color: "#69db7c" }}>€{fmt2(T_draft.payable)}</b></span></div>}
          </Section>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            <button onClick={doValidate} style={bG}>{LT ? "Tikrinti (EN 16931 · Peppol · LT)" : "Validate (EN 16931 · Peppol · LT)"}</button>
            <button onClick={() => setShowXml(!showXml)} style={bG}>{showXml ? (LT ? "Slėpti XML" : "Hide XML") : "UBL XML"}</button>
            <div style={{ flex: 1 }} />
            <button disabled={!val?.ok} onClick={doIssue} style={{ ...bP, opacity: val?.ok ? 1 : 0.45 }}>{LT ? "Išrašyti ir įtraukti į eilę →" : "Issue & queue →"}</button>
          </div>
          {showXml && <pre style={{ background: "var(--bg2)", border: `1px solid ${PL_LINE}`, padding: 12, color: "#bcbcb8", fontFamily: "var(--m)", fontSize: 9.5, lineHeight: 1.5, overflowX: "auto", maxHeight: 300, marginTop: 12 }}>{buildUBLInvoice(draft)}</pre>}
        </div>
        <div>
          <Section title={LT ? "Maršrutas" : "Route"} accent="#69db7c">
            {(() => { const r = selectRoute(draft, einv.settings); return <div><Chip c={r.route === "SABIS" ? "#ffd43b" : r.route === "PEPPOL" ? "#69db7c" : "#74c0fc"}>{r.route}</Chip><div style={{ fontFamily: "var(--s)", fontSize: 12, color: "#bcbcb8", marginTop: 8, lineHeight: 1.5 }}>{LT ? r.reasonLt : r.reason}</div></div>; })()}
          </Section>
          <Section title={`${LT ? "Patikros radiniai" : "Validation findings"}${val ? ` (${val.findings.length})` : ""}`} accent={val ? (val.ok ? "#69db7c" : "#ff6b6b") : undefined}>
            {!val && <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 12 }}>{LT ? "Paspauskite „Tikrinti“." : "Press Validate."}</div>}
            {val && val.ok && !val.findings.length && <div style={{ color: "#69db7c", fontFamily: "var(--m)", fontSize: 12 }}>✓ {LT ? "Visi sluoksniai švarūs" : "All layers clean"}</div>}
            {val && ["EN16931", "PEPPOL", "LT"].map((layer) => { const fs = val.findings.filter((f) => f.layer === layer); return !fs.length ? null : <div key={layer} style={{ marginBottom: 10 }}>
              <div style={{ ...lbl, marginBottom: 6 }}>{layer} ({fs.length})</div>
              {fs.map((f, i) => <div key={i} style={{ display: "flex", gap: 8, alignItems: "flex-start", padding: "7px 0", borderBottom: `1px solid ${PL_SOFT}` }}>
                <Chip c={SC(f.severityUi)}>{f.severity}</Chip>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ color: "#fff", fontFamily: "var(--s)", fontSize: 12, fontWeight: 600 }}>{f.rule_id} · {LT ? f.ruleMeta.titleLt : f.ruleMeta.titleEn}</div>
                  <div style={{ color: "#8c8c88", fontFamily: "var(--m)", fontSize: 10, marginTop: 2, wordBreak: "break-word" }}>{f.detail}</div>
                  <div title={f.legalId ? (LEGAL_DB.find((x) => x.id === f.legalId) || {})[LT ? "text" : "textEn"] : ""} style={{ color: "#74c0fc", fontFamily: "var(--m)", fontSize: 9.5, marginTop: 3, cursor: f.legalId ? "help" : "default" }}>§ {f.legal_basis}</div>
                </div>
              </div>)}
            </div>; })}
            {val && <div style={{ ...lbl, fontSize: 8.5, marginTop: 8, textTransform: "none", letterSpacing: ".03em" }}>{LT ? "Sluoksniai: EN 16931 (BR/BR-CO) → Peppol BIS 3.0 → LT (PVMĮ 19/58/96/101-1 str., IBAN, SABIS)." : "Layers: EN 16931 (BR/BR-CO) → Peppol BIS 3.0 → LT (PVMĮ art. 19/58/96/101-1, IBAN, SABIS)."}</div>}
          </Section>
        </div>
      </div>}
    </div>}

    {/* ── OUTBOX ── */}
    {sub === "outbox" && <div>
      {!einv.outbox.length && <Section title={LT ? "Tuščia" : "Empty"}><div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 13 }}>{LT ? "Išrašykite sąskaitą skiltyje „Nauja sąskaita“." : "Issue an invoice in Compose."}</div></Section>}
      {einv.outbox.map((e) => { const T = computeEinvTotals(e.inv); const open = openRow === e.inv.id; return <div key={e.inv.id} style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", marginBottom: 10 }}>
        <div onClick={() => setOpenRow(open ? "" : e.inv.id)} style={{ display: "flex", alignItems: "center", gap: 14, padding: "11px 16px", cursor: "pointer", flexWrap: "wrap" }}>
          <Chip c={STC(e.state)}>{e.state}</Chip>
          <span style={{ fontFamily: "var(--m)", fontSize: 12.5, color: "#fff", fontWeight: 700 }}>{e.inv.invoiceNo}</span>
          <span style={{ fontFamily: "var(--s)", fontSize: 12.5, color: "#d2d2ce", flex: 1, minWidth: 140 }}>{e.inv.buyer.name}{e.inv.buyer.isPublic ? " · B2G" : ""}</span>
          <span style={{ fontFamily: "var(--m)", fontSize: 11, color: "#8c8c88" }}>{e.inv.issueDate}</span>
          <span style={{ fontFamily: "var(--m)", fontSize: 12.5, color: "#fff" }}>€{fmt2(T.taxInc)}</span>
          <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#74c0fc" }}>{(e.routing || selectRoute(e.inv, einv.settings)).route}</span>
          {e.state === "ISSUED" && <button disabled={busyId === e.inv.id} onClick={(ev) => { ev.stopPropagation(); doTransmit(e); }} style={{ ...bP, padding: "6px 14px", opacity: busyId === e.inv.id ? 0.6 : 1 }}>{busyId === e.inv.id ? "…" : (LT ? "Siųsti" : "Transmit")}</button>}
          {["DELIVERED", "ACCEPTED"].includes(e.state) && <button onClick={(ev) => { ev.stopPropagation(); markPaid(e); }} style={{ ...bG, padding: "6px 12px" }}>{LT ? "Apmokėta" : "Mark paid"}</button>}
          <button onClick={(ev) => { ev.stopPropagation(); const w = window.open("", "_blank"); w.document.write(einvPrintHtml(e.inv, undefined, lang)); w.document.close(); w.print(); }} style={{ ...bG, padding: "6px 12px" }}>{LT ? "Spausdinti" : "Print"}</button>
        </div>
        {open && <div style={{ borderTop: `1px solid ${PL_SOFT}`, padding: "12px 16px" }}>
          <div style={{ ...lbl, marginBottom: 8 }}>{LT ? "Įvykiai" : "Events"}</div>
          {e.events.map((ev2, i) => <div key={i} style={{ display: "flex", gap: 10, padding: "4px 0", fontFamily: "var(--m)", fontSize: 10.5 }}>
            <span style={{ color: "#666", width: 150, flexShrink: 0 }}>{ev2.at.replace("T", " ").slice(0, 19)}</span>
            <span style={{ color: STC(ev2.state), width: 100, flexShrink: 0 }}>{ev2.state}</span>
            <span style={{ color: "#bcbcb8", wordBreak: "break-word" }}>{ev2.detail}</span>
          </div>)}
          {e.mlr && <div style={{ marginTop: 8, fontFamily: "var(--m)", fontSize: 10.5, color: e.mlr.status === "AB" ? "#69db7c" : "#ff6b6b" }}>MLR: {e.mlr.status} · {e.mlr.code} · {e.mlr.reason}</div>}
          {e.sbdh && <details style={{ marginTop: 8 }}><summary style={{ ...lbl, cursor: "pointer" }}>SBDH</summary><pre style={{ background: "var(--bg)", border: `1px solid ${PL_SOFT}`, padding: 10, color: "#8c8c88", fontFamily: "var(--m)", fontSize: 9, overflowX: "auto", margin: "6px 0 0" }}>{e.sbdh}</pre></details>}
        </div>}
      </div>; })}
    </div>}

    {/* ── INBOX ── */}
    {sub === "inbox" && <div>
      <Section title={LT ? "Gauti UBL XML (AP)" : "Receive UBL XML (AP)"}>
        <textarea value={pasteXml} onChange={(e) => setPasteXml(e.target.value)} placeholder={LT ? "Įklijuokite UBL 2.1 Invoice XML…" : "Paste UBL 2.1 Invoice XML…"} style={{ ...inp, height: 90, fontFamily: "var(--m)", fontSize: 10, resize: "vertical" }} />
        <div style={{ display: "flex", gap: 10, marginTop: 10 }}>
          <button onClick={() => { if (pasteXml.trim()) { intakeInbound(pasteXml.trim(), "paste"); setPasteXml(""); } }} style={bP}>{LT ? "Apdoroti ir sutikrinti" : "Parse & match"}</button>
          <button onClick={demoInbound} style={bG}>{LT ? "Generuoti demo gautą sąskaitą" : "Generate demo inbound"}</button>
        </div>
        <div style={{ ...lbl, fontSize: 8.5, marginTop: 8, textTransform: "none" }}>{LT ? "Sutikrinimas: 2 krypčių (ERP pirkimo sąskaita) / 3 krypčių (+ mokėjimas) pagal tiekėjo PVM kodą ir sumas." : "Matching: 2-way (ERP bill) / 3-way (+ payment) by supplier VAT and amounts."}</div>
      </Section>
      {einv.inbox.map((e) => { const T = computeEinvTotals(e.inv); return <div key={e.inv.id} style={{ border: `1px solid ${PL_LINE}`, background: "var(--bg2)", marginBottom: 10, padding: "11px 16px", display: "flex", alignItems: "center", gap: 14, flexWrap: "wrap" }}>
        <Chip c={STC(e.state)}>{e.state}</Chip>
        <span style={{ fontFamily: "var(--m)", fontSize: 12.5, color: "#fff", fontWeight: 700 }}>{e.inv.invoiceNo}</span>
        <span style={{ fontFamily: "var(--s)", fontSize: 12.5, color: "#d2d2ce", flex: 1, minWidth: 140 }}>{e.inv.seller.name} · {e.inv.seller.vatNo || e.inv.seller.regNo}</span>
        <span style={{ fontFamily: "var(--m)", fontSize: 12.5, color: "#fff" }}>€{fmt2(e.inv._declared?.taxInc ?? T.taxInc)}</span>
        <span style={{ fontFamily: "var(--m)", fontSize: 10, color: e.validation.ok ? "#69db7c" : "#ff6b6b" }}>{e.validation.ok ? "✓ valid" : `✗ ${e.validation.bySeverity.Block + e.validation.bySeverity.Reject} blocking`}</span>
        <span title={e.match.detail} style={{ fontFamily: "var(--m)", fontSize: 10, color: e.match.level === "3-way" ? "#69db7c" : e.match.level === "2-way" ? "#ffd43b" : "#ff6b6b", cursor: "help" }}>{e.match.level}{e.match.matched ? ` · Δ€${fmt2(e.match.deltas.gross)}` : ""}</span>
        {e.state !== "ACCEPTED" && e.state !== "REJECTED" && <button onClick={() => acceptInbound(e)} style={{ ...bG, padding: "6px 12px" }}>{LT ? "Priimti" : "Accept"}</button>}
        {e.state !== "ACCEPTED" && e.state !== "REJECTED" && <button onClick={() => { setEinv((s2) => ({ ...s2, inbox: s2.inbox.map((x) => x.inv.id === e.inv.id ? { ...x, state: "REJECTED" } : x) })); downloadText(buildApplicationResponse(e.inv, "RE", LT ? "Atmesta gavėjo" : "Rejected by recipient"), `IMR-RE-${e.inv.invoiceNo}.xml`); audit.log("EINV_INBOUND_REJECTED", e.inv.invoiceNo); }} style={{ ...bG, padding: "6px 12px", color: "#ff6b6b", borderColor: "rgba(255,107,107,.35)" }}>{LT ? "Atmesti" : "Reject"}</button>}
        {(e.state === "ACCEPTED" || e.state === "REJECTED") && <button onClick={() => downloadText(buildApplicationResponse(e.inv, e.state === "ACCEPTED" ? "AB" : "RE", ""), `IMR-${e.state === "ACCEPTED" ? "AB" : "RE"}-${e.inv.invoiceNo}.xml`)} style={{ ...bG, padding: "6px 12px" }}>{LT ? "Atsakymas ⬇" : "Response ⬇"}</button>}
      </div>; })}
    </div>}

    {/* ── ARCHIVE ── */}
    {sub === "archive" && <div>
      <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 12, flexWrap: "wrap" }}>
        <button onClick={async () => { setChain({ pending: true }); setChain(await verifyArchiveChain(einv.archive)); audit.log("EINV_ARCHIVE_VERIFY", `${einv.archive.length} entries`); }} style={bP}>{LT ? "Tikrinti grandinę" : "Verify chain"}</button>
        {chain && !chain.pending && <span style={{ fontFamily: "var(--m)", fontSize: 12, color: chain.ok ? "#69db7c" : "#ff6b6b" }}>{chain.ok ? `✓ ${LT ? "Grandinė vientisa" : "Chain intact"} (${chain.length})` : `✗ ${LT ? "Pažeista ties" : "Broken at"} #${chain.brokenAt}`}</span>}
      </div>
      {!einv.archive.length ? <Section title={LT ? "Archyvas tuščias" : "Archive empty"}><div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 13 }}>{LT ? "Įrašai atsiranda išrašius ar priėmus sąskaitą." : "Entries appear when an invoice is issued or accepted."}</div></Section> :
        <DataTable columns={[{ key: "seq", label: "#", mono: true }, { key: "invoiceNo", label: "Nr.", mono: true }, { key: "direction", label: LT ? "Kryptis" : "Dir", mono: true }, { key: "sha", label: "SHA-256", mono: true }, { key: "prev", label: "Prev", mono: true }, { key: "bytes", label: "B", mono: true }, { key: "retainUntil", label: LT ? "Saugoti iki" : "Retain until", mono: true }]} data={einv.archive.map((a) => ({ seq: a.seq, invoiceNo: a.invoiceNo, direction: a.direction, sha: a.sha256.slice(0, 16) + "…", prev: a.prevHash === "GENESIS" ? "GENESIS" : a.prevHash.slice(0, 12) + "…", bytes: a.bytes, retainUntil: a.retainUntil }))} maxRows={50} />}
      <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11.5, lineHeight: 1.6, marginTop: 12 }}>{LT ? "Saugojimas 10 metų. Vientisumas: SHA-256 grandinė per tikslų XML turinį (demo); gamyboje — kvalifikuotas el. parašas/antspaudas arba audituojamas vientisumo užtikrinimas pagal eIDAS (910/2014)." : "10-year retention. Integrity: SHA-256 chain over the exact XML bytes (demo); in production — qualified e-signature/seal or audited integrity per eIDAS (Reg. 910/2014)."}</div>
    </div>}

    {/* ── RULES ── */}
    {sub === "rules" && <div>
      <Section title={`${EINV_RULE_COUNT} ${LT ? "vykdomų taisyklių" : "executable rules"} · EN 16931 · Peppol BIS 3.0 · LT`} accent="#74c0fc">
        <input value={ruleQ} onChange={(e) => setRuleQ(e.target.value)} placeholder={LT ? "Paieška (id, pavadinimas)…" : "Search (id, title)…"} style={{ ...inp, maxWidth: 360, marginBottom: 12 }} />
        {["EN16931", "PEPPOL", "LT"].map((layer) => { const list = EINV_RULES.filter((r) => r.layer === layer && (!ruleQ || (r.id + " " + r.en + " " + r.lt).toLowerCase().includes(ruleQ.toLowerCase()))); return !list.length ? null : <div key={layer} style={{ marginBottom: 14 }}>
          <div style={{ ...lbl, marginBottom: 6 }}>{layer} ({list.length})</div>
          {list.map((r) => <div key={r.id + r.sev} style={{ display: "flex", gap: 10, padding: "5px 0", borderBottom: `1px solid ${PL_SOFT}`, alignItems: "baseline" }}>
            <span style={{ fontFamily: "var(--m)", fontSize: 10, color: "#74c0fc", width: 170, flexShrink: 0 }}>{r.id}</span>
            <Chip c={r.sev === "Block" ? "#ff6b6b" : r.sev === "Reject" ? "#ffd43b" : "#8c8c88"}>{r.sev}</Chip>
            <span style={{ fontFamily: "var(--s)", fontSize: 12, color: "#d2d2ce" }}>{LT ? r.lt : r.en}</span>
            <span style={{ fontFamily: "var(--m)", fontSize: 9, color: "#666", marginLeft: "auto", textAlign: "right" }}>§ {einvLegal(r.legal)}</span>
          </div>)}
        </div>; })}
      </Section>
    </div>}

    {/* ── SETTINGS · ViDA ── */}
    {sub === "settings" && <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, alignItems: "start" }}>
      <div>
        <Section title={LT ? "Įmonės profilis (pardavėjas)" : "Company profile (seller)"}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
            {[["name", LT ? "Pavadinimas" : "Name"], ["regNo", LT ? "JA kodas" : "Company code"], ["vatNo", LT ? "PVM kodas" : "VAT no."], ["iban", "IBAN"], ["city", LT ? "Miestas" : "City"], ["street", LT ? "Gatvė" : "Street"], ["postal", LT ? "Pašto kodas" : "Postal"], ["series", LT ? "Serija" : "Series"]].map(([k, l]) => <div key={k}><div style={{ ...lbl, marginBottom: 5 }}>{l}</div><input value={einv.profile[k] || ""} onChange={(e) => setProfile(k, e.target.value)} style={inp} /></div>)}
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center", marginTop: 12 }}>
            <span style={lbl}>Peppol</span>
            <select value={einv.profile.peppolScheme} onChange={(e) => setProfile("peppolScheme", e.target.value)} style={{ ...inp, width: 100, fontFamily: "var(--m)", fontSize: 11 }}><option value="0200">0200 (JA)</option><option value="9937">9937 (PVM)</option></select>
            <span style={{ fontFamily: "var(--m)", fontSize: 11.5, color: "#74c0fc" }}>{einv.profile.peppolScheme}:{einv.profile.peppolScheme === "9937" ? einv.profile.vatNo : einv.profile.regNo}</span>
          </div>
        </Section>
        <Section title={LT ? "Kanalai" : "Channels"}>
          {[["peppolEnabled", LT ? "Peppol tinklas įjungtas" : "Peppol network enabled"], ["emailConsent", LT ? "Gavėjų sutikimas dėl e. sąskaitų el. paštu (2006/112/EB 232 str.)" : "Recipients consent to e-invoices by e-mail (Dir. 2006/112/EC art. 232)"], ["vida", LT ? "ViDA režimo peržiūra (2030)" : "ViDA mode preview (2030)"]].map(([k, l]) => <label key={k} style={{ display: "flex", gap: 8, alignItems: "center", color: "#d2d2ce", fontFamily: "var(--s)", fontSize: 12.5, cursor: "pointer", marginBottom: 9 }}><input type="checkbox" checked={!!einv.settings[k]} onChange={(e) => setSettings(k, e.target.checked)} />{l}</label>)}
          <div style={{ color: "#8c8c88", fontFamily: "var(--s)", fontSize: 11.5, lineHeight: 1.55, marginTop: 6 }}>{LT ? "Maršrutas: viešasis pirkėjas → SABIS (privaloma); kitaip Peppol (jei dalyvis žinomas); kitaip el. paštas su sutikimu; kitaip PDF." : "Routing: public buyer → SABIS (mandatory); else Peppol (if participant known); else e-mail with consent; else PDF."}</div>
        </Section>
      </div>
      <Section title={`ViDA — (ES) 2025/516 · ${vida.days} ${LT ? "d. iki" : "days to"} ${vida.mandatoryFrom}`} accent={vida.ready ? "#69db7c" : "#ffd43b"}>
        <div style={{ color: "#bcbcb8", fontFamily: "var(--s)", fontSize: 12, lineHeight: 1.55, marginBottom: 12 }}>{LT ? EINV_REGIME.vida.note : EINV_REGIME.vida.noteEn} {LT ? "Priimta" : "Adopted"} {EINV_REGIME.vida.adopted}, {LT ? "įsigaliojo" : "in force"} {EINV_REGIME.vida.inForce}.</div>
        {vida.items.map((it) => <div key={it.key} style={{ display: "flex", gap: 10, alignItems: "flex-start", padding: "7px 0", borderBottom: `1px solid ${PL_SOFT}` }}>
          <span style={{ fontFamily: "var(--m)", fontSize: 12, color: it.ok ? "#69db7c" : "#ffd43b", width: 16 }}>{it.ok ? "✓" : "○"}</span>
          <div style={{ flex: 1 }}>
            <div style={{ color: "#fff", fontFamily: "var(--s)", fontSize: 12.5 }}>{LT ? it.lt : it.en}</div>
            <div style={{ color: "#8c8c88", fontFamily: "var(--m)", fontSize: 10, marginTop: 2 }}>{it.detail}</div>
          </div>
        </div>)}
        <div style={{ ...lbl, fontSize: 9, marginTop: 10 }}>{LT ? "ES vidaus AR dalis" : "Intra-EU AR share"}: {vida.intraEuShare}%</div>
      </Section>
    </div>}
  </div>;
}

